Definition buf5_lt4 {X : Type} (b : Buf5 X) : Prop :=
  match b with
  | B0 | B1 _ | B2 _ _ | B3 _ _ _ => True
  | _ => False
  end.

Definition buf5_yellow_pop_direct {X : Type} (b : Buf5 X) : Prop :=
  match b with
  | B2 _ _ | B3 _ _ _ | B4 _ _ _ _ => True
  | _ => False
  end.

Definition buf5_green_exact {X : Type} (b : Buf5 X) : Prop :=
  match b with
  | B2 _ _ | B3 _ _ _ => True
  | _ => False
  end.

Lemma buf5_green_exact_not_b5 :
  forall (X : Type) (b : Buf5 X),
    buf5_green_exact b ->
    is_b5 b = false.
Proof.
  intros X b Hb.
  destruct b; cbn in Hb |- *; try contradiction; reflexivity.
Qed.

Definition buf5_yellow_repair_absorbs {X : Type} (b : Buf5 X) : Prop :=
  match b with
  | B1 _ | B2 _ _ | B3 _ _ _ => True
  | _ => False
  end.

Definition kt4_push_ending_packet_view_ready {A : Type}
    (b : Buf5 (E.t A)) : Prop :=
  match b with
  | B4 _ _ cc d => E.level A cc = E.level A d
  | B5 _ _ _ d e => E.level A d = E.level A e
  | _ => True
  end.

Definition kt4_inject_ending_packet_view_ready {A : Type}
    (b : Buf5 (E.t A)) : Prop :=
  match b with
  | B4 a b _ _ => E.level A a = E.level A b
  | B5 a b _ _ _ => E.level A a = E.level A b
  | _ => True
  end.

Definition kt4_push_packet_view_ready {A : Type} (c : KChain A) : Prop :=
  match c with
  | KEnding b => kt4_push_ending_packet_view_ready b
  | KCons Green (PNode _ _ _) _ => True
  | KCons Yellow (PNode pre i suf) _ =>
      match pre with
      | B1 _ | B2 _ _ | B3 _ _ _ => True
      | B4 _ _ _ _ =>
          match i with
          | PNode pre' _ _ => buf5_yellow_repair_absorbs pre' /\
                              buf5_green_exact suf
          | Hole => False
          end
      | _ => False
      end
  | _ => False
  end.

Definition kt4_inject_packet_view_ready {A : Type} (c : KChain A) : Prop :=
  match c with
  | KEnding b => kt4_inject_ending_packet_view_ready b
  | KCons Green (PNode _ _ _) _ => True
  | KCons Yellow (PNode pre i suf) _ =>
      match suf with
      | B1 _ | B2 _ _ | B3 _ _ _ => True
      | B4 _ _ _ _ =>
          match i with
          | PNode _ _ suf' => buf5_green_exact pre /\
                              buf5_yellow_repair_absorbs suf'
          | Hole => False
          end
      | _ => False
      end
  | _ => False
  end.

Theorem push_kt4_direct_erasure_bridge_ending_lt4 :
  forall A (x : E.t A) (b : Buf5 (E.t A)) c',
    buf5_lt4 b ->
    push_kt4 x (KEnding b) = PushOk c' ->
    push_chain_full x (kchain_to_chain (KEnding b)) =
      Some (kchain_to_chain c').
Proof.
  intros A x b c' Hlt4 Hpush.
  destruct b; cbn in Hlt4, Hpush |- *; try contradiction;
    inversion Hpush; reflexivity.
Qed.

Theorem inject_kt4_direct_erasure_bridge_ending_lt4 :
  forall A (x : E.t A) (b : Buf5 (E.t A)) c',
    buf5_lt4 b ->
    inject_kt4 (KEnding b) x = PushOk c' ->
    inject_chain_full (kchain_to_chain (KEnding b)) x =
      Some (kchain_to_chain c').
Proof.
  intros A x b c' Hlt4 Hinject.
  destruct b; cbn in Hlt4, Hinject |- *; try contradiction;
    inversion Hinject; reflexivity.
Qed.

Inductive kt4_packet_chain_view {A : Type} : KChain A -> Chain A -> Prop :=
| kpcv_direct :
    forall c,
      kt4_packet_chain_view c (kchain_to_chain c)
| kpcv_terminal_b5_push :
    forall a b cc d e c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_view ->
      kt4_packet_chain_view (KEnding (B5 a b cc d e)) c_view
| kpcv_terminal_b5_inject :
    forall a b cc d e c_view,
      make_red_inject_chain (Ending (B5 a b cc d e)) = Some c_view ->
      kt4_packet_chain_view (KEnding (B5 a b cc d e)) c_view
| kpcv_terminal_b5_push_after_push :
    forall x a b cc d e c_prev c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      push_chain_full x c_prev = Some c_view ->
      kt4_packet_chain_view
        (KCons Green (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0))
        c_view
| kpcv_terminal_b5_inject_after_inject :
    forall x a b cc d e c_prev c_view,
      make_red_inject_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      inject_chain_full c_prev x = Some c_view ->
      kt4_packet_chain_view
        (KCons Green (PNode (B3 a b cc) Hole (B3 d e x)) (KEnding B0))
        c_view
| kpcv_terminal_b5_push_after_pop :
    forall a b cc d e c_prev c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      pop_chain_full c_prev = Some (a, c_view) ->
      kt4_packet_chain_view (KEnding (B4 b cc d e)) c_view
| kpcv_terminal_b5_push_after_pop_after_pop :
    forall a b cc d e c_prev c_mid c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      pop_chain_full c_prev = Some (a, c_mid) ->
      pop_chain_full c_mid = Some (b, c_view) ->
      kt4_packet_chain_view (KEnding (B3 cc d e)) c_view
| kpcv_terminal_b5_push_after_pop_after_inject :
    forall y a b cc d e c_prev c_mid c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      pop_chain_full c_prev = Some (a, c_mid) ->
      inject_chain_full c_mid y = Some c_view ->
      kt4_packet_chain_view (KEnding (B5 b cc d e y)) c_view
| kpcv_terminal_b5_push_after_pop_after_eject :
    forall a b cc d e c_prev c_mid c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      pop_chain_full c_prev = Some (a, c_mid) ->
      eject_chain_full c_mid = Some (c_view, e) ->
      kt4_packet_chain_view (KEnding (B3 b cc d)) c_view
| kpcv_terminal_b5_push_after_eject :
    forall a b cc d e c_prev c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      eject_chain_full c_prev = Some (c_view, e) ->
      kt4_packet_chain_view (KEnding (B4 a b cc d)) c_view
| kpcv_terminal_b5_push_after_eject_after_push :
    forall y a b cc d e c_prev c_mid c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      eject_chain_full c_prev = Some (c_mid, e) ->
      push_chain_full y c_mid = Some c_view ->
      kt4_packet_chain_view (KEnding (B5 y a b cc d)) c_view
| kpcv_terminal_b5_push_after_eject_after_inject :
    forall y a b cc d e c_prev c_mid c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      eject_chain_full c_prev = Some (c_mid, e) ->
      inject_chain_full c_mid y = Some c_view ->
      kt4_packet_chain_view (KEnding (B5 a b cc d y)) c_view
| kpcv_terminal_b5_push_after_eject_after_pop :
    forall a b cc d e c_prev c_mid c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      eject_chain_full c_prev = Some (c_mid, e) ->
      pop_chain_full c_mid = Some (a, c_view) ->
      kt4_packet_chain_view (KEnding (B3 b cc d)) c_view
| kpcv_terminal_b5_push_after_eject_after_eject :
    forall a b cc d e c_prev c_mid c_view,
      make_red_push_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      eject_chain_full c_prev = Some (c_mid, e) ->
      eject_chain_full c_mid = Some (c_view, d) ->
      kt4_packet_chain_view (KEnding (B3 a b cc)) c_view
| kpcv_terminal_b5_inject_after_pop :
    forall a b cc d e c_prev c_view,
      make_red_inject_chain (Ending (B5 a b cc d e)) = Some c_prev ->
      pop_chain_full c_prev = Some (a, c_view) ->
      kt4_packet_chain_view (KEnding (B4 b cc d e)) c_view
| kpcv_terminal_b5_inject_after_pop_after_push :
