| kpcv_green_of_red_pending :
    forall pre i suf tail c_repair,
      green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c_repair ->
      kt4_packet_chain_view c_repair
        (ChainCons (PNode pre i suf) (kchain_to_chain tail))
| kpcv_yellow_wrap_pending :
    forall pre i suf tail c_repair,
      green_of_red_k tail = Some c_repair ->
      kt4_packet_chain_view
        (KCons Yellow (PNode pre i suf) c_repair)
        (ChainCons (PNode pre i suf) (kchain_to_chain tail)).

Theorem push_kt4_packet_view_bridge_ending_b4 :
  forall A (x a b cc d : E.t A) c',
    E.level A cc = E.level A d ->
    push_kt4 x (KEnding (B4 a b cc d)) = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KEnding (B4 a b cc d)) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs'.
Proof.
  intros A x a b cc d c' Hlevel Hpush.
  cbn in Hpush. inversion Hpush; subst c'; clear Hpush.
  destruct (make_red_push_chain (Ending (B5 x a b cc d)))
    as [c_abs'|] eqn:Hnorm.
  - exists (Ending (B4 a b cc d)), c_abs'.
    repeat split.
    + constructor.
    + apply kpcv_terminal_b5_push. exact Hnorm.
    + cbn. exact Hnorm.
  - exfalso.
    cbn in Hnorm.
    destruct (Nat.eq_dec (E.level A cc) (E.level A d)) as [Heq|Hneq];
      [discriminate|congruence].
Qed.

Theorem inject_kt4_packet_view_bridge_ending_b4 :
