  cbn in Hinject. inversion Hinject; subst c'; clear Hinject.
  destruct (make_red_inject_chain (Ending (B5 a b cc d x)))
    as [c_abs'|] eqn:Hnorm.
  - exists (Ending (B4 a b cc d)), c_abs'.
    repeat split.
    + constructor.
    + apply kpcv_terminal_b5_inject. exact Hnorm.
    + cbn. exact Hnorm.
  - exfalso.
    cbn in Hnorm.
    destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq];
      [discriminate|congruence].
Qed.

Theorem push_kt4_packet_view_bridge_ending_b5 :
  forall A (x a b cc d e : E.t A) c',
    E.level A d = E.level A e ->
    push_kt4 x (KEnding (B5 a b cc d e)) = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KEnding (B5 a b cc d e)) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs'.
Proof.
  intros A x a b cc d e c' Hlevel Hpush.
  cbn in Hpush. inversion Hpush; subst c'; clear Hpush.
  destruct (make_red_push_chain (Ending (B5 a b cc d e)))
    as [c_abs|] eqn:Hnorm.
  - destruct (push_chain_full x c_abs) as [c_abs'|] eqn:Hstep.
    + exists c_abs, c_abs'.
      repeat split.
      * apply kpcv_terminal_b5_push. exact Hnorm.
      * eapply kpcv_terminal_b5_push_after_push; eauto.
      * exact Hstep.
    + exfalso.
      cbn in Hnorm.
      destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Heq|Hneq].
      * inversion Hnorm; subst c_abs; clear Hnorm.
        cbn in Hstep. discriminate.
      * congruence.
  - exfalso.
    cbn in Hnorm.
    destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Heq|Hneq];
      [discriminate|congruence].
Qed.

Theorem inject_kt4_packet_view_bridge_ending_b5 :
