Theorem push_kt4_packet_view_bridge_ending :
  forall A (x : E.t A) (b : Buf5 (E.t A)) c',
    kt4_push_ending_packet_view_ready b ->
    push_kt4 x (KEnding b) = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KEnding b) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs'.
Proof.
  intros A x b c' Hready Hpush.
  destruct b as [|a|a b|a b cc|a b cc d|a b cc d e];
    cbn in Hready.
  - exists (kchain_to_chain (KEnding B0)), (kchain_to_chain c').
    repeat split; try constructor.
    eapply push_kt4_direct_erasure_bridge_ending_lt4; [exact I|exact Hpush].
  - exists (kchain_to_chain (KEnding (B1 a))), (kchain_to_chain c').
    repeat split; try constructor.
    eapply push_kt4_direct_erasure_bridge_ending_lt4; [exact I|exact Hpush].
  - exists (kchain_to_chain (KEnding (B2 a b))), (kchain_to_chain c').
    repeat split; try constructor.
    eapply push_kt4_direct_erasure_bridge_ending_lt4; [exact I|exact Hpush].
  - exists (kchain_to_chain (KEnding (B3 a b cc))), (kchain_to_chain c').
    repeat split; try constructor.
    eapply push_kt4_direct_erasure_bridge_ending_lt4; [exact I|exact Hpush].
  - eapply push_kt4_packet_view_bridge_ending_b4; eauto.
  - eapply push_kt4_packet_view_bridge_ending_b5; eauto.
Qed.

