Qed.

Theorem push_kt4_direct_erasure_bridge_yellow_nonoverflow :
  forall A (x : E.t A) pre i suf tail c',
    buf5_lt4 pre ->
    push_kt4 x (KCons Yellow (PNode pre i suf) tail) = PushOk c' ->
    push_chain_full
      x (kchain_to_chain (KCons Yellow (PNode pre i suf) tail)) =
      Some (kchain_to_chain c').
Proof.
  intros A x pre i suf tail c' Hlt4 Hpush.
  destruct pre; cbn in Hlt4, Hpush |- *; try contradiction;
