Theorem push_kt4_direct_erasure_bridge_yellow_overflow_nested_green_suffix :
  forall A (x a b cc d : E.t A) pre' i' suf' suf tail c',
    buf5_yellow_repair_absorbs pre' ->
    buf5_green_exact suf ->
    push_kt4 x
      (KCons Yellow (PNode (B4 a b cc d) (PNode pre' i' suf') suf) tail) =
      PushOk c' ->
    push_chain_full x
      (kchain_to_chain
        (KCons Yellow (PNode (B4 a b cc d) (PNode pre' i' suf') suf) tail)) =
      Some (kchain_to_chain c').
Proof.
  intros A x a b cc d pre' i' suf' suf tail c' Hpre' Hsuf Hpush.
  unfold push_kt4 in Hpush; cbn -[green_of_red_k] in Hpush.
  destruct (green_of_red_k
      (KCons Red (PNode (B5 x a b cc d) (PNode pre' i' suf') suf) tail))
    as [c_repair|] eqn:Hred; [|inversion Hpush].
  inversion Hpush; subst; clear Hpush.
  unfold green_of_red_k in Hred.
  cbn -[Nat.eq_dec] in Hred |- *.
  destruct pre' as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    cbn in Hpre', Hred |- *; try contradiction; try discriminate;
    destruct suf as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn in Hsuf, Hred |- *; try contradiction;
    try solve [
      destruct (Nat.eq_dec (E.level A cc) (E.level A d)) as [Heq|Hneq];
      [inversion Hred; reflexivity|discriminate Hred]
    ].
Qed.

Theorem inject_kt4_direct_erasure_bridge_yellow_overflow_nested_green_prefix :
  forall A (x a b cc d : E.t A) pre pre' i' suf' tail c',
    buf5_green_exact pre ->
    buf5_yellow_repair_absorbs suf' ->
    inject_kt4
      (KCons Yellow (PNode pre (PNode pre' i' suf') (B4 a b cc d)) tail) x =
      PushOk c' ->
    inject_chain_full
      (kchain_to_chain
