      Some (kchain_to_chain c').
Proof.
  intros A x a b cc d pre pre' i' suf' tail c' Hpre Hsuf' Hinject.
  unfold inject_kt4 in Hinject; cbn -[green_of_red_k] in Hinject.
  destruct (green_of_red_k
      (KCons Red (PNode pre (PNode pre' i' suf') (B5 a b cc d x)) tail))
    as [c_repair|] eqn:Hred; [|inversion Hinject].
  inversion Hinject; subst; clear Hinject.
  unfold green_of_red_k in Hred.
  cbn -[Nat.eq_dec] in Hred |- *.
  destruct pre as [|q1|q1 q2|q1 q2 q3|q1 q2 q3 q4|q1 q2 q3 q4 q5];
    cbn in Hpre, Hred |- *; try contradiction; try discriminate;
    destruct suf' as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn in Hsuf', Hred |- *; try contradiction;
    try solve [
      destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq];
      [inversion Hred; reflexivity|discriminate Hred]
    ].
Qed.

