Theorem push_kt4_direct_erasure_bridge_green_non_red_tail :
  forall A (x : E.t A) (pre suf : Buf5 (E.t A)) (i : Packet A)
    (tail c' : KChain A),
    kchain_top_color tail <> Red ->
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    push_chain_full
      x (kchain_to_chain (KCons Green (PNode pre i suf) tail)) =
      Some (kchain_to_chain c').
Proof.
  intros A x pre suf i tail c' Hnotred Hpush.
  destruct pre; cbn in Hpush |- *; try discriminate;
    destruct tail as [bt|col p tail']; cbn in Hnotred, Hpush |- *.
  - destruct i; inversion Hpush; reflexivity.
  - destruct col; cbn in Hnotred, Hpush |- *;
      try (destruct i; inversion Hpush; reflexivity);
      exfalso; apply Hnotred; reflexivity.
  - destruct i; inversion Hpush; reflexivity.
  - destruct col; cbn in Hnotred, Hpush |- *;
      try (destruct i; inversion Hpush; reflexivity);
      exfalso; apply Hnotred; reflexivity.
Qed.

