Theorem push_kt4_packet_view_bridge_green_red_tail_pending :
  forall A (x : E.t A) (pre suf : Buf5 (E.t A)) (i : Packet A)
    (tail c' : KChain A),
    kchain_top_color tail = Red ->
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KCons Green (PNode pre i suf) tail) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs'.
Proof.
  intros A x pre suf i tail c' Hred_tail Hpush.
  destruct pre as [|a|a b|a b cc|a b cc d|a b cc d e];
    cbn -[yellow_wrap_pr green_of_red_k] in Hpush; try discriminate.
  - unfold yellow_wrap_pr in Hpush.
    destruct tail as [bt|col p tail'];
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpush; try discriminate.
    destruct col;
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpush; try discriminate.
    destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
      [|inversion Hpush].
    inversion Hpush; subst; clear Hpush.
    exists (kchain_to_chain
        (KCons Green (PNode (B2 a b) i suf) (KCons Red p tail'))),
      (ChainCons (PNode (B3 x a b) i suf)
         (kchain_to_chain (KCons Red p tail'))).
    repeat split.
    + constructor.
    + eapply kpcv_yellow_wrap_pending. exact Hred.
    + destruct i; reflexivity.
  - unfold yellow_wrap_pr in Hpush.
    destruct tail as [bt|col p tail'];
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpush; try discriminate.
    destruct col;
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpush; try discriminate.
    destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
      [|inversion Hpush].
    inversion Hpush; subst; clear Hpush.
    exists (kchain_to_chain
        (KCons Green (PNode (B3 a b cc) i suf) (KCons Red p tail'))),
      (ChainCons (PNode (B4 x a b cc) i suf)
         (kchain_to_chain (KCons Red p tail'))).
    repeat split.
    + constructor.
    + eapply kpcv_yellow_wrap_pending. exact Hred.
    + destruct i; reflexivity.
Qed.

Theorem inject_kt4_packet_view_bridge_green_red_tail_pending :
  forall A (x : E.t A) (pre suf : Buf5 (E.t A)) (i : Packet A)
    (tail c' : KChain A),
    kchain_top_color tail = Red ->
    inject_kt4 (KCons Green (PNode pre i suf) tail) x = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KCons Green (PNode pre i suf) tail) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
