Proof.
  intros A x pre suf i tail c' Hred_tail Hinject.
  destruct suf as [|a|a b|a b cc|a b cc d|a b cc d e];
    cbn -[yellow_wrap_pr green_of_red_k] in Hinject; try discriminate.
  - unfold yellow_wrap_pr in Hinject.
    destruct tail as [bt|col p tail'];
      cbn in Hred_tail; cbn -[green_of_red_k] in Hinject; try discriminate.
    destruct col;
      cbn in Hred_tail; cbn -[green_of_red_k] in Hinject; try discriminate.
    destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
      [|inversion Hinject].
    inversion Hinject; subst; clear Hinject.
    exists (kchain_to_chain
        (KCons Green (PNode pre i (B2 a b)) (KCons Red p tail'))),
      (ChainCons (PNode pre i (B3 a b x))
         (kchain_to_chain (KCons Red p tail'))).
    repeat split.
    + constructor.
    + eapply kpcv_yellow_wrap_pending. exact Hred.
    + destruct i; reflexivity.
  - unfold yellow_wrap_pr in Hinject.
    destruct tail as [bt|col p tail'];
      cbn in Hred_tail; cbn -[green_of_red_k] in Hinject; try discriminate.
    destruct col;
      cbn in Hred_tail; cbn -[green_of_red_k] in Hinject; try discriminate.
    destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
      [|inversion Hinject].
    inversion Hinject; subst; clear Hinject.
    exists (kchain_to_chain
        (KCons Green (PNode pre i (B3 a b cc)) (KCons Red p tail'))),
      (ChainCons (PNode pre i (B4 a b cc x))
         (kchain_to_chain (KCons Red p tail'))).
    repeat split.
    + constructor.
    + eapply kpcv_yellow_wrap_pending. exact Hred.
    + destruct i; reflexivity.
Qed.

Theorem push_kt4_packet_view_bridge_green :
  forall A (x : E.t A) (pre suf : Buf5 (E.t A)) (i : Packet A)
    (tail c' : KChain A),
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KCons Green (PNode pre i suf) tail) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs'.
Proof.
  intros A x pre suf i tail c' Hpush.
  destruct (kchain_top_color tail) eqn:Htop.
  - eapply push_kt4_packet_view_bridge_green_non_red_tail; eauto.
    rewrite Htop. discriminate.
  - eapply push_kt4_packet_view_bridge_green_non_red_tail; eauto.
    rewrite Htop. discriminate.
  - eapply push_kt4_packet_view_bridge_green_red_tail_pending; eauto.
Qed.

Theorem inject_kt4_packet_view_bridge_green :
