      inject_chain_full c_abs x = Some c_abs'.
Proof.
  intros A x pre suf i tail c' Hinject.
  destruct (kchain_top_color tail) eqn:Htop.
  - eapply inject_kt4_packet_view_bridge_green_non_red_tail; eauto.
    rewrite Htop. discriminate.
  - eapply inject_kt4_packet_view_bridge_green_non_red_tail; eauto.
    rewrite Htop. discriminate.
  - eapply inject_kt4_packet_view_bridge_green_red_tail_pending; eauto.
Qed.

Theorem push_kt4_packet_view_bridge_ready :
  forall A (x : E.t A) (c c' : KChain A),
    kt4_push_packet_view_ready c ->
    push_kt4 x c = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs'.
Proof.
  intros A x c c' Hready Hpush.
  destruct c as [b|col p tail].
  - eapply push_kt4_packet_view_bridge_ending; eauto.
  - destruct col; cbn in Hready, Hpush.
    + destruct p as [|pre i suf]; [contradiction|].
      eapply push_kt4_packet_view_bridge_green; eauto.
    + destruct p as [|pre i suf]; [contradiction|].
      destruct pre as [|a|a b|a b cc|a b cc d|a b cc d e];
        cbn in Hready, Hpush; try contradiction.
      * eapply push_kt4_packet_view_bridge_yellow_nonoverflow;
          [exact I|exact Hpush].
      * eapply push_kt4_packet_view_bridge_yellow_nonoverflow;
          [exact I|exact Hpush].
      * eapply push_kt4_packet_view_bridge_yellow_nonoverflow;
          [exact I|exact Hpush].
      * destruct i as [|pre' i' suf']; [contradiction|].
        destruct Hready as [Hpre' Hsuf].
        eapply push_kt4_packet_view_bridge_yellow_overflow_nested_green_suffix;
          eauto.
    + contradiction.
Qed.

Theorem inject_kt4_packet_view_bridge_ready :
  forall A (x : E.t A) (c c' : KChain A),
    kt4_inject_packet_view_ready c ->
    inject_kt4 c x = PushOk c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      inject_chain_full c_abs x = Some c_abs'.
Proof.
  intros A x c c' Hready Hinject.
  destruct c as [b|col p tail].
  - eapply inject_kt4_packet_view_bridge_ending; eauto.
  - destruct col; cbn in Hready, Hinject.
    + destruct p as [|pre i suf]; [contradiction|].
      eapply inject_kt4_packet_view_bridge_green; eauto.
    + destruct p as [|pre i suf]; [contradiction|].
      destruct suf as [|a|a b|a b cc|a b cc d|a b cc d e];
        cbn in Hready, Hinject; try contradiction.
      * eapply inject_kt4_packet_view_bridge_yellow_nonoverflow;
          [exact I|exact Hinject].
      * eapply inject_kt4_packet_view_bridge_yellow_nonoverflow;
          [exact I|exact Hinject].
      * eapply inject_kt4_packet_view_bridge_yellow_nonoverflow;
          [exact I|exact Hinject].
      * destruct i as [|pre' i' suf']; [contradiction|].
        destruct Hready as [Hpre Hsuf'].
        eapply inject_kt4_packet_view_bridge_yellow_overflow_nested_green_prefix;
          eauto.
    + contradiction.
Qed.

