Theorem pop_kt4_packet_view_bridge_green_red_tail_pending :
  forall A (pre suf : Buf5 (E.t A)) (i : Packet A)
    (tail : KChain A) (x : E.t A) c',
    kchain_top_color tail = Red ->
    pop_kt4 (KCons Green (PNode pre i suf) tail) = PopOk x c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KCons Green (PNode pre i suf) tail) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      pop_chain_full c_abs = Some (x, c_abs').
Proof.
  intros A pre suf i tail x c' Hred_tail Hpop.
  destruct pre as [|a|a b|a b cc|a b cc d|a b cc d e];
    cbn -[yellow_wrap_pr green_of_red_k] in Hpop; try discriminate.
  - unfold yellow_wrap_pr in Hpop.
    destruct tail as [bt|col p tail'];
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpop; try discriminate.
    destruct col;
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpop; try discriminate.
    destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
      [|inversion Hpop].
    inversion Hpop; subst; clear Hpop.
    exists (kchain_to_chain
        (KCons Green (PNode (B2 x b) i suf) (KCons Red p tail'))),
      (ChainCons (PNode (B1 b) i suf)
         (kchain_to_chain (KCons Red p tail'))).
    repeat split.
    + constructor.
    + eapply kpcv_yellow_wrap_pending. exact Hred.
    + destruct i; reflexivity.
  - unfold yellow_wrap_pr in Hpop.
    destruct tail as [bt|col p tail'];
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpop; try discriminate.
    destruct col;
      cbn in Hred_tail; cbn -[green_of_red_k] in Hpop; try discriminate.
    destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
      [|inversion Hpop].
    inversion Hpop; subst; clear Hpop.
    exists (kchain_to_chain
        (KCons Green (PNode (B3 x b cc) i suf) (KCons Red p tail'))),
      (ChainCons (PNode (B2 b cc) i suf)
         (kchain_to_chain (KCons Red p tail'))).
    repeat split.
    + constructor.
    + eapply kpcv_yellow_wrap_pending. exact Hred.
    + destruct i; reflexivity.
Qed.

