Theorem pop_kt4_packet_view_bridge_green :
  forall A (pre suf : Buf5 (E.t A)) (i : Packet A)
    (tail : KChain A) (x : E.t A) c',
    pop_kt4 (KCons Green (PNode pre i suf) tail) = PopOk x c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view (KCons Green (PNode pre i suf) tail) c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      pop_chain_full c_abs = Some (x, c_abs').
Proof.
  intros A pre suf i tail x c' Hpop.
  destruct (kchain_top_color tail) eqn:Htop.
  - eapply pop_kt4_packet_view_bridge_green_non_red_tail; eauto.
    rewrite Htop. discriminate.
  - eapply pop_kt4_packet_view_bridge_green_non_red_tail; eauto.
    rewrite Htop. discriminate.
  - eapply pop_kt4_packet_view_bridge_green_red_tail_pending; eauto.
Qed.

