Theorem pop_kt4_packet_view_bridge_non_red_top :
  forall A (c c' : KChain A) (x : E.t A),
    kchain_top_color c <> Red ->
    pop_kt4 c = PopOk x c' ->
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      pop_chain_full c_abs = Some (x, c_abs').
Proof.
  intros A c c' x Htop Hpop.
  destruct c as [b|col p tail].
  - eapply pop_kt4_packet_view_bridge_ending; eauto.
  - destruct col; cbn in Htop, Hpop.
    + destruct p as [|pre i suf]; [discriminate|].
      eapply pop_kt4_packet_view_bridge_green; eauto.
    + destruct p as [|pre i suf]; [discriminate|].
      eapply pop_kt4_packet_view_bridge_yellow; eauto.
    + exfalso. apply Htop. reflexivity.
Qed.

