Theorem push_kt4_packet_view_exec_correct_O1_repr_ready :
  forall (A : Type) (lroot : Loc) (x : E.t A) (c c' : KChain A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    kt4_push_packet_view_ready c ->
    push_kt4 x c = PushOk c' ->
    E.level A x = 0 ->
    well_formed_heap H ->
    exec_push_pkt_C lroot x H = Some (H', lroot', n) ->
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs' /\
      (chain_repr H lroot c_abs ->
       n <= NF_PUSH_PKT_FULL /\
       chain_to_list c_abs' = E.to_list A x ++ chain_to_list c_abs /\
       chain_repr H' lroot' c_abs').
Proof.
  intros A lroot x c c' H H' lroot' n Hready Hpush Hlevel Hwf Hexec.
  destruct (@push_kt4_packet_view_bridge_ready A x c c' Hready Hpush)
    as [c_abs [c_abs' [Hview [Hview' Habs]]]].
  exists c_abs, c_abs'.
  split; [exact Hview|].
  split; [exact Hview'|].
  split; [exact Habs|].
  intros HR.
  eapply packet_push_full_correct_O1_repr; eauto.
Qed.

Theorem inject_kt4_packet_view_exec_correct_O1_repr_ready :
  forall (A : Type) (lroot : Loc) (x : E.t A) (c c' : KChain A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
