Definition kt4_heap_packet_view_repr {A : Type}
    (H : HeapP (E.t A)) (lroot : Loc) (c : KChain A) : Prop :=
  exists c_abs,
    kt4_packet_chain_view c c_abs /\
    chain_repr H lroot c_abs.

Definition kt4_push_heap_packet_view_step_repr {A : Type}
    (H : HeapP (E.t A)) (lroot : Loc) (x : E.t A)
    (c c' : KChain A) : Prop :=
  exists c_abs c_abs',
    kt4_packet_chain_view c c_abs /\
    kt4_packet_chain_view c' c_abs' /\
    push_chain_full x c_abs = Some c_abs' /\
    chain_repr H lroot c_abs.

Definition kt4_inject_heap_packet_view_step_repr {A : Type}
    (H : HeapP (E.t A)) (lroot : Loc) (c : KChain A)
    (x : E.t A) (c' : KChain A) : Prop :=
  exists c_abs c_abs',
    kt4_packet_chain_view c c_abs /\
    kt4_packet_chain_view c' c_abs' /\
    inject_chain_full c_abs x = Some c_abs' /\
    is_b5 (chain_top_pre c_abs') = false /\
    chain_repr H lroot c_abs.

Definition kt4_pop_heap_packet_view_step_repr {A : Type}
    (H : HeapP (E.t A)) (lroot : Loc) (c : KChain A)
    (x : E.t A) (c' : KChain A) : Prop :=
  exists c_abs c_abs',
    kt4_packet_chain_view c c_abs /\
    kt4_packet_chain_view c' c_abs' /\
    pop_chain_full c_abs = Some (x, c_abs') /\
    chain_repr H lroot c_abs.

Definition kt4_eject_heap_packet_view_step_repr {A : Type}
    (H : HeapP (E.t A)) (lroot : Loc) (c : KChain A)
    (x : E.t A) (c' : KChain A) : Prop :=
  exists c_abs c_abs',
    kt4_packet_chain_view c c_abs /\
    kt4_packet_chain_view c' c_abs' /\
    eject_chain_full c_abs = Some (c_abs', x) /\
    chain_repr H lroot c_abs.

Theorem push_kt4_heap_packet_view_exec_preserves_step_repr :
  forall (A : Type) (lroot : Loc) (x : E.t A) (c c' : KChain A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    E.level A x = 0 ->
    well_formed_heap H ->
    exec_push_pkt_C lroot x H = Some (H', lroot', n) ->
    kt4_push_heap_packet_view_step_repr H lroot x c c' ->
    n <= NF_PUSH_PKT_FULL /\
    kt4_heap_packet_view_repr H' lroot' c' /\
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs' /\
      chain_to_list c_abs' = E.to_list A x ++ chain_to_list c_abs /\
      chain_repr H' lroot' c_abs'.
Proof.
  intros A lroot x c c' H H' lroot' n Hlevel Hwf Hexec Hstep.
  destruct Hstep as [c_abs [c_abs' [Hview [Hview' [Habs HR]]]]].
  destruct (@packet_push_full_correct_O1_repr
      A lroot x c_abs c_abs' H H' lroot' n
      HR Hlevel Hwf Habs Hexec) as [Hcost [Hseq Hrepr']].
  split; [exact Hcost|].
  split.
  - exists c_abs'. split; assumption.
  - exists c_abs, c_abs'.
    repeat split; assumption.
Qed.

