    kt4_pop_heap_packet_view_step_repr H lroot c x c'.

Definition kt4_eject_role_heap_packet_view_repr {A : Type}
    (H : HeapP (E.t A)) (lroot : Loc) (c : KChain A) : Prop :=
  forall x c',
    kchain_top_color c <> Red ->
    eject_kt4 c = PopOk x c' ->
    kt4_eject_heap_packet_view_step_repr H lroot c x c'.

Definition kt4_all_role_heap_packet_view_repr {A : Type}
    (H : HeapP (E.t A)) (lroot : Loc) (c : KChain A) : Prop :=
  kt4_push_role_heap_packet_view_repr H lroot c /\
  kt4_inject_role_heap_packet_view_repr H lroot c /\
  kt4_pop_role_heap_packet_view_repr H lroot c /\
  kt4_eject_role_heap_packet_view_repr H lroot c.

Theorem push_kt4_heap_packet_view_exec_preserves_role_repr :
  forall (A : Type) (lroot : Loc) (x : E.t A) (c c' : KChain A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    kt4_push_role_heap_packet_view_repr H lroot c ->
    kt4_push_packet_view_ready c ->
    push_kt4 x c = PushOk c' ->
    E.level A x = 0 ->
    well_formed_heap H ->
    exec_push_pkt_C lroot x H = Some (H', lroot', n) ->
    n <= NF_PUSH_PKT_FULL /\
    kt4_heap_packet_view_repr H' lroot' c' /\
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs' /\
      chain_to_list c_abs' = E.to_list A x ++ chain_to_list c_abs /\
      chain_repr H' lroot' c_abs'.
Proof.
  intros A lroot x c c' H H' lroot' n
    Hrole Hready Hpush Hlevel Hwf Hexec.
  eapply push_kt4_heap_packet_view_exec_preserves_step_repr; eauto.
Qed.

