Theorem kt4_all_role_heap_packet_view_exec_cost_refinement_contract :
  (forall (A : Type) (lroot : Loc) (x : E.t A) (c c' : KChain A)
          (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    kt4_all_role_heap_packet_view_repr H lroot c ->
    kt4_push_packet_view_ready c ->
