      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      push_chain_full x c_abs = Some c_abs' /\
      chain_to_list c_abs' = E.to_list A x ++ chain_to_list c_abs /\
      chain_repr H' lroot' c_abs') /\
  (forall (A : Type) (lroot : Loc) (c : KChain A) (x : E.t A)
          (c' : KChain A) (H H' : HeapP (E.t A)) (lroot' : Loc)
          (n : nat),
    kt4_all_role_heap_packet_view_repr H lroot c ->
    kt4_inject_packet_view_ready c ->
    inject_kt4 c x = PushOk c' ->
    E.level A x = 0 ->
    well_formed_heap H ->
    exec_inject_pkt_C lroot x H = Some (H', lroot', n) ->
    n <= NF_PUSH_PKT_FULL /\
    kt4_heap_packet_view_repr H' lroot' c' /\
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      inject_chain_full c_abs x = Some c_abs' /\
      is_b5 (chain_top_pre c_abs') = false /\
      chain_to_list c_abs' = chain_to_list c_abs ++ E.to_list A x /\
      chain_repr H' lroot' c_abs') /\
  (forall (A : Type) (lroot : Loc) (c c' : KChain A) (x : E.t A)
          (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    kt4_all_role_heap_packet_view_repr H lroot c ->
    kchain_top_color c <> Red ->
    pop_kt4 c = PopOk x c' ->
    well_formed_heap H ->
    exec_pop_pkt_full_C lroot H = Some (H', Some (x, lroot'), n) ->
    n <= NF_POP_PKT_FULL /\
    kt4_heap_packet_view_repr H' lroot' c' /\
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      pop_chain_full c_abs = Some (x, c_abs') /\
      chain_to_list c_abs = E.to_list A x ++ chain_to_list c_abs' /\
      chain_repr H' lroot' c_abs') /\
  (forall (A : Type) (lroot : Loc) (c c' : KChain A) (x : E.t A)
          (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    kt4_all_role_heap_packet_view_repr H lroot c ->
    kchain_top_color c <> Red ->
    eject_kt4 c = PopOk x c' ->
    well_formed_heap H ->
    exec_eject_pkt_full_C lroot H = Some (H', Some (lroot', x), n) ->
    n <= NF_POP_PKT_FULL /\
    kt4_heap_packet_view_repr H' lroot' c' /\
    exists c_abs c_abs',
      kt4_packet_chain_view c c_abs /\
      kt4_packet_chain_view c' c_abs' /\
      eject_chain_full c_abs = Some (c_abs', x) /\
      chain_to_list c_abs = chain_to_list c_abs' ++ E.to_list A x /\
      chain_repr H' lroot' c_abs').
Proof.
  split.
  - exact (@push_kt4_all_role_heap_packet_view_exec_preserves_heap_packet_view_repr).
  - split.
    + exact (@inject_kt4_all_role_heap_packet_view_exec_preserves_heap_packet_view_repr).
    + split.
      * exact (@pop_kt4_all_role_heap_packet_view_exec_preserves_heap_packet_view_repr).
      * exact (@eject_kt4_all_role_heap_packet_view_exec_preserves_heap_packet_view_repr).
Qed.

Theorem direct_green_heap_view_supports_push_role_repr_general :
  forall (A : Type) (pre suf : Buf5 (E.t A)) (i : Packet A)
         (tail : KChain A) (H : HeapP (E.t A)) (lroot : Loc),
    buf5_green_exact pre ->
    chain_repr H lroot
      (kchain_to_chain (KCons Green (PNode pre i suf) tail)) ->
    kt4_push_role_heap_packet_view_repr H lroot
      (KCons Green (PNode pre i suf) tail).
Proof.
  intros A pre suf i tail H lroot Hpre Hrepr x c' _ Hpush.
  exists (kchain_to_chain (KCons Green (PNode pre i suf) tail)).
  destruct (kchain_top_color tail) eqn:Htop.
  - exists (kchain_to_chain c').
    repeat split; try constructor.
    + eapply push_kt4_direct_erasure_bridge_green_non_red_tail; eauto.
      rewrite Htop. discriminate.
    + exact Hrepr.
  - exists (kchain_to_chain c').
    repeat split; try constructor.
    + eapply push_kt4_direct_erasure_bridge_green_non_red_tail; eauto.
      rewrite Htop. discriminate.
    + exact Hrepr.
  - destruct pre as [|a|a b|a b cc|a b cc d|a b cc d e];
      cbn in Hpre; try contradiction;
      cbn -[yellow_wrap_pr green_of_red_k] in Hpush.
    + unfold yellow_wrap_pr in Hpush.
      destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Hpush; try discriminate.
      destruct col;
        cbn in Htop; cbn -[green_of_red_k] in Hpush; try discriminate.
      destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
        [|inversion Hpush].
      inversion Hpush; subst c'; clear Hpush.
      exists (ChainCons (PNode (B3 x a b) i suf)
        (kchain_to_chain (KCons Red p tail'))).
      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * exact Hrepr.
    + unfold yellow_wrap_pr in Hpush.
      destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Hpush; try discriminate.
      destruct col;
        cbn in Htop; cbn -[green_of_red_k] in Hpush; try discriminate.
      destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
        [|inversion Hpush].
      inversion Hpush; subst c'; clear Hpush.
      exists (ChainCons (PNode (B4 x a b cc) i suf)
        (kchain_to_chain (KCons Red p tail'))).
      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * exact Hrepr.
Qed.

Theorem direct_green_heap_view_supports_inject_role_repr_general :
  forall (A : Type) (pre suf : Buf5 (E.t A)) (i : Packet A)
         (tail : KChain A) (H : HeapP (E.t A)) (lroot : Loc),
    buf5_green_exact pre ->
    buf5_green_exact suf ->
    chain_repr H lroot
      (kchain_to_chain (KCons Green (PNode pre i suf) tail)) ->
    kt4_inject_role_heap_packet_view_repr H lroot
      (KCons Green (PNode pre i suf) tail).
Proof.
  intros A pre suf i tail H lroot Hpre Hsuf Hrepr x c' _ Hinject.
  exists (kchain_to_chain (KCons Green (PNode pre i suf) tail)).
  destruct (kchain_top_color tail) eqn:Htop.
  - assert (Hnot_b5 : is_b5 (chain_top_pre (kchain_to_chain c')) = false).
    {
      destruct pre as [|pa|pa pb|pa pb pc|pa pb pc pd|pa pb pc pd pe];
        cbn in Hpre; try contradiction;
        destruct suf as [|sa|sa sb|sa sb sc|sa sb sc sd|sa sb sc sd se];
        cbn in Hsuf, Hinject; try contradiction;
        unfold yellow_wrap_pr in Hinject;
        destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Hinject;
        try (destruct i; inversion Hinject; cbn; reflexivity);
        destruct col; cbn in Htop; cbn -[green_of_red_k] in Hinject;
        try discriminate;
        destruct i; inversion Hinject; cbn; reflexivity.
    }
    exists (kchain_to_chain c').
    repeat split; try constructor.
    + eapply inject_kt4_direct_erasure_bridge_green_non_red_tail; eauto.
      rewrite Htop. discriminate.
    + exact Hnot_b5.
    + exact Hrepr.
  - assert (Hnot_b5 : is_b5 (chain_top_pre (kchain_to_chain c')) = false).
    {
      destruct pre as [|pa|pa pb|pa pb pc|pa pb pc pd|pa pb pc pd pe];
        cbn in Hpre; try contradiction;
        destruct suf as [|sa|sa sb|sa sb sc|sa sb sc sd|sa sb sc sd se];
        cbn in Hsuf, Hinject; try contradiction;
        unfold yellow_wrap_pr in Hinject;
        destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Hinject;
        try (destruct i; inversion Hinject; cbn; reflexivity);
        destruct col; cbn in Htop; cbn -[green_of_red_k] in Hinject;
        try discriminate;
        destruct i; inversion Hinject; cbn; reflexivity.
    }
    exists (kchain_to_chain c').
    repeat split; try constructor.
    + eapply inject_kt4_direct_erasure_bridge_green_non_red_tail; eauto.
      rewrite Htop. discriminate.
    + exact Hnot_b5.
    + exact Hrepr.
  - destruct suf as [|a|a b|a b cc|a b cc d|a b cc d e];
      cbn in Hsuf; try contradiction;
      cbn -[yellow_wrap_pr green_of_red_k] in Hinject.
    + unfold yellow_wrap_pr in Hinject.
      destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Hinject; try discriminate.
      destruct col;
        cbn in Htop; cbn -[green_of_red_k] in Hinject; try discriminate.
      destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
        [|inversion Hinject].
      inversion Hinject; subst; clear Hinject.
      exists (ChainCons (PNode pre i (B3 a b x))
        (kchain_to_chain (KCons Red p tail'))).
      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * destruct pre as [|pa|pa pb|pa pb pc|pa pb pc pd|pa pb pc pd pe];
          cbn in Hpre; try contradiction; reflexivity.
      * exact Hrepr.
    + unfold yellow_wrap_pr in Hinject.
      destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Hinject; try discriminate.
      destruct col;
        cbn in Htop; cbn -[green_of_red_k] in Hinject; try discriminate.
      destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
        [|inversion Hinject].
      inversion Hinject; subst c'; clear Hinject.
      exists (ChainCons (PNode pre i (B4 a b cc x))
        (kchain_to_chain (KCons Red p tail'))).
      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * destruct pre as [|pa|pa pb|pa pb pc|pa pb pc pd|pa pb pc pd pe];
          cbn in Hpre; try contradiction; reflexivity.
      * exact Hrepr.
Qed.

