      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * exact Hrepr.
    + unfold yellow_wrap_pr in Hpop.
      destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Hpop; try discriminate.
      destruct col;
        cbn in Htop; cbn -[green_of_red_k] in Hpop; try discriminate.
      destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
        [|inversion Hpop].
      inversion Hpop; subst x c'; clear Hpop.
      exists (ChainCons (PNode (B2 b cc) i suf)
        (kchain_to_chain (KCons Red p tail'))).
      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * exact Hrepr.
Qed.

Theorem direct_green_heap_view_supports_eject_role_repr_general :
  forall (A : Type) (pre suf : Buf5 (E.t A)) (i : Packet A)
         (tail : KChain A) (H : HeapP (E.t A)) (lroot : Loc),
    buf5_green_exact suf ->
    chain_repr H lroot
      (kchain_to_chain (KCons Green (PNode pre i suf) tail)) ->
    kt4_eject_role_heap_packet_view_repr H lroot
      (KCons Green (PNode pre i suf) tail).
Proof.
  intros A pre suf i tail H lroot Hsuf Hrepr x c' _ Heject.
  exists (kchain_to_chain (KCons Green (PNode pre i suf) tail)).
  destruct (kchain_top_color tail) eqn:Htop.
  - exists (kchain_to_chain c').
    repeat split; try constructor.
    + eapply eject_kt4_direct_erasure_bridge_green_non_red_tail; eauto.
      rewrite Htop. discriminate.
    + exact Hrepr.
  - exists (kchain_to_chain c').
    repeat split; try constructor.
    + eapply eject_kt4_direct_erasure_bridge_green_non_red_tail; eauto.
      rewrite Htop. discriminate.
    + exact Hrepr.
  - destruct suf as [|a|a b|a b cc|a b cc d|a b cc d e];
      cbn in Hsuf; try contradiction;
      cbn -[yellow_wrap_pr green_of_red_k] in Heject.
    + unfold yellow_wrap_pr in Heject.
      destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Heject; try discriminate.
      destruct col;
        cbn in Htop; cbn -[green_of_red_k] in Heject; try discriminate.
      destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
        [|inversion Heject].
      inversion Heject; subst x c'; clear Heject.
      exists (ChainCons (PNode pre i (B1 a))
        (kchain_to_chain (KCons Red p tail'))).
      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * exact Hrepr.
    + unfold yellow_wrap_pr in Heject.
      destruct tail as [bt|col p tail'];
        cbn in Htop; cbn -[green_of_red_k] in Heject; try discriminate.
      destruct col;
        cbn in Htop; cbn -[green_of_red_k] in Heject; try discriminate.
      destruct (green_of_red_k (KCons Red p tail')) as [c_repair|] eqn:Hred;
        [|inversion Heject].
      inversion Heject; subst x c'; clear Heject.
      exists (ChainCons (PNode pre i (B2 a b))
        (kchain_to_chain (KCons Red p tail'))).
      repeat split.
      * constructor.
      * eapply kpcv_yellow_wrap_pending. exact Hred.
      * destruct i; reflexivity.
      * exact Hrepr.
Qed.

