Theorem direct_ending_nb5_heap_view_supports_push_role_repr_general :
  forall (A : Type) (b : Buf5 (E.t A)) (H : HeapP (E.t A)) (lroot : Loc),
    is_b5 b = false ->
    chain_repr H lroot (kchain_to_chain (KEnding b)) ->
    kt4_push_role_heap_packet_view_repr H lroot (KEnding b).
Proof.
  intros A b H lroot Hnb5 Hrepr x c' Hready Hpush.
  destruct b as [|a|a b|a b cc|a b cc d|a b cc d e];
    cbn in Hnb5, Hready, Hpush; try discriminate.
  - exists (Ending B0), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply push_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hpush].
    + exact Hrepr.
  - exists (Ending (B1 a)), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply push_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hpush].
    + exact Hrepr.
  - exists (Ending (B2 a b)), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply push_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hpush].
    + exact Hrepr.
  - exists (Ending (B3 a b cc)), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply push_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hpush].
    + exact Hrepr.
  - inversion Hpush; subst c'; clear Hpush.
    destruct (make_red_push_chain (Ending (B5 x a b cc d)))
      as [c_abs'|] eqn:Hnorm.
    + exists (Ending (B4 a b cc d)), c_abs'.
      repeat split.
      * constructor.
      * apply kpcv_terminal_b5_push. exact Hnorm.
      * cbn. exact Hnorm.
      * exact Hrepr.
    + exfalso.
      cbn in Hnorm.
      destruct (Nat.eq_dec (E.level A cc) (E.level A d)) as [Heq|Hneq];
        [discriminate|congruence].
Qed.

Theorem direct_ending_nb5_heap_view_supports_inject_role_repr_general :
  forall (A : Type) (b : Buf5 (E.t A)) (H : HeapP (E.t A)) (lroot : Loc),
    is_b5 b = false ->
    chain_repr H lroot (kchain_to_chain (KEnding b)) ->
    kt4_inject_role_heap_packet_view_repr H lroot (KEnding b).
Proof.
  intros A b H lroot Hnb5 Hrepr x c' Hready Hinject.
  destruct b as [|a|a b|a b cc|a b cc d|a b cc d e];
    cbn in Hnb5, Hready, Hinject; try discriminate.
  - exists (Ending B0), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply inject_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hinject].
    + destruct c'; inversion Hinject; subst; cbn; reflexivity.
    + exact Hrepr.
  - exists (Ending (B1 a)), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply inject_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hinject].
    + destruct c'; inversion Hinject; subst; cbn; reflexivity.
    + exact Hrepr.
  - exists (Ending (B2 a b)), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply inject_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hinject].
    + destruct c'; inversion Hinject; subst; cbn; reflexivity.
    + exact Hrepr.
  - exists (Ending (B3 a b cc)), (kchain_to_chain c').
    repeat split; try constructor.
    + eapply inject_kt4_direct_erasure_bridge_ending_lt4;
        [exact I|exact Hinject].
    + destruct c'; inversion Hinject; subst; cbn; reflexivity.
    + exact Hrepr.
  - inversion Hinject; subst c'; clear Hinject.
    destruct (make_red_inject_chain (Ending (B5 a b cc d x)))
      as [c_abs'|] eqn:Hnorm.
    + assert (Hnot_b5 : is_b5 (chain_top_pre c_abs') = false).
      {
        cbn in Hnorm.
        destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq];
          [|congruence].
        inversion Hnorm; subst c_abs'. cbn. reflexivity.
      }
      exists (Ending (B4 a b cc d)), c_abs'.
      repeat split.
      * constructor.
      * apply kpcv_terminal_b5_inject. exact Hnorm.
      * cbn. exact Hnorm.
      * exact Hnot_b5.
      * exact Hrepr.
    + exfalso.
      cbn in Hnorm.
      destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq];
        [discriminate|congruence].
Qed.

