Lemma inject_kt4_yellow_overflow_nested_green_prefix_result_not_b5 :
  forall (A : Type) (x a b cc d : E.t A)
         (pre pre' suf' : Buf5 (E.t A)) (i' : Packet A)
         (tail c' : KChain A),
    buf5_green_exact pre ->
    inject_kt4
      (KCons Yellow (PNode pre (PNode pre' i' suf') (B4 a b cc d)) tail) x =
      PushOk c' ->
    is_b5 (chain_top_pre (kchain_to_chain c')) = false.
Proof.
  intros A x a b cc d pre pre' suf' i' tail c' Hpre Hinject.
  unfold inject_kt4 in Hinject; cbn -[green_of_red_k] in Hinject.
  destruct (green_of_red_k
      (KCons Red (PNode pre (PNode pre' i' suf') (B5 a b cc d x)) tail))
    as [c_repair|] eqn:Hred; [|discriminate].
  inversion Hinject; subst c_repair; clear Hinject.
  unfold green_of_red_k in Hred.
  cbn -[Nat.eq_dec] in Hred.
  destruct pre as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    cbn in Hpre, Hred |- *; try contradiction; try discriminate.
  - destruct
      (match Nat.eq_dec (E.level A a) (E.level A b) with
       | left eq =>
           match yellow_inject suf' (E.pair A a b eq) with
           | Some b1' => Some (b1', B3 cc d x)
           | None => None
           end
       | right _ => None
       end) as [[suf2' suf1']|] eqn:Hcat; [|discriminate].
    inversion Hred; subst c'; cbn; reflexivity.
  - destruct
      (match Nat.eq_dec (E.level A a) (E.level A b) with
       | left eq =>
           match yellow_inject suf' (E.pair A a b eq) with
           | Some b1' => Some (b1', B3 cc d x)
           | None => None
           end
       | right _ => None
       end) as [[suf2' suf1']|] eqn:Hcat; [|discriminate].
    inversion Hred; subst c'; cbn; reflexivity.
Qed.

