Lemma packet_repr_at_functional :
  forall (A : Type) (H : HeapP (E.t A)) (il : option Loc)
         (p1 p2 : Packet A) (k : nat),
    packet_repr_at H il p1 k ->
    packet_repr_at H il p2 k ->
    p1 = p2.
Proof.
  intros A H il p1 p2 k HR1.
  generalize dependent p2.
  induction HR1 as
    [ H k
    | H inner_loc pre suf i cell k Hlk _ Hpre Hsuf _ _ _ HRi IHi ];
    intros p2 HR2.
  - inversion HR2; subst; reflexivity.
  - inversion HR2; subst.
    rewrite Hlk in H2. inversion H2; subst cell0.
    f_equal; try congruence.
    eapply IHi; eauto.
Qed.

Lemma chain_repr_at_functional :
  forall (A : Type) (H : HeapP (E.t A)) (l : Loc)
         (c1 c2 : Chain A) (k : nat),
    chain_repr_at H l c1 k ->
    chain_repr_at H l c2 k ->
    c1 = c2.
Proof.
  intros A H l c1 c2 k HR1.
  generalize dependent c2.
  induction HR1 as
    [ H l b cell k Hlk _ Hpre Hsuf Hinner Htail _
    | H l ltail pre suf cell c' k Hlk _ Hpre Hsuf Hinner Htail _ _ HRtail IHtail
    | H l ltail inner_loc pre suf pre' suf' i' cell c' k
        Hlk _ Hpre Hsuf Hinner Htail _ _ HRpkt HRtail IHtail ];
    intros c2 HR2.
  - inversion HR2; subst.
    + rewrite Hlk in H1. inversion H1; subst cell0.
      f_equal; congruence.
    + rewrite Hlk in H1. inversion H1; subst cell0. congruence.
    + rewrite Hlk in H1. inversion H1; subst cell0. congruence.
  - inversion HR2; subst.
    + rewrite Hlk in H1. inversion H1; subst cell0. congruence.
    + rewrite Hlk in H1. inversion H1; subst cell0.
      match goal with
      | |- ChainCons _ c' = ChainCons _ ?ct =>
          match goal with
          | Htail_repr : chain_repr_at H ?lt ct (S k) |- _ =>
              replace lt with ltail in Htail_repr by congruence;
              pose proof (IHtail ct Htail_repr) as Htail_eq;
              subst ct
          end
      end.
      reflexivity.
    + rewrite Hlk in H1. inversion H1; subst cell0. congruence.
  - inversion HR2; subst.
    + rewrite Hlk in H1. inversion H1; subst cell0. congruence.
    + rewrite Hlk in H1. inversion H1; subst cell0. congruence.
    + rewrite Hlk in H1. inversion H1; subst cell0.
      match goal with
      | |- ChainCons _ _ =
           ChainCons (PNode _ (PNode ?pre2 ?i2 ?suf2) _) _ =>
          assert (PNode pre2 i2 suf2 = PNode pre' i' suf') as Hpacket
          by (match goal with
              | HRpkt2 : packet_repr_at H (Some ?il)
                    (PNode pre2 i2 suf2) (S k) |- _ =>
                  replace il with inner_loc in HRpkt2 by congruence;
                  eapply packet_repr_at_functional; eauto
              end);
          inversion Hpacket; subst pre2 i2 suf2; clear Hpacket
      end.
      match goal with
      | |- ChainCons _ c' = ChainCons _ ?ct =>
          match goal with
          | Htail_repr : chain_repr_at H ?lt ct
              (S (S k) + packet_depth i') |- _ =>
              replace lt with ltail in Htail_repr by congruence;
              pose proof (IHtail ct Htail_repr) as Htail_eq;
              subst ct
          end
      end.
      reflexivity.
Qed.

Lemma chain_repr_functional :
  forall (A : Type) (H : HeapP (E.t A)) (l : Loc)
         (c1 c2 : Chain A),
    chain_repr H l c1 ->
    chain_repr H l c2 ->
    c1 = c2.
Proof.
  intros A H l c1 c2 HR1 HR2.
  eapply chain_repr_at_functional; eauto.
Qed.

(* A global direct bridge from [kt4] erasure to the [_chain_full] packet
   abstraction is not the remaining Gate-B refinement: [kt4] deliberately
   keeps a terminal [B5] until the next public operation, while
   [push_chain_full] / [inject_chain_full] normalize the [B4 -> B5]
   transition immediately through opposite front/back [make_red] normal forms.
   The exact packet bridge therefore needs an explicit representation relation
   between extracted [KChain] states and packet-level [Chain] states. *)
Theorem push_kt4_direct_erasure_bridge_fails :
  exists (x : E.t nat) (c c' : KChain nat),
    push_kt4 x c = PushOk c' /\
    push_chain_full x (kchain_to_chain c) <> Some (kchain_to_chain c').
Proof.
  exists (E.base nat 0).
  exists (KEnding (B4 (E.base nat 1) (E.base nat 2)
                      (E.base nat 3) (E.base nat 4))).
  exists (KEnding (B5 (E.base nat 0) (E.base nat 1) (E.base nat 2)
                      (E.base nat 3) (E.base nat 4))).
  split.
  - reflexivity.
  - cbn. discriminate.
Qed.

Theorem inject_kt4_direct_erasure_bridge_fails :
  exists (x : E.t nat) (c c' : KChain nat),
    inject_kt4 c x = PushOk c' /\
    inject_chain_full (kchain_to_chain c) x <> Some (kchain_to_chain c').
Proof.
  exists (E.base nat 4).
  exists (KEnding (B4 (E.base nat 0) (E.base nat 1)
                      (E.base nat 2) (E.base nat 3))).
  exists (KEnding (B5 (E.base nat 0) (E.base nat 1) (E.base nat 2)
                      (E.base nat 3) (E.base nat 4))).
  split.
  - reflexivity.
  - cbn. discriminate.
Qed.

Theorem terminal_b5_push_inject_packet_normal_forms_differ :
  exists (b : Buf5 (E.t nat)) push_view inject_view,
    make_red_push_chain (Ending b) = Some push_view /\
    make_red_inject_chain (Ending b) = Some inject_view /\
    push_view <> inject_view.
Proof.
  exists (B5 (E.base nat 0) (E.base nat 1) (E.base nat 2)
             (E.base nat 3) (E.base nat 4)).
  eexists. eexists.
  repeat split; cbn; try reflexivity.
  discriminate.
Qed.

Theorem terminal_b5_push_inject_heap_packet_views_incompatible :
  exists (b : Buf5 (E.t nat)) push_view inject_view,
    make_red_push_chain (Ending b) = Some push_view /\
    make_red_inject_chain (Ending b) = Some inject_view /\
    push_view <> inject_view /\
    forall (H : HeapP (E.t nat)) (lroot : Loc),
      chain_repr H lroot push_view ->
      chain_repr H lroot inject_view ->
      False.
Proof.
  destruct terminal_b5_push_inject_packet_normal_forms_differ as
    [b [push_view [inject_view [Hpush [Hinject Hneq]]]]].
  exists b, push_view, inject_view.
  repeat split; try assumption.
  intros H lroot Hpush_repr Hinject_repr.
  apply Hneq.
  eapply chain_repr_functional; eauto.
Qed.

Theorem terminal_b5_push_heap_view_supports_inject_step_repr :
  exists (b : Buf5 (E.t nat)) (x : E.t nat) c' push_view,
    make_red_push_chain (Ending b) = Some push_view /\
    inject_kt4 (KEnding b) x = PushOk c' /\
    forall (H : HeapP (E.t nat)) (lroot : Loc),
      chain_repr H lroot push_view ->
      kt4_inject_heap_packet_view_step_repr H lroot (KEnding b) x c'.
Proof.
  set (a0 := E.base nat 0).
  set (a1 := E.base nat 1).
  set (a2 := E.base nat 2).
  set (a3 := E.base nat 3).
  set (a4 := E.base nat 4).
  set (x := E.base nat 5).
  exists (B5 a0 a1 a2 a3 a4), x,
    (KCons Green (PNode (B3 a0 a1 a2) Hole (B3 a3 a4 x)) (KEnding B0)).
  cbn.
  destruct (Nat.eq_dec (E.level nat a3) (E.level nat a4)) as [Heq|Hneq].
  2: contradiction Hneq; reflexivity.
  exists (ChainCons (PNode (B3 a0 a1 a2) Hole B0)
    (Ending (B1 (E.pair nat a3 a4 eq_refl)))).
  split; [reflexivity|].
  split; [reflexivity|].
  intros H lroot Hpush_repr.
  exists
    (ChainCons (PNode (B3 a0 a1 a2) Hole B0)
       (Ending (B1 (E.pair nat a3 a4 eq_refl)))).
  exists
    (ChainCons (PNode (B3 a0 a1 a2) Hole (B1 x))
       (Ending (B1 (E.pair nat a3 a4 eq_refl)))).
  split.
  - apply kpcv_terminal_b5_push.
    cbn. reflexivity.
  - split.
    + refine (kpcv_green_of_red_pending
      (pre:=B3 a0 a1 a2) (i:=Hole) (suf:=B1 x)
      (tail:=KEnding (B1 (E.pair nat a3 a4 eq_refl)))
      (c_repair:=KCons Green
        (PNode (B3 a0 a1 a2) Hole (B3 a3 a4 x)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * cbn. reflexivity.
      * split.
        -- cbn. reflexivity.
        -- exact Hpush_repr.
Qed.

Theorem terminal_b5_inject_heap_view_supports_push_step_repr :
  exists (b : Buf5 (E.t nat)) (x : E.t nat) c' inject_view,
    make_red_inject_chain (Ending b) = Some inject_view /\
    push_kt4 x (KEnding b) = PushOk c' /\
    forall (H : HeapP (E.t nat)) (lroot : Loc),
      chain_repr H lroot inject_view ->
      kt4_push_heap_packet_view_step_repr H lroot x (KEnding b) c'.
Proof.
  set (a0 := E.base nat 0).
  set (a1 := E.base nat 1).
  set (a2 := E.base nat 2).
  set (a3 := E.base nat 3).
  set (a4 := E.base nat 4).
  set (x := E.base nat 5).
  exists (B5 a0 a1 a2 a3 a4), x,
    (KCons Green (PNode (B3 x a0 a1) Hole (B3 a2 a3 a4)) (KEnding B0)).
  cbn.
  destruct (Nat.eq_dec (E.level nat a0) (E.level nat a1)) as [Heq|Hneq].
  2: contradiction Hneq; reflexivity.
  exists (ChainCons (PNode B0 Hole (B3 a2 a3 a4))
    (Ending (B1 (E.pair nat a0 a1 eq_refl)))).
  split; [reflexivity|].
  split; [reflexivity|].
  intros H lroot Hinject_repr.
  exists
    (ChainCons (PNode B0 Hole (B3 a2 a3 a4))
       (Ending (B1 (E.pair nat a0 a1 eq_refl)))).
  exists
    (ChainCons (PNode (B1 x) Hole (B3 a2 a3 a4))
       (Ending (B1 (E.pair nat a0 a1 eq_refl)))).
  split.
  - apply kpcv_terminal_b5_inject.
    cbn. reflexivity.
  - split.
    + refine (kpcv_green_of_red_pending
      (pre:=B1 x) (i:=Hole) (suf:=B3 a2 a3 a4)
      (tail:=KEnding (B1 (E.pair nat a0 a1 eq_refl)))
      (c_repair:=KCons Green
        (PNode (B3 x a0 a1) Hole (B3 a2 a3 a4)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * cbn. reflexivity.
      * exact Hinject_repr.
Qed.

Theorem terminal_b5_push_heap_view_supports_inject_step_repr_general :
  forall (A : Type) (a b cc d e x : E.t A)
         (push_view : Chain A) (H : HeapP (E.t A)) (lroot : Loc),
    make_red_push_chain (Ending (B5 a b cc d e)) = Some push_view ->
    chain_repr H lroot push_view ->
    kt4_inject_heap_packet_view_step_repr H lroot
      (KEnding (B5 a b cc d e)) x
      (KCons Green (PNode (B3 a b cc) Hole (B3 d e x)) (KEnding B0)).
Proof.
  intros A a b cc d e x push_view H lroot Hmake Hrepr.
  pose proof Hmake as Hview.
  cbn in Hmake.
  destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Heq|Hneq];
    [|discriminate].
  inversion Hmake; subst push_view; clear Hmake.
  exists
    (ChainCons (PNode (B3 a b cc) Hole B0)
       (Ending (B1 (E.pair A d e Heq)))).
  exists
    (ChainCons (PNode (B3 a b cc) Hole (B1 x))
       (Ending (B1 (E.pair A d e Heq)))).
  split.
  - apply kpcv_terminal_b5_push. exact Hview.
  - split.
    + refine (kpcv_green_of_red_pending
        (pre:=B3 a b cc) (i:=Hole) (suf:=B1 x)
        (tail:=KEnding (B1 (E.pair A d e Heq)))
        (c_repair:=KCons Green
          (PNode (B3 a b cc) Hole (B3 d e x)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * cbn. reflexivity.
      * split.
        -- cbn. reflexivity.
        -- exact Hrepr.
Qed.

Theorem terminal_b5_inject_heap_view_supports_push_step_repr_general :
  forall (A : Type) (a b cc d e x : E.t A)
         (inject_view : Chain A) (H : HeapP (E.t A)) (lroot : Loc),
