        (tail:=KEnding (B1 (E.pair A a b Heq)))
        (c_repair:=KCons Green
          (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * cbn. reflexivity.
      * exact Hrepr.
Qed.

Theorem terminal_b5_push_heap_view_supports_push_step_repr_general :
  forall (A : Type) (a b cc d e x : E.t A)
         (push_view : Chain A) (H : HeapP (E.t A)) (lroot : Loc),
    make_red_push_chain (Ending (B5 a b cc d e)) = Some push_view ->
