Theorem terminal_b5_push_heap_view_supports_all_role_repr_general :
  forall (A : Type) (a b cc d e : E.t A)
         (push_view : Chain A) (H : HeapP (E.t A)) (lroot : Loc),
    make_red_push_chain (Ending (B5 a b cc d e)) = Some push_view ->
