  repeat split.
  - eapply terminal_b5_push_heap_view_supports_push_role_repr_general; eauto.
  - eapply terminal_b5_push_heap_view_supports_inject_role_repr_general; eauto.
  - eapply terminal_b5_push_heap_view_supports_pop_role_repr_general; eauto.
  - eapply terminal_b5_push_heap_view_supports_eject_role_repr_general; eauto.
