Theorem terminal_b5_push_after_push_heap_view_supports_all_role_repr_general :
  forall (A : Type) (x a b cc d e : E.t A)
         (push_view c_mid : Chain A)
         (H : HeapP (E.t A)) (lroot : Loc),
    E.level A b = E.level A cc ->
    make_red_push_chain (Ending (B5 a b cc d e)) = Some push_view ->
    push_chain_full x push_view = Some c_mid ->
    chain_repr H lroot c_mid ->
    kt4_all_role_heap_packet_view_repr H lroot
      (KCons Green (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0)).
Proof.
  intros A x a b cc d e push_view c_mid H lroot Hbcc Hmake Hmid Hrepr.
  pose proof Hmake as Hview.
  cbn in Hmake.
  destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Hde|Hneq];
    [|discriminate].
  inversion Hmake; subst push_view; clear Hmake.
  cbn in Hmid.
  inversion Hmid; subst c_mid; clear Hmid.
  unfold kt4_all_role_heap_packet_view_repr.
  repeat split.
  - intros y c' _ Hpush.
    cbn in Hpush.
    inversion Hpush; subst c'; clear Hpush.
    destruct (push_chain_full y
      (ChainCons (PNode (B4 x a b cc) Hole B0)
         (Ending (B1 (E.pair A d e Hde))))) as [c_abs'|] eqn:Hstep.
    + exists
        (ChainCons (PNode (B4 x a b cc) Hole B0)
           (Ending (B1 (E.pair A d e Hde)))).
      exists c_abs'.
      split.
      * eapply kpcv_terminal_b5_push_after_push.
        -- exact Hview.
        -- cbn. reflexivity.
      * split.
        -- eapply kpcv_terminal_b5_push_after_push_after_push.
           ++ exact Hview.
           ++ cbn. reflexivity.
           ++ exact Hstep.
        -- split; [exact Hstep|exact Hrepr].
    + exfalso.
      cbn in Hstep.
      destruct (Nat.eq_dec (E.level A b) (E.level A cc)) as [|Hneq];
        [discriminate|congruence].
  - intros y c' _ Hinject.
    cbn in Hinject.
    inversion Hinject; subst c'; clear Hinject.
    destruct (inject_chain_full
      (ChainCons (PNode (B4 x a b cc) Hole B0)
         (Ending (B1 (E.pair A d e Hde)))) y) as [c_abs'|] eqn:Hstep.
    + assert (Hnot_b5 : is_b5 (chain_top_pre c_abs') = false).
      {
        cbn in Hstep.
        inversion Hstep; subst c_abs'.
        cbn. reflexivity.
      }
      exists
        (ChainCons (PNode (B4 x a b cc) Hole B0)
           (Ending (B1 (E.pair A d e Hde)))).
      exists c_abs'.
      split.
      * eapply kpcv_terminal_b5_push_after_push.
        -- exact Hview.
        -- cbn. reflexivity.
      * split.
        -- eapply kpcv_terminal_b5_push_after_push_after_inject.
           ++ exact Hview.
           ++ cbn. reflexivity.
           ++ exact Hstep.
        -- split; [exact Hstep|].
           split; [exact Hnot_b5|exact Hrepr].
    + discriminate.
  - intros y c' _ Hpop.
    cbn in Hpop.
    inversion Hpop; subst y c'; clear Hpop.
    destruct (pop_chain_full
      (ChainCons (PNode (B4 x a b cc) Hole B0)
         (Ending (B1 (E.pair A d e Hde)))))
        as [[x_abs c_abs']|] eqn:Hstep.
    + pose proof Hstep as Hstep_view.
      cbn in Hstep.
      inversion Hstep; subst x_abs c_abs'; clear Hstep.
      exists
        (ChainCons (PNode (B4 x a b cc) Hole B0)
           (Ending (B1 (E.pair A d e Hde)))).
      exists
        (ChainCons (PNode (B3 a b cc) Hole B0)
           (Ending (B1 (E.pair A d e Hde)))).
      split.
      * eapply kpcv_terminal_b5_push_after_push.
        -- exact Hview.
        -- cbn. reflexivity.
      * split.
        -- eapply kpcv_terminal_b5_push_after_push_after_pop.
           ++ exact Hview.
           ++ cbn. reflexivity.
           ++ exact Hstep_view.
        -- split; [exact Hstep_view|exact Hrepr].
    + discriminate.
  - intros y c' _ Heject.
    cbn in Heject.
    inversion Heject; subst y c'; clear Heject.
    destruct (eject_chain_full
      (ChainCons (PNode (B4 x a b cc) Hole B0)
         (Ending (B1 (E.pair A d e Hde)))))
        as [[c_abs' x_abs]|] eqn:Hstep.
    + pose proof Hstep as Hstep_view.
      cbn -[E.unpair] in Hstep.
      rewrite E.unpair_pair in Hstep.
      inversion Hstep; subst c_abs' x_abs; clear Hstep.
      exists
        (ChainCons (PNode (B4 x a b cc) Hole B0)
           (Ending (B1 (E.pair A d e Hde)))).
      exists
        (ChainCons (PNode (B4 x a b cc) Hole (B1 d)) (Ending B0)).
      split.
      * eapply kpcv_terminal_b5_push_after_push.
        -- exact Hview.
        -- cbn. reflexivity.
      * split.
        -- eapply kpcv_terminal_b5_push_after_push_after_eject.
           ++ exact Hview.
           ++ cbn. reflexivity.
           ++ exact Hstep_view.
        -- split; [exact Hstep_view|exact Hrepr].
    + exfalso.
      cbn -[E.unpair] in Hstep.
      rewrite E.unpair_pair in Hstep.
      discriminate.
Qed.

