Theorem terminal_b5_inject_after_push_heap_view_supports_all_role_repr_general :
  forall (A : Type) (x a b cc d e : E.t A)
         (inject_view c_mid : Chain A)
         (H : HeapP (E.t A)) (lroot : Loc),
    make_red_inject_chain (Ending (B5 a b cc d e)) = Some inject_view ->
    push_chain_full x inject_view = Some c_mid ->
    chain_repr H lroot c_mid ->
    kt4_all_role_heap_packet_view_repr H lroot
      (KCons Green (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0)).
Proof.
  intros A x a b cc d e inject_view c_mid H lroot Hmake Hmid Hrepr.
  pose proof Hmake as Hview.
  cbn in Hmake.
  destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Hab|Hneq];
    [|discriminate].
  inversion Hmake; subst inject_view; clear Hmake.
  cbn in Hmid.
  inversion Hmid; subst c_mid; clear Hmid.
  unfold kt4_all_role_heap_packet_view_repr.
  repeat split.
  - intros y c' _ Hpush.
    cbn in Hpush.
    inversion Hpush; subst c'; clear Hpush.
    exists
      (ChainCons (PNode (B1 x) Hole (B3 cc d e))
         (Ending (B1 (E.pair A a b Hab)))).
    exists
      (ChainCons (PNode (B2 y x) Hole (B3 cc d e))
         (Ending (B1 (E.pair A a b Hab)))).
    split.
    + refine (kpcv_green_of_red_pending
        (pre:=B1 x) (i:=Hole) (suf:=B3 cc d e)
        (tail:=KEnding (B1 (E.pair A a b Hab)))
        (c_repair:=KCons Green
          (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * eapply kpcv_terminal_b5_inject_after_push_after_push.
        -- exact Hview.
        -- cbn. reflexivity.
        -- cbn. reflexivity.
      * split; [cbn; reflexivity|exact Hrepr].
  - intros y c' _ Hinject.
    cbn in Hinject.
    inversion Hinject; subst c'; clear Hinject.
    exists
      (ChainCons (PNode (B1 x) Hole (B3 cc d e))
         (Ending (B1 (E.pair A a b Hab)))).
    exists
      (ChainCons (PNode (B1 x) Hole (B4 cc d e y))
         (Ending (B1 (E.pair A a b Hab)))).
    split.
    + refine (kpcv_green_of_red_pending
        (pre:=B1 x) (i:=Hole) (suf:=B3 cc d e)
        (tail:=KEnding (B1 (E.pair A a b Hab)))
        (c_repair:=KCons Green
          (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * eapply kpcv_terminal_b5_inject_after_push_after_inject.
        -- exact Hview.
        -- cbn. reflexivity.
        -- cbn. reflexivity.
      * split; [cbn; reflexivity|].
        split; [cbn; reflexivity|exact Hrepr].
  - intros y c' _ Hpop.
    cbn in Hpop.
    inversion Hpop; subst y c'; clear Hpop.
    exists
      (ChainCons (PNode (B1 x) Hole (B3 cc d e))
         (Ending (B1 (E.pair A a b Hab)))).
    exists
      (ChainCons (PNode B0 Hole (B3 cc d e))
         (Ending (B1 (E.pair A a b Hab)))).
    split.
    + refine (kpcv_green_of_red_pending
        (pre:=B1 x) (i:=Hole) (suf:=B3 cc d e)
        (tail:=KEnding (B1 (E.pair A a b Hab)))
        (c_repair:=KCons Green
          (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * eapply kpcv_terminal_b5_inject_after_push_after_pop.
        -- exact Hview.
        -- cbn. reflexivity.
        -- cbn. reflexivity.
      * split; [cbn; reflexivity|exact Hrepr].
  - intros y c' _ Heject.
    cbn in Heject.
    inversion Heject; subst y c'; clear Heject.
    exists
      (ChainCons (PNode (B1 x) Hole (B3 cc d e))
         (Ending (B1 (E.pair A a b Hab)))).
    exists
      (ChainCons (PNode (B1 x) Hole (B2 cc d))
         (Ending (B1 (E.pair A a b Hab)))).
    split.
    + refine (kpcv_green_of_red_pending
        (pre:=B1 x) (i:=Hole) (suf:=B3 cc d e)
        (tail:=KEnding (B1 (E.pair A a b Hab)))
        (c_repair:=KCons Green
          (PNode (B3 x a b) Hole (B3 cc d e)) (KEnding B0)) _).
      cbn -[E.pair E.unpair].
      rewrite E.unpair_pair.
      reflexivity.
    + split.
      * eapply kpcv_terminal_b5_inject_after_push_after_eject.
        -- exact Hview.
        -- cbn. reflexivity.
        -- cbn. reflexivity.
      * split; [cbn; reflexivity|exact Hrepr].
Unshelve.
  all: eauto.
Qed.

Lemma element_pair_level_eq_irrel :
  forall (A : Type) (x y : E.t A)
         (p q : E.level A x = E.level A y),
    E.pair A x y p = E.pair A x y q.
Proof.
  intros A [lx px] [ly py] p q.
  cbn in p, q.
  subst ly.
  assert (q = eq_refl) by apply UIP_refl_nat.
  subst q.
  reflexivity.
Qed.

