      (ChainCons (PNode (B1 cc) Hole B0)
         (Ending (B1 (E.pair A d e Hde)))).
    split.
    + eapply kpcv_terminal_b5_push_after_pop.
      * exact Hview.
      * exact Hpop_view.
    + split.
      * eapply kpcv_terminal_b5_push_after_pop_after_pop.
        -- exact Hview.
        -- exact Hpop_view.
        -- cbn. reflexivity.
