    split.
    + eapply kpcv_terminal_b5_push_after_pop.
      * exact Hview.
      * exact Hpop_view.
    + split.
      * eapply kpcv_terminal_b5_push_after_pop_after_eject.
        -- exact Hview.
        -- exact Hpop_view.
        -- cbn -[E.unpair].
           rewrite E.unpair_pair.
