Theorem push_kt4_ending_b4_exec_preserves_all_role_repr :
  forall (A : Type) (lroot : Loc) (x a b cc d : E.t A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    E.level A x = 0 ->
    E.level A cc = E.level A d ->
    chain_repr H lroot (Ending (B4 a b cc d)) ->
    well_formed_heap H ->
    exec_push_pkt_C lroot x H = Some (H', lroot', n) ->
    n <= NF_PUSH_PKT_FULL /\
    kt4_all_role_heap_packet_view_repr H' lroot'
      (KEnding (B5 x a b cc d)).
Proof.
  intros A lroot x a b cc d H H' lroot' n
    Hx Hpair Hrepr Hwf Hexec.
  destruct (make_red_push_chain (Ending (B5 x a b cc d)))
    as [push_view|] eqn:Hmake.
  - assert (Habs :
      push_chain_full x (Ending (B4 a b cc d)) = Some push_view).
    { cbn. exact Hmake. }
    destruct (@packet_push_full_correct_O1_repr
        A lroot x (Ending (B4 a b cc d)) push_view
        H H' lroot' n Hrepr Hx Hwf Habs Hexec)
      as [Hcost [_ Hrepr']].
    split; [exact Hcost|].
    unfold kt4_all_role_heap_packet_view_repr.
    eapply terminal_b5_push_heap_view_supports_all_role_repr_general;
      eauto.
  - exfalso.
    cbn in Hmake.
    destruct (Nat.eq_dec (E.level A cc) (E.level A d)) as [Heq|Hneq].
    + discriminate.
    + congruence.
Qed.

Theorem inject_kt4_ending_b4_exec_preserves_all_role_repr :
  forall (A : Type) (lroot : Loc) (a b cc d x : E.t A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    E.level A x = 0 ->
    E.level A a = E.level A b ->
    chain_repr H lroot (Ending (B4 a b cc d)) ->
    well_formed_heap H ->
    exec_inject_pkt_C lroot x H = Some (H', lroot', n) ->
