Theorem push_kt4_direct_green_non_red_tail_exec_preserves_all_role_repr :
  forall (A : Type) (lroot : Loc) (x : E.t A)
         (pre suf : Buf5 (E.t A)) (i : Packet A) (tail c' : KChain A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    E.level A x = 0 ->
    buf5_green_exact pre ->
    buf5_green_exact suf ->
    kchain_top_color tail <> Red ->
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    chain_repr H lroot
      (kchain_to_chain (KCons Green (PNode pre i suf) tail)) ->
    well_formed_heap H ->
    exec_push_pkt_C lroot x H = Some (H', lroot', n) ->
    n <= NF_PUSH_PKT_FULL /\
    kt4_all_role_heap_packet_view_repr H' lroot' c'.
Proof.
  intros A lroot x pre suf i tail c' H H' lroot' n
    Hx Hpre Hsuf Hnotred Hpush Hrepr Hwf Hexec.
  assert (Habs :
    push_chain_full x
      (kchain_to_chain (KCons Green (PNode pre i suf) tail)) =
    Some (kchain_to_chain c')).
  {
    eapply push_kt4_direct_erasure_bridge_green_non_red_tail; eauto.
  }
  destruct (@packet_push_full_correct_O1_repr
      A lroot x
      (kchain_to_chain (KCons Green (PNode pre i suf) tail))
      (kchain_to_chain c') H H' lroot' n
      Hrepr Hx Hwf Habs Hexec) as [Hcost [_ Hrepr']].
  split; [exact Hcost|].
  destruct pre as [|a|a b|a b cc|a b cc d|a b cc d e];
    cbn in Hpre, Hpush; try contradiction; try discriminate;
    unfold yellow_wrap_pr in Hpush;
    destruct tail as [bt|col p tail'];
    cbn in Hnotred, Hpush;
    try (inversion Hpush; subst c'; clear Hpush;
         eapply direct_yellow_nb5pre_heap_view_supports_all_role_repr_general;
         [cbn; reflexivity|exact Hrepr']);
    destruct col; cbn in Hnotred, Hpush;
    try (inversion Hpush; subst c'; clear Hpush;
         eapply direct_yellow_nb5pre_heap_view_supports_all_role_repr_general;
         [cbn; reflexivity|exact Hrepr']);
    exfalso; apply Hnotred; reflexivity.
Qed.

