    cbn in Hsuf, Hinject; try contradiction; try discriminate;
    unfold yellow_wrap_pr in Hinject;
    destruct tail as [bt|col p tail'];
    cbn in Hnotred, Hinject;
    try (inversion Hinject; subst c'; clear Hinject;
