    pop_kt4 c_repair = PopOk x c_after /\
    (forall H lroot,
      chain_repr H lroot pending ->
      ~ kt4_all_role_heap_packet_view_repr H lroot c_repair).
Proof.
  pose (e0 := E.base nat 0).
  pose (e1 := E.base nat 1).
  pose (e2 := E.base nat 2).
  pose (e3 := E.base nat 3).
  pose (e4 := E.base nat 4).
  pose (e5 := E.base nat 5).
  pose (e6 := E.base nat 6).
  pose (e7 := E.base nat 7).
  pose (p01 := E.pair nat e0 e1 eq_refl).
  pose (p23 := E.pair nat e2 e3 eq_refl).
  pose (p45 := E.pair nat e4 e5 eq_refl).
  pose (p67 := E.pair nat e6 e7 eq_refl).
  pose (i := PNode (B2 p01 p23) Hole (B2 p45 p67)).
  pose (pending :=
    ChainCons (PNode B0 i B0) (kchain_to_chain (KEnding B0))).
  pose (c_repair :=
    KCons Green (PNode (B2 e0 e1) Hole (B2 e6 e7))
      (KCons Red (PNode (B1 p23) Hole (B1 p45)) (KEnding B0))).
  pose (c_after :=
    KCons Yellow (PNode (B1 e1) Hole (B2 e6 e7))
      (KEnding (B2 p23 p45))).
  exists i, pending, c_repair, c_after, e0.
  split.
  - cbn. reflexivity.
  - split.
    + eapply kpcv_green_of_red_pending. cbn. reflexivity.
    + split.
      * cbn. reflexivity.
      * intros H lroot Hpending Hall.
        destruct Hall as [_ [_ [Hpop_role _]]].
        destruct (Hpop_role e0 c_after) as
          [c_abs [c_abs' [_ [_ [Hstep Hrepr_abs]]]]].
        -- cbn. discriminate.
        -- cbn. reflexivity.
        -- pose proof (@chain_repr_functional nat H lroot
            pending c_abs Hpending Hrepr_abs) as Heq.
          subst c_abs.
          cbn in Hstep. discriminate.
Qed.

Theorem green_of_red_pending_nested_eject_all_role_gap :
  exists (i : Packet nat) (pending : Chain nat)
         (c_repair c_after : KChain nat) (x : E.t nat),
    green_of_red_k (KCons Red (PNode B0 i B0) (KEnding B0)) =
      Some c_repair /\
    kt4_packet_chain_view c_repair pending /\
    eject_kt4 c_repair = PopOk x c_after /\
    (forall H lroot,
      chain_repr H lroot pending ->
      ~ kt4_all_role_heap_packet_view_repr H lroot c_repair).
Proof.
  pose (e0 := E.base nat 0).
  pose (e1 := E.base nat 1).
  pose (e2 := E.base nat 2).
  pose (e3 := E.base nat 3).
  pose (e4 := E.base nat 4).
  pose (e5 := E.base nat 5).
  pose (e6 := E.base nat 6).
  pose (e7 := E.base nat 7).
  pose (p01 := E.pair nat e0 e1 eq_refl).
  pose (p23 := E.pair nat e2 e3 eq_refl).
  pose (p45 := E.pair nat e4 e5 eq_refl).
  pose (p67 := E.pair nat e6 e7 eq_refl).
  pose (i := PNode (B2 p01 p23) Hole (B2 p45 p67)).
  pose (pending :=
    ChainCons (PNode B0 i B0) (kchain_to_chain (KEnding B0))).
  pose (c_repair :=
    KCons Green (PNode (B2 e0 e1) Hole (B2 e6 e7))
      (KCons Red (PNode (B1 p23) Hole (B1 p45)) (KEnding B0))).
  pose (c_after :=
    KCons Yellow (PNode (B2 e0 e1) Hole (B1 e6))
      (KEnding (B2 p23 p45))).
  exists i, pending, c_repair, c_after, e7.
  split.
  - cbn. reflexivity.
  - split.
    + eapply kpcv_green_of_red_pending. cbn. reflexivity.
    + split.
      * cbn. reflexivity.
      * intros H lroot Hpending Hall.
        destruct Hall as [_ [_ [_ Heject_role]]].
        destruct (Heject_role e7 c_after) as
          [c_abs [c_abs' [_ [_ [Hstep Hrepr_abs]]]]].
        -- cbn. discriminate.
        -- cbn. reflexivity.
        -- pose proof (@chain_repr_functional nat H lroot
            pending c_abs Hpending Hrepr_abs) as Heq.
          subst c_abs.
          cbn in Hstep. discriminate.
Qed.

(* ========================================================================== *)
(* Sufficient totality preconditions for the extracted [kt4] family.           *)
(*                                                                             *)
(* [regular_kt_top] alone is too weak: it says the top is not Red and the       *)
(* colour sequence is regular, but it does not say that a Green packet really  *)
(* has Green-sized boundary buffers, nor that the one possible red-fix step     *)
(* succeeds.  These predicates make those missing obligations explicit and      *)
(* prove that, once supplied, the [kt4] public operations cannot return Fail.   *)
(* The remaining Gate-B work is to strengthen this sufficient-precondition     *)
(* bundle into a preserved reachable-state invariant.                          *)
(* ========================================================================== *)

Definition buf5_is_green_shape {X : Type} (b : Buf5 X) : Prop :=
  match b with
  | B2 _ _ | B3 _ _ _ => True
  | _ => False
  end.

Definition buf5_is_not_red_shape {X : Type} (b : Buf5 X) : Prop :=
  match b with
  | B1 _ | B2 _ _ | B3 _ _ _ | B4 _ _ _ _ => True
  | _ => False
  end.

Lemma buf5_green_shape_not_red :
  forall X (b : Buf5 X),
    buf5_is_green_shape b ->
    buf5_is_not_red_shape b.
Proof.
  intros X b Hgreen.
  destruct b; cbn in Hgreen |- *; try contradiction; exact I.
Qed.

Lemma element_unpair_succeeds_at_s :
  forall A k (e : E.t A),
    E.level A e = S k ->
    exists x y, E.unpair A e = Some (x, y).
Proof.
  intros A k e Hlevel.
  destruct e as [[|n] payload].
  - cbn in Hlevel. discriminate.
  - destruct payload as [left right].
    exists (existT _ n left), (existT _ n right).
    reflexivity.
Qed.

Lemma green_prefix_concat_total_under_levels :
  forall A k (b1 b2 : Buf5 (E.t A)),
    buf_all_at_level k b1 ->
    buf_all_at_level (S k) b2 ->
    buf5_is_green_shape b2 ->
    exists b1' b2', green_prefix_concat b1 b2 = Some (b1', b2').
Proof.
  intros A k b1 b2 Hb1 Hb2 Hgreen.
  unfold green_prefix_concat.
  destruct b2 as [|u|u v|u v w|u v w r|u v w r s];
    cbn in Hgreen; try contradiction.
  - cbn in Hb2. destruct Hb2 as [Hu Hv].
    destruct b1 as [|a|a b|a b c|a b c d|a b c d e]; cbn in Hb1 |- *.
    + destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + repeat eexists.
    + repeat eexists.
    + destruct Hb1 as [_ [_ [Hc Hd]]].
      destruct (Nat.eq_dec (E.level A c) (E.level A d)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
    + destruct Hb1 as [_ [_ [_ [Hd He]]]].
      destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
  - cbn in Hb2. destruct Hb2 as [Hu [Hv Hw]].
    destruct b1 as [|a|a b|a b c|a b c d|a b c d e]; cbn in Hb1 |- *.
    + destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + repeat eexists.
    + repeat eexists.
    + destruct Hb1 as [_ [_ [Hc Hd]]].
      destruct (Nat.eq_dec (E.level A c) (E.level A d)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
    + destruct Hb1 as [_ [_ [_ [Hd He]]]].
      destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
Qed.

Lemma green_suffix_concat_total_under_levels :
  forall A k (b1 b2 : Buf5 (E.t A)),
    buf_all_at_level (S k) b1 ->
    buf_all_at_level k b2 ->
    buf5_is_green_shape b1 ->
    exists b1' b2', green_suffix_concat b1 b2 = Some (b1', b2').
Proof.
  intros A k b1 b2 Hb1 Hb2 Hgreen.
  unfold green_suffix_concat.
  destruct b1 as [|u|u v|u v w|u v w r|u v w r s];
    cbn in Hgreen; try contradiction.
  - cbn in Hb1. destruct Hb1 as [Hu Hv].
    destruct b2 as [|a|a b|a b c|a b c d|a b c d e]; cbn in Hb2 |- *.
    + destruct (@element_unpair_succeeds_at_s A k v Hv) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + destruct (@element_unpair_succeeds_at_s A k v Hv) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + repeat eexists.
    + repeat eexists.
    + destruct Hb2 as [Ha [Hb _]].
      destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
    + destruct Hb2 as [Ha [Hb _]].
      destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
  - cbn in Hb1. destruct Hb1 as [Hu [Hv Hw]].
    destruct b2 as [|a|a b|a b c|a b c d|a b c d e]; cbn in Hb2 |- *.
    + destruct (@element_unpair_succeeds_at_s A k w Hw) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + destruct (@element_unpair_succeeds_at_s A k w Hw) as [x [y Hup]].
      rewrite Hup. repeat eexists.
    + repeat eexists.
    + repeat eexists.
    + destruct Hb2 as [Ha [Hb _]].
      destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
    + destruct Hb2 as [Ha [Hb _]].
      destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq].
      * repeat eexists.
      * exfalso. apply Hneq. congruence.
Qed.

Lemma green_of_red_k_case2_total_under_levels :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail : KChain A) (col : color),
    buf_all_at_level k pre1 ->
    buf_all_at_level k suf1 ->
    buf5_is_green_shape pre2 ->
    buf5_is_green_shape suf2 ->
    packet_levels (S k) (PNode pre2 child suf2) ->
    exists c',
      green_of_red_k
        (KCons Red (PNode pre1 Hole suf1)
           (KCons col (PNode pre2 child suf2) tail)) = Some c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail col
    Hpre1 Hsuf1 Hpre2_shape Hsuf2_shape Hpkt.
  inversion Hpkt as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  unfold green_of_red_k.
  destruct (@green_prefix_concat_total_under_levels A k pre1 pre2
              Hpre1 Hpre2 Hpre2_shape) as [pre1' [pre2' Hpre_concat]].
  destruct (@green_suffix_concat_total_under_levels A k suf2 suf1
              Hsuf2 Hsuf1 Hsuf2_shape) as [suf2' [suf1' Hsuf_concat]].
  rewrite Hpre_concat, Hsuf_concat.
  eexists; reflexivity.
Qed.

Lemma yellow_pop_unpair_total_under_levels :
  forall A k (b : Buf5 (E.t A)),
    buf_all_at_level (S k) b ->
    buf5_is_not_red_shape b ->
    exists ab b' x y,
      yellow_pop b = Some (ab, b') /\ E.unpair A ab = Some (x, y).
Proof.
  intros A k b Hb Hshape.
  destruct b as [|u|u v|u v w|u v w r|u v w r s];
    cbn in Hshape; try contradiction.
  - cbn in Hb.
    destruct (@element_unpair_succeeds_at_s A k u Hb) as [x [y Hup]].
    exists u, B0, x, y. split; [reflexivity|exact Hup].
  - cbn in Hb. destruct Hb as [Hu Hv].
    destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
    exists u, (B1 v), x, y. split; [reflexivity|exact Hup].
  - cbn in Hb. destruct Hb as [Hu [Hv Hw]].
    destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
    exists u, (B2 v w), x, y. split; [reflexivity|exact Hup].
  - cbn in Hb. destruct Hb as [Hu [Hv [Hw Hr]]].
    destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
    exists u, (B3 v w r), x, y. split; [reflexivity|exact Hup].
Qed.

Lemma yellow_eject_unpair_total_under_levels :
  forall A k (b : Buf5 (E.t A)),
    buf_all_at_level (S k) b ->
    buf5_is_not_red_shape b ->
    exists b' ab x y,
      yellow_eject b = Some (b', ab) /\ E.unpair A ab = Some (x, y).
Proof.
  intros A k b Hb Hshape.
  destruct b as [|u|u v|u v w|u v w r|u v w r s];
    cbn in Hshape; try contradiction.
  - cbn in Hb.
    destruct (@element_unpair_succeeds_at_s A k u Hb) as [x [y Hup]].
    exists B0, u, x, y. split; [reflexivity|exact Hup].
  - cbn in Hb. destruct Hb as [Hu Hv].
    destruct (@element_unpair_succeeds_at_s A k v Hv) as [x [y Hup]].
    exists (B1 u), v, x, y. split; [reflexivity|exact Hup].
  - cbn in Hb. destruct Hb as [Hu [Hv Hw]].
    destruct (@element_unpair_succeeds_at_s A k w Hw) as [x [y Hup]].
    exists (B2 u v), w, x, y. split; [reflexivity|exact Hup].
  - cbn in Hb. destruct Hb as [Hu [Hv [Hw Hr]]].
    destruct (@element_unpair_succeeds_at_s A k r Hr) as [x [y Hup]].
    exists (B3 u v w), r, x, y. split; [reflexivity|exact Hup].
Qed.

Lemma yellow_push_total_under_shape :
  forall X (x : X) (b : Buf5 X),
    buf5_is_not_red_shape b ->
    exists b', yellow_push x b = Some b'.
Proof.
  intros X x b Hshape.
  destruct b; cbn in Hshape; try contradiction; eexists; reflexivity.
Qed.

Lemma yellow_inject_total_under_shape :
  forall X (b : Buf5 X) (x : X),
    buf5_is_not_red_shape b ->
    exists b', yellow_inject b x = Some b'.
Proof.
  intros X b x Hshape.
  destruct b; cbn in Hshape; try contradiction; eexists; reflexivity.
Qed.

Lemma prefix_concat_total_under_levels :
  forall A k (b1 b2 : Buf5 (E.t A)),
    buf_all_at_level k b1 ->
    buf_all_at_level (S k) b2 ->
    buf5_is_not_red_shape b2 ->
    exists b1' b2', prefix_concat b1 b2 = Some (b1', b2').
Proof.
  intros A k b1 b2 Hb1 Hb2 Hshape2.
  unfold prefix_concat.
  destruct b1 as [|a|a b|a b c|a b c d|a b c d e]; cbn in Hb1 |- *.
  - destruct (@yellow_pop_unpair_total_under_levels A k b2 Hb2 Hshape2)
      as [ab [b2' [x [y [Hpop Hup]]]]].
    rewrite Hpop, Hup. repeat eexists.
  - destruct (@yellow_pop_unpair_total_under_levels A k b2 Hb2 Hshape2)
      as [ab [b2' [x [y [Hpop Hup]]]]].
    rewrite Hpop, Hup. repeat eexists.
  - repeat eexists.
  - repeat eexists.
  - destruct Hb1 as [_ [_ [Hc Hd]]].
    destruct (Nat.eq_dec (E.level A c) (E.level A d)) as [Heq|Hneq].
    + destruct (@yellow_push_total_under_shape (E.t A)
                  (E.pair A c d Heq) b2 Hshape2) as [b2' Hpush].
      rewrite Hpush. repeat eexists.
    + exfalso. apply Hneq. congruence.
  - destruct Hb1 as [_ [_ [_ [Hd He]]]].
    destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Heq|Hneq].
    + destruct (@yellow_push_total_under_shape (E.t A)
                  (E.pair A d e Heq) b2 Hshape2) as [b2' Hpush].
      rewrite Hpush. repeat eexists.
    + exfalso. apply Hneq. congruence.
Qed.

Lemma suffix_concat_total_under_levels :
  forall A k (b1 b2 : Buf5 (E.t A)),
    buf_all_at_level (S k) b1 ->
    buf_all_at_level k b2 ->
    buf5_is_not_red_shape b1 ->
    exists b1' b2', suffix_concat b1 b2 = Some (b1', b2').
Proof.
  intros A k b1 b2 Hb1 Hb2 Hshape1.
  unfold suffix_concat.
  destruct b2 as [|a|a b|a b c|a b c d|a b c d e]; cbn in Hb2 |- *.
  - destruct (@yellow_eject_unpair_total_under_levels A k b1 Hb1 Hshape1)
      as [b1' [ab [x [y [Hej Hup]]]]].
    rewrite Hej, Hup. repeat eexists.
  - destruct (@yellow_eject_unpair_total_under_levels A k b1 Hb1 Hshape1)
      as [b1' [ab [x [y [Hej Hup]]]]].
    rewrite Hej, Hup. repeat eexists.
  - repeat eexists.
  - repeat eexists.
  - destruct Hb2 as [Ha [Hb _]].
    destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq].
    + destruct (@yellow_inject_total_under_shape (E.t A)
                  b1 (E.pair A a b Heq) Hshape1) as [b1' Hinj].
      rewrite Hinj. repeat eexists.
    + exfalso. apply Hneq. congruence.
  - destruct Hb2 as [Ha [Hb _]].
    destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq].
    + destruct (@yellow_inject_total_under_shape (E.t A)
                  b1 (E.pair A a b Heq) Hshape1) as [b1' Hinj].
      rewrite Hinj. repeat eexists.
    + exfalso. apply Hneq. congruence.
Qed.

Lemma green_of_red_k_case3_total_under_levels :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail : KChain A),
    buf_all_at_level k pre1 ->
    buf_all_at_level k suf1 ->
    buf5_is_not_red_shape pre2 ->
    buf5_is_not_red_shape suf2 ->
    packet_levels (S k) (PNode pre2 child suf2) ->
    exists c',
      green_of_red_k
        (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) = Some c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail
    Hpre1 Hsuf1 Hpre2_shape Hsuf2_shape Hpkt.
  inversion Hpkt as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  unfold green_of_red_k.
  destruct (@prefix_concat_total_under_levels A k pre1 pre2
              Hpre1 Hpre2 Hpre2_shape) as [pre1' [pre2' Hpre_concat]].
  destruct (@suffix_concat_total_under_levels A k suf2 suf1
              Hsuf2 Hsuf1 Hsuf2_shape) as [suf2' [suf1' Hsuf_concat]].
  rewrite Hpre_concat, Hsuf_concat.
  eexists; reflexivity.
Qed.

Lemma prefix_concat_preserves_outer_green_levels :
  forall A k (b1 b2 b1' b2' : Buf5 (E.t A)),
    buf_all_at_level k b1 ->
    buf_all_at_level (S k) b2 ->
    buf5_is_not_red_shape b2 ->
    prefix_concat b1 b2 = Some (b1', b2') ->
    buf5_is_green_shape b1' /\
    buf_all_at_level k b1' /\
    buf_all_at_level (S k) b2'.
Proof.
  intros A k b1 b2 b1' b2' Hb1 Hb2 Hshape Hconcat.
  unfold prefix_concat in Hconcat.
  destruct b1 as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b2 as [|q1|q1 q2|q1 q2 q3|q1 q2 q3 q4|q1 q2 q3 q4 q5];
    cbn in Hb1, Hb2, Hshape, Hconcat |- *; try contradiction; try discriminate;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          destruct (E.unpair A e) as [[u v]|] eqn:?; try discriminate;
          pose proof (E.unpair_level A e u v Heqo) as [? ?]
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [yellow_push ?x ?b] |- _ =>
          destruct (yellow_push x b) eqn:?; try discriminate
      end;
    inversion Hconcat; subst; clear Hconcat; cbn; repeat split; try assumption;
    try rewrite E.level_pair; try assumption; try lia.
Qed.

Lemma suffix_concat_preserves_outer_green_levels :
  forall A k (b1 b2 b1' b2' : Buf5 (E.t A)),
    buf_all_at_level (S k) b1 ->
    buf_all_at_level k b2 ->
    buf5_is_not_red_shape b1 ->
    suffix_concat b1 b2 = Some (b1', b2') ->
    buf_all_at_level (S k) b1' /\
    buf5_is_green_shape b2' /\
    buf_all_at_level k b2'.
Proof.
  intros A k b1 b2 b1' b2' Hb1 Hb2 Hshape Hconcat.
  unfold suffix_concat in Hconcat.
  destruct b1 as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b2 as [|q1|q1 q2|q1 q2 q3|q1 q2 q3 q4|q1 q2 q3 q4 q5];
    cbn in Hb1, Hb2, Hshape, Hconcat |- *; try contradiction; try discriminate;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          destruct (E.unpair A e) as [[u v]|] eqn:?; try discriminate;
          pose proof (E.unpair_level A e u v Heqo) as [? ?]
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [yellow_inject ?b ?x] |- _ =>
          destruct (yellow_inject b x) eqn:?; try discriminate
      end;
    inversion Hconcat; subst; clear Hconcat; cbn; repeat split; try assumption;
    try rewrite E.level_pair; try assumption; try lia.
Qed.

Theorem pop_kt4_direct_yellow_nested_underflow_repair_exec_preserves_all_role_repr :
  forall (A : Type) (lroot : Loc) (a : E.t A)
         (pre2 suf2 suf1 pre1' pre2' suf2' suf1' : Buf5 (E.t A))
         (child : Packet A) (tail : KChain A)
         (H H' : HeapP (E.t A)) (lroot' : Loc) (n : nat),
    buf5_is_not_red_shape pre2 ->
    buf5_is_not_red_shape suf2 ->
    prefix_concat B0 pre2 = Some (pre1', pre2') ->
    suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    chain_repr H lroot
      (kchain_to_chain
        (KCons Yellow (PNode (B1 a) (PNode pre2 child suf2) suf1) tail)) ->
    well_formed_heap H ->
    exec_pop_pkt_full_repair_C lroot H = Some (H', Some (a, lroot'), n) ->
    pop_kt4
      (KCons Yellow (PNode (B1 a) (PNode pre2 child suf2) suf1) tail) =
      PopOk a
        (KCons Green (PNode pre1' Hole suf1')
          (KCons Red (PNode pre2' child suf2') tail)) /\
    n <= NF_POP_PKT_FULL /\
    kt4_all_role_heap_packet_view_repr H' lroot'
      (KCons Green (PNode pre1' Hole suf1')
        (KCons Red (PNode pre2' child suf2') tail)).
Proof.
  intros A lroot a pre2 suf2 suf1 pre1' pre2' suf2' suf1' child tail
    H H' lroot' n Hpre2_shape Hsuf2_shape Hpre_concat Hsuf_concat
    Hrepr Hwf Hexec.
  destruct (@chain_repr_cons_inv_nested A H lroot
    (B1 a) suf1 pre2 suf2 child (kchain_to_chain tail) Hrepr)
    as (top_cell & ltail & inner_loc & Hlk_top & Hpre_top & Hsuf_top &
        Hinner_top & Htail_top & Hpre_top_level & Hsuf1_level & HRpkt &
        HRtl).
  destruct (@packet_repr_at_pnode_inv A H inner_loc pre2 suf2 child 1 HRpkt)
    as (_ & _ & _ & _ & _ & _ & Hpre2_level & Hsuf2_level & _).
  destruct (@prefix_concat_preserves_outer_green_levels A 0
      B0 pre2 pre1' pre2' I Hpre2_level Hpre2_shape Hpre_concat)
    as [Hpre1_green [Hpre1_level Hpre2_level']].
  destruct (@suffix_concat_preserves_outer_green_levels A 0
      suf2 suf1 suf2' suf1' Hsuf2_level Hsuf1_level Hsuf2_shape
      Hsuf_concat)
    as [Hsuf2_level' [Hsuf1_green Hsuf1_level']].
  assert (Hrepr' : chain_repr H' lroot'
    (ChainCons (PNode pre1' Hole suf1')
      (ChainCons (PNode pre2' child suf2') (kchain_to_chain tail)))).
  {
    eapply exec_pop_pkt_full_repair_C_refines_nested_underflow; eauto.
    destruct top_cell as [tp ts ti tt]; cbn in *; subst.
    exact Hlk_top.
  }
  split.
  - unfold pop_kt4. cbn -[green_of_red_k].
    unfold green_of_red_k. rewrite Hpre_concat, Hsuf_concat. reflexivity.
  - split.
    + eapply exec_pop_pkt_full_repair_C_cost; eauto.
    + eapply direct_green_heap_view_supports_all_role_repr_general; eauto.
Qed.

