Theorem prefix_concat_inner_green_shape_gap :
  exists (pre_in pre_next pre_out pre_repair : Buf5 (E.t unit)),
    buf_all_at_level 0 pre_in /\
    buf_all_at_level 1 pre_next /\
    buf5_is_not_red_shape pre_next /\
    prefix_concat pre_in pre_next = Some (pre_out, pre_repair) /\
    ~ buf5_is_green_shape pre_repair.
Proof.
  pose (x := E.base unit tt).
  pose (p := E.pair unit x x eq_refl).
  exists B0, (B1 p), (B2 x x), B0.
  split.
  - exact I.
  - split.
    + unfold p, x. cbn. reflexivity.
    + split.
      * exact I.
      * split.
        -- unfold p, x. cbn. reflexivity.
        -- cbn. tauto.
Qed.

Theorem suffix_concat_inner_green_shape_gap :
  exists (suf_next repair_suf suf_repair repair_suf' : Buf5 (E.t unit)),
    buf_all_at_level 1 suf_next /\
    buf_all_at_level 0 repair_suf /\
    buf5_is_not_red_shape suf_next /\
    suffix_concat suf_next repair_suf = Some (suf_repair, repair_suf') /\
    ~ buf5_is_green_shape suf_repair.
Proof.
  pose (x := E.base unit tt).
  pose (p := E.pair unit x x eq_refl).
  exists (B1 p), B0, B0, (B2 x x).
  split.
  - unfold p, x. cbn. reflexivity.
  - split.
    + exact I.
    + split.
      * exact I.
      * split.
        -- unfold p, x. cbn. reflexivity.
        -- cbn. tauto.
Qed.

Definition prefix_concat_inner_green_compatible {X : Type}
    (outer inner : Buf5 X) : Prop :=
  match outer, inner with
  | B0, B3 _ _ _
  | B0, B4 _ _ _ _
  | B1 _, B3 _ _ _
  | B1 _, B4 _ _ _ _
  | B2 _ _, B2 _ _
  | B2 _ _, B3 _ _ _
  | B3 _ _ _, B2 _ _
  | B3 _ _ _, B3 _ _ _
  | B4 _ _ _ _, B1 _
  | B4 _ _ _ _, B2 _ _
  | B5 _ _ _ _ _, B1 _
  | B5 _ _ _ _ _, B2 _ _ => True
  | _, _ => False
  end.

Definition suffix_concat_inner_green_compatible {X : Type}
    (inner outer : Buf5 X) : Prop :=
  match inner, outer with
  | B3 _ _ _, B0
  | B4 _ _ _ _, B0
  | B3 _ _ _, B1 _
  | B4 _ _ _ _, B1 _
  | B2 _ _, B2 _ _
  | B3 _ _ _, B2 _ _
  | B2 _ _, B3 _ _ _
  | B3 _ _ _, B3 _ _ _
  | B1 _, B4 _ _ _ _
  | B2 _ _, B4 _ _ _ _
  | B1 _, B5 _ _ _ _ _
  | B2 _ _, B5 _ _ _ _ _ => True
  | _, _ => False
  end.

Lemma prefix_concat_inner_green_shape_from_compatible :
  forall A (outer inner outer' inner' : Buf5 (E.t A)),
    prefix_concat_inner_green_compatible outer inner ->
    prefix_concat outer inner = Some (outer', inner') ->
    buf5_is_green_shape inner'.
Proof.
  intros A outer inner outer' inner' Hcompat Hconcat.
  unfold prefix_concat_inner_green_compatible in Hcompat.
  unfold prefix_concat in Hconcat.
  destruct outer as [|o1|o1 o2|o1 o2 o3|o1 o2 o3 o4|o1 o2 o3 o4 o5];
    destruct inner as [|i1|i1 i2|i1 i2 i3|i1 i2 i3 i4|i1 i2 i3 i4 i5];
    cbn in Hcompat, Hconcat |- *; try contradiction; try discriminate;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          destruct (E.unpair A e) as [[u v]|] eqn:?; try discriminate
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [yellow_push ?x ?b] |- _ =>
          destruct (yellow_push x b) eqn:?; try discriminate
      end;
    inversion Hconcat; subst; cbn; exact I.
Qed.

