Lemma pair_each_buf_after_halve_total_under_levels :
  forall A k (b : Buf5 (E.t A)) mid rest,
    buf_all_at_level (S k) b ->
    buffer_halve b = (mid, rest) ->
    exists rest', pair_each_buf rest = Some rest'.
Proof.
  intros A k b mid rest Hb Hhalve.
  destruct b as [|a|a b|a b c|a b c d|a b c d e];
    cbn in Hb, Hhalve; inversion Hhalve; subst mid rest; clear Hhalve;
    cbn.
  - eexists; reflexivity.
  - eexists; reflexivity.
  - destruct Hb as [Ha Hb].
    unfold pair_one.
    destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Heq|Hneq].
    + eexists; reflexivity.
    + exfalso. apply Hneq. congruence.
  - destruct Hb as [_ [Hb Hc]].
    unfold pair_one.
    destruct (Nat.eq_dec (E.level A b) (E.level A c)) as [Heq|Hneq].
    + eexists; reflexivity.
    + exfalso. apply Hneq. congruence.
  - destruct Hb as [Ha [Hb [Hc Hd]]].
    unfold pair_one.
    destruct (Nat.eq_dec (E.level A a) (E.level A b)) as [Hab|Hnab];
      [|exfalso; apply Hnab; congruence].
    destruct (Nat.eq_dec (E.level A c) (E.level A d)) as [Hcd|Hncd];
      [|exfalso; apply Hncd; congruence].
    eexists; reflexivity.
  - destruct Hb as [_ [Hb [Hc [Hd He]]]].
    unfold pair_one.
    destruct (Nat.eq_dec (E.level A b) (E.level A c)) as [Hbc|Hnbc];
      [|exfalso; apply Hnbc; congruence].
    destruct (Nat.eq_dec (E.level A d) (E.level A e)) as [Hde|Hnde];
      [|exfalso; apply Hnde; congruence].
    eexists; reflexivity.
Qed.

Lemma suffix_rot_unpair_total_under_levels :
  forall A k (b2 : Buf5 (E.t A)) (a b : E.t A)
         (eq : E.level A a = E.level A b),
    buf_all_at_level (S k) b2 ->
    let '(cd_paired, center) := suffix_rot b2 (E.pair A a b eq) in
    exists x y, E.unpair A cd_paired = Some (x, y).
Proof.
  intros A k b2 a b eq Hb2.
  destruct b2 as [|u|u v|u v w|u v w r|u v w r s]; cbn in Hb2 |- *.
  - exists a, b. apply E.unpair_pair.
  - destruct (@element_unpair_succeeds_at_s A k u Hb2) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu Hv].
    destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu [Hv Hw]].
    destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu [Hv [Hw Hr]]].
    destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu [Hv [Hw [Hr Hs]]]].
    destruct (@element_unpair_succeeds_at_s A k u Hu) as [x [y Hup]].
    rewrite Hup. repeat eexists.
Qed.

Lemma prefix_rot_unpair_total_under_levels :
  forall A k (b2 : Buf5 (E.t A)) (c d : E.t A)
         (eq : E.level A c = E.level A d),
    buf_all_at_level (S k) b2 ->
    let '(center, ab_paired) := prefix_rot (E.pair A c d eq) b2 in
    exists x y, E.unpair A ab_paired = Some (x, y).
Proof.
  intros A k b2 c d eq Hb2.
  destruct b2 as [|u|u v|u v w|u v w r|u v w r s]; cbn in Hb2 |- *.
  - exists c, d. apply E.unpair_pair.
  - destruct (@element_unpair_succeeds_at_s A k u Hb2) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu Hv].
    destruct (@element_unpair_succeeds_at_s A k v Hv) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu [Hv Hw]].
    destruct (@element_unpair_succeeds_at_s A k w Hw) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu [Hv [Hw Hr]]].
    destruct (@element_unpair_succeeds_at_s A k r Hr) as [x [y Hup]].
    rewrite Hup. repeat eexists.
  - destruct Hb2 as [Hu [Hv [Hw [Hr Hs]]]].
    destruct (@element_unpair_succeeds_at_s A k s Hs) as [x [y Hup]].
    rewrite Hup. repeat eexists.
Qed.

Lemma make_small_total_under_levels :
  forall A k (b1 b2 b3 : Buf5 (E.t A)),
    buf_all_at_level k b1 ->
    buf_all_at_level (S k) b2 ->
    buf_all_at_level k b3 ->
    exists c, make_small b1 b2 b3 = Some c.
Proof.
  intros A k b1 b2 b3 Hb1 Hb2 Hb3.
  unfold make_small.
  destruct b1 as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b3 as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn -[E.pair E.unpair] in Hb1, Hb2, Hb3 |- *;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | |- context [Nat.eq_dec ?x ?y] =>
          destruct (Nat.eq_dec x y); [| exfalso; congruence]
      end;
    repeat match goal with
      | H : E.level ?A ?e = S ?k |- context [E.unpair ?A ?e] =>
          let x := fresh "x" in
          let y := fresh "y" in
          let Hup := fresh "Hup" in
          destruct (@element_unpair_succeeds_at_s A k e H) as [x [y Hup]];
          rewrite Hup
      end;
    try rewrite E.unpair_pair;
    try solve [eexists; reflexivity].
  all:
    destruct b2 as [|u|u v|u v w|u v w r|u v w r s];
    cbn -[E.pair E.unpair] in Hb2 |- *;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | |- context [Nat.eq_dec ?x ?y] =>
          destruct (Nat.eq_dec x y); [| exfalso; congruence]
      end;
    repeat match goal with
      | H : E.level ?A ?e = S ?k |- context [E.unpair ?A ?e] =>
          let x := fresh "x" in
          let y := fresh "y" in
          let Hup := fresh "Hup" in
          destruct (@element_unpair_succeeds_at_s A k e H) as [x [y Hup]];
          rewrite Hup
      end;
    try rewrite E.unpair_pair;
    eexists; reflexivity.
Qed.

Lemma green_of_red_k_case1_total_under_levels :
  forall A k (pre suf b : Buf5 (E.t A)),
    buf_all_at_level k pre ->
    buf_all_at_level k suf ->
    buf_all_at_level (S k) b ->
    exists c',
      green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) = Some c'.
Proof.
  intros A k pre suf b Hpre Hsuf Hb.
  unfold green_of_red_k.
  destruct (@make_small_total_under_levels A k pre b suf Hpre Hb Hsuf)
    as [c Hmake].
  rewrite Hmake.
  eexists; reflexivity.
Qed.

Definition green_of_red_k_ready_at {A : Type}
    (k : nat) (p : Packet A) (tail : KChain A) : Prop :=
  match p, tail with
  | PNode _ Hole _, KEnding b =>
      buf_all_at_level (S k) b
  | PNode _ Hole _, KCons _ (PNode pre2 child suf2) _ =>
      buf5_is_green_shape pre2 /\
      buf5_is_green_shape suf2 /\
      packet_levels (S k) (PNode pre2 child suf2)
  | PNode _ (PNode pre2 child suf2) _, _ =>
      buf5_is_not_red_shape pre2 /\
      buf5_is_not_red_shape suf2 /\
      packet_levels (S k) (PNode pre2 child suf2)
  | _, _ => False
  end.

Definition green_of_red_k_context_ready_at {A : Type}
    (k : nat) (i : Packet A) (tail : KChain A) : Prop :=
  match i, tail with
  | Hole, KEnding b =>
      buf_all_at_level (S k) b
  | Hole, KCons _ (PNode pre2 child suf2) _ =>
      buf5_is_green_shape pre2 /\
      buf5_is_green_shape suf2 /\
      packet_levels (S k) (PNode pre2 child suf2)
  | PNode pre2 child suf2, _ =>
      buf5_is_not_red_shape pre2 /\
      buf5_is_not_red_shape suf2 /\
      packet_levels (S k) (PNode pre2 child suf2)
  | _, _ => False
  end.

Lemma green_of_red_k_ready_at_from_context :
  forall (A : Type) k (pre : Buf5 (E.t A)) (i : Packet A)
         (suf : Buf5 (E.t A)) (tail : KChain A),
    green_of_red_k_context_ready_at k i tail ->
    green_of_red_k_ready_at k (PNode pre i suf) tail.
Proof.
  intros A k pre i suf tail Hctx.
  destruct i as [|pre2 child2 suf2].
  - destruct tail as [b|col p2 tail2]; cbn in Hctx |- *; assumption.
  - cbn in Hctx |- *. assumption.
Qed.

Lemma green_of_red_k_success_requires_red_top :
  forall A (tail c_tail : KChain A),
    green_of_red_k tail = Some c_tail ->
    kchain_top_color tail = Red.
Proof.
  intros A tail c_tail Hred.
  destruct tail as [b|col p tail']; cbn in Hred |- *; try discriminate.
  destruct col; try discriminate; reflexivity.
Qed.

Lemma make_small_chain_to_kchain_g_context_ready :
  forall A k (pre b suf : Buf5 (E.t A)) c,
    buf_all_at_level (S k) pre ->
    buf_all_at_level (S (S k)) b ->
    buf_all_at_level (S k) suf ->
    make_small pre b suf = Some c ->
    green_of_red_k_context_ready_at k Hole (chain_to_kchain_g c).
Proof.
  intros A k pre b suf c Hpre Hb Hsuf Hmake.
  unfold make_small in Hmake.
  destruct pre as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b as [|m1|m1 m2|m1 m2 m3|m1 m2 m3 m4|m1 m2 m3 m4 m5];
    destruct suf as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn -[E.pair E.unpair] in Hpre, Hb, Hsuf, Hmake |- *;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : E.unpair A e = _ |- _ => fail
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [OpsKT.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (OpsKT.E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Model.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (Model.E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [buf5_push_naive ?x ?b] |- _ =>
          destruct (buf5_push_naive x b) eqn:?; try discriminate
      | H : context [buf5_inject_naive ?b ?x] |- _ =>
          destruct (buf5_inject_naive b x) eqn:?; try discriminate
      | H : context [buf5_pop_naive ?b] |- _ =>
          destruct (buf5_pop_naive b) as [[u v]|] eqn:?; try discriminate
      | H : context [buf5_eject_naive ?b] |- _ =>
          destruct (buf5_eject_naive b) as [[u v]|] eqn:?; try discriminate
      | H : context [pair_each_buf ?b] |- _ =>
          destruct (pair_each_buf b) eqn:?; try discriminate
      end;
    inversion Hmake; subst c; clear Hmake;
    cbn -[E.pair E.unpair]; repeat split; try exact I; try assumption;
    try rewrite E.level_pair in *; try lia;
    try solve [
      repeat constructor; cbn; repeat split; try exact I; try assumption;
      try rewrite E.level_pair in *; try lia].
Qed.

Lemma green_of_red_k_case1_output_context_ready :
  forall A k (pre suf b : Buf5 (E.t A)) c',
    packet_levels (S k) (PNode pre Hole suf) ->
    buf_all_at_level (S (S k)) b ->
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
      Some c' ->
    green_of_red_k_context_ready_at k Hole c'.
Proof.
  intros A k pre suf b c' Hpkt Hb Hred.
  inversion Hpkt as [|? ? ? ? Hpre _ Hsuf]; subst.
  unfold green_of_red_k in Hred.
  destruct (make_small pre b suf) as [c|] eqn:Hmake; [|discriminate].
  inversion Hred; subst c'; clear Hred.
  exact (@make_small_chain_to_kchain_g_context_ready
    A k pre b suf c Hpre Hb Hsuf Hmake).
Qed.

Lemma green_of_red_k_total_under_ready_levels :
  forall A k (p : Packet A) (tail : KChain A),
    packet_levels k p ->
    green_of_red_k_ready_at k p tail ->
    exists c', green_of_red_k (KCons Red p tail) = Some c'.
Proof.
  intros A k p tail Hpkt Hready.
  destruct p as [|pre i suf]; cbn in Hready; try contradiction.
  destruct i as [|pre2 child suf2].
  - destruct tail as [b|col p2 tail2].
    + inversion Hpkt as [|? ? ? ? Hpre _ Hsuf]; subst.
      eapply green_of_red_k_case1_total_under_levels; eauto.
    + destruct p2 as [|pre2 child suf2]; cbn in Hready; try contradiction.
      destruct Hready as [Hpre2_shape [Hsuf2_shape Hpkt2]].
      inversion Hpkt as [|? ? ? ? Hpre _ Hsuf]; subst.
      eapply green_of_red_k_case2_total_under_levels; eauto.
  - destruct Hready as [Hpre2_shape [Hsuf2_shape Hpkt2]].
    inversion Hpkt as [|? ? ? ? Hpre Hinner Hsuf]; subst.
    eapply green_of_red_k_case3_total_under_levels; eauto.
Qed.

Lemma packet_levels_push_overflow_pre :
  forall A k (x a b c d : E.t A) i suf,
    E.level A x = k ->
    packet_levels k (PNode (B4 a b c d) i suf) ->
    packet_levels k (PNode (B5 x a b c d) i suf).
Proof.
  intros A k x a b c d i suf Hx Hpkt.
  inversion Hpkt as [|? ? ? ? Hpre Hinner Hsuf]; subst.
  cbn in Hpre. destruct Hpre as [Ha [Hb [Hc Hd]]].
  constructor; cbn; [repeat split; assumption|assumption|assumption].
Qed.

Lemma packet_levels_inject_overflow_suf :
  forall A k pre i (a b c d x : E.t A),
    E.level A x = k ->
    packet_levels k (PNode pre i (B4 a b c d)) ->
    packet_levels k (PNode pre i (B5 a b c d x)).
Proof.
  intros A k pre i a b c d x Hx Hpkt.
  inversion Hpkt as [|? ? ? ? Hpre Hinner Hsuf]; subst.
  cbn in Hsuf. destruct Hsuf as [Ha [Hb [Hc Hd]]].
  constructor; cbn; [assumption|assumption|repeat split; assumption].
Qed.

Lemma packet_levels_pop_underflow_pre :
  forall A k (a : E.t A) i suf,
    packet_levels k (PNode (B1 a) i suf) ->
    packet_levels k (PNode B0 i suf).
Proof.
  intros A k a i suf Hpkt.
  inversion Hpkt as [|? ? ? ? Hpre Hinner Hsuf]; subst.
  constructor; cbn; [exact I|assumption|assumption].
Qed.

Lemma packet_levels_eject_underflow_suf :
  forall A k pre i (a : E.t A),
    packet_levels k (PNode pre i (B1 a)) ->
    packet_levels k (PNode pre i B0).
Proof.
  intros A k pre i a Hpkt.
  inversion Hpkt as [|? ? ? ? Hpre Hinner Hsuf]; subst.
  constructor; cbn; [assumption|assumption|exact I].
Qed.

Lemma yellow_push_red_repair_witness_from_ready :
  forall A k (x a b c d : E.t A) i suf tail,
    E.level A x = k ->
    packet_levels k (PNode (B4 a b c d) i suf) ->
    green_of_red_k_ready_at k (PNode (B5 x a b c d) i suf) tail ->
    exists c',
      green_of_red_k (KCons Red (PNode (B5 x a b c d) i suf) tail) =
        Some c'.
Proof.
  intros A k x a b c d i suf tail Hx Hpkt Hready.
  eapply green_of_red_k_total_under_ready_levels; [|exact Hready].
  eapply packet_levels_push_overflow_pre; eauto.
Qed.

Lemma yellow_inject_red_repair_witness_from_ready :
  forall A k pre i (a b c d x : E.t A) tail,
    E.level A x = k ->
    packet_levels k (PNode pre i (B4 a b c d)) ->
    green_of_red_k_ready_at k (PNode pre i (B5 a b c d x)) tail ->
    exists c',
      green_of_red_k (KCons Red (PNode pre i (B5 a b c d x)) tail) =
        Some c'.
Proof.
  intros A k pre i a b c d x tail Hx Hpkt Hready.
  eapply green_of_red_k_total_under_ready_levels; [|exact Hready].
  eapply packet_levels_inject_overflow_suf; eauto.
Qed.

Lemma yellow_pop_red_repair_witness_from_ready :
  forall A k (a : E.t A) i suf tail,
    packet_levels k (PNode (B1 a) i suf) ->
    green_of_red_k_ready_at k (PNode B0 i suf) tail ->
    exists c',
      green_of_red_k (KCons Red (PNode B0 i suf) tail) = Some c'.
Proof.
  intros A k a i suf tail Hpkt Hready.
  eapply green_of_red_k_total_under_ready_levels; [|exact Hready].
  eapply packet_levels_pop_underflow_pre; eauto.
Qed.

Lemma yellow_eject_red_repair_witness_from_ready :
  forall A k pre i (a : E.t A) tail,
    packet_levels k (PNode pre i (B1 a)) ->
    green_of_red_k_ready_at k (PNode pre i B0) tail ->
    exists c',
      green_of_red_k (KCons Red (PNode pre i B0) tail) = Some c'.
Proof.
  intros A k pre i a tail Hpkt Hready.
  eapply green_of_red_k_total_under_ready_levels; [|exact Hready].
  eapply packet_levels_eject_underflow_suf; eauto.
Qed.

Definition yellow_wrap_pr_total_pre {A : Type} (c : KChain A) : Prop :=
  match c with
  | KCons Red _ _ => exists c', green_of_red_k c = Some c'
  | _ => True
  end.

Lemma yellow_wrap_pr_total :
  forall A (pre : Buf5 (E.t A)) (i : Packet A) (suf : Buf5 (E.t A))
         (c : KChain A),
    yellow_wrap_pr_total_pre c ->
    exists c', yellow_wrap_pr pre i suf c = PushOk c'.
Proof.
  intros A pre i suf c Hpre.
  unfold yellow_wrap_pr_total_pre in Hpre.
  unfold yellow_wrap_pr.
  destruct c as [b|col p tail].
  - eexists; reflexivity.
  - destruct col.
    + eexists; reflexivity.
    + eexists; reflexivity.
    + destruct Hpre as [c' Hg]. rewrite Hg. eexists; reflexivity.
Qed.

Corollary yellow_wrap_pr_no_fail_under_pre :
  forall A (pre : Buf5 (E.t A)) (i : Packet A) (suf : Buf5 (E.t A))
         (c : KChain A),
    yellow_wrap_pr_total_pre c ->
    yellow_wrap_pr pre i suf c <> PushFail.
Proof.
  intros A pre i suf c Hpre Hfail.
  destruct (@yellow_wrap_pr_total A pre i suf c Hpre) as [c' Hok].
  rewrite Hok in Hfail. discriminate.
Qed.

Definition push_kt4_total_pre {A : Type} (x : E.t A) (c : KChain A) : Prop :=
  match c with
  | KEnding _ => True
  | KCons Green (PNode pre _ _) tail =>
      buf5_is_green_shape pre /\ yellow_wrap_pr_total_pre tail
  | KCons Yellow (PNode pre i suf) tail =>
      match pre with
      | B1 _ | B2 _ _ | B3 _ _ _ => True
      | B4 a b c d =>
          exists c',
            green_of_red_k (KCons Red (PNode (B5 x a b c d) i suf) tail) = Some c'
      | _ => False
      end
  | _ => False
  end.

Definition inject_kt4_total_pre {A : Type} (c : KChain A) (x : E.t A) : Prop :=
  match c with
  | KEnding _ => True
  | KCons Green (PNode _ _ suf) tail =>
      buf5_is_green_shape suf /\ yellow_wrap_pr_total_pre tail
  | KCons Yellow (PNode pre i suf) tail =>
      match suf with
      | B1 _ | B2 _ _ | B3 _ _ _ => True
      | B4 a b c d =>
          exists c',
            green_of_red_k (KCons Red (PNode pre i (B5 a b c d x)) tail) = Some c'
      | _ => False
      end
  | _ => False
  end.

Definition pop_kt4_total_pre {A : Type} (c : KChain A) : Prop :=
  match c with
  | KEnding B0 => False
  | KEnding _ => True
  | KCons Green (PNode pre _ _) tail =>
      buf5_is_green_shape pre /\ yellow_wrap_pr_total_pre tail
  | KCons Yellow (PNode pre i suf) tail =>
      match pre with
      | B1 _ =>
          exists c',
            green_of_red_k (KCons Red (PNode B0 i suf) tail) = Some c'
      | B2 _ _ | B3 _ _ _ | B4 _ _ _ _ => True
      | _ => False
      end
  | _ => False
  end.

Definition eject_kt4_total_pre {A : Type} (c : KChain A) : Prop :=
  match c with
  | KEnding B0 => False
  | KEnding _ => True
  | KCons Green (PNode _ _ suf) tail =>
      buf5_is_green_shape suf /\ yellow_wrap_pr_total_pre tail
  | KCons Yellow (PNode pre i suf) tail =>
      match suf with
      | B1 _ =>
          exists c',
            green_of_red_k (KCons Red (PNode pre i B0) tail) = Some c'
      | B2 _ _ | B3 _ _ _ | B4 _ _ _ _ => True
      | _ => False
      end
  | _ => False
  end.

(* -------------------------------------------------------------------------- *)
(* A reusable state-level totality invariant candidate.                         *)
(*                                                                            *)
(* This is the first explicit aggregation of the per-operation totality         *)
(* obligations above.  It is intentionally a pure KChain predicate: Green      *)
(* links require Green boundary buffers and a total yellow-tail wrapper; Yellow *)
(* links require non-Red boundary buffers plus the four possible one-step       *)
(* red-fix witnesses that public operations may need.                          *)
(* -------------------------------------------------------------------------- *)

Definition kt4_nonempty_state {A : Type} (c : KChain A) : Prop :=
  match c with
  | KEnding B0 => False
  | _ => True
  end.

Definition kt4_total_state {A : Type} (c : KChain A) : Prop :=
  match c with
  | KEnding _ => True
  | KCons Green (PNode pre _ suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      yellow_wrap_pr_total_pre tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      (forall x,
          match pre with
          | B4 a b c d =>
              exists c',
                green_of_red_k
                  (KCons Red (PNode (B5 x a b c d) i suf) tail) = Some c'
          | _ => True
          end) /\
      (forall x,
          match suf with
          | B4 a b c d =>
              exists c',
                green_of_red_k
                  (KCons Red (PNode pre i (B5 a b c d x)) tail) = Some c'
          | _ => True
          end) /\
      (match pre with
       | B1 _ =>
           exists c',
             green_of_red_k (KCons Red (PNode B0 i suf) tail) = Some c'
       | _ => True
       end) /\
      (match suf with
       | B1 _ =>
           exists c',
             green_of_red_k (KCons Red (PNode pre i B0) tail) = Some c'
       | _ => True
       end)
  | _ => False
  end.

Theorem empty_kchain_kt4_total_state :
  forall A, kt4_total_state (@empty_kchain A).
Proof.
  intros A. unfold kt4_total_state, empty_kchain. exact I.
Qed.

Theorem kt4_total_state_push_pre :
  forall A (x : E.t A) (c : KChain A),
    kt4_total_state c ->
    push_kt4_total_pre x c.
Proof.
  intros A x c Hstate.
  unfold kt4_total_state in Hstate.
  unfold push_kt4_total_pre.
  destruct c as [b|col p tail].
  - exact I.
  - destruct col; destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [Hpre [_ Hyw]].
      exact (conj Hpre Hyw).
    + destruct Hstate as [Hpre [_ [Hpush _]]].
      destruct pre as [|a|a b|a b c0|a b c0 d|];
        cbn in Hpre; try contradiction; try exact I.
      exact (Hpush x).
Qed.

Theorem kt4_total_state_inject_pre :
  forall A (c : KChain A) (x : E.t A),
    kt4_total_state c ->
    inject_kt4_total_pre c x.
Proof.
  intros A c x Hstate.
  unfold kt4_total_state in Hstate.
  unfold inject_kt4_total_pre.
  destruct c as [b|col p tail].
  - exact I.
  - destruct col; destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [_ [Hsuf Hyw]].
      exact (conj Hsuf Hyw).
    + destruct Hstate as [_ [Hsuf [_ [Hinject _]]]].
      destruct suf as [|a|a b|a b c0|a b c0 d|];
        cbn in Hsuf; try contradiction; try exact I.
      exact (Hinject x).
Qed.

Theorem kt4_total_state_pop_pre :
  forall A (c : KChain A),
    kt4_total_state c ->
    kt4_nonempty_state c ->
    pop_kt4_total_pre c.
Proof.
  intros A c Hstate Hnonempty.
  unfold kt4_total_state in Hstate.
  unfold kt4_nonempty_state in Hnonempty.
  unfold pop_kt4_total_pre.
  destruct c as [b|col p tail].
  - destruct b; cbn in Hnonempty; try contradiction; exact I.
  - destruct col; destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [Hpre [_ Hyw]].
      exact (conj Hpre Hyw).
    + destruct Hstate as [Hpre [_ [_ [_ [Hpop _]]]]].
      destruct pre as [|a|a b|a b c0|a b c0 d|];
        cbn in Hpre; try contradiction; try exact I.
      exact Hpop.
Qed.

Theorem kt4_total_state_eject_pre :
  forall A (c : KChain A),
    kt4_total_state c ->
    kt4_nonempty_state c ->
    eject_kt4_total_pre c.
Proof.
  intros A c Hstate Hnonempty.
  unfold kt4_total_state in Hstate.
  unfold kt4_nonempty_state in Hnonempty.
  unfold eject_kt4_total_pre.
  destruct c as [b|col p tail].
  - destruct b; cbn in Hnonempty; try contradiction; exact I.
  - destruct col; destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [_ [Hsuf Hyw]].
      exact (conj Hsuf Hyw).
    + destruct Hstate as [_ [Hsuf [_ [_ [_ Heject]]]]].
      destruct suf as [|a|a b|a b c0|a b c0 d|];
        cbn in Hsuf; try contradiction; try exact I.
      exact Heject.
Qed.

Theorem push_kt4_total_under_pre :
  forall A (x : E.t A) (c : KChain A),
    push_kt4_total_pre x c ->
    exists c', push_kt4 x c = PushOk c'.
Proof.
  intros A x c Hpre.
  unfold push_kt4_total_pre in Hpre.
  unfold push_kt4.
  destruct c as [b|col p tail].
  - destruct b; eexists; reflexivity.
  - destruct col; destruct p as [|pre i suf]; cbn in Hpre; try contradiction.
    + destruct Hpre as [Hgreen Hyw].
      destruct pre; cbn in Hgreen; try contradiction;
        match goal with
        | |- exists c', yellow_wrap_pr ?pre ?i ?suf ?tail = PushOk c' =>
            destruct (@yellow_wrap_pr_total A pre i suf tail Hyw) as [c' Hyw'];
            rewrite Hyw'; eexists; reflexivity
        end.
    + destruct pre as [|a|a b|a b c0|a b c0 d|];
        try (cbn in Hpre; contradiction); try (eexists; reflexivity).
      change (exists c',
        green_of_red_k (KCons Red (PNode (B5 x a b c0 d) i suf) tail) = Some c') in Hpre.
      destruct Hpre as [c' Hg].
      destruct (green_of_red_k (KCons Red (PNode (B5 x a b c0 d) i suf) tail))
        as [c''|] eqn:Hg';
        [eexists; reflexivity | congruence].
Qed.

Corollary push_kt4_no_fail_under_pre :
  forall A (x : E.t A) (c : KChain A),
    push_kt4_total_pre x c ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hpre Hfail.
  destruct (@push_kt4_total_under_pre A x c Hpre) as [c' Hok].
  rewrite Hok in Hfail. discriminate.
Qed.

Corollary push_kt4_no_fail_under_total_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_total_state c ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hstate.
  apply push_kt4_no_fail_under_pre.
  apply kt4_total_state_push_pre.
  exact Hstate.
Qed.

Theorem inject_kt4_total_under_pre :
  forall A (c : KChain A) (x : E.t A),
    inject_kt4_total_pre c x ->
    exists c', inject_kt4 c x = PushOk c'.
Proof.
  intros A c x Hpre.
  unfold inject_kt4_total_pre in Hpre.
  unfold inject_kt4.
  destruct c as [b|col p tail].
  - destruct b; eexists; reflexivity.
  - destruct col; destruct p as [|pre i suf]; cbn in Hpre; try contradiction.
    + destruct Hpre as [Hgreen Hyw].
      destruct suf; cbn in Hgreen; try contradiction;
        match goal with
        | |- exists c', yellow_wrap_pr ?pre ?i ?suf ?tail = PushOk c' =>
            destruct (@yellow_wrap_pr_total A pre i suf tail Hyw) as [c' Hyw'];
            rewrite Hyw'; eexists; reflexivity
        end.
    + destruct suf as [|a|a b|a b c0|a b c0 d|];
        try (cbn in Hpre; contradiction); try (eexists; reflexivity).
      change (exists c',
        green_of_red_k (KCons Red (PNode pre i (B5 a b c0 d x)) tail) = Some c') in Hpre.
      destruct Hpre as [c' Hg].
      destruct (green_of_red_k (KCons Red (PNode pre i (B5 a b c0 d x)) tail))
        as [c''|] eqn:Hg';
        [eexists; reflexivity | congruence].
Qed.

Corollary inject_kt4_no_fail_under_pre :
  forall A (c : KChain A) (x : E.t A),
    inject_kt4_total_pre c x ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x Hpre Hfail.
  destruct (@inject_kt4_total_under_pre A c x Hpre) as [c' Hok].
  rewrite Hok in Hfail. discriminate.
Qed.

Corollary inject_kt4_no_fail_under_total_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_total_state c ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x Hstate.
  apply inject_kt4_no_fail_under_pre.
  apply kt4_total_state_inject_pre.
  exact Hstate.
Qed.

Theorem pop_kt4_total_under_pre :
  forall A (c : KChain A),
    pop_kt4_total_pre c ->
    exists x c', pop_kt4 c = PopOk x c'.
Proof.
  intros A c Hpre.
  unfold pop_kt4_total_pre in Hpre.
  unfold pop_kt4.
  destruct c as [b|col p tail].
  - destruct b; cbn in Hpre; try contradiction; repeat eexists; reflexivity.
  - destruct col; destruct p as [|pre i suf]; cbn in Hpre; try contradiction.
    + destruct Hpre as [Hgreen Hyw].
      destruct pre; cbn in Hgreen; try contradiction;
        match goal with
        | |- exists x c', match yellow_wrap_pr ?pre ?i ?suf ?tail with
                          | PushFail => PopFail
                          | PushOk c'' => PopOk _ c''
                          end = PopOk x c' =>
            destruct (@yellow_wrap_pr_total A pre i suf tail Hyw) as [c' Hyw'];
            rewrite Hyw'; repeat eexists; reflexivity
        end.
    + destruct pre as [|a|a b|a b c0|a b c0 d|];
        try (cbn in Hpre; contradiction); try (repeat eexists; reflexivity).
      change (exists c',
        green_of_red_k (KCons Red (PNode B0 i suf) tail) = Some c') in Hpre.
      destruct Hpre as [c' Hg].
      destruct (green_of_red_k (KCons Red (PNode B0 i suf) tail))
        as [c''|] eqn:Hg';
        [repeat eexists; reflexivity | congruence].
Qed.

Corollary pop_kt4_no_fail_under_pre :
  forall A (c : KChain A),
    pop_kt4_total_pre c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c Hpre Hfail.
  destruct (@pop_kt4_total_under_pre A c Hpre) as [x [c' Hok]].
  rewrite Hok in Hfail. discriminate.
Qed.

Corollary pop_kt4_no_fail_under_total_state :
  forall A (c : KChain A),
    kt4_total_state c ->
    kt4_nonempty_state c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c Hstate Hnonempty.
  apply pop_kt4_no_fail_under_pre.
  eapply kt4_total_state_pop_pre; eauto.
Qed.

Theorem eject_kt4_total_under_pre :
  forall A (c : KChain A),
    eject_kt4_total_pre c ->
    exists x c', eject_kt4 c = PopOk x c'.
Proof.
  intros A c Hpre.
  unfold eject_kt4_total_pre in Hpre.
  unfold eject_kt4.
  destruct c as [b|col p tail].
  - destruct b; cbn in Hpre; try contradiction; repeat eexists; reflexivity.
  - destruct col; destruct p as [|pre i suf]; cbn in Hpre; try contradiction.
    + destruct Hpre as [Hgreen Hyw].
      destruct suf; cbn in Hgreen; try contradiction;
        match goal with
        | |- exists x c', match yellow_wrap_pr ?pre ?i ?suf ?tail with
                          | PushFail => PopFail
                          | PushOk c'' => PopOk _ c''
                          end = PopOk x c' =>
            destruct (@yellow_wrap_pr_total A pre i suf tail Hyw) as [c' Hyw'];
            rewrite Hyw'; repeat eexists; reflexivity
        end.
    + destruct suf as [|a|a b|a b c0|a b c0 d|];
        try (cbn in Hpre; contradiction); try (repeat eexists; reflexivity).
      change (exists c',
        green_of_red_k (KCons Red (PNode pre i B0) tail) = Some c') in Hpre.
      destruct Hpre as [c' Hg].
      destruct (green_of_red_k (KCons Red (PNode pre i B0) tail))
        as [c''|] eqn:Hg';
        [repeat eexists; reflexivity | congruence].
Qed.

Corollary eject_kt4_no_fail_under_pre :
  forall A (c : KChain A),
    eject_kt4_total_pre c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hpre Hfail.
  destruct (@eject_kt4_total_under_pre A c Hpre) as [x [c' Hok]].
  rewrite Hok in Hfail. discriminate.
Qed.

Corollary eject_kt4_no_fail_under_total_state :
  forall A (c : KChain A),
    kt4_total_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hstate Hnonempty.
  apply eject_kt4_no_fail_under_pre.
  eapply kt4_total_state_eject_pre; eauto.
Qed.

(* -------------------------------------------------------------------------- *)
(* Level-aware totality-state candidate.                                       *)
(*                                                                            *)
(* [kt4_total_state] above is intentionally operation-local and quantifies     *)
(* future push/inject elements without level restrictions.  That is too broad  *)
(* for the real public surface, where newly supplied elements must match the   *)
(* current chain level (level 0 at the API boundary).  The predicate below      *)
(* keeps the explicit red-repair witnesses but adds packet/buffer level         *)
(* consistency and allows internal Red nodes, which can arise below a Green     *)
(* top after a repair.                                                         *)
(*                                                                            *)
(* This is still a candidate, not Gate-B closure: the boundary theorem below   *)
(* shows it is not push-closed for all non-empty [KCons] states.  The next      *)
(* invariant must carry enough tail-shape / future-repair closure to use the    *)
(* structural [green_of_red_k] derivations for reachable states.                *)
(* -------------------------------------------------------------------------- *)

Fixpoint kt4_level_total_state_at {A : Type} (k : nat) (c : KChain A) : Prop :=
  match c with
  | KEnding b => buf_all_at_level k b
  | KCons Green (PNode pre i suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_total_state_at (k + packet_depth (PNode pre i suf)) tail /\
      yellow_wrap_pr_total_pre tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_total_state_at (k + packet_depth (PNode pre i suf)) tail /\
      (forall x,
          E.level A x = k ->
          match pre with
          | B4 a b c d =>
              exists c',
                green_of_red_k
                  (KCons Red (PNode (B5 x a b c d) i suf) tail) = Some c'
          | _ => True
          end) /\
      (forall x,
          E.level A x = k ->
          match suf with
          | B4 a b c d =>
              exists c',
                green_of_red_k
                  (KCons Red (PNode pre i (B5 a b c d x)) tail) = Some c'
          | _ => True
          end) /\
      (match pre with
       | B1 _ =>
           exists c',
             green_of_red_k (KCons Red (PNode B0 i suf) tail) = Some c'
       | _ => True
       end) /\
      (match suf with
       | B1 _ =>
           exists c',
             green_of_red_k (KCons Red (PNode pre i B0) tail) = Some c'
       | _ => True
       end)
  | KCons Red (PNode pre i suf) tail =>
      packet_levels k (PNode pre i suf) /\
      kt4_level_total_state_at (k + packet_depth (PNode pre i suf)) tail /\
      exists c', green_of_red_k c = Some c'
  | _ => False
  end.

Definition kt4_public_level_total_state {A : Type} (c : KChain A) : Prop :=
  kchain_top_color c <> Red /\ kt4_level_total_state_at 0 c.

Theorem empty_kchain_kt4_public_level_total_state :
  forall A, kt4_public_level_total_state (@empty_kchain A).
Proof.
  intros A.
  unfold kt4_public_level_total_state, empty_kchain.
  split; [cbn; discriminate|cbn; exact I].
Qed.

Theorem kt4_level_total_state_push_pre :
  forall A k (x : E.t A) (c : KChain A),
    kchain_top_color c <> Red ->
    E.level A x = k ->
    kt4_level_total_state_at k c ->
    push_kt4_total_pre x c.
Proof.
  intros A k x c Htop Hlx Hstate.
  unfold push_kt4_total_pre.
  destruct c as [b|col p tail].
  - exact I.
  - destruct col; [| | exfalso; apply Htop; reflexivity];
      destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [Hpre [_ [_ [_ Hyw]]]].
      exact (conj Hpre Hyw).
    + destruct Hstate as [Hpre [_ [_ [_ [Hpush _]]]]].
      destruct pre as [|a|a b|a b c0|a b c0 d|];
        cbn in Hpre; try contradiction; try exact I.
      exact (Hpush x Hlx).
Qed.

Theorem kt4_level_total_state_inject_pre :
  forall A k (c : KChain A) (x : E.t A),
    kchain_top_color c <> Red ->
    E.level A x = k ->
    kt4_level_total_state_at k c ->
    inject_kt4_total_pre c x.
Proof.
  intros A k c x Htop Hlx Hstate.
  unfold inject_kt4_total_pre.
  destruct c as [b|col p tail].
  - exact I.
  - destruct col; [| | exfalso; apply Htop; reflexivity];
      destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [_ [Hsuf [_ [_ Hyw]]]].
      exact (conj Hsuf Hyw).
    + destruct Hstate as [_ [Hsuf [_ [_ [_ [Hinject _]]]]]].
      destruct suf as [|a|a b|a b c0|a b c0 d|];
        cbn in Hsuf; try contradiction; try exact I.
      exact (Hinject x Hlx).
Qed.

Theorem kt4_level_total_state_pop_pre :
  forall A k (c : KChain A),
    kchain_top_color c <> Red ->
    kt4_level_total_state_at k c ->
    kt4_nonempty_state c ->
    pop_kt4_total_pre c.
Proof.
  intros A k c Htop Hstate Hnonempty.
  unfold pop_kt4_total_pre.
  destruct c as [b|col p tail].
  - unfold kt4_nonempty_state in Hnonempty.
    destruct b; cbn in Hnonempty; try contradiction; exact I.
  - destruct col; [| | exfalso; apply Htop; reflexivity];
      destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [Hpre [_ [_ [_ Hyw]]]].
      exact (conj Hpre Hyw).
    + destruct Hstate as [Hpre [_ [_ [_ [_ [_ [Hpop _]]]]]]].
      destruct pre as [|a|a b|a b c0|a b c0 d|];
        cbn in Hpre; try contradiction; try exact I.
      exact Hpop.
Qed.

Theorem kt4_level_total_state_eject_pre :
  forall A k (c : KChain A),
    kchain_top_color c <> Red ->
    kt4_level_total_state_at k c ->
    kt4_nonempty_state c ->
    eject_kt4_total_pre c.
Proof.
  intros A k c Htop Hstate Hnonempty.
  unfold eject_kt4_total_pre.
  destruct c as [b|col p tail].
  - unfold kt4_nonempty_state in Hnonempty.
    destruct b; cbn in Hnonempty; try contradiction; exact I.
  - destruct col; [| | exfalso; apply Htop; reflexivity];
      destruct p as [|pre i suf]; cbn in Hstate; try contradiction.
    + destruct Hstate as [_ [Hsuf [_ [_ Hyw]]]].
      exact (conj Hsuf Hyw).
    + destruct Hstate as [_ [Hsuf [_ [_ [_ [_ [_ Heject]]]]]]].
      destruct suf as [|a|a b|a b c0|a b c0 d|];
        cbn in Hsuf; try contradiction; try exact I.
      exact Heject.
Qed.

Corollary push_kt4_no_fail_under_public_level_total_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_public_level_total_state c ->
    E.level A x = 0 ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c [Htop Hstate] Hlx.
  apply push_kt4_no_fail_under_pre.
  eapply kt4_level_total_state_push_pre; eauto.
Qed.

Corollary inject_kt4_no_fail_under_public_level_total_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_public_level_total_state c ->
    E.level A x = 0 ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x [Htop Hstate] Hlx.
  apply inject_kt4_no_fail_under_pre.
  eapply kt4_level_total_state_inject_pre; eauto.
Qed.

Corollary pop_kt4_no_fail_under_public_level_total_state :
  forall A (c : KChain A),
    kt4_public_level_total_state c ->
    kt4_nonempty_state c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c [Htop Hstate] Hnonempty.
  apply pop_kt4_no_fail_under_pre.
  eapply kt4_level_total_state_pop_pre; eauto.
Qed.

Corollary eject_kt4_no_fail_under_public_level_total_state :
  forall A (c : KChain A),
    kt4_public_level_total_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c [Htop Hstate] Hnonempty.
  apply eject_kt4_no_fail_under_pre.
  eapply kt4_level_total_state_eject_pre; eauto.
Qed.

(* -------------------------------------------------------------------------- *)
(* Stronger ready-state candidate.                                             *)
(*                                                                            *)
(* The public level-aware predicate above records the witnesses needed by the  *)
(* current operation.  The next reachable-state invariant also has to record   *)
(* that the surrounding packet context is ready for the next red repair after  *)
(* a Green/Yellow boundary update.  This candidate is intentionally still only *)
(* a target: it implies the totality predicate used by the no-Fail corollaries *)
(* below, while preservation across non-ending chains remains the next Gate-B  *)
(* proof obligation.                                                           *)
(* -------------------------------------------------------------------------- *)

Fixpoint kt4_level_ready_state_at {A : Type} (k : nat) (c : KChain A) : Prop :=
  match c with
  | KEnding b => buf_all_at_level k b
  | KCons Green (PNode pre i suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      yellow_wrap_pr_total_pre tail /\
      green_of_red_k_context_ready_at k i tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      green_of_red_k_context_ready_at k i tail
  | KCons Red (PNode pre i suf) tail =>
      packet_levels k (PNode pre i suf) /\
      kt4_level_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      green_of_red_k_context_ready_at k i tail
  | _ => False
  end.

Definition kt4_public_level_ready_state {A : Type} (c : KChain A) : Prop :=
  kchain_top_color c <> Red /\ kt4_level_ready_state_at 0 c.

Theorem empty_kchain_kt4_public_level_ready_state :
  forall A, kt4_public_level_ready_state (@empty_kchain A).
Proof.
  intros A.
  unfold kt4_public_level_ready_state, empty_kchain.
  split; [cbn; discriminate|cbn; exact I].
Qed.

Theorem kt4_level_ready_state_total_state_at :
  forall A k (c : KChain A),
    kt4_level_ready_state_at k c ->
    kt4_level_total_state_at k c.
Proof.
  intros A k c.
  revert k.
  induction c as [b|col p tail IH]; intros k Hready.
  - exact Hready.
  - destruct col; destruct p as [|pre i suf]; cbn in Hready |- *;
      try contradiction.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail [Hyw _]]]]].
      repeat split; try assumption.
      apply IH. exact Htail.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail Hctx]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * intros x Hx.
        destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_push_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context. exact Hctx.
      * intros x Hx.
        destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_inject_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context. exact Hctx.
      * destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_pop_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context. exact Hctx.
      * destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_eject_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context. exact Hctx.
    + destruct Hready as [Hpkt [Htail Hctx]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * change (exists c',
            green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c').
        eapply green_of_red_k_total_under_ready_levels; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context. exact Hctx.
Qed.

Theorem kt4_public_level_ready_state_total_state :
  forall A (c : KChain A),
    kt4_public_level_ready_state c ->
    kt4_public_level_total_state c.
Proof.
  intros A c [Htop Hready].
  split; [exact Htop|].
  eapply kt4_level_ready_state_total_state_at. exact Hready.
Qed.

Corollary push_kt4_no_fail_under_public_level_ready_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_public_level_ready_state c ->
    E.level A x = 0 ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hready Hx.
  eapply push_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_ready_state_total_state. exact Hready.
Qed.

Corollary inject_kt4_no_fail_under_public_level_ready_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_public_level_ready_state c ->
    E.level A x = 0 ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x Hready Hx.
  eapply inject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_ready_state_total_state. exact Hready.
Qed.

Corollary pop_kt4_no_fail_under_public_level_ready_state :
  forall A (c : KChain A),
    kt4_public_level_ready_state c ->
    kt4_nonempty_state c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply pop_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_ready_state_total_state. exact Hready.
Qed.

Corollary eject_kt4_no_fail_under_public_level_ready_state :
  forall A (c : KChain A),
    kt4_public_level_ready_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply eject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_ready_state_total_state. exact Hready.
Qed.

(* -------------------------------------------------------------------------- *)
(* Nested-context ready-state candidate.                                       *)
(*                                                                            *)
(* [kt4_level_ready_state_at] records enough packet-context readiness for the  *)
(* immediate [green_of_red_k] call.  Case 3 of [green_of_red_k] can expose a   *)
(* nested child packet as a fresh Red inner chain, so preservation needs the   *)
(* child context to be ready as well.  The inductive predicate below records   *)
(* that recursive packet-context obligation without changing the older         *)
(* candidate, whose counterexample remains useful documentation.               *)
(* -------------------------------------------------------------------------- *)

Inductive packet_context_deep_ready_at {A : Type}
    : nat -> Packet A -> KChain A -> Prop :=
| pcdr_hole_ending :
    forall k b,
      buf_all_at_level (S k) b ->
      packet_context_deep_ready_at k Hole (KEnding b)
| pcdr_hole_kcons :
    forall k col pre child suf tail,
      buf5_is_green_shape pre ->
      buf5_is_green_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_deep_ready_at (S k) child tail ->
      packet_context_deep_ready_at k Hole (KCons col (PNode pre child suf) tail)
| pcdr_pnode :
    forall k pre child suf tail,
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_deep_ready_at (S k) child tail ->
      packet_context_deep_ready_at k (PNode pre child suf) tail.

Lemma packet_context_deep_ready_context_ready :
  forall A k (i : Packet A) (tail : KChain A),
    packet_context_deep_ready_at k i tail ->
    green_of_red_k_context_ready_at k i tail.
Proof.
  intros A k i tail Hdeep.
  inversion Hdeep; subst; cbn; repeat split; assumption.
Qed.

Fixpoint kt4_level_deep_ready_state_at {A : Type} (k : nat) (c : KChain A)
    : Prop :=
  match c with
  | KEnding b => buf_all_at_level k b
  | KCons Green (PNode pre i suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_deep_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      yellow_wrap_pr_total_pre tail /\
      packet_context_deep_ready_at k i tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_deep_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_deep_ready_at k i tail
  | KCons Red (PNode pre i suf) tail =>
      packet_levels k (PNode pre i suf) /\
      kt4_level_deep_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_deep_ready_at k i tail
  | _ => False
  end.

Definition kt4_public_level_deep_ready_state {A : Type} (c : KChain A)
    : Prop :=
  kchain_top_color c <> Red /\ kt4_level_deep_ready_state_at 0 c.

Theorem empty_kchain_kt4_public_level_deep_ready_state :
  forall A, kt4_public_level_deep_ready_state (@empty_kchain A).
Proof.
  intros A.
  unfold kt4_public_level_deep_ready_state, empty_kchain.
  split; [cbn; discriminate|cbn; exact I].
Qed.

Theorem kt4_level_deep_ready_state_ready_state_at :
  forall A k (c : KChain A),
    kt4_level_deep_ready_state_at k c ->
    kt4_level_ready_state_at k c.
Proof.
  intros A k c.
  revert k.
  induction c as [b|col p tail IH]; intros k Hdeep.
  - exact Hdeep.
  - destruct col; destruct p as [|pre i suf]; cbn in Hdeep |- *;
      try contradiction.
    + destruct Hdeep as [Hpre [Hsuf [Hpkt [Htail [Hyw Hctx]]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * eapply packet_context_deep_ready_context_ready. exact Hctx.
    + destruct Hdeep as [Hpre [Hsuf [Hpkt [Htail Hctx]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * eapply packet_context_deep_ready_context_ready. exact Hctx.
    + destruct Hdeep as [Hpkt [Htail Hctx]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * eapply packet_context_deep_ready_context_ready. exact Hctx.
Qed.

Theorem kt4_public_level_deep_ready_state_ready_state :
  forall A (c : KChain A),
    kt4_public_level_deep_ready_state c ->
    kt4_public_level_ready_state c.
Proof.
  intros A c [Htop Hdeep].
  split; [exact Htop|].
  eapply kt4_level_deep_ready_state_ready_state_at. exact Hdeep.
Qed.

Corollary push_kt4_no_fail_under_public_level_deep_ready_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_public_level_deep_ready_state c ->
    E.level A x = 0 ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hdeep Hx.
  eapply push_kt4_no_fail_under_public_level_ready_state; eauto.
  eapply kt4_public_level_deep_ready_state_ready_state. exact Hdeep.
Qed.

Corollary inject_kt4_no_fail_under_public_level_deep_ready_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_public_level_deep_ready_state c ->
    E.level A x = 0 ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x Hdeep Hx.
  eapply inject_kt4_no_fail_under_public_level_ready_state; eauto.
  eapply kt4_public_level_deep_ready_state_ready_state. exact Hdeep.
Qed.

Corollary pop_kt4_no_fail_under_public_level_deep_ready_state :
  forall A (c : KChain A),
    kt4_public_level_deep_ready_state c ->
    kt4_nonempty_state c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c Hdeep Hnonempty.
  eapply pop_kt4_no_fail_under_public_level_ready_state; eauto.
  eapply kt4_public_level_deep_ready_state_ready_state. exact Hdeep.
Qed.

Corollary eject_kt4_no_fail_under_public_level_deep_ready_state :
  forall A (c : KChain A),
    kt4_public_level_deep_ready_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hdeep Hnonempty.
  eapply eject_kt4_no_fail_under_public_level_ready_state; eauto.
  eapply kt4_public_level_deep_ready_state_ready_state. exact Hdeep.
Qed.

Theorem push_kt4_preserves_public_level_deep_ready_state_ending :
  forall A (x : E.t A) (b : Buf5 (E.t A)) c',
    E.level A x = 0 ->
    kt4_public_level_deep_ready_state (KEnding b) ->
    push_kt4 x (KEnding b) = PushOk c' ->
    kt4_public_level_deep_ready_state c'.
Proof.
  intros A x b c' Hx [_ Hb] Hpush.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hpush. inversion Hpush; subst; clear Hpush.
    split; [discriminate|cbn; exact Hx].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha Hb].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn].
    repeat split; try exact I; try congruence.
    constructor; cbn; [repeat split; congruence|constructor|repeat split; congruence].
    constructor. exact I.
Qed.

Theorem inject_kt4_preserves_public_level_deep_ready_state_ending :
  forall A (b : Buf5 (E.t A)) (x : E.t A) c',
    E.level A x = 0 ->
    kt4_public_level_deep_ready_state (KEnding b) ->
    inject_kt4 (KEnding b) x = PushOk c' ->
    kt4_public_level_deep_ready_state c'.
Proof.
  intros A b x c' Hx [_ Hb] Hinject.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hinject. inversion Hinject; subst; clear Hinject.
    split; [discriminate|cbn; exact Hx].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha Hb].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn].
    repeat split; try exact I; try congruence.
    constructor; cbn; [repeat split; congruence|constructor|repeat split; congruence].
    constructor. exact I.
Qed.

Theorem pop_kt4_preserves_public_level_deep_ready_state_ending :
  forall A (b : Buf5 (E.t A)) x c',
    kt4_public_level_deep_ready_state (KEnding b) ->
    pop_kt4 (KEnding b) = PopOk x c' ->
    kt4_public_level_deep_ready_state c'.
Proof.
  intros A b x c' [_ Hb] Hpop.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hpop. discriminate.
  - cbn in Hpop. inversion Hpop; subst; clear Hpop.
    split; [discriminate|cbn; exact I].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ Hb].
    split; [discriminate|cbn; exact Hb].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn; repeat split; assumption].
Qed.

Theorem eject_kt4_preserves_public_level_deep_ready_state_ending :
  forall A (b : Buf5 (E.t A)) x c',
    kt4_public_level_deep_ready_state (KEnding b) ->
    eject_kt4 (KEnding b) = PopOk x c' ->
    kt4_public_level_deep_ready_state c'.
Proof.
  intros A b x c' [_ Hb] Heject.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Heject. discriminate.
  - cbn in Heject. inversion Heject; subst; clear Heject.
    split; [discriminate|cbn; exact I].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha _].
    split; [discriminate|cbn; exact Ha].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha [Hb _]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha [Hb [Hc _]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha [Hb [Hc [Hd _]]]].
    split; [discriminate|cbn; repeat split; assumption].
Qed.

Lemma yellow_wrap_pr_preserves_deep_ready_state_non_red_tail :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    kchain_top_color tail <> Red ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_deep_ready_state_at (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_deep_ready_at k i tail ->
    yellow_wrap_pr pre i suf tail = PushOk c' ->
    kchain_top_color c' <> Red /\ kt4_level_deep_ready_state_at k c'.
Proof.
  intros A k pre i suf tail c' Htop Hpre Hsuf Hpkt Htail Hctx Hyw.
  unfold yellow_wrap_pr in Hyw.
  destruct tail as [b|col p tail2].
  - inversion Hyw; subst; clear Hyw.
    split; [discriminate|cbn].
    repeat split; assumption.
  - destruct col; try (inversion Hyw; subst; clear Hyw;
      split; [discriminate|cbn]; repeat split; assumption).
    exfalso. apply Htop. reflexivity.
Qed.

Theorem push_kt4_preserves_public_level_deep_ready_state_green_non_red_tail :
  forall A (x : E.t A) pre i suf tail c',
    E.level A x = 0 ->
    kt4_public_level_deep_ready_state (KCons Green (PNode pre i suf) tail) ->
    kchain_top_color tail <> Red ->
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    kt4_public_level_deep_ready_state c'.
Proof.
  intros A x pre i suf tail c' Hx [_ Hstate] Htail_top Hpush.
  cbn in Hstate.
  destruct Hstate as [Hpre_shape [Hsuf_shape [Hpkt [Htail [_ Hctx]]]]].
  unfold push_kt4 in Hpush.
  destruct pre as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hpre_shape, Hpush; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha Hb].
    destruct (@yellow_wrap_pr_preserves_deep_ready_state_non_red_tail
        A 0 (B3 x a b) i suf tail c' Htail_top)
      as [Htop' Hdeep']; try exact Hpush.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn;
        [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx.
    + split; assumption.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb Hc]].
    destruct (@yellow_wrap_pr_preserves_deep_ready_state_non_red_tail
        A 0 (B4 x a b c0) i suf tail c' Htail_top)
      as [Htop' Hdeep']; try exact Hpush.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn;
        [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx.
    + split; assumption.
Qed.

