  cbn in Hstate.
  destruct Hstate as [Hpre_shape [Hsuf_shape [Hpkt [Htail [_ Hctx]]]]].
  unfold pop_kt4 in Hpop.
  destruct pre as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hpre_shape, Hpop; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha Hb].
    destruct (yellow_wrap_pr (B1 b) i suf tail) as [|c''] eqn:Hyw;
      [discriminate|].
    inversion Hpop; subst; clear Hpop.
    destruct (@yellow_wrap_pr_preserves_ready_state_non_red_tail
        A 0 (B1 b) i suf tail c' Htail_top)
      as [Htop' Hready']; try exact Hyw.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn; [exact Hb|assumption|assumption].
    + exact Htail.
    + exact Hctx.
    + split; assumption.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb Hc]].
    destruct (yellow_wrap_pr (B2 b c0) i suf tail) as [|c''] eqn:Hyw;
      [discriminate|].
    inversion Hpop; subst; clear Hpop.
    destruct (@yellow_wrap_pr_preserves_ready_state_non_red_tail
        A 0 (B2 b c0) i suf tail c' Htail_top)
      as [Htop' Hready']; try exact Hyw.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn; [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx.
    + split; assumption.
Qed.

