(* -------------------------------------------------------------------------- *)
(* Boundary check: [kt4_total_state] is a sufficient precondition bundle, not  *)
(* the final reachable-state invariant.  It intentionally records only the     *)
(* obligations needed to make the current public operation total.  A Green     *)
(* [B3] prefix can become a Yellow [B4] prefix after [push_kt4], and the new   *)
(* Yellow state then needs a future red-repair witness that the old Green      *)
(* state did not record.  Without level constraints, that future witness can   *)
(* fail.                                                                       *)
(* -------------------------------------------------------------------------- *)

Theorem kt4_total_state_not_push_closed :
  exists (x : E.t nat) (c c' : KChain nat),
    kt4_total_state c /\
    push_kt4 x c = PushOk c' /\
    ~ kt4_total_state c'.
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  exists z.
  exists (KCons Green (PNode (B3 z z p) Hole (B2 z z)) (KEnding B0)).
  exists (KCons Yellow (PNode (B4 z z z p) Hole (B2 z z)) (KEnding B0)).
  split.
  - cbn. repeat split.
  - split.
    + reflexivity.
    + intros Hstate.
      cbn in Hstate.
      destruct Hstate as [_ [_ [Hpush _]]].
      specialize (Hpush z).
      cbn in Hpush.
      destruct Hpush as [c_bad Hbad].
      cbn in Hbad.
      destruct (Nat.eq_dec (E.level nat z) (E.level nat p)) as [Heq|Hneq].
      * subst z p.
        cbn in Heq.
        discriminate.
      * discriminate.
Qed.

Theorem kt4_public_level_total_state_not_push_closed :
  exists (x : E.t nat) (c c' : KChain nat),
    E.level nat x = 0 /\
    kt4_public_level_total_state c /\
    push_kt4 x c = PushOk c' /\
    ~ kt4_public_level_total_state c'.
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (tail := KCons Yellow (PNode (B1 p) Hole (B2 p p)) (KEnding B0)).
  exists z.
  exists (KCons Green (PNode (B3 z z z) Hole (B2 z z)) tail).
  exists (KCons Yellow (PNode (B4 z z z z) Hole (B2 z z)) tail).
  split.
  - reflexivity.
  - split.
    + split; [discriminate|].
      cbn. repeat split.
      * constructor; cbn;
          [repeat split; try reflexivity|constructor|repeat split; try reflexivity].
      * cbn. repeat split; try exact I.
        -- constructor; cbn;
             [reflexivity|constructor|repeat split; try reflexivity].
      * eexists; reflexivity.
    + split.
      * reflexivity.
      * intros [_ Hstate].
        cbn in Hstate.
        destruct Hstate as [_ [_ [_ [_ [Hpush _]]]]].
        specialize (Hpush z eq_refl).
        destruct Hpush as [c_bad Hbad].
        cbn in Hbad.
        destruct (Nat.eq_dec (E.level nat z) (E.level nat z)) as [_|Hneq].
        -- discriminate.
        -- exfalso. apply Hneq. reflexivity.
Qed.

Theorem kt4_public_level_ready_state_not_push_closed :
  exists (x : E.t nat) (c c' : KChain nat),
    E.level nat x = 0 /\
    kt4_public_level_ready_state c /\
    push_kt4 x c = PushOk c' /\
    ~ kt4_public_level_ready_state c'.
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (child := PNode B0 Hole B0 : Packet nat).
  exists z.
  exists (KCons Yellow
            (PNode (B4 z z z z) (PNode (B1 p) child (B1 p)) (B1 z))
            (KEnding B0)).
  exists (KCons Green
            (PNode (B3 z z z) Hole (B3 z z z))
            (KCons Red (PNode (B2 p p) child B0) (KEnding B0))).
  split.
  - reflexivity.
  - split.
    + split; [discriminate|].
      cbn. repeat split; try reflexivity.
      * constructor; cbn.
        -- repeat split; try reflexivity.
        -- constructor; cbn.
           ++ reflexivity.
           ++ unfold child. constructor; cbn; [exact I|constructor|exact I].
           ++ reflexivity.
        -- reflexivity.
      * constructor; cbn.
        -- reflexivity.
        -- unfold child. constructor; cbn; [exact I|constructor|exact I].
        -- reflexivity.
    + split.
      * cbn.
        destruct (Nat.eq_dec (E.level nat z) (E.level nat z)) as [_|Hneq].
        -- unfold p. reflexivity.
        -- exfalso. apply Hneq. reflexivity.
      * intros [_ Hready].
        cbn in Hready.
        destruct Hready as [_ [_ [_ [Hred_tail _]]]].
        cbn in Hred_tail.
        destruct Hred_tail as [_ [_ Hctx_child]].
        cbn in Hctx_child.
        destruct Hctx_child as [Hbad _].
        exact Hbad.
Qed.

Theorem kt4_public_level_deep_ready_state_not_push_closed :
  exists (x : E.t nat) (c c' : KChain nat),
    E.level nat x = 0 /\
    kt4_public_level_deep_ready_state c /\
    push_kt4 x c = PushOk c' /\
    ~ kt4_public_level_deep_ready_state c'.
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  exists z.
  exists (KCons Yellow
            (PNode (B4 z z z z) (PNode (B1 p) Hole (B1 p)) (B1 z))
            (KEnding B0)).
  exists (KCons Green
            (PNode (B3 z z z) Hole (B3 z z z))
            (KCons Red (PNode (B2 p p) Hole B0) (KEnding B0))).
  split.
  - reflexivity.
  - split.
    + split; [discriminate|].
      cbn. repeat split; try reflexivity.
      * constructor; cbn.
        -- repeat split; try reflexivity.
        -- constructor; cbn.
           ++ reflexivity.
           ++ constructor.
           ++ reflexivity.
        -- reflexivity.
      * constructor; cbn.
        -- exact I.
        -- exact I.
        -- constructor; cbn; [reflexivity|constructor|reflexivity].
        -- constructor. exact I.
    + split.
      * cbn.
        destruct (Nat.eq_dec (E.level nat z) (E.level nat z)) as [_|Hneq].
        -- unfold p. reflexivity.
        -- exfalso. apply Hneq. reflexivity.
      * intros [_ Hdeep].
        cbn in Hdeep.
        destruct Hdeep as [_ [_ [_ [_ [_ Hctx]]]]].
        inversion Hctx; subst; cbn in *; contradiction.
Qed.

(* -------------------------------------------------------------------------- *)
(* Repair-aware ready-state candidate.                                         *)
(*                                                                            *)
(* [kt4_public_level_deep_ready_state_not_push_closed] shows that one context  *)
(* predicate is not quite precise enough: a Green top with [Hole] inner can    *)
(* carry a Red tail produced by Case 3 even when that Red tail's boundary      *)
(* buffers are not green-sized.  That state is still safe because the next     *)
(* Green operation repairs the Red tail directly.  Yellow/Red repair contexts  *)
(* remain stricter: if they form a Red packet with [Hole] inner, Case 2 still  *)
(* needs the following packet's boundaries to be green-sized.                  *)
(* -------------------------------------------------------------------------- *)

Inductive packet_context_repair_ready_at {A : Type}
    : nat -> Packet A -> KChain A -> Prop :=
| pcrr_hole_ending :
    forall k b,
      buf_all_at_level (S k) b ->
      packet_context_repair_ready_at k Hole (KEnding b)
| pcrr_hole_kcons :
    forall k col pre child suf tail,
      buf5_is_green_shape pre ->
      buf5_is_green_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_repair_ready_at (S k) child tail ->
      packet_context_repair_ready_at k Hole (KCons col (PNode pre child suf) tail)
| pcrr_pnode :
    forall k pre child suf tail,
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_repair_ready_at (S k) child tail ->
      packet_context_repair_ready_at k (PNode pre child suf) tail.

Inductive packet_context_green_ready_at {A : Type}
    : nat -> Packet A -> KChain A -> Prop :=
| pcgr_hole_ending :
    forall k b,
      buf_all_at_level (S k) b ->
      packet_context_green_ready_at k Hole (KEnding b)
| pcgr_hole_non_red_kcons :
    forall k col pre child suf tail,
      col <> Red ->
      buf5_is_green_shape pre ->
      buf5_is_green_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_repair_ready_at (S k) child tail ->
      packet_context_green_ready_at k Hole (KCons col (PNode pre child suf) tail)
| pcgr_hole_red_kcons :
    forall k pre child suf tail,
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_repair_ready_at (S k) child tail ->
      packet_context_green_ready_at k Hole (KCons Red (PNode pre child suf) tail)
| pcgr_pnode :
    forall k pre child suf tail,
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_repair_ready_at (S k) child tail ->
      packet_context_green_ready_at k (PNode pre child suf) tail.

Definition packet_context_wrap_ready_at {A : Type}
    (k : nat) (i : Packet A) (tail : KChain A) : Prop :=
  packet_context_green_ready_at k i tail /\
  forall c',
    green_of_red_k tail = Some c' ->
    packet_context_repair_ready_at k i c'.

Lemma packet_context_repair_ready_context_ready :
  forall A k (i : Packet A) (tail : KChain A),
    packet_context_repair_ready_at k i tail ->
    green_of_red_k_context_ready_at k i tail.
Proof.
  intros A k i tail Hctx.
  inversion Hctx; subst; cbn; repeat split; assumption.
Qed.

Lemma packet_context_green_ready_repair_ready_non_red_tail :
  forall A k (i : Packet A) (tail : KChain A),
    kchain_top_color tail <> Red ->
    packet_context_green_ready_at k i tail ->
    packet_context_repair_ready_at k i tail.
Proof.
  intros A k i tail Htop Hctx.
  inversion Hctx; subst.
  - constructor. assumption.
  - constructor; assumption.
  - exfalso. apply Htop. reflexivity.
  - constructor; assumption.
Qed.

Fixpoint kt4_level_repair_ready_state_at {A : Type} (k : nat) (c : KChain A)
    : Prop :=
  match c with
  | KEnding b => buf_all_at_level k b
  | KCons Green (PNode pre i suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_repair_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      yellow_wrap_pr_total_pre tail /\
      packet_context_green_ready_at k i tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_repair_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_repair_ready_at k i tail
  | KCons Red (PNode pre i suf) tail =>
      packet_levels k (PNode pre i suf) /\
      kt4_level_repair_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_repair_ready_at k i tail
  | _ => False
  end.

Definition kt4_public_level_repair_ready_state {A : Type} (c : KChain A)
    : Prop :=
  kchain_top_color c <> Red /\ kt4_level_repair_ready_state_at 0 c.

Theorem empty_kchain_kt4_public_level_repair_ready_state :
  forall A, kt4_public_level_repair_ready_state (@empty_kchain A).
Proof.
  intros A.
  unfold kt4_public_level_repair_ready_state, empty_kchain.
  split; [cbn; discriminate|cbn; exact I].
Qed.

Theorem kt4_level_repair_ready_state_total_state_at :
  forall A k (c : KChain A),
    kt4_level_repair_ready_state_at k c ->
    kt4_level_total_state_at k c.
Proof.
  intros A k c.
  revert k.
  induction c as [b|col p tail IH]; intros k Hready.
  - exact Hready.
  - destruct col; destruct p as [|pre i suf]; cbn in Hready |- *;
      try contradiction.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail [Hyw _]]]]].
      repeat split; try assumption.
      apply IH. exact Htail.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail Hctx]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * intros x Hx.
        destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_push_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_repair_ready_context_ready. exact Hctx.
      * intros x Hx.
        destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_inject_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_repair_ready_context_ready. exact Hctx.
      * destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_pop_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_repair_ready_context_ready. exact Hctx.
      * destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_eject_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_repair_ready_context_ready. exact Hctx.
    + destruct Hready as [Hpkt [Htail Hctx]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * change (exists c',
            green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c').
        eapply green_of_red_k_total_under_ready_levels; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_repair_ready_context_ready. exact Hctx.
Qed.

Theorem kt4_public_level_repair_ready_state_total_state :
  forall A (c : KChain A),
    kt4_public_level_repair_ready_state c ->
    kt4_public_level_total_state c.
Proof.
  intros A c [Htop Hready].
  split; [exact Htop|].
  eapply kt4_level_repair_ready_state_total_state_at. exact Hready.
Qed.

Corollary push_kt4_no_fail_under_public_level_repair_ready_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_public_level_repair_ready_state c ->
    E.level A x = 0 ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hready Hx.
  eapply push_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_repair_ready_state_total_state. exact Hready.
Qed.

Corollary inject_kt4_no_fail_under_public_level_repair_ready_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_public_level_repair_ready_state c ->
    E.level A x = 0 ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x Hready Hx.
  eapply inject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_repair_ready_state_total_state. exact Hready.
Qed.

Corollary pop_kt4_no_fail_under_public_level_repair_ready_state :
  forall A (c : KChain A),
    kt4_public_level_repair_ready_state c ->
    kt4_nonempty_state c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply pop_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_repair_ready_state_total_state. exact Hready.
Qed.

Corollary eject_kt4_no_fail_under_public_level_repair_ready_state :
  forall A (c : KChain A),
    kt4_public_level_repair_ready_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply eject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_repair_ready_state_total_state. exact Hready.
Qed.

Theorem kt4_public_level_repair_ready_state_not_push_closed :
  exists (x : E.t nat) (c c' : KChain nat),
    E.level nat x = 0 /\
    kt4_public_level_repair_ready_state c /\
    push_kt4 x c = PushOk c' /\
    ~ kt4_public_level_repair_ready_state c'.
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  set (red_tail :=
    KCons Red
      (PNode (B5 p p p p p) (PNode (B1 q) Hole (B1 q)) (B1 p))
      (KEnding B0)).
  exists z.
  exists (KCons Green (PNode (B2 z z) Hole (B2 z z)) red_tail).
  exists (KCons Yellow (PNode (B3 z z z) Hole (B2 z z))
    (KCons Green (PNode (B3 p p p) Hole (B3 p p p))
      (KCons Red (PNode (B2 q q) Hole B0) (KEnding B0)))).
  split.
  - reflexivity.
  - split.
    + split; [discriminate|].
      cbn. repeat split; try exact I; try reflexivity.
      * constructor; cbn;
          [repeat split; try reflexivity|constructor|repeat split; try reflexivity].
      * unfold red_tail. constructor; cbn.
        { repeat split; try reflexivity. }
        { constructor; cbn; [reflexivity|constructor|reflexivity]. }
        { reflexivity. }
      * cbn.
        constructor; cbn.
        { exact I. }
        { exact I. }
        { constructor; cbn; [reflexivity|constructor|reflexivity]. }
        { constructor. exact I. }
      * unfold yellow_wrap_pr_total_pre, red_tail. eexists.
        cbn.
        destruct (Nat.eq_dec (E.level nat p) (E.level nat p)) as [_|Hneq].
        { unfold q. reflexivity. }
        { exfalso. apply Hneq. reflexivity. }
      * unfold red_tail. eapply pcgr_hole_red_kcons; cbn.
        { constructor; cbn.
          - repeat split; try reflexivity.
          - constructor; cbn; [reflexivity|constructor|reflexivity].
          - reflexivity. }
        { constructor; cbn.
          - exact I.
          - exact I.
          - constructor; cbn; [reflexivity|constructor|reflexivity].
          - constructor. exact I. }
    + split.
      * unfold red_tail.
        cbn.
        destruct (Nat.eq_dec (E.level nat p) (E.level nat p)) as [_|Hneq].
        { unfold q. reflexivity. }
        { exfalso. apply Hneq. reflexivity. }
      * intros [_ Hready].
        cbn in Hready.
        destruct Hready as [_ [_ [_ [_ Hctx]]]].
        inversion Hctx; subst; clear Hctx.
        match goal with
        | H : packet_context_repair_ready_at _ Hole
                (KCons Red (PNode (B2 _ _) Hole B0) (KEnding B0)) |- _ =>
            inversion H; subst; cbn in *; contradiction
        end.
Qed.

Fixpoint kt4_level_wrap_ready_state_at {A : Type} (k : nat) (c : KChain A)
    : Prop :=
  match c with
  | KEnding b => buf_all_at_level k b
  | KCons Green (PNode pre i suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_wrap_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      yellow_wrap_pr_total_pre tail /\
      packet_context_wrap_ready_at k i tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_wrap_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_repair_ready_at k i tail
  | KCons Red (PNode pre i suf) tail =>
      packet_levels k (PNode pre i suf) /\
      kt4_level_wrap_ready_state_at (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_repair_ready_at k i tail
  | _ => False
  end.

Definition kt4_public_level_wrap_ready_state {A : Type} (c : KChain A)
    : Prop :=
  kchain_top_color c <> Red /\ kt4_level_wrap_ready_state_at 0 c.

Theorem empty_kchain_kt4_public_level_wrap_ready_state :
  forall A, kt4_public_level_wrap_ready_state (@empty_kchain A).
Proof.
  intros A.
  unfold kt4_public_level_wrap_ready_state, empty_kchain.
  split; [cbn; discriminate|cbn; exact I].
Qed.

Theorem kt4_level_wrap_ready_state_repair_ready_state_at :
  forall A k (c : KChain A),
    kt4_level_wrap_ready_state_at k c ->
    kt4_level_repair_ready_state_at k c.
Proof.
  intros A k c.
  revert k.
  induction c as [b|col p tail IH]; intros k Hwrap.
  - exact Hwrap.
  - destruct col; destruct p as [|pre i suf]; cbn in Hwrap |- *;
      try contradiction.
    + destruct Hwrap as [Hpre [Hsuf [Hpkt [Htail [Hyw [Hctx _]]]]]].
      repeat split; try assumption.
      apply IH. exact Htail.
    + destruct Hwrap as [Hpre [Hsuf [Hpkt [Htail Hctx]]]].
      repeat split; try assumption.
      apply IH. exact Htail.
    + destruct Hwrap as [Hpkt [Htail Hctx]].
      repeat split; try assumption.
      apply IH. exact Htail.
Qed.

Theorem kt4_public_level_wrap_ready_state_repair_ready_state :
  forall A (c : KChain A),
    kt4_public_level_wrap_ready_state c ->
    kt4_public_level_repair_ready_state c.
Proof.
  intros A c [Htop Hwrap].
  split; [exact Htop|].
  eapply kt4_level_wrap_ready_state_repair_ready_state_at. exact Hwrap.
Qed.

Corollary push_kt4_no_fail_under_public_level_wrap_ready_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_public_level_wrap_ready_state c ->
    E.level A x = 0 ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hwrap Hx.
  eapply push_kt4_no_fail_under_public_level_repair_ready_state; eauto.
  eapply kt4_public_level_wrap_ready_state_repair_ready_state. exact Hwrap.
Qed.

Corollary inject_kt4_no_fail_under_public_level_wrap_ready_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_public_level_wrap_ready_state c ->
    E.level A x = 0 ->
