Corollary eject_kt4_no_fail_under_public_level_wrap_ready_state :
  forall A (c : KChain A),
    kt4_public_level_wrap_ready_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hwrap Hnonempty.
  eapply eject_kt4_no_fail_under_public_level_repair_ready_state; eauto.
  eapply kt4_public_level_wrap_ready_state_repair_ready_state. exact Hwrap.
Qed.

Theorem kt4_public_level_wrap_ready_state_not_push_closed :
  exists (x : E.t nat) (c c' : KChain nat),
    E.level nat x = 0 /\
    kt4_public_level_wrap_ready_state c /\
    push_kt4 x c = PushOk c' /\
    ~ kt4_public_level_wrap_ready_state c'.
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  set (child := PNode (B1 q) Hole (B1 q) : Packet nat).
  set (red_tail :=
    KCons Red (PNode (B2 p p) child B0) (KEnding B0)).
  set (inner_after :=
    KCons Green (PNode (B2 p p) Hole (B2 p p))
      (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
  exists z.
  exists (KCons Yellow
            (PNode (B4 z z z z) (PNode (B1 p) child (B1 p)) (B1 z))
            (KEnding B0)).
  exists (KCons Green
            (PNode (B3 z z z) Hole (B3 z z z))
            red_tail).
  split.
  - reflexivity.
  - split.
    + split; [discriminate|].
      cbn. repeat split; try reflexivity.
      * constructor; cbn.
        -- repeat split; try reflexivity.
        -- constructor; cbn.
           ++ reflexivity.
           ++ unfold child. constructor; cbn.
              ** reflexivity.
              ** constructor.
              ** reflexivity.
           ++ reflexivity.
        -- reflexivity.
      * unfold child. constructor; cbn.
        -- exact I.
        -- exact I.
        -- constructor; cbn.
           ++ reflexivity.
           ++ constructor; cbn; [reflexivity|constructor|reflexivity].
           ++ reflexivity.
        -- constructor; cbn.
           ++ exact I.
           ++ exact I.
           ++ constructor; cbn; [reflexivity|constructor|reflexivity].
           ++ constructor. exact I.
    + split.
      * cbn.
        destruct (Nat.eq_dec (E.level nat z) (E.level nat z)) as [_|Hneq].
        -- unfold p, red_tail. reflexivity.
        -- exfalso. apply Hneq. reflexivity.
      * intros [_ Hwrap].
        cbn in Hwrap.
        destruct Hwrap as [_ [_ [_ [_ [_ Hctx_wrap]]]]].
        destruct Hctx_wrap as [_ Hafter].
        assert (Hinner :
          green_of_red_k red_tail = Some inner_after).
        { unfold red_tail, inner_after, child, q.
          reflexivity. }
        specialize (Hafter inner_after Hinner).
        unfold inner_after in Hafter.
        inversion Hafter; subst; clear Hafter.
        match goal with
        | H : packet_context_repair_ready_at _ Hole
                (KCons Red (PNode (B1 _) Hole B0) (KEnding B0)) |- _ =>
            inversion H; subst; cbn in *; contradiction
        end.
Qed.

(* -------------------------------------------------------------------------- *)
(* Recursive wrap-ready candidate.                                             *)
(*                                                                            *)
(* [kt4_public_level_wrap_ready_state_not_push_closed] shows that the          *)
(* post-repair context required after one Red-tail wrap must itself be closed  *)
(* for later repairs.  The mutually coinductive context predicates below       *)
(* record that future obligation directly: Case 1 [make_small] outputs can     *)
(* reintroduce the same "later repair" shape after a concat step.  The repair  *)
(* context is the strict Yellow/Red-facing mode; the Green context additionally*)
(* permits a Hole over a Red tail when repairing that Red tail yields a strict *)
(* repair context.  Continuations are restricted to the level-correct outer    *)
(* buffers supplied by the enclosing packet; arbitrary unlevelled buffers are  *)
(* not part of the operational repair surface.                                *)
(* -------------------------------------------------------------------------- *)

CoInductive packet_context_recursive_repair_ready_at {A : Type}
    : nat -> Packet A -> KChain A -> Prop :=
| pcrwr_hole_ending :
    forall k b,
      buf_all_at_level (S k) b ->
      packet_context_recursive_repair_ready_at k Hole (KEnding b)
| pcrwr_hole_kcons :
    forall k col pre child suf tail,
      buf5_is_green_shape pre ->
      buf5_is_green_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_recursive_green_ready_at (S k) child tail ->
      (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
          : Buf5 (E.t A)),
        buf_all_at_level k outer_pre ->
        buf_all_at_level k outer_suf ->
        green_prefix_concat outer_pre pre = Some (outer_pre', pre') ->
        green_suffix_concat suf outer_suf = Some (suf', outer_suf') ->
        packet_context_recursive_green_ready_at
          k (PNode pre' child suf') tail) ->
      packet_context_recursive_repair_ready_at
        k Hole (KCons col (PNode pre child suf) tail)
| pcrwr_pnode :
    forall k pre child suf tail,
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_recursive_green_ready_at (S k) child tail ->
      (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
          : Buf5 (E.t A)) c_inner,
        buf_all_at_level k outer_pre ->
        buf_all_at_level k outer_suf ->
        prefix_concat outer_pre pre = Some (outer_pre', pre') ->
        suffix_concat suf outer_suf = Some (suf', outer_suf') ->
        green_of_red_k (KCons Red (PNode pre' child suf') tail) =
          Some c_inner ->
        packet_context_recursive_repair_ready_at k Hole c_inner) ->
      packet_context_recursive_repair_ready_at
        k (PNode pre child suf) tail
with packet_context_recursive_green_ready_at {A : Type}
    : nat -> Packet A -> KChain A -> Prop :=
| pcgwr_repair :
    forall k i tail,
      packet_context_recursive_repair_ready_at k i tail ->
      packet_context_recursive_green_ready_at k i tail
| pcgwr_hole_red_kcons :
    forall k pre child suf tail,
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_recursive_green_ready_at (S k) child tail ->
      (forall c',
        green_of_red_k (KCons Red (PNode pre child suf) tail) = Some c' ->
        packet_context_recursive_repair_ready_at k Hole c') ->
      packet_context_recursive_green_ready_at
        k Hole (KCons Red (PNode pre child suf) tail).

Lemma packet_context_recursive_repair_ready_context_ready :
  forall A k (i : Packet A) (tail : KChain A),
    packet_context_recursive_repair_ready_at k i tail ->
    green_of_red_k_context_ready_at k i tail.
Proof.
  intros A k i tail Hctx.
  destruct Hctx; cbn; repeat split; assumption.
Qed.

Fixpoint kt4_level_recursive_wrap_ready_state_at {A : Type}
    (k : nat) (c : KChain A) : Prop :=
  match c with
  | KEnding b => buf_all_at_level k b
  | KCons Green (PNode pre i suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_recursive_wrap_ready_state_at
        (k + packet_depth (PNode pre i suf)) tail /\
      yellow_wrap_pr_total_pre tail /\
      packet_context_recursive_green_ready_at k i tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_recursive_wrap_ready_state_at
        (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_recursive_repair_ready_at k i tail
  | KCons Red (PNode pre i suf) tail =>
      packet_levels k (PNode pre i suf) /\
      kt4_level_recursive_wrap_ready_state_at
        (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_recursive_repair_ready_at k i tail
  | _ => False
  end.

Definition kt4_public_level_recursive_wrap_ready_state {A : Type}
    (c : KChain A) : Prop :=
  kchain_top_color c <> Red /\ kt4_level_recursive_wrap_ready_state_at 0 c.

Theorem empty_kchain_kt4_public_level_recursive_wrap_ready_state :
  forall A, kt4_public_level_recursive_wrap_ready_state (@empty_kchain A).
Proof.
  intros A.
  unfold kt4_public_level_recursive_wrap_ready_state, empty_kchain.
  split; [cbn; discriminate|cbn; exact I].
Qed.

Theorem kt4_level_recursive_wrap_ready_state_total_state_at :
  forall A k (c : KChain A),
    kt4_level_recursive_wrap_ready_state_at k c ->
    kt4_level_total_state_at k c.
Proof.
  intros A k c.
  revert k.
  induction c as [b|col p tail IH]; intros k Hready.
  - exact Hready.
  - destruct col; destruct p as [|pre i suf]; cbn in Hready |- *;
      try contradiction.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail [Hyw _]]]]].
      repeat split; try assumption.
      apply IH. exact Htail.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail Hctx]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * intros x Hx.
        destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_push_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_context_ready.
        exact Hctx.
      * intros x Hx.
        destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_inject_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_context_ready.
        exact Hctx.
      * destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_pop_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_context_ready.
        exact Hctx.
      * destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_eject_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_context_ready.
        exact Hctx.
    + destruct Hready as [Hpkt [Htail Hctx]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * change (exists c',
            green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c').
        eapply green_of_red_k_total_under_ready_levels; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_context_ready.
        exact Hctx.
Qed.

Theorem kt4_public_level_recursive_wrap_ready_state_total_state :
  forall A (c : KChain A),
    kt4_public_level_recursive_wrap_ready_state c ->
    kt4_public_level_total_state c.
Proof.
  intros A c [Htop Hready].
  split; [exact Htop|].
  eapply kt4_level_recursive_wrap_ready_state_total_state_at.
  exact Hready.
Qed.

Corollary push_kt4_no_fail_under_public_level_recursive_wrap_ready_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_public_level_recursive_wrap_ready_state c ->
    E.level A x = 0 ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hready Hx.
  eapply push_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_state_total_state.
  exact Hready.
Qed.

Corollary inject_kt4_no_fail_under_public_level_recursive_wrap_ready_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_public_level_recursive_wrap_ready_state c ->
    E.level A x = 0 ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x Hready Hx.
  eapply inject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_state_total_state.
  exact Hready.
Qed.

Corollary pop_kt4_no_fail_under_public_level_recursive_wrap_ready_state :
  forall A (c : KChain A),
    kt4_public_level_recursive_wrap_ready_state c ->
    kt4_nonempty_state c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply pop_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_state_total_state.
  exact Hready.
Qed.

Corollary eject_kt4_no_fail_under_public_level_recursive_wrap_ready_state :
  forall A (c : KChain A),
    kt4_public_level_recursive_wrap_ready_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply eject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_state_total_state.
  exact Hready.
Qed.

Theorem push_kt4_preserves_public_level_recursive_wrap_ready_state_ending :
  forall A (x : E.t A) (b : Buf5 (E.t A)) c',
    E.level A x = 0 ->
    kt4_public_level_recursive_wrap_ready_state (KEnding b) ->
    push_kt4 x (KEnding b) = PushOk c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A x b c' Hx [_ Hb] Hpush.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hpush. inversion Hpush; subst; clear Hpush.
    split; [discriminate|cbn; exact Hx].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha Hb].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn].
    repeat split; try exact I; try congruence.
    + constructor; cbn;
        [repeat split; congruence|constructor|repeat split; congruence].
    + constructor. constructor. exact I.
Qed.

Theorem inject_kt4_preserves_public_level_recursive_wrap_ready_state_ending :
  forall A (b : Buf5 (E.t A)) (x : E.t A) c',
    E.level A x = 0 ->
    kt4_public_level_recursive_wrap_ready_state (KEnding b) ->
    inject_kt4 (KEnding b) x = PushOk c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A b x c' Hx [_ Hb] Hinject.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hinject. inversion Hinject; subst; clear Hinject.
    split; [discriminate|cbn; exact Hx].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha Hb].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn].
    repeat split; try exact I; try congruence.
    + constructor; cbn;
        [repeat split; congruence|constructor|repeat split; congruence].
    + constructor. constructor. exact I.
Qed.

Theorem pop_kt4_preserves_public_level_recursive_wrap_ready_state_ending :
  forall A (b : Buf5 (E.t A)) x c',
    kt4_public_level_recursive_wrap_ready_state (KEnding b) ->
    pop_kt4 (KEnding b) = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A b x c' [_ Hb] Hpop.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hpop. discriminate.
  - cbn in Hpop. inversion Hpop; subst; clear Hpop.
    split; [discriminate|cbn; exact I].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ Hb].
    split; [discriminate|cbn; exact Hb].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn; repeat split; assumption].
Qed.

Theorem eject_kt4_preserves_public_level_recursive_wrap_ready_state_ending :
  forall A (b : Buf5 (E.t A)) x c',
    kt4_public_level_recursive_wrap_ready_state (KEnding b) ->
    eject_kt4 (KEnding b) = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A b x c' [_ Hb] Heject.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Heject. discriminate.
  - cbn in Heject. inversion Heject; subst; clear Heject.
    split; [discriminate|cbn; exact I].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha _].
    split; [discriminate|cbn; exact Ha].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha [Hb _]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha [Hb [Hc _]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Heject. inversion Heject; subst; clear Heject.
    destruct Hb as [Ha [Hb [Hc [Hd _]]]].
    split; [discriminate|cbn; repeat split; assumption].
Qed.

Lemma packet_context_recursive_green_ready_repair_ready_non_red_tail :
  forall A k (i : Packet A) (tail : KChain A),
    kchain_top_color tail <> Red ->
    packet_context_recursive_green_ready_at k i tail ->
    packet_context_recursive_repair_ready_at k i tail.
Proof.
  intros A k i tail Htop Hctx.
  inversion Hctx; subst.
  - assumption.
  - exfalso. apply Htop. reflexivity.
Qed.

Lemma kchain_top_color_chain_to_kchain_g_not_red :
  forall A (c : Chain A),
    kchain_top_color (chain_to_kchain_g c) <> Red.
Proof.
  intros A c.
  destruct c; cbn; discriminate.
Qed.

Definition kchain_top_color_chain_to_kchain_g_not_red_guarded :
  forall A (c : Chain A),
    kchain_top_color (chain_to_kchain_g c) <> Red.
Proof.
  intros A c.
  destruct c; cbn; discriminate.
Defined.

Lemma packet_context_recursive_green_ready_chain_to_kchain_g_repair_ready :
  forall A k (i : Packet A) (c : Chain A),
    packet_context_recursive_green_ready_at k i (chain_to_kchain_g c) ->
    packet_context_recursive_repair_ready_at k i (chain_to_kchain_g c).
Proof.
  intros A k i c Hctx.
  eapply packet_context_recursive_green_ready_repair_ready_non_red_tail.
  - apply kchain_top_color_chain_to_kchain_g_not_red.
  - exact Hctx.
Qed.

Definition packet_context_recursive_green_ready_chain_to_kchain_g_repair_ready_guarded :
  forall A k (i : Packet A) (c : Chain A),
    packet_context_recursive_green_ready_at k i (chain_to_kchain_g c) ->
    packet_context_recursive_repair_ready_at k i (chain_to_kchain_g c).
Proof.
  intros A k i c Hctx.
  eapply packet_context_recursive_green_ready_repair_ready_non_red_tail.
  - apply kchain_top_color_chain_to_kchain_g_not_red_guarded.
  - exact Hctx.
Defined.

Lemma yellow_wrap_pr_preserves_recursive_wrap_ready_state_non_red_tail :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    kchain_top_color tail <> Red ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_recursive_repair_ready_at k i tail ->
    yellow_wrap_pr pre i suf tail = PushOk c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre i suf tail c' Htop Hpre Hsuf Hpkt Htail Hctx Hyw.
  unfold yellow_wrap_pr in Hyw.
  destruct tail as [b|col p tail2].
  - inversion Hyw; subst; clear Hyw.
    split; [discriminate|cbn].
    repeat split; assumption.
  - destruct col; try (inversion Hyw; subst; clear Hyw;
      split; [discriminate|cbn]; repeat split; assumption).
    exfalso. apply Htop. reflexivity.
Qed.

Lemma yellow_wrap_pr_preserves_recursive_wrap_ready_state_wrap_tail :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt tail ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_recursive_green_ready_at k i tail ->
    (forall c'',
      green_of_red_k tail = Some c'' ->
      kt4_level_recursive_wrap_ready_state_at
        (k + packet_depth (PNode pre i suf)) c'') ->
    (forall c'',
      green_of_red_k tail = Some c'' ->
      packet_context_recursive_repair_ready_at k i c'') ->
    yellow_wrap_pr pre i suf tail = PushOk c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpre Hsuf Hpkt Htail Hctx_green
    Htail_after Hctx_after Hyw.
  unfold yellow_wrap_pr in Hyw.
  destruct tail as [b|col p tail2].
  - inversion Hyw; subst; clear Hyw.
    split; [discriminate|cbn].
    repeat split; try assumption.
    eapply packet_context_recursive_green_ready_repair_ready_non_red_tail;
      [cbn; discriminate|exact Hctx_green].
  - destruct col.
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_recursive_green_ready_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_recursive_green_ready_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + destruct (green_of_red_k (KCons Red p tail2)) as [c''|]
        eqn:Hred; [|discriminate].
      inversion Hyw; subst c'; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      * eapply Htail_after. reflexivity.
      * eapply Hctx_after. reflexivity.
Qed.

Theorem push_kt4_preserves_public_level_recursive_wrap_ready_state_green_non_red_tail :
  forall A (x : E.t A) pre i suf tail c',
    E.level A x = 0 ->
    kt4_public_level_recursive_wrap_ready_state
      (KCons Green (PNode pre i suf) tail) ->
    kchain_top_color tail <> Red ->
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A x pre i suf tail c' Hx [_ Hstate] Htail_top Hpush.
  cbn in Hstate.
  destruct Hstate as [Hpre_shape [Hsuf_shape [Hpkt [Htail [_ Hctx_green]]]]].
  pose proof (@packet_context_recursive_green_ready_repair_ready_non_red_tail
      A 0 i tail Htail_top Hctx_green) as Hctx.
  unfold push_kt4 in Hpush.
  destruct pre as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hpre_shape, Hpush; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha Hb].
    destruct (@yellow_wrap_pr_preserves_recursive_wrap_ready_state_non_red_tail
        A 0 (B3 x a b) i suf tail c' Htail_top)
      as [Htop' Hready']; try exact Hpush.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn;
        [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx.
    + split; assumption.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb Hc]].
    destruct (@yellow_wrap_pr_preserves_recursive_wrap_ready_state_non_red_tail
