    constructor; cbn; [exact Hb|assumption|assumption].
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb Hc]].
    inversion Hpop; subst; clear Hpop.
    split; [discriminate|cbn].
    repeat split; try exact I; try assumption.
    constructor; cbn; [repeat split; assumption|assumption|assumption].
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb [Hc Hd]]].
    inversion Hpop; subst; clear Hpop.
    split; [discriminate|cbn].
    repeat split; try exact I; try assumption.
    constructor; cbn; [repeat split; assumption|assumption|assumption].
Qed.

Theorem eject_kt4_preserves_public_level_recursive_wrap_ready_state_yellow_no_repair :
  forall (A : Type) (pre : Buf5 (E.t A)) i suf tail x c',
    kt4_public_level_recursive_wrap_ready_state
      (KCons Yellow (PNode pre i suf) tail) ->
    (match suf with B1 _ => False | _ => True end) ->
    eject_kt4 (KCons Yellow (PNode pre i suf) tail) = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A pre i suf tail x c' [_ Hstate] Hno_repair Heject.
  cbn in Hstate.
  destruct Hstate as [Hpre_shape [Hsuf_shape [Hpkt [Htail Hctx]]]].
  unfold eject_kt4 in Heject.
  destruct suf as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hsuf_shape, Hno_repair, Heject; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hsuf_levels. destruct Hsuf_levels as [Ha Hb].
    inversion Heject; subst; clear Heject.
    split; [discriminate|cbn].
    repeat split; try exact I; try assumption.
    constructor; cbn; [assumption|assumption|exact Ha].
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hsuf_levels. destruct Hsuf_levels as [Ha [Hb Hc]].
    inversion Heject; subst; clear Heject.
    split; [discriminate|cbn].
    repeat split; try exact I; try assumption.
    constructor; cbn; [assumption|assumption|repeat split; assumption].
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hsuf_levels. destruct Hsuf_levels as [Ha [Hb [Hc Hd]]].
    inversion Heject; subst; clear Heject.
    split; [discriminate|cbn].
    repeat split; try exact I; try assumption.
    constructor; cbn; [assumption|assumption|repeat split; assumption].
Qed.

Lemma green_of_red_k_case2_preserves_recursive_wrap_ready_state_regular :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) col tail c',
    regular_kt
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) ->
    packet_levels k (PNode pre1 Hole suf1) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre1 Hole suf1))
      (KCons col (PNode pre2 child suf2) tail) ->
    packet_context_recursive_repair_ready_at k Hole
      (KCons col (PNode pre2 child suf2) tail) ->
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) = Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child col tail c'
    Hreg Hpkt Htail_state Hctx Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hctx as
      [|? ? ? ? ? ? Hpre2_shape Hsuf2_shape Hinner Hctx_child Hctx_after|];
    subst.
  replace (k + packet_depth (PNode pre1 Hole suf1)) with (S k) in Htail_state
    by (cbn; lia).
  unfold green_of_red_k in Hred.
  destruct (green_prefix_concat pre1 pre2) as [[pre1' pre2']|]
    eqn:Hpre_concat; [|discriminate].
  destruct (green_suffix_concat suf2 suf1) as [[suf2' suf1']|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst c'; clear Hred.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k pre1 pre2 pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre2'_shape [Hpre1' Hpre2']]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k suf2 suf1 suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2'_shape [Hsuf1'_shape [Hsuf2' Hsuf1']]].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  apply regular_kt_red_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|exact Hinner'|assumption].
  - destruct col.
    + cbn in Htail_state.
      destruct Htail_state as [_ [_ [_ [Htail [Hyw _]]]]].
      split.
      * replace (k + S (S (packet_depth child)))
          with (S (k + S (packet_depth child))) by lia.
        exact Htail.
      * split.
	        -- exact Hyw.
	        -- exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1'
	              Hpre1 Hsuf1 Hpre_concat Hsuf_concat).
    + cbn in Htail_state.
      destruct Htail_state as [_ [_ [_ [Htail _]]]].
      apply regular_kt_yellow_inv in Htail_reg.
      destruct Htail_reg as [_ [Htail_non_red _]].
      split.
      * replace (k + S (S (packet_depth child)))
          with (S (k + S (packet_depth child))) by lia.
        exact Htail.
      * split.
        -- destruct tail as [b|tail_col tail_p tail_tail];
             cbn in Htail_non_red |- *; try exact I.
	           destruct tail_col; try exact I.
	           exfalso. apply Htail_non_red. reflexivity.
	        -- exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1'
	              Hpre1 Hsuf1 Hpre_concat Hsuf_concat).
    + exfalso. apply Htail_top. reflexivity.
Qed.

Lemma green_of_red_k_case2_output_context_ready :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) col tail c',
    packet_levels (S k) (PNode pre1 Hole suf1) ->
    packet_context_recursive_repair_ready_at (S k) Hole
      (KCons col (PNode pre2 child suf2) tail) ->
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) = Some c' ->
    green_of_red_k_context_ready_at k Hole c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child col tail c' Hpkt Hctx Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hctx as
      [|? ? ? ? ? ? Hpre2_shape Hsuf2_shape Hinner _ _|];
    subst.
  unfold green_of_red_k in Hred.
  destruct (green_prefix_concat pre1 pre2) as [[pre1' pre2']|]
    eqn:Hpre_concat; [|discriminate].
  destruct (green_suffix_concat suf2 suf1) as [[suf2' suf1']|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst c'; clear Hred.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A (S k) pre1 pre2 pre1' pre2'
      Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [_ [Hpre1' Hpre2']]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A (S k) suf2 suf1 suf2' suf1'
      Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [_ [Hsuf1'_shape [Hsuf2' Hsuf1']]].
  cbn. repeat split; try assumption.
  constructor; [exact Hpre1'|constructor; assumption|exact Hsuf1'].
Qed.

Lemma green_of_red_k_case3_output_context_ready :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) tail c',
