      A (S k) pre1 pre2 pre1' pre2'
      Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre1' _]].
  destruct (@suffix_concat_preserves_outer_green_levels
