Lemma green_of_red_k_output_context_ready_from_recursive_context :
  forall A k (pre suf : Buf5 (E.t A)) i tail c',
    packet_levels (S k) (PNode pre i suf) ->
    packet_context_recursive_repair_ready_at (S k) i tail ->
    green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c' ->
    green_of_red_k_context_ready_at k Hole c'.
Proof.
  intros A k pre suf i tail c' Hpkt Hctx Hred.
  destruct i as [|pre2 child suf2].
  - destruct tail as [b|col p tail2].
    + inversion Hctx; subst.
      eapply green_of_red_k_case1_output_context_ready; eauto.
    + destruct p as [|pre_tail child_tail suf_tail];
        [cbn in Hred; discriminate|].
      eapply green_of_red_k_case2_output_context_ready;
        [exact Hpkt|exact Hctx|exact Hred].
  - eapply green_of_red_k_case3_output_context_ready;
      [exact Hpkt|exact Hctx|exact Hred].
Qed.

Lemma green_of_red_k_case3_preserves_recursive_wrap_ready_state_under_child_repair_context :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail c' : KChain A),
    packet_levels k (PNode pre1 (PNode pre2 child suf2) suf1) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1)) tail ->
    packet_context_recursive_repair_ready_at k (PNode pre2 child suf2) tail ->
    packet_context_recursive_repair_ready_at (S k) child tail ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) = Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail c'
    Hpkt Htail Hctx Hchild_repair Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 Hinner Hsuf1]; subst.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  inversion Hctx as
      [| |? ? ? ? ? Hpre2_shape Hsuf2_shape _ Hctx_child Hctx_after];
    subst.
  unfold green_of_red_k in Hred.
  destruct (prefix_concat pre1 pre2) as [[pre1' pre2']|] eqn:Hpre_concat;
    [|discriminate].
  destruct (suffix_concat suf2 suf1) as [[suf2' suf1']|] eqn:Hsuf_concat;
    [|discriminate].
  inversion Hred; subst c'; clear Hred.
  destruct (@prefix_concat_preserves_outer_green_levels A k pre1 pre2
      pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre1' Hpre2']].
  destruct (@suffix_concat_preserves_outer_green_levels A k suf2 suf1
      suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2' [Hsuf1'_shape Hsuf1']].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|constructor|assumption].
  - split.
    + cbn.
      replace (k + 1) with (S k) by lia.
      split; [exact Hinner'|].
      split.
      * replace (S k + S (packet_depth child))
          with (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1))
          by (cbn; lia).
        exact Htail.
      * exact Hchild_repair.
    + split.
      * change (exists c'0,
          green_of_red_k (KCons Red (PNode pre2' child suf2') tail) =
            Some c'0).
        eapply green_of_red_k_total_under_ready_levels; [exact Hinner'|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_context_ready.
        exact Hchild_repair.
      * eapply pcgwr_hole_red_kcons.
        -- exact Hinner'.
	        -- exact Hctx_child.
	        -- intros c_inner Hred_inner.
	           exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1'
	             c_inner Hpre1 Hsuf1 Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma green_of_red_k_case3_preserves_recursive_wrap_ready_state_regular :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail c' : KChain A),
    regular_kt
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) ->
    packet_levels k (PNode pre1 (PNode pre2 child suf2) suf1) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1)) tail ->
    packet_context_recursive_repair_ready_at
      k (PNode pre2 child suf2) tail ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) =
        Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail c'
    Hreg Hpkt Htail Hctx Hred.
  pose proof Hreg as Hreg_inv.
  apply regular_kt_red_inv in Hreg_inv.
  destruct Hreg_inv as [_ [Htail_top _]].
  inversion Hctx as
      [| |? ? ? ? ? Hpre2_shape Hsuf2_shape _ Hctx_child Hctx_after];
    subst.
  assert (Hchild_repair :
    packet_context_recursive_repair_ready_at (S k) child tail).
  { eapply packet_context_recursive_green_ready_repair_ready_non_red_tail;
      eauto. }
  eapply green_of_red_k_case3_preserves_recursive_wrap_ready_state_under_child_repair_context;
    eauto.
Qed.

Lemma packet_context_recursive_repair_ready_hole_green_ending :
  forall A k (pre suf b : Buf5 (E.t A)),
    buf5_is_green_shape pre ->
    buf5_is_green_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    buf_all_at_level (S (S k)) b ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k) pre0 ->
      buf_all_at_level (S (S k)) b0 ->
      buf_all_at_level (S k) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_at k Hole
        (chain_to_kchain_g c0)) ->
    packet_context_recursive_repair_ready_at k Hole
      (KCons Green (PNode pre Hole suf) (KEnding b)).
Proof.
  intros A k pre suf b Hpre_shape Hsuf_shape Hpkt Hb Hcase1.
  inversion Hpkt as [|? ? ? ? Hpre_levels _ Hsuf_levels]; subst.
  eapply pcrwr_hole_kcons.
  - exact Hpre_shape.
  - exact Hsuf_shape.
  - exact Hpkt.
  - eapply pcgwr_repair. eapply pcrwr_hole_ending. exact Hb.
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_concat Hsuf_concat.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k outer_pre pre outer_pre' pre'
        Houter_pre Hpre_levels Hpre_shape Hpre_concat)
      as [_ [Hpre'_shape [_ Hpre'_levels]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k suf outer_suf suf' outer_suf'
        Hsuf_levels Houter_suf Hsuf_shape Hsuf_concat)
      as [Hsuf'_shape [_ [Hsuf'_levels _]]].
    eapply pcgwr_repair.
    eapply pcrwr_pnode.
    + exact Hpre'_shape.
    + exact Hsuf'_shape.
    + constructor; [exact Hpre'_levels|constructor|exact Hsuf'_levels].
    + eapply pcgwr_repair. eapply pcrwr_hole_ending. exact Hb.
    + intros outer_pre2 outer_suf2 outer_pre2' pre2' suf2' outer_suf2'
        c_inner Houter_pre2 Houter_suf2 Hpre_concat2 Hsuf_concat2 Hred.
      unfold green_of_red_k in Hred.
      destruct (make_small pre2' b suf2') as [c0|] eqn:Hmake;
        [|discriminate].
      inversion Hred; subst c_inner; clear Hred.
      eapply Hcase1; [|exact Hb| |exact Hmake].
      * destruct (@prefix_concat_preserves_outer_green_levels
            A k outer_pre2 pre' outer_pre2' pre2'
            Houter_pre2 Hpre'_levels Hpre'_shape Hpre_concat2)
          as [_ [_ Hpre2'_levels]].
        exact Hpre2'_levels.
      * destruct (@suffix_concat_preserves_outer_green_levels
            A k suf' outer_suf2 suf2' outer_suf2'
            Hsuf'_levels Houter_suf2 Hsuf'_shape Hsuf_concat2)
          as [Hsuf2'_levels [_ _]].
        exact Hsuf2'_levels.
Qed.

