      unfold green_of_red_k in Hred.
      destruct (make_small pre2' b suf2') as [c0|] eqn:Hmake;
        [|discriminate].
      inversion Hred; subst c_inner; clear Hred.
      eapply Hcase1; [|exact Hb| |exact Hmake].
      * destruct (@prefix_concat_preserves_outer_green_levels
            A k outer_pre2 pre' outer_pre2' pre2'
            Houter_pre2 Hpre'_levels Hpre'_shape Hpre_concat2)
          as [_ [_ Hpre2'_levels]].
        exact Hpre2'_levels.
      * destruct (@suffix_concat_preserves_outer_green_levels
            A k suf' outer_suf2 suf2' outer_suf2'
