Defined.

Lemma green_of_red_k_case1_empty_middle_underflow_recursive_context :
  forall A k (pre suf : Buf5 (E.t A)) c',
    buf_all_at_level (S k) pre ->
    buf_all_at_level (S k) suf ->
    (match prefix_decompose pre, suffix_decompose suf with
     | BD_pre_underflow _, BD_suf_underflow _ => True
     | _, _ => False
     end) ->
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding B0)) =
      Some c' ->
    packet_context_recursive_repair_ready_at k Hole c'.
Proof.
  intros A k pre suf c' Hpre Hsuf Hunder Hred.
  unfold green_of_red_k, make_small in Hred.
  destruct pre as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct suf as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn in Hpre, Hsuf, Hunder, Hred |- *;
    try contradiction; try discriminate;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    inversion Hred; subst; clear Hred;
    constructor; cbn; repeat split; assumption.
Qed.

Lemma green_of_red_k_case1_underflow_underflow_preserves_recursive_wrap_ready_state :
  forall A k (pre suf b : Buf5 (E.t A)) c',
    packet_levels k (PNode pre Hole suf) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre Hole suf)) (KEnding b) ->
    (match prefix_decompose pre, suffix_decompose suf with
     | BD_pre_underflow _, BD_suf_underflow _ => True
     | _, _ => False
     end) ->
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
      Some c' ->
