Lemma buffer_inject_chain_recursive_wrap_ready_state_and_context :
  forall A k (b : Buf5 (E.t A)) x,
    buf_all_at_level (S k) b ->
    E.level A x = S k ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k) pre0 ->
      buf_all_at_level (S (S k)) b0 ->
      buf_all_at_level (S k) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_at k Hole
        (chain_to_kchain_g c0)) ->
    kt4_level_recursive_wrap_ready_state_at (S k)
      (chain_to_kchain_g (buffer_inject_chain b x)) /\
    packet_context_recursive_green_ready_at k Hole
      (chain_to_kchain_g (buffer_inject_chain b x)).
Proof.
  intros A k b x Hb Hx Hcase1.
  destruct b.
  all: cbn in Hb |- *; repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end.
  all: try solve [
      split;
      [cbn; repeat split; try assumption
      |apply pcgwr_repair; apply pcrwr_hole_ending;
       cbn; repeat split; try assumption]].
  split.
  - cbn; repeat split; try assumption.
    + constructor; cbn; repeat split; try constructor; try assumption.
    + apply pcgwr_repair. apply pcrwr_hole_ending. exact I.
  - apply pcgwr_repair.
    eapply packet_context_recursive_repair_ready_hole_green_ending.
    + cbn. exact I.
    + cbn. exact I.
    + constructor; cbn; repeat split; try constructor; try assumption.
    + cbn. exact I.
    + exact Hcase1.
Qed.

