Lemma pair_each_buf_after_halve_preserves_levels :
  forall A k (b : Buf5 (E.t A)) mid rest_pairs rest,
    buf_all_at_level (S k) b ->
    buffer_halve b = (mid, rest_pairs) ->
    pair_each_buf rest_pairs = Some rest ->
    (match mid with
     | Some x => E.level A x = S k
     | None => True
     end) /\
    buf_all_at_level (S (S k)) rest.
Proof.
  intros A k b mid rest_pairs rest Hb Hhalve Hpair.
  destruct b;
    cbn in Hb, Hhalve; inversion Hhalve; subst mid rest_pairs; clear Hhalve;
    cbn in Hpair |- *;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    unfold pair_one in Hpair;
    repeat match goal with
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      end;
    inversion Hpair; subst rest; clear Hpair;
    cbn; repeat split; try assumption; try rewrite E.level_pair; lia.
Qed.

Lemma packet_context_recursive_green_ready_nested_case1_inner :
  forall A k (pre suf rest : Buf5 (E.t A)),
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    buf_all_at_level (S (S k)) rest ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k) pre0 ->
      buf_all_at_level (S (S k)) b0 ->
      buf_all_at_level (S k) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_at k Hole
        (chain_to_kchain_g c0)) ->
    packet_context_recursive_green_ready_at k (PNode pre Hole suf)
      (KEnding rest).
Proof.
  intros A k pre suf rest Hpre_shape Hsuf_shape Hpkt Hrest Hcase1.
  inversion Hpkt as [|? ? ? ? Hpre_levels _ Hsuf_levels]; subst.
  apply pcgwr_repair.
  eapply pcrwr_pnode.
  - exact Hpre_shape.
  - exact Hsuf_shape.
  - exact Hpkt.
  - apply pcgwr_repair. apply pcrwr_hole_ending. exact Hrest.
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred.
    unfold green_of_red_k in Hred.
    destruct (make_small pre' rest suf') as [c0|] eqn:Hmake;
      [|discriminate].
    inversion Hred; subst c_inner; clear Hred.
    eapply Hcase1; [|exact Hrest| |exact Hmake].
    + destruct (@prefix_concat_preserves_outer_green_levels
          A k outer_pre pre outer_pre' pre'
          Houter_pre Hpre_levels Hpre_shape Hpre_concat)
        as [_ [_ Hpre'_levels]].
      exact Hpre'_levels.
    + destruct (@suffix_concat_preserves_outer_green_levels
          A k suf outer_suf suf' outer_suf'
          Hsuf_levels Houter_suf Hsuf_shape Hsuf_concat)
        as [Hsuf'_levels [_ _]].
      exact Hsuf'_levels.
Qed.

