    eapply packet_context_recursive_repair_ready_hole_green_ending.
    - exact Hpre2_shape.
    - exact Hsuf2_shape.
    - exact Hpkt2.
    - exact Hb.
    - intros pre0 b0 suf0 c0 Hpre0 Hb0 Hsuf0 Hmake0.
      exact (Hcase1 (S k) pre0 b0 suf0 c0
        Hpre0 Hb0 Hsuf0 Hmake0). }
  eapply pcrwr_hole_kcons.
  - exact Hpre_shape.
  - exact Hsuf_shape.
  - exact Hpkt.
  - exact Hinner_green.
  - exact Hafter.
Qed.

