Lemma packet_context_recursive_repair_ready_hole_green_green_ending_outer_continuation_from_context :
  forall A k (pre suf pre2 suf2 b : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Green (PNode pre Hole suf)
        (KCons Green (PNode pre2 Hole suf2) (KEnding b))) ->
    forall outer_pre outer_suf outer_pre' pre' suf' outer_suf',
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre = Some (outer_pre', pre') ->
      green_suffix_concat suf outer_suf = Some (suf', outer_suf') ->
      packet_context_recursive_green_ready_at k (PNode pre' Hole suf')
        (KCons Green (PNode pre2 Hole suf2) (KEnding b)).
Proof.
  intros A k pre suf pre2 suf2 b Hctx
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_concat Hsuf_concat.
  inversion Hctx as
      [|? ? ? ? ? ? _ _ _ _ Hafter|];
    subst; clear Hctx.
  exact (Hafter outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_concat Hsuf_concat).
Qed.

Theorem packet_context_recursive_repair_ready_hole_green_green_ending_iff_outer_continuation :
  forall A k (pre suf pre2 suf2 b : Buf5 (E.t A)),
    buf5_is_green_shape pre ->
    buf5_is_green_shape suf ->
    buf5_is_green_shape pre2 ->
    buf5_is_green_shape suf2 ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_levels (S (S k)) (PNode pre2 Hole suf2) ->
    buf_all_at_level (S (S (S k))) b ->
    (forall k0 (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k0) pre0 ->
      buf_all_at_level (S (S k0)) b0 ->
      buf_all_at_level (S k0) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_at k0 Hole
        (chain_to_kchain_g c0)) ->
    (packet_context_recursive_repair_ready_at k Hole
      (KCons Green (PNode pre Hole suf)
        (KCons Green (PNode pre2 Hole suf2) (KEnding b))) <->
     (forall outer_pre outer_suf outer_pre' pre' suf' outer_suf',
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre = Some (outer_pre', pre') ->
      green_suffix_concat suf outer_suf = Some (suf', outer_suf') ->
      packet_context_recursive_green_ready_at k (PNode pre' Hole suf')
        (KCons Green (PNode pre2 Hole suf2) (KEnding b)))).
Proof.
  intros A k pre suf pre2 suf2 b Hpre_shape Hsuf_shape Hpre2_shape
    Hsuf2_shape Hpkt Hpkt2 Hb Hcase1.
  split.
  - eapply packet_context_recursive_repair_ready_hole_green_green_ending_outer_continuation_from_context.
  - intros Hafter.
    eapply packet_context_recursive_repair_ready_hole_green_green_ending_from_outer_continuation;
      eauto.
Qed.

Lemma packet_context_recursive_green_ready_hole_green_hole_ending_outer_continuation_from_pnode_strict_child_context :
  forall A,
    (forall k (pre suf child_pre : Buf5 (E.t A)) child child_suf tail,
      (forall k0 (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
        buf_all_at_level (S k0) pre0 ->
        buf_all_at_level (S (S k0)) b0 ->
        buf_all_at_level (S k0) suf0 ->
        make_small pre0 b0 suf0 = Some c0 ->
        packet_context_recursive_repair_ready_at k0 Hole
          (chain_to_kchain_g c0)) ->
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels
        (S k) (PNode pre (PNode child_pre child child_suf) suf) ->
      packet_context_recursive_green_ready_at
        (S k) (PNode child_pre child child_suf) tail ->
      packet_context_recursive_green_ready_at
        k (PNode pre (PNode child_pre child child_suf) suf) tail) ->
    forall k (pre suf pre2 suf2 b : Buf5 (E.t A)),
      buf5_is_green_shape pre ->
      buf5_is_green_shape suf ->
      buf5_is_green_shape pre2 ->
      buf5_is_green_shape suf2 ->
      packet_levels (S k) (PNode pre Hole suf) ->
      packet_levels (S (S k)) (PNode pre2 Hole suf2) ->
      buf_all_at_level (S (S (S k))) b ->
      (forall k0 (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
        buf_all_at_level (S k0) pre0 ->
        buf_all_at_level (S (S k0)) b0 ->
        buf_all_at_level (S k0) suf0 ->
        make_small pre0 b0 suf0 = Some c0 ->
        packet_context_recursive_repair_ready_at k0 Hole
          (chain_to_kchain_g c0)) ->
      forall outer_pre outer_suf outer_pre' pre' suf' outer_suf',
        buf_all_at_level k outer_pre ->
        buf_all_at_level k outer_suf ->
        green_prefix_concat outer_pre pre = Some (outer_pre', pre') ->
        green_suffix_concat suf outer_suf = Some (suf', outer_suf') ->
        packet_context_recursive_green_ready_at k (PNode pre' Hole suf')
          (KCons Green (PNode pre2 Hole suf2) (KEnding b)).
Proof.
  intros A Hpnode k pre suf pre2 suf2 b Hpre_shape Hsuf_shape
    Hpre2_shape Hsuf2_shape Hpkt Hpkt2 Hb Hcase1
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_concat Hsuf_concat.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  inversion Hpkt2 as [|? ? ? ? Hpre2_level _ Hsuf2_level]; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k outer_pre pre outer_pre' pre'
      Houter_pre Hpre_level Hpre_shape Hpre_concat)
    as [_ [Hpre'_shape [_ Hpre'_level]]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k suf outer_suf suf' outer_suf'
      Hsuf_level Houter_suf Hsuf_shape Hsuf_concat)
    as [Hsuf'_shape [_ [Hsuf'_level _]]].
  assert (Hinner_green :
    packet_context_recursive_green_ready_at (S k) Hole
      (KCons Green (PNode pre2 Hole suf2) (KEnding b))).
  { apply pcgwr_repair.
    eapply packet_context_recursive_repair_ready_hole_green_ending_guarded.
    - exact Hpre2_shape.
    - exact Hsuf2_shape.
    - exact Hpkt2.
    - exact Hb.
    - intros pre0 b0 suf0 c0 Hpre0 Hb0 Hsuf0 Hmake0.
      exact (Hcase1 (S k) pre0 b0 suf0 c0
        Hpre0 Hb0 Hsuf0 Hmake0). }
  apply pcgwr_repair.
  eapply pcrwr_pnode.
  - exact Hpre'_shape.
  - exact Hsuf'_shape.
  - constructor; [exact Hpre'_level|constructor|exact Hsuf'_level].
  - exact Hinner_green.
  - intros outer_pre2 outer_suf2 outer_pre2' pre_after
      suf_after outer_suf2' c_inner
      Houter_pre2 Houter_suf2 Hpre_concat2 Hsuf_concat2 Hred_inner.
    destruct (@prefix_concat_preserves_outer_green_levels
        A k outer_pre2 pre' outer_pre2' pre_after
        Houter_pre2 Hpre'_level Hpre'_shape Hpre_concat2)
      as [_ [_ Hpre_after_level]].
    destruct (@suffix_concat_preserves_outer_green_levels
        A k suf' outer_suf2 suf_after outer_suf2'
        Hsuf'_level Houter_suf2 Hsuf'_shape Hsuf_concat2)
      as [Hsuf_after_level _].
    unfold green_of_red_k in Hred_inner.
    destruct (green_prefix_concat pre_after pre2)
      as [[case2_pre_out pre2_after]|] eqn:Hcase2_pre;
      [|discriminate].
    destruct (green_suffix_concat suf2 suf_after)
      as [[suf2_after case2_suf_out]|] eqn:Hcase2_suf;
      [|discriminate].
    inversion Hred_inner; subst c_inner; clear Hred_inner.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A (S k) pre_after pre2 case2_pre_out pre2_after
        Hpre_after_level Hpre2_level Hpre2_shape Hcase2_pre)
      as [Hcase2_pre_shape [Hpre2_after_shape
          [Hcase2_pre_level Hpre2_after_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A (S k) suf2 suf_after suf2_after case2_suf_out
        Hsuf2_level Hsuf_after_level Hsuf2_shape Hcase2_suf)
      as [Hsuf2_after_shape [Hcase2_suf_shape
          [Hsuf2_after_level Hcase2_suf_level]]].
    assert (Hchild_pkt :
      packet_levels (S (S k)) (PNode pre2_after Hole suf2_after)).
    { constructor; [exact Hpre2_after_level|constructor|exact Hsuf2_after_level]. }
    assert (Hchild_ctx :
      packet_context_recursive_green_ready_at (S k)
        (PNode pre2_after Hole suf2_after) (KEnding b)).
    { eapply packet_context_recursive_green_ready_nested_case1_inner_guarded.
      - exact Hpre2_after_shape.
      - exact Hsuf2_after_shape.
      - exact Hchild_pkt.
      - exact Hb.
      - intros pre0 b0 suf0 c0 Hpre0 Hb0 Hsuf0 Hmake0.
        exact (Hcase1 (S k) pre0 b0 suf0 c0
          Hpre0 Hb0 Hsuf0 Hmake0). }
    eapply pcrwr_hole_kcons.
    + exact Hcase2_pre_shape.
    + exact Hcase2_suf_shape.
    + constructor; [exact Hcase2_pre_level|exact Hchild_pkt|exact Hcase2_suf_level].
    + exact Hchild_ctx.
    + intros future_pre future_suf future_pre' pre_out
        suf_out future_suf'
        Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
      destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
          A k future_pre case2_pre_out future_pre' pre_out
          Hfuture_pre Hcase2_pre_level Hcase2_pre_shape
          Hfuture_pre_concat)
        as [_ [Hpre_out_shape [_ Hpre_out_level]]].
      destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
          A k case2_suf_out future_suf suf_out future_suf'
          Hcase2_suf_level Hfuture_suf Hcase2_suf_shape
          Hfuture_suf_concat)
        as [Hsuf_out_shape [_ [Hsuf_out_level _]]].
      assert (Hparent_pkt :
        packet_levels (S k)
          (PNode pre_out (PNode pre2_after Hole suf2_after) suf_out)).
      { constructor; [exact Hpre_out_level|exact Hchild_pkt|exact Hsuf_out_level]. }
      exact (Hpnode k pre_out suf_out pre2_after Hole suf2_after
        (KEnding b) Hcase1 Hpre_out_shape Hsuf_out_shape
        Hparent_pkt Hchild_ctx).
Qed.

Lemma green_of_red_k_case1_outer_split_preserves_recursive_wrap_ready_state_when_case1_context :
  forall A k (pre suf b : Buf5 (E.t A)) c',
    packet_levels k (PNode pre Hole suf) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre Hole suf)) (KEnding b) ->
    (match prefix_decompose pre, suffix_decompose suf with
     | BD_pre_ok _, BD_suf_overflow _ _ _ => True
     | BD_pre_overflow _ _ _, BD_suf_ok _ => True
     | _, _ => False
     end) ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k) pre0 ->
      buf_all_at_level (S (S k)) b0 ->
      buf_all_at_level (S k) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_at k Hole
        (chain_to_kchain_g c0)) ->
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
      Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre suf b c' Hpkt Hb Hsplit Hcase1 Hred.
  inversion Hpkt as [|? ? ? ? Hpre _ Hsuf]; subst.
  replace (k + packet_depth (PNode pre Hole suf)) with (S k) in Hb
    by (cbn; lia).
  unfold green_of_red_k, make_small in Hred.
  destruct pre; destruct suf.
  all: cbn in Hpre, Hsuf, Hsplit, Hred |- *;
       try contradiction; try discriminate.
  all: repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end.
  all: repeat match goal with
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      end.
  all: inversion Hred; subst; clear Hred.
  all: split; [cbn; discriminate|].
  all: cbn -[E.pair]; repeat split; try assumption; try lia;
       try solve [constructor; cbn; repeat split; try constructor; try assumption; try rewrite E.level_pair; lia].
  all: try match goal with
      | |- kt4_level_recursive_wrap_ready_state_at (?k0 + 1)
            (chain_to_kchain_g (buffer_inject_chain ?b ?x)) =>
          replace (k0 + 1) with (S k0) by lia;
          destruct (@buffer_inject_chain_recursive_wrap_ready_state_and_context
              A k0 b x) as [Htail _];
          [exact Hb
          |try rewrite E.level_pair; lia
          |exact Hcase1
          |exact Htail]
      | |- kt4_level_recursive_wrap_ready_state_at (S ?k0)
            (chain_to_kchain_g (buffer_inject_chain ?b ?x)) =>
          destruct (@buffer_inject_chain_recursive_wrap_ready_state_and_context
              A k0 b x) as [Htail _];
          [exact Hb
          |try rewrite E.level_pair; lia
          |exact Hcase1
          |exact Htail]
      | |- packet_context_recursive_green_ready_at ?k0 Hole
            (chain_to_kchain_g (buffer_inject_chain ?b ?x)) =>
          destruct (@buffer_inject_chain_recursive_wrap_ready_state_and_context
              A k0 b x) as [_ Hctx];
          [exact Hb
          |try rewrite E.level_pair; lia
          |exact Hcase1
          |exact Hctx]
      | |- kt4_level_recursive_wrap_ready_state_at (?k0 + 1)
            (chain_to_kchain_g (buffer_push_chain ?x ?b)) =>
          replace (k0 + 1) with (S k0) by lia;
          destruct (@buffer_push_chain_recursive_wrap_ready_state_and_context
              A k0 x b) as [Htail _];
          [try rewrite E.level_pair; lia
          |exact Hb
          |exact Hcase1
          |exact Htail]
      | |- kt4_level_recursive_wrap_ready_state_at (S ?k0)
            (chain_to_kchain_g (buffer_push_chain ?x ?b)) =>
          destruct (@buffer_push_chain_recursive_wrap_ready_state_and_context
              A k0 x b) as [Htail _];
          [try rewrite E.level_pair; lia
          |exact Hb
          |exact Hcase1
          |exact Htail]
      | |- packet_context_recursive_green_ready_at ?k0 Hole
            (chain_to_kchain_g (buffer_push_chain ?x ?b)) =>
          destruct (@buffer_push_chain_recursive_wrap_ready_state_and_context
              A k0 x b) as [_ Hctx];
          [try rewrite E.level_pair; lia
          |exact Hb
          |exact Hcase1
          |exact Hctx]
      | |- yellow_wrap_pr_total_pre
            (chain_to_kchain_g (buffer_inject_chain ?b ?x)) =>
          destruct b; cbn; exact I
      | |- yellow_wrap_pr_total_pre
            (chain_to_kchain_g (buffer_push_chain ?x ?b)) =>
          destruct b; cbn; exact I
      end.
Qed.

Lemma green_of_red_k_case1_nested_overflow_preserves_recursive_wrap_ready_state_when_case1_context :
  forall A k (pre suf b : Buf5 (E.t A)) c',
    packet_levels k (PNode pre Hole suf) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre Hole suf)) (KEnding b) ->
    (match prefix_decompose pre, suffix_decompose suf with
     | BD_pre_overflow _ _ _, BD_suf_overflow _ _ _ => True
     | _, _ => False
     end) ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k) pre0 ->
      buf_all_at_level (S (S k)) b0 ->
      buf_all_at_level (S k) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_at k Hole
        (chain_to_kchain_g c0)) ->
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
      Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre suf b c' Hpkt Hb Hnested Hcase1 Hred.
  inversion Hpkt as [|? ? ? ? Hpre _ Hsuf]; subst.
  replace (k + packet_depth (PNode pre Hole suf)) with (S k) in Hb
    by (cbn; lia).
  unfold green_of_red_k, make_small in Hred.
  destruct pre; destruct suf.
  all: cbn -[E.pair] in Hpre, Hsuf, Hnested, Hred |- *;
       try contradiction; try discriminate.
  all: repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end.
  all: repeat match goal with
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      end.
  all: destruct (buffer_halve b) as [mid rest_pairs] eqn:Hhalve.
  all: destruct (pair_each_buf rest_pairs) as [rest|] eqn:Hpair;
       try discriminate.
  all: destruct (@pair_each_buf_after_halve_preserves_levels
        A k b mid rest_pairs rest Hb Hhalve Hpair) as [Hmid Hrest].
  all: cbn in Hmid.
  all: destruct mid as [mid_elt|]; cbn in Hmid.
  all: inversion Hred; subst; clear Hred.
  all: split; [cbn; discriminate|].
  all: try match goal with
      | |- buf_all_at_level (?k0 + 2) _ =>
          replace (k0 + 2) with (S (S k0)) by lia
      end.
  all: cbn -[E.pair]; repeat split; try assumption; try lia;
       try match goal with
       | H : buf_all_at_level (S (S ?k0)) ?rest
         |- buf_all_at_level (?k0 + 2) ?rest =>
           replace (k0 + 2) with (S (S k0)) by lia; exact H
       end.
  all: try solve [
      repeat constructor; cbn; repeat split; try assumption;
      try rewrite E.level_pair in *; try lia].
  all: try solve [
      eapply packet_context_recursive_green_ready_nested_case1_inner;
      [cbn; exact I
      |cbn; exact I
      |repeat constructor; cbn; repeat split; try assumption;
       try rewrite E.level_pair in *; try lia
      |exact Hrest
      |exact Hcase1]].
Qed.

Theorem packet_context_recursive_repair_ready_hole_green_nested_ending_boundary_gap :
  ~ packet_context_recursive_repair_ready_at 0 Hole
      (let z := E.base nat 0 in
       let p := E.pair nat z z eq_refl in
       let q := E.pair nat p p eq_refl in
       KCons Green
         (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
         (KEnding B0)).
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (~ packet_context_recursive_repair_ready_at 0 Hole
      (KCons Green
        (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
        (KEnding B0))).
  intros Hctx.
  inversion Hctx; subst; clear Hctx; cbn in *; try contradiction.
  match goal with
  | Hchild : packet_context_recursive_green_ready_at _
      (PNode (B1 q) Hole B0) (KEnding B0) |- _ =>
      inversion Hchild; subst; clear Hchild; cbn in *; try contradiction;
      match goal with
      | Hrepair : packet_context_recursive_repair_ready_at _
          (PNode (B1 q) Hole B0) (KEnding B0) |- _ =>
          inversion Hrepair; subst; cbn in *; contradiction
      end
  end.
Qed.

Theorem packet_context_recursive_repair_ready_hole_green_red_tail_boundary_gap :
  ~ packet_context_recursive_repair_ready_at 0 Hole
      (let z := E.base nat 0 in
       let p := E.pair nat z z eq_refl in
       let q := E.pair nat p p eq_refl in
       KCons Green (PNode (B2 p p) Hole (B2 p p))
        (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (~ packet_context_recursive_repair_ready_at 0 Hole
      (KCons Green (PNode (B2 p p) Hole (B2 p p))
        (KCons Red (PNode (B1 q) Hole B0) (KEnding B0)))).
  intros Hctx.
  inversion Hctx; subst; clear Hctx; cbn in *; try contradiction.
  assert (Hgreen :
    packet_context_recursive_green_ready_at 0 (PNode (B1 p) Hole (B1 p))
      (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
  { apply (H9 B0 B0 (B2 z z) (B1 p) (B1 p) (B2 z z));
      cbn; repeat split; try reflexivity. }
  inversion Hgreen; subst; clear Hgreen.
  inversion H; subst; clear H; cbn in *; try contradiction.
  assert (Hbad :
    packet_context_recursive_repair_ready_at 0 Hole
      (KCons Green (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
         (KEnding B0))).
  { apply (H14 (B4 z z z z) (B4 z z z z)
      (B2 z z) (B2 p p) (B2 p p) (B2 z z)
      (KCons Green (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
         (KEnding B0)));
      cbn; repeat split; try reflexivity. }
  eapply packet_context_recursive_repair_ready_hole_green_nested_ending_boundary_gap.
  exact Hbad.
Qed.

Theorem packet_context_recursive_green_ready_pnode_red_tail_boundary_gap :
  ~ (let z := E.base nat 0 in
     let p := E.pair nat z z eq_refl in
     let q := E.pair nat p p eq_refl in
     packet_context_recursive_green_ready_at 0
       (PNode (B1 p) Hole (B1 p))
       (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (~ packet_context_recursive_green_ready_at 0
      (PNode (B1 p) Hole (B1 p))
      (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
  intros Hgreen.
  inversion Hgreen; subst; clear Hgreen.
  inversion H; subst; clear H; cbn in *; try contradiction.
  assert (Hbad :
    packet_context_recursive_repair_ready_at 0 Hole
      (KCons Green (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
         (KEnding B0))).
  { match goal with
    | Hafter :
        forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
          : Buf5 (E.t nat)) (c_inner : KChain nat), _ |- _ =>
        apply (Hafter (B4 z z z z) (B4 z z z z)
          (B2 z z) (B2 p p) (B2 p p) (B2 z z)
          (KCons Green
             (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
             (KEnding B0)));
        cbn; repeat split; try reflexivity
    end. }
  eapply packet_context_recursive_repair_ready_hole_green_nested_ending_boundary_gap.
  exact Hbad.
Qed.

Theorem packet_context_recursive_green_ready_pnode_red_tail_boundary_b1_b2_gap :
  ~ (let z := E.base nat 0 in
     let p := E.pair nat z z eq_refl in
     let q := E.pair nat p p eq_refl in
     packet_context_recursive_green_ready_at 0
       (PNode (B1 p) Hole (B2 p p))
       (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (~ packet_context_recursive_green_ready_at 0
      (PNode (B1 p) Hole (B2 p p))
      (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
  intros Hgreen.
  inversion Hgreen; subst; clear Hgreen.
  inversion H; subst; clear H; cbn in *; try contradiction.
  assert (Hbad :
    packet_context_recursive_repair_ready_at 0 Hole
      (KCons Green (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
         (KEnding B0))).
  { match goal with
    | Hafter :
        forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
          : Buf5 (E.t nat)) (c_inner : KChain nat), _ |- _ =>
        apply (Hafter (B4 z z z z) (B2 z z)
          (B2 z z) (B2 p p) (B2 p p) (B2 z z)
          (KCons Green
             (PNode (B2 p p) (PNode (B1 q) Hole B0) (B2 p p))
             (KEnding B0)));
