Theorem packet_context_recursive_repair_ready_hole_green_nested_reachable_ending_boundary_gap :
  ~ packet_context_recursive_repair_ready_at 0 Hole
      (let z := E.base nat 0 in
       let p := E.pair nat z z eq_refl in
       let q := E.pair nat p p eq_refl in
       KCons Green
         (PNode (B2 p p) (PNode (B1 q) Hole (B1 q)) (B2 p p))
         (KEnding B0)).
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (~ packet_context_recursive_repair_ready_at 0 Hole
      (KCons Green
        (PNode (B2 p p) (PNode (B1 q) Hole (B1 q)) (B2 p p))
        (KEnding B0))).
  intros Hctx.
  inversion Hctx; subst; clear Hctx; cbn in *; try contradiction.
  assert (Hgreen :
    packet_context_recursive_green_ready_at 0
      (PNode (B2 p p) (PNode (B1 q) Hole (B1 q)) (B2 p p))
      (KEnding B0)).
  { apply (H9 (B2 z z) (B2 z z)
      (B2 z z) (B2 p p) (B2 p p) (B2 z z));
      cbn; repeat split; reflexivity. }
  inversion Hgreen; subst; clear Hgreen.
  inversion H; subst; clear H; cbn in *; try contradiction.
  pose proof (H14 (B2 z z) B0
    (B2 z z) (B2 p p) (B1 p) (B2 z z)
    (KCons Green (PNode (B2 p p) Hole (B3 p p p))
       (KCons Red (PNode (B1 q) Hole B0) (KEnding B0)))
    ltac:(cbn; repeat split; reflexivity)
    ltac:(cbn; exact I)
    ltac:(cbn; reflexivity)
    ltac:(cbn; reflexivity)
    ltac:(cbn; reflexivity)) as Hrepair.
  inversion Hrepair; subst; clear Hrepair; cbn in *; try contradiction.
  assert (Hbad_green :
    packet_context_recursive_green_ready_at 0
      (PNode (B1 p) Hole (B2 p p))
      (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
  { match goal with
    | Hcont :
        forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
          : Buf5 (E.t nat)), _ |- _ =>
        exact (Hcont B0 B0 (B2 z z) (B1 p) (B2 p p) (B2 z z)
          ltac:(cbn; exact I)
          ltac:(cbn; exact I)
          ltac:(cbn; reflexivity)
          ltac:(cbn; reflexivity))
    end. }
  eapply packet_context_recursive_green_ready_pnode_red_tail_boundary_b1_b2_gap.
  exact Hbad_green.
Qed.

Definition buf5_is_not_red_or_empty_shape {X : Type} (b : Buf5 X) : Prop :=
  match b with
  | B0 | B1 _ | B2 _ _ | B3 _ _ _ | B4 _ _ _ _ => True
  | _ => False
  end.

Lemma green_prefix_concat_preserves_not_red_or_empty_inner_shape :
  forall A (b1 b2 b1' b2' : Buf5 (E.t A)),
    buf5_is_not_red_or_empty_shape b2 ->
    green_prefix_concat b1 b2 = Some (b1', b2') ->
    buf5_is_not_red_or_empty_shape b2'.
Proof.
  intros A b1 b2 b1' b2' Hshape Hconcat.
  unfold green_prefix_concat in Hconcat.
  destruct b1 as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b2 as [|q1|q1 q2|q1 q2 q3|q1 q2 q3 q4|q1 q2 q3 q4 q5];
    cbn in Hshape, Hconcat |- *; try contradiction; try discriminate;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          destruct (E.unpair A e) as [[u v]|] eqn:?; try discriminate
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [green_push ?x ?b] |- _ =>
          destruct (green_push x b) eqn:?; try discriminate
      | H : context [green_pop ?b] |- _ =>
          destruct (green_pop b) as [[u v]|] eqn:?; try discriminate
      end;
    inversion Hconcat; subst; cbn; exact I.
Qed.

Lemma green_suffix_concat_preserves_not_red_or_empty_inner_shape :
  forall A (b1 b2 b1' b2' : Buf5 (E.t A)),
    buf5_is_not_red_or_empty_shape b1 ->
    green_suffix_concat b1 b2 = Some (b1', b2') ->
    buf5_is_not_red_or_empty_shape b1'.
Proof.
  intros A b1 b2 b1' b2' Hshape Hconcat.
  unfold green_suffix_concat in Hconcat.
  destruct b1 as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b2 as [|q1|q1 q2|q1 q2 q3|q1 q2 q3 q4|q1 q2 q3 q4 q5];
    cbn in Hshape, Hconcat |- *; try contradiction; try discriminate;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          destruct (E.unpair A e) as [[u v]|] eqn:?; try discriminate
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [green_inject ?b ?x] |- _ =>
          destruct (green_inject b x) eqn:?; try discriminate
      | H : context [green_eject ?b] |- _ =>
          destruct (green_eject b) as [[u v]|] eqn:?; try discriminate
      end;
    inversion Hconcat; subst; cbn; exact I.
Qed.

Theorem prefix_concat_not_red_or_empty_inner_shape_gap :
  ~ (forall A (b1 b2 b1' b2' : Buf5 (E.t A)),
      buf5_is_not_red_or_empty_shape b2 ->
      prefix_concat b1 b2 = Some (b1', b2') ->
      buf5_is_not_red_or_empty_shape b2').
Proof.
  intros Hpreserve.
  set (z := E.base unit tt).
  pose proof (Hpreserve unit
      (B4 z z z z) (B4 z z z z)
      (B2 z z) (B5 (E.pair unit z z eq_refl) z z z z)
      ltac:(cbn; exact I)
      ltac:(unfold prefix_concat, z; cbn; reflexivity)) as Hbad.
  cbn in Hbad.
  exact Hbad.
Qed.

Theorem suffix_concat_not_red_or_empty_inner_shape_gap :
  ~ (forall A (b1 b2 b1' b2' : Buf5 (E.t A)),
      buf5_is_not_red_or_empty_shape b1 ->
      suffix_concat b1 b2 = Some (b1', b2') ->
      buf5_is_not_red_or_empty_shape b1').
Proof.
  intros Hpreserve.
  set (z := E.base unit tt).
  pose proof (Hpreserve unit
      (B4 z z z z) (B4 z z z z)
      (B5 z z z z (E.pair unit z z eq_refl)) (B2 z z)
      ltac:(cbn; exact I)
      ltac:(unfold suffix_concat, z; cbn; reflexivity)) as Hbad.
  cbn in Hbad.
  exact Hbad.
Qed.

Lemma green_of_red_k_case2_preserves_not_red_or_empty_inner_shapes :
  forall A (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) child2
         (suf2 : Buf5 (E.t A)) tail
         pre1' pre2' suf2' suf1',
    buf5_is_not_red_or_empty_shape pre2 ->
    buf5_is_not_red_or_empty_shape suf2 ->
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) =
      Some (KCons Green (PNode pre1' (PNode pre2' child2 suf2') suf1')
        tail) ->
    buf5_is_not_red_or_empty_shape pre2' /\
    buf5_is_not_red_or_empty_shape suf2'.
Proof.
  intros A pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hpre2 Hsuf2 Hred.
  unfold green_of_red_k in Hred.
  destruct (green_prefix_concat pre1 pre2) as [[pre1_o pre2_o]|]
    eqn:Hpre_concat; [|discriminate].
  destruct (green_suffix_concat suf2 suf1) as [[suf2_o suf1_o]|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst; clear Hred.
  split.
  - exact (@green_prefix_concat_preserves_not_red_or_empty_inner_shape
      A pre1 pre2 pre1' pre2' Hpre2 Hpre_concat).
  - exact (@green_suffix_concat_preserves_not_red_or_empty_inner_shape
      A suf2 suf1 suf2' suf1' Hsuf2 Hsuf_concat).
Qed.

Theorem green_of_red_k_case3_not_red_or_empty_inner_shapes_gap :
  ~ (forall A (pre1 pre2 : Buf5 (E.t A)) child2
          (suf2 suf1 : Buf5 (E.t A)) tail
          pre1' pre2' suf2' suf1',
      buf5_is_not_red_or_empty_shape pre2 ->
      buf5_is_not_red_or_empty_shape suf2 ->
      green_of_red_k
        (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail) =
        Some (KCons Green (PNode pre1' Hole suf1')
          (KCons Red (PNode pre2' child2 suf2') tail)) ->
      buf5_is_not_red_or_empty_shape pre2' /\
      buf5_is_not_red_or_empty_shape suf2').
Proof.
  intros Hpreserve.
  set (z := E.base unit tt).
  destruct (Hpreserve unit
      (B4 z z z z) (B4 z z z z) Hole (B2 z z) (B2 z z)
      (KEnding B0)
      (B2 z z) (B5 (E.pair unit z z eq_refl) z z z z)
      (B2 z z) (B2 z z)
      ltac:(cbn; exact I)
      ltac:(cbn; exact I)
      ltac:(unfold green_of_red_k, prefix_concat, suffix_concat, z;
        cbn; reflexivity))
    as [Hbad _].
  cbn in Hbad.
  exact Hbad.
Qed.

Lemma green_of_red_k_case3_preserves_green_inner_shapes_under_boundary_compatibility :
  forall A (pre1 pre2 : Buf5 (E.t A)) child2
         (suf2 suf1 : Buf5 (E.t A)) tail
         pre1' pre2' suf2' suf1',
    prefix_concat_inner_green_compatible pre1 pre2 ->
    suffix_concat_inner_green_compatible suf2 suf1 ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail) =
      Some (KCons Green (PNode pre1' Hole suf1')
        (KCons Red (PNode pre2' child2 suf2') tail)) ->
    buf5_is_green_shape pre2' /\ buf5_is_green_shape suf2'.
Proof.
  intros A pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hpre_compat Hsuf_compat Hred.
  unfold green_of_red_k in Hred.
  destruct (prefix_concat pre1 pre2) as [[pre1_o pre2_o]|]
    eqn:Hpre_concat; [|discriminate].
  destruct (suffix_concat suf2 suf1) as [[suf2_o suf1_o]|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst; clear Hred.
  split.
  - eapply prefix_concat_inner_green_shape_from_compatible; eauto.
  - eapply suffix_concat_inner_green_shape_from_compatible; eauto.
Qed.

CoInductive packet_context_recursive_green_ready_refined_at {A : Type}
    : nat -> Packet A -> KChain A -> Prop :=
| pcgrr_existing :
    forall k i tail,
      packet_context_recursive_green_ready_at k i tail ->
      packet_context_recursive_green_ready_refined_at k i tail
| pcgrr_repair_refined_non_red_tail :
    forall k i tail,
      kchain_top_color tail <> Red ->
      packet_context_recursive_repair_ready_refined_at k i tail ->
      packet_context_recursive_green_ready_refined_at k i tail
| pcgrr_pnode_bottom_red_tail_empty_boundary :
    forall k pre suf red_pre red_suf b,
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      buf5_is_not_red_or_empty_shape red_pre ->
      buf5_is_not_red_or_empty_shape red_suf ->
      (red_pre = B0 \/ red_suf = B0) ->
      packet_levels (S k) (PNode pre Hole suf) ->
      packet_levels (S (S k)) (PNode red_pre Hole red_suf) ->
      buf_all_at_level (S (S (S k))) b ->
      packet_context_recursive_green_ready_refined_at k
        (PNode pre Hole suf)
        (KCons Red (PNode red_pre Hole red_suf) (KEnding b))
| pcgrr_pnode_red_tail_refined :
    forall k pre child suf red_pre red_child red_suf tail,
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_recursive_green_ready_refined_at (S k) child
        (KCons Red (PNode red_pre red_child red_suf) tail) ->
      (forall c_tail,
        green_of_red_k (KCons Red (PNode red_pre red_child red_suf) tail) =
          Some c_tail ->
        packet_context_recursive_repair_ready_refined_at
          k (PNode pre child suf) c_tail) ->
      packet_context_recursive_green_ready_refined_at k
        (PNode pre child suf)
        (KCons Red (PNode red_pre red_child red_suf) tail)
| pcgrr_hole_red_kcons_refined :
    forall k pre child suf tail,
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_recursive_green_ready_refined_at (S k) child tail ->
      (forall c',
        green_of_red_k (KCons Red (PNode pre child suf) tail) =
          Some c' ->
        packet_context_recursive_repair_ready_refined_at k Hole c') ->
      packet_context_recursive_green_ready_refined_at
        k Hole (KCons Red (PNode pre child suf) tail)
with packet_context_recursive_repair_ready_refined_at {A : Type}
    : nat -> Packet A -> KChain A -> Prop :=
| pcrrr_existing :
    forall k i tail,
      packet_context_recursive_repair_ready_at k i tail ->
      packet_context_recursive_repair_ready_refined_at k i tail
| pcrrr_hole_kcons :
    forall k col pre child suf tail,
      buf5_is_green_shape pre ->
      buf5_is_green_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_recursive_green_ready_refined_at (S k) child tail ->
      (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
          : Buf5 (E.t A)),
        buf_all_at_level k outer_pre ->
        buf_all_at_level k outer_suf ->
        green_prefix_concat outer_pre pre = Some (outer_pre', pre') ->
        green_suffix_concat suf outer_suf = Some (suf', outer_suf') ->
        packet_context_recursive_green_ready_refined_at
          k (PNode pre' child suf') tail) ->
      packet_context_recursive_repair_ready_refined_at
        k Hole (KCons col (PNode pre child suf) tail)
| pcrrr_pnode :
    forall k pre child suf tail,
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre child suf) ->
      packet_context_recursive_green_ready_refined_at (S k) child tail ->
      (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
          : Buf5 (E.t A)) c_inner,
        buf_all_at_level k outer_pre ->
        buf_all_at_level k outer_suf ->
        prefix_concat outer_pre pre = Some (outer_pre', pre') ->
        suffix_concat suf outer_suf = Some (suf', outer_suf') ->
        green_of_red_k (KCons Red (PNode pre' child suf') tail) =
          Some c_inner ->
      packet_context_recursive_repair_ready_refined_at k Hole c_inner) ->
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre child suf) tail.

Lemma packet_context_recursive_green_ready_refined_pnode_bottom_red_tail_empty_boundary_context :
  forall A k (pre suf red_pre red_suf b : Buf5 (E.t A)),
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    buf5_is_not_red_or_empty_shape red_pre ->
    buf5_is_not_red_or_empty_shape red_suf ->
    (red_pre = B0 \/ red_suf = B0) ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_levels (S (S k)) (PNode red_pre Hole red_suf) ->
    buf_all_at_level (S (S (S k))) b ->
    packet_context_recursive_green_ready_refined_at k
      (PNode pre Hole suf)
      (KCons Red (PNode red_pre Hole red_suf) (KEnding b)).
Proof.
  intros A k pre suf red_pre red_suf b
    Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb.
  eapply pcgrr_pnode_bottom_red_tail_empty_boundary; eauto.
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_red_tail_context :
  forall A k (pre suf red_pre red_suf : Buf5 (E.t A))
         (child red_child : Packet A) tail,
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre child suf) ->
    packet_context_recursive_green_ready_refined_at (S k) child
      (KCons Red (PNode red_pre red_child red_suf) tail) ->
    (forall c_tail,
      green_of_red_k (KCons Red (PNode red_pre red_child red_suf) tail) =
        Some c_tail ->
      packet_context_recursive_repair_ready_refined_at
        k (PNode pre child suf) c_tail) ->
    packet_context_recursive_green_ready_refined_at k
      (PNode pre child suf)
      (KCons Red (PNode red_pre red_child red_suf) tail).
Proof.
  intros A k pre suf red_pre red_suf child red_child tail
    Hpre Hsuf Hpkt Hchild_ctx Hrepair_tail.
  eapply pcgrr_pnode_red_tail_refined; eauto.
Qed.

Lemma packet_context_recursive_repair_ready_refined_hole_green_bottom_red_tail_empty_boundary_context :
  forall A k (pre suf red_pre red_suf b : Buf5 (E.t A)),
    buf5_is_green_shape pre ->
    buf5_is_green_shape suf ->
    buf5_is_not_red_or_empty_shape red_pre ->
    buf5_is_not_red_or_empty_shape red_suf ->
    (red_pre = B0 \/ red_suf = B0) ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_levels (S (S k)) (PNode red_pre Hole red_suf) ->
    buf_all_at_level (S (S (S k))) b ->
    (forall c',
      green_of_red_k (KCons Red (PNode red_pre Hole red_suf) (KEnding b)) =
        Some c' ->
      packet_context_recursive_repair_ready_refined_at (S k) Hole c') ->
    packet_context_recursive_repair_ready_refined_at k Hole
      (KCons Green (PNode pre Hole suf)
        (KCons Red (PNode red_pre Hole red_suf) (KEnding b))).
Proof.
  intros A k pre suf red_pre red_suf b
    Hpre_shape Hsuf_shape Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb
    Hred_repair.
  inversion Hpkt as [|? ? ? ? Hpre_levels _ Hsuf_levels]; subst.
  eapply pcrrr_hole_kcons.
  - exact Hpre_shape.
  - exact Hsuf_shape.
  - exact Hpkt.
  - eapply pcgrr_hole_red_kcons_refined.
    + exact Hred_pkt.
    + apply pcgrr_existing.
      eapply pcgwr_repair. eapply pcrwr_hole_ending. exact Hb.
    + exact Hred_repair.
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_concat Hsuf_concat.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k outer_pre pre outer_pre' pre'
        Houter_pre Hpre_levels Hpre_shape Hpre_concat)
      as [_ [Hpre'_shape [_ Hpre'_levels]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k suf outer_suf suf' outer_suf'
        Hsuf_levels Houter_suf Hsuf_shape Hsuf_concat)
      as [Hsuf'_shape [_ [Hsuf'_levels _]]].
    eapply packet_context_recursive_green_ready_refined_pnode_bottom_red_tail_empty_boundary_context.
    + exact Hpre'_shape.
    + exact Hsuf'_shape.
    + exact Hred_pre.
    + exact Hred_suf.
    + exact Hempty.
    + constructor; [exact Hpre'_levels|constructor|exact Hsuf'_levels].
    + exact Hred_pkt.
    + exact Hb.
Qed.

Theorem packet_context_recursive_green_ready_refined_pnode_red_tail_boundary :
  let z := E.base nat 0 in
  let p := E.pair nat z z eq_refl in
  let q := E.pair nat p p eq_refl in
  packet_context_recursive_green_ready_refined_at 0
    (PNode (B1 p) Hole (B1 p))
    (KCons Red (PNode (B1 q) Hole B0) (KEnding B0)).
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (packet_context_recursive_green_ready_refined_at 0
    (PNode (B1 p) Hole (B1 p))
    (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
  eapply packet_context_recursive_green_ready_refined_pnode_bottom_red_tail_empty_boundary_context.
  - cbn. exact I.
  - cbn. exact I.
  - cbn. exact I.
  - cbn. exact I.
  - right. reflexivity.
  - constructor; cbn; try constructor; repeat split; try reflexivity.
  - constructor; cbn; try constructor; repeat split; try reflexivity.
  - cbn. exact I.
Qed.

Theorem packet_context_recursive_green_ready_refined_pnode_red_tail_boundary_b1_b2 :
  let z := E.base nat 0 in
