Qed.

Theorem packet_context_recursive_repair_ready_refined_hole_green_red_tail_boundary :
  let z := E.base nat 0 in
  let p := E.pair nat z z eq_refl in
  let q := E.pair nat p p eq_refl in
  packet_context_recursive_repair_ready_refined_at 0 Hole
    (KCons Green (PNode (B2 p p) Hole (B2 p p))
      (KCons Red (PNode (B1 q) Hole B0) (KEnding B0))).
Proof.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (packet_context_recursive_repair_ready_refined_at 0 Hole
    (KCons Green (PNode (B2 p p) Hole (B2 p p))
      (KCons Red (PNode (B1 q) Hole B0) (KEnding B0)))).
  eapply packet_context_recursive_repair_ready_refined_hole_green_bottom_red_tail_empty_boundary_context.
  - cbn. exact I.
  - cbn. exact I.
  - cbn. exact I.
  - cbn. exact I.
  - right. reflexivity.
  - constructor; cbn; try constructor; repeat split; try reflexivity.
  - constructor; cbn; try constructor; repeat split; try reflexivity.
  - cbn. exact I.
  - intros c' Hred.
    unfold green_of_red_k, make_small in Hred.
    inversion Hred; subst c'; clear Hred.
    constructor. constructor. cbn. reflexivity.
Qed.

Lemma packet_context_recursive_repair_ready_refined_context_ready :
  forall A k (i : Packet A) (tail : KChain A),
    packet_context_recursive_repair_ready_refined_at k i tail ->
    green_of_red_k_context_ready_at k i tail.
Proof.
  intros A k i tail Hctx.
  destruct Hctx; cbn; repeat split; try assumption.
  eapply packet_context_recursive_repair_ready_context_ready.
  exact H.
Qed.

Fixpoint kt4_level_recursive_wrap_ready_refined_state_at {A : Type}
    (k : nat) (c : KChain A) : Prop :=
  match c with
  | KEnding b => buf_all_at_level k b
  | KCons Green (PNode pre i suf) tail =>
      buf5_is_green_shape pre /\
      buf5_is_green_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_recursive_wrap_ready_refined_state_at
        (k + packet_depth (PNode pre i suf)) tail /\
      yellow_wrap_pr_total_pre tail /\
      packet_context_recursive_green_ready_refined_at k i tail
  | KCons Yellow (PNode pre i suf) tail =>
      buf5_is_not_red_shape pre /\
      buf5_is_not_red_shape suf /\
      packet_levels k (PNode pre i suf) /\
      kt4_level_recursive_wrap_ready_refined_state_at
        (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_recursive_repair_ready_refined_at k i tail
  | KCons Red (PNode pre i suf) tail =>
      packet_levels k (PNode pre i suf) /\
      kt4_level_recursive_wrap_ready_refined_state_at
        (k + packet_depth (PNode pre i suf)) tail /\
      packet_context_recursive_repair_ready_refined_at k i tail
  | _ => False
  end.

Definition kt4_public_level_recursive_wrap_ready_refined_state {A : Type}
    (c : KChain A) : Prop :=
  kchain_top_color c <> Red /\
  kt4_level_recursive_wrap_ready_refined_state_at 0 c.

Theorem kt4_level_recursive_wrap_ready_state_refined_state_at :
  forall A k (c : KChain A),
    kt4_level_recursive_wrap_ready_state_at k c ->
    kt4_level_recursive_wrap_ready_refined_state_at k c.
Proof.
  intros A k c.
  revert k.
  induction c as [b|col p tail IH]; intros k Hready.
  - exact Hready.
  - destruct col; destruct p as [|pre i suf]; cbn in Hready |- *;
      try contradiction.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail [Hyw Hctx]]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * apply pcgrr_existing. exact Hctx.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail Hctx]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * apply pcrrr_existing. exact Hctx.
    + destruct Hready as [Hpkt [Htail Hctx]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * apply pcrrr_existing. exact Hctx.
Qed.

Theorem kt4_public_level_recursive_wrap_ready_state_refined_state :
  forall A (c : KChain A),
    kt4_public_level_recursive_wrap_ready_state c ->
    kt4_public_level_recursive_wrap_ready_refined_state c.
Proof.
  intros A c [Htop Hready].
  split; [exact Htop|].
  eapply kt4_level_recursive_wrap_ready_state_refined_state_at.
  exact Hready.
Qed.

Theorem empty_kchain_kt4_public_level_recursive_wrap_ready_refined_state :
  forall A,
    kt4_public_level_recursive_wrap_ready_refined_state (@empty_kchain A).
Proof.
  intros A.
  eapply kt4_public_level_recursive_wrap_ready_state_refined_state.
  apply empty_kchain_kt4_public_level_recursive_wrap_ready_state.
Qed.

Theorem kt4_level_recursive_wrap_ready_refined_state_total_state_at :
  forall A k (c : KChain A),
    kt4_level_recursive_wrap_ready_refined_state_at k c ->
    kt4_level_total_state_at k c.
Proof.
  intros A k c.
  revert k.
  induction c as [b|col p tail IH]; intros k Hready.
  - exact Hready.
  - destruct col; destruct p as [|pre i suf]; cbn in Hready |- *;
      try contradiction.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail [Hyw _]]]]].
      repeat split; try assumption.
      apply IH. exact Htail.
    + destruct Hready as [Hpre [Hsuf [Hpkt [Htail Hctx]]]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * intros x Hx.
        destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_push_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_refined_context_ready.
        exact Hctx.
      * intros x Hx.
        destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_inject_red_repair_witness_from_ready; [exact Hx|exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_refined_context_ready.
        exact Hctx.
      * destruct pre as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_pop_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_refined_context_ready.
        exact Hctx.
      * destruct suf as [|a|a b|a b c0|a b c0 d|]; try exact I.
        eapply yellow_eject_red_repair_witness_from_ready; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_refined_context_ready.
        exact Hctx.
    + destruct Hready as [Hpkt [Htail Hctx]].
      repeat split; try assumption.
      * apply IH. exact Htail.
      * change (exists c',
            green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c').
        eapply green_of_red_k_total_under_ready_levels; [exact Hpkt|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_refined_context_ready.
        exact Hctx.
Qed.

Theorem kt4_public_level_recursive_wrap_ready_refined_state_total_state :
  forall A (c : KChain A),
    kt4_public_level_recursive_wrap_ready_refined_state c ->
    kt4_public_level_total_state c.
Proof.
  intros A c [Htop Hready].
  split; [exact Htop|].
  eapply kt4_level_recursive_wrap_ready_refined_state_total_state_at.
  exact Hready.
Qed.

Corollary push_kt4_no_fail_under_public_level_recursive_wrap_ready_refined_state :
  forall A (x : E.t A) (c : KChain A),
    kt4_public_level_recursive_wrap_ready_refined_state c ->
    E.level A x = 0 ->
    push_kt4 x c <> PushFail.
Proof.
  intros A x c Hready Hx.
  eapply push_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_refined_state_total_state.
  exact Hready.
Qed.

Corollary inject_kt4_no_fail_under_public_level_recursive_wrap_ready_refined_state :
  forall A (c : KChain A) (x : E.t A),
    kt4_public_level_recursive_wrap_ready_refined_state c ->
    E.level A x = 0 ->
    inject_kt4 c x <> PushFail.
Proof.
  intros A c x Hready Hx.
  eapply inject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_refined_state_total_state.
  exact Hready.
Qed.

Corollary pop_kt4_no_fail_under_public_level_recursive_wrap_ready_refined_state :
  forall A (c : KChain A),
    kt4_public_level_recursive_wrap_ready_refined_state c ->
    kt4_nonempty_state c ->
    pop_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply pop_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_refined_state_total_state.
  exact Hready.
Qed.

Corollary eject_kt4_no_fail_under_public_level_recursive_wrap_ready_refined_state :
  forall A (c : KChain A),
    kt4_public_level_recursive_wrap_ready_refined_state c ->
    kt4_nonempty_state c ->
    eject_kt4 c <> PopFail.
Proof.
  intros A c Hready Hnonempty.
  eapply eject_kt4_no_fail_under_public_level_total_state; eauto.
  eapply kt4_public_level_recursive_wrap_ready_refined_state_total_state.
  exact Hready.
Qed.

Theorem push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_ending :
  forall A (x : E.t A) (b : Buf5 (E.t A)) c',
    E.level A x = 0 ->
    kt4_public_level_recursive_wrap_ready_refined_state (KEnding b) ->
    push_kt4 x (KEnding b) = PushOk c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A x b c' Hx [_ Hb] Hpush.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hpush. inversion Hpush; subst; clear Hpush.
    split; [discriminate|cbn; exact Hx].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha Hb].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpush. inversion Hpush; subst; clear Hpush.
    destruct Hb as [Ha [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn].
    repeat split; try exact I; try congruence.
    + constructor; cbn;
        [repeat split; congruence|constructor|repeat split; congruence].
    + constructor. constructor. constructor. exact I.
Qed.

Theorem inject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_ending :
  forall A (b : Buf5 (E.t A)) (x : E.t A) c',
    E.level A x = 0 ->
    kt4_public_level_recursive_wrap_ready_refined_state (KEnding b) ->
    inject_kt4 (KEnding b) x = PushOk c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A b x c' Hx [_ Hb] Hinject.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hinject. inversion Hinject; subst; clear Hinject.
    split; [discriminate|cbn; exact Hx].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha Hb].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hinject. inversion Hinject; subst; clear Hinject.
    destruct Hb as [Ha [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn].
    repeat split; try exact I; try congruence.
    + constructor; cbn;
        [repeat split; congruence|constructor|repeat split; congruence].
    + constructor. constructor. constructor. exact I.
Qed.

Theorem pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_ending :
  forall A (b : Buf5 (E.t A)) x c',
    kt4_public_level_recursive_wrap_ready_refined_state (KEnding b) ->
    pop_kt4 (KEnding b) = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A b x c' [_ Hb] Hpop.
  destruct b as [|a|a b|a b c|a b c d|a b c d e].
  - cbn in Hpop. discriminate.
  - cbn in Hpop. inversion Hpop; subst; clear Hpop.
    split; [discriminate|cbn; exact I].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ Hb].
    split; [discriminate|cbn; exact Hb].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb Hc]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb [Hc Hd]]].
    split; [discriminate|cbn; repeat split; assumption].
  - cbn in Hb, Hpop. inversion Hpop; subst; clear Hpop.
    destruct Hb as [_ [Hb [Hc [Hd He]]]].
    split; [discriminate|cbn; repeat split; assumption].
Qed.

Theorem eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_ending :
  forall A (b : Buf5 (E.t A)) x c',
