Qed.

Theorem push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail :
  forall A (x : E.t A) pre i suf tail c',
    E.level A x = 0 ->
    kt4_public_level_recursive_wrap_ready_refined_state
      (KCons Green (PNode pre i suf) tail) ->
    kchain_top_color tail <> Red ->
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A x pre i suf tail c' Hx [_ Hstate] Htail_top Hpush.
  cbn in Hstate.
  destruct Hstate as [Hpre_shape [Hsuf_shape [Hpkt [Htail [_ Hctx_green]]]]].
  pose proof (@packet_context_recursive_green_ready_refined_repair_ready_non_red_tail
      A 0 i tail Htail_top Hctx_green) as Hctx.
  unfold push_kt4 in Hpush.
  destruct pre as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hpre_shape, Hpush; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha Hb].
    destruct (@yellow_wrap_pr_preserves_recursive_wrap_ready_refined_state_non_red_tail
        A 0 (B3 x a b) i suf tail c' Htail_top)
      as [Htop' Hready']; try exact Hpush.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn;
        [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx.
    + split; assumption.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb Hc]].
    destruct (@yellow_wrap_pr_preserves_recursive_wrap_ready_refined_state_non_red_tail
        A 0 (B4 x a b c0) i suf tail c' Htail_top)
      as [Htop' Hready']; try exact Hpush.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn;
        [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx.
    + split; assumption.
Qed.

