Lemma yellow_wrap_pr_preserves_recursive_wrap_ready_refined_state_wrap_tail :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt tail ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_recursive_wrap_ready_refined_state_at
      (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_recursive_green_ready_refined_at k i tail ->
    (forall c'',
      green_of_red_k tail = Some c'' ->
      kt4_level_recursive_wrap_ready_refined_state_at
        (k + packet_depth (PNode pre i suf)) c'') ->
    (forall c'',
      green_of_red_k tail = Some c'' ->
      packet_context_recursive_repair_ready_refined_at k i c'') ->
    yellow_wrap_pr pre i suf tail = PushOk c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_refined_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpre Hsuf Hpkt Htail Hctx_green
    Htail_after Hctx_after Hyw.
  unfold yellow_wrap_pr in Hyw.
  destruct tail as [b|col p tail2].
  - inversion Hyw; subst; clear Hyw.
    split; [discriminate|cbn].
    repeat split; try assumption.
    eapply packet_context_recursive_green_ready_refined_repair_ready_non_red_tail;
      [cbn; discriminate|exact Hctx_green].
  - destruct col.
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_recursive_green_ready_refined_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_recursive_green_ready_refined_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + destruct (green_of_red_k (KCons Red p tail2)) as [c''|]
        eqn:Hred; [|discriminate].
      inversion Hyw; subst c'; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      * eapply Htail_after. reflexivity.
      * eapply Hctx_after. reflexivity.
Qed.

