  intros A x c c' Hx Hreg Hstate Hgreen_tail_state Hgreen_tail_ctx
    Hyellow_repair_state Hpush.
  destruct c as [b|col p tail].
  - eapply push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_ending;
      eauto.
  - destruct p as [|pre i suf].
    { destruct col; cbn in Hpush; discriminate. }
    cbn in Hstate.
    destruct col.
    + apply regular_kt_green_inv in Hreg.
      destruct Hreg as [_ Htail_reg].
      destruct tail as [tb|tail_col tail_p tail_tail] eqn:Htail_eq.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
          [exact Hx|exact Hstate|cbn; discriminate|exact Hpush].
      * destruct tail_col.
        -- eapply push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
             [exact Hx|exact Hstate|cbn; discriminate|exact Hpush].
