              eapply Hgreen_tail_state; [reflexivity|exact Hred].
           ++ intros c_tail Hred.
              eapply Hgreen_tail_ctx; [reflexivity|exact Hred].
    + destruct pre as [|a|a b0|a b0 c0|a b0 c0 d|a b0 c0 d e];
        cbn in Hpush; try discriminate.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_repair_when_repair_wraps;
          [exact Hx|exact Hstate| |exact Hpush].
        intros c_repair Hred.
        eapply Hyellow_repair_state; [reflexivity|exact Hred].
    + destruct Hstate as [Htop _].
      exfalso. apply Htop. reflexivity.
