    (forall a i suf tail c_repair,
      c = KCons Yellow (PNode (B1 a) i suf) tail ->
      green_of_red_k (KCons Red (PNode B0 i suf) tail) = Some c_repair ->
      kt4_level_recursive_wrap_ready_refined_state_at 0 c_repair) ->
    pop_kt4 c = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A c x c' Hreg Hstate Hgreen_tail_state Hgreen_tail_ctx
    Hyellow_repair_state Hpop.
  destruct c as [b|col p tail].
  - eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_ending;
      eauto.
  - destruct p as [|pre i suf].
    { destruct col; cbn in Hpop; discriminate. }
    cbn in Hstate.
    destruct col.
    + apply regular_kt_green_inv in Hreg.
      destruct Hreg as [_ Htail_reg].
      destruct tail as [tb|tail_col tail_p tail_tail] eqn:Htail_eq.
      * eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
          [exact Hstate|cbn; discriminate|exact Hpop].
      * destruct tail_col.
        -- eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
             [exact Hstate|cbn; discriminate|exact Hpop].
        -- eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
             [exact Hstate|cbn; discriminate|exact Hpop].
        -- eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_tail_repair_wraps;
             [exact Htail_reg|exact Hstate| | |exact Hpop].
           ++ intros c_tail Hred.
              eapply Hgreen_tail_state; [reflexivity|exact Hred].
           ++ intros c_tail Hred.
              eapply Hgreen_tail_ctx; [reflexivity|exact Hred].
    + destruct pre as [|a|a b0|a b0 c0|a b0 c0 d|a b0 c0 d e];
        cbn in Hpop; try discriminate.
      * eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_repair_when_repair_wraps;
          [exact Hstate| |exact Hpop].
        intros c_repair Hred.
        eapply Hyellow_repair_state; [reflexivity|exact Hred].
      * eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply pop_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
    + destruct Hstate as [Htop _].
      exfalso. apply Htop. reflexivity.
Qed.

Theorem eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_when_repairs_wrap :
  forall (A : Type) (c : KChain A) (x : E.t A) c',
    regular_kt c ->
    kt4_public_level_recursive_wrap_ready_refined_state c ->
    (forall pre i suf tail c_tail,
      c = KCons Green (PNode pre i suf) tail ->
      green_of_red_k tail = Some c_tail ->
      kt4_level_recursive_wrap_ready_refined_state_at
        (packet_depth (PNode pre i suf)) c_tail) ->
    (forall pre i suf tail c_tail,
      c = KCons Green (PNode pre i suf) tail ->
      green_of_red_k tail = Some c_tail ->
      packet_context_recursive_repair_ready_refined_at 0 i c_tail) ->
    (forall pre i a tail c_repair,
      c = KCons Yellow (PNode pre i (B1 a)) tail ->
      green_of_red_k (KCons Red (PNode pre i B0) tail) = Some c_repair ->
      kt4_level_recursive_wrap_ready_refined_state_at 0 c_repair) ->
    eject_kt4 c = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A c x c' Hreg Hstate Hgreen_tail_state Hgreen_tail_ctx
    Hyellow_repair_state Heject.
  destruct c as [b|col p tail].
  - eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_ending;
      eauto.
  - destruct p as [|pre i suf].
    { destruct col; cbn in Heject; discriminate. }
    cbn in Hstate.
    destruct col.
    + apply regular_kt_green_inv in Hreg.
      destruct Hreg as [_ Htail_reg].
      destruct tail as [tb|tail_col tail_p tail_tail] eqn:Htail_eq.
      * eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
          [exact Hstate|cbn; discriminate|exact Heject].
      * destruct tail_col.
        -- eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
             [exact Hstate|cbn; discriminate|exact Heject].
        -- eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_non_red_tail;
             [exact Hstate|cbn; discriminate|exact Heject].
        -- eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_green_tail_repair_wraps;
             [exact Htail_reg|exact Hstate| | |exact Heject].
           ++ intros c_tail Hred.
              eapply Hgreen_tail_state; [reflexivity|exact Hred].
           ++ intros c_tail Hred.
              eapply Hgreen_tail_ctx; [reflexivity|exact Hred].
    + destruct suf as [|a|a b0|a b0 c0|a b0 c0 d|a b0 c0 d e];
        cbn in Heject; try discriminate.
      * eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_repair_when_repair_wraps;
          [exact Hstate| |exact Heject].
        intros c_repair Hred.
        eapply Hyellow_repair_state; [reflexivity|exact Hred].
      * eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_no_repair;
          eauto; cbn; exact I.
    + destruct Hstate as [Htop _].
      exfalso. apply Htop. reflexivity.
Qed.

Lemma packet_context_recursive_repair_ready_refined_hole_kcons_components :
  forall A k col (pre : Buf5 (E.t A)) child suf tail,
    packet_context_recursive_repair_ready_refined_at
      k Hole (KCons col (PNode pre child suf) tail) ->
    buf5_is_green_shape pre /\
    buf5_is_green_shape suf /\
    packet_levels (S k) (PNode pre child suf) /\
    packet_context_recursive_green_ready_refined_at (S k) child tail /\
    (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        : Buf5 (E.t A)),
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre = Some (outer_pre', pre') ->
      green_suffix_concat suf outer_suf = Some (suf', outer_suf') ->
      packet_context_recursive_green_ready_refined_at
        k (PNode pre' child suf') tail).
Proof.
  intros A k col pre child suf tail Hctx.
  inversion Hctx; subst; clear Hctx.
  - inversion H; subst; clear H; try discriminate.
    repeat split; try assumption.
    + apply pcgrr_existing. assumption.
    + intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        Houter_pre Houter_suf Hpre_concat Hsuf_concat.
      apply pcgrr_existing.
      eauto.
  - repeat split; eauto.
Qed.

Lemma green_of_red_k_case2_preserves_recursive_wrap_ready_refined_state_regular :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) col tail c',
    regular_kt
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) ->
    packet_levels k (PNode pre1 Hole suf1) ->
    kt4_level_recursive_wrap_ready_refined_state_at
      (k + packet_depth (PNode pre1 Hole suf1))
      (KCons col (PNode pre2 child suf2) tail) ->
    packet_context_recursive_repair_ready_refined_at k Hole
      (KCons col (PNode pre2 child suf2) tail) ->
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) = Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_refined_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child col tail c'
    Hreg Hpkt Htail_state Hctx Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  destruct (@packet_context_recursive_repair_ready_refined_hole_kcons_components
      A k col pre2 child suf2 tail Hctx)
    as [Hpre2_shape [Hsuf2_shape [Hpkt2 [Hctx_child Hctx_after]]]].
  replace (k + packet_depth (PNode pre1 Hole suf1)) with (S k) in Htail_state
    by (cbn; lia).
  unfold green_of_red_k in Hred.
  destruct (green_prefix_concat pre1 pre2) as [[pre1' pre2']|]
    eqn:Hpre_concat; [|discriminate].
  destruct (green_suffix_concat suf2 suf1) as [[suf2' suf1']|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst c'; clear Hred.
  inversion Hpkt2 as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k pre1 pre2 pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre2'_shape [Hpre1' Hpre2']]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k suf2 suf1 suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2'_shape [Hsuf1'_shape [Hsuf2' Hsuf1']]].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  apply regular_kt_red_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|exact Hinner'|assumption].
  - destruct col.
    + cbn in Htail_state.
      destruct Htail_state as [_ [_ [_ [Htail [Hyw _]]]]].
      split.
      * replace (k + S (S (packet_depth child)))
          with (S (k + S (packet_depth child))) by lia.
        exact Htail.
      * split.
        -- exact Hyw.
        -- exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1'
             Hpre1 Hsuf1 Hpre_concat Hsuf_concat).
    + cbn in Htail_state.
      destruct Htail_state as [_ [_ [_ [Htail _]]]].
      apply regular_kt_yellow_inv in Htail_reg.
      destruct Htail_reg as [_ [Htail_non_red _]].
      split.
      * replace (k + S (S (packet_depth child)))
          with (S (k + S (packet_depth child))) by lia.
        exact Htail.
      * split.
        -- destruct tail as [b|tail_col tail_p tail_tail];
             cbn in Htail_non_red |- *; try exact I.
           destruct tail_col; try exact I.
           exfalso. apply Htail_non_red. reflexivity.
        -- exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1'
             Hpre1 Hsuf1 Hpre_concat Hsuf_concat).
    + exfalso. apply Htail_top. reflexivity.
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_components :
  forall A k (pre : Buf5 (E.t A)) child suf tail,
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre child suf) tail ->
    buf5_is_not_red_shape pre /\
    buf5_is_not_red_shape suf /\
    packet_levels (S k) (PNode pre child suf) /\
    packet_context_recursive_green_ready_refined_at (S k) child tail /\
    (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        : Buf5 (E.t A)) c_inner,
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      prefix_concat outer_pre pre = Some (outer_pre', pre') ->
      suffix_concat suf outer_suf = Some (suf', outer_suf') ->
      green_of_red_k (KCons Red (PNode pre' child suf') tail) =
        Some c_inner ->
      packet_context_recursive_repair_ready_refined_at k Hole c_inner).
Proof.
  intros A k pre child suf tail Hctx.
  set (pkt := PNode pre child suf) in Hctx.
  assert (Hpkt : pkt = PNode pre child suf) by reflexivity.
  clearbody pkt.
  revert pre child suf Hpkt.
  inversion Hctx; subst; clear Hctx; intros pre0 child0 suf0 Hpkt;
    try discriminate.
  - inversion H; subst; clear H; try discriminate.
    match goal with
    | H : PNode _ _ _ = PNode _ _ _ |- _ => inversion H; subst; clear H
    end.
    repeat split; try assumption.
    + apply pcgrr_existing. assumption.
    + intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred.
      apply pcrrr_existing.
      eauto.
  - match goal with
    | H : PNode _ _ _ = PNode _ _ _ |- _ => inversion H; subst; clear H
    end.
    repeat split; eauto.
Qed.

Lemma green_of_red_k_case3_preserves_recursive_wrap_ready_refined_state_under_child_repair_and_output_context :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail c' : KChain A),
    packet_levels k (PNode pre1 (PNode pre2 child suf2) suf1) ->
    kt4_level_recursive_wrap_ready_refined_state_at
      (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1)) tail ->
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre2 child suf2) tail ->
    packet_context_recursive_repair_ready_refined_at (S k) child tail ->
    (forall pre1' pre2' suf2' suf1',
      prefix_concat pre1 pre2 = Some (pre1', pre2') ->
      suffix_concat suf2 suf1 = Some (suf2', suf1') ->
      packet_context_recursive_green_ready_refined_at k Hole
        (KCons Red (PNode pre2' child suf2') tail)) ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) =
        Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_refined_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail c'
    Hpkt Htail Hctx Hchild_repair Houtput_context Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 Hinner Hsuf1]; subst.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  destruct (@packet_context_recursive_repair_ready_refined_pnode_components
      A k pre2 child suf2 tail Hctx)
    as [Hpre2_shape [Hsuf2_shape [_ [_ _]]]].
  unfold green_of_red_k in Hred.
  destruct (prefix_concat pre1 pre2) as [[pre1' pre2']|] eqn:Hpre_concat;
    [|discriminate].
  destruct (suffix_concat suf2 suf1) as [[suf2' suf1']|] eqn:Hsuf_concat;
    [|discriminate].
  inversion Hred; subst c'; clear Hred.
  destruct (@prefix_concat_preserves_outer_green_levels A k pre1 pre2
      pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre1' Hpre2']].
  destruct (@suffix_concat_preserves_outer_green_levels A k suf2 suf1
      suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2' [Hsuf1'_shape Hsuf1']].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|constructor|assumption].
  - split.
    + cbn.
      replace (k + 1) with (S k) by lia.
      split; [exact Hinner'|].
      split.
      * replace (S k + S (packet_depth child))
          with (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1))
          by (cbn; lia).
        exact Htail.
      * exact Hchild_repair.
    + split.
      * change (exists c'0,
          green_of_red_k (KCons Red (PNode pre2' child suf2') tail) =
            Some c'0).
        eapply green_of_red_k_total_under_ready_levels; [exact Hinner'|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_recursive_repair_ready_refined_context_ready.
        exact Hchild_repair.
      * exact (Houtput_context pre1' pre2' suf2' suf1'
          eq_refl eq_refl).
Qed.

Lemma green_of_red_k_case3_preserves_recursive_wrap_ready_refined_state_regular_when_output_context :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail c' : KChain A),
    regular_kt
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) ->
    packet_levels k (PNode pre1 (PNode pre2 child suf2) suf1) ->
    kt4_level_recursive_wrap_ready_refined_state_at
      (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1)) tail ->
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre2 child suf2) tail ->
    (forall pre1' pre2' suf2' suf1',
      prefix_concat pre1 pre2 = Some (pre1', pre2') ->
      suffix_concat suf2 suf1 = Some (suf2', suf1') ->
      packet_context_recursive_green_ready_refined_at k Hole
        (KCons Red (PNode pre2' child suf2') tail)) ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) =
        Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_refined_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail c'
    Hreg Hpkt Htail Hctx Houtput_context Hred.
  pose proof Hreg as Hreg_inv.
  apply regular_kt_red_inv in Hreg_inv.
  destruct Hreg_inv as [_ [Htail_top _]].
  destruct (@packet_context_recursive_repair_ready_refined_pnode_components
      A k pre2 child suf2 tail Hctx)
    as [_ [_ [_ [Hctx_child _]]]].
  assert (Hchild_repair :
    packet_context_recursive_repair_ready_refined_at (S k) child tail).
  { eapply packet_context_recursive_green_ready_refined_repair_ready_non_red_tail;
      eauto. }
  eapply green_of_red_k_case3_preserves_recursive_wrap_ready_refined_state_under_child_repair_and_output_context;
    eauto.
Qed.

Lemma packet_context_recursive_repair_ready_refined_case3_output_context :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) tail pre1' pre2' suf2' suf1',
    buf_all_at_level k pre1 ->
    buf_all_at_level k suf1 ->
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre2 child suf2) tail ->
    prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    packet_context_recursive_green_ready_refined_at k Hole
      (KCons Red (PNode pre2' child suf2') tail).
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail pre1' pre2' suf2' suf1'
    Hpre1 Hsuf1 Hctx Hpre_concat Hsuf_concat.
  destruct (@packet_context_recursive_repair_ready_refined_pnode_components
      A k pre2 child suf2 tail Hctx)
    as [Hpre2_shape [Hsuf2_shape [Hpkt [Hchild_ctx Hafter]]]].
  inversion Hpkt as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k pre1 pre2 pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [_ [_ Hpre2']].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf2 suf1 suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2' _].
  eapply pcgrr_hole_red_kcons_refined.
  - constructor; [exact Hpre2'|exact Hchild|exact Hsuf2'].
  - exact Hchild_ctx.
  - intros c_inner Hred_inner.
    exact (Hafter pre1 suf1 pre1' pre2' suf2' suf1' c_inner
      Hpre1 Hsuf1 Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma green_of_red_k_case3_preserves_recursive_wrap_ready_refined_state_regular :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail c' : KChain A),
    regular_kt
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) ->
    packet_levels k (PNode pre1 (PNode pre2 child suf2) suf1) ->
    kt4_level_recursive_wrap_ready_refined_state_at
      (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1)) tail ->
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre2 child suf2) tail ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) =
        Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_refined_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail c'
    Hreg Hpkt Htail Hctx Hred.
  eapply green_of_red_k_case3_preserves_recursive_wrap_ready_refined_state_regular_when_output_context.
  - exact Hreg.
  - exact Hpkt.
  - exact Htail.
  - exact Hctx.
  - intros pre1' pre2' suf2' suf1' Hpre_concat Hsuf_concat.
    inversion Hpkt as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
    eapply packet_context_recursive_repair_ready_refined_case3_output_context.
    + exact Hpre1.
    + exact Hsuf1.
    + exact Hctx.
    + exact Hpre_concat.
    + exact Hsuf_concat.
  - exact Hred.
Qed.

Lemma green_of_red_k_preserves_recursive_wrap_ready_refined_state_regular_when_case1_wraps :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt (KCons Red (PNode pre i suf) tail) ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_recursive_wrap_ready_refined_state_at
      (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_recursive_repair_ready_refined_at k i tail ->
    (forall b c_case1,
      tail = KEnding b ->
      i = Hole ->
      green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
        Some c_case1 ->
      kt4_level_recursive_wrap_ready_refined_state_at k c_case1) ->
    green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_refined_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpkt Htail Hctx Hcase1 Hred.
  destruct i as [|pre2 child suf2].
  - destruct tail as [b|col p tail2].
    + split.
      * pose proof Hred as Htop.
        apply green_of_red_k_top_green in Htop.
        rewrite Htop. discriminate.
      * eapply Hcase1; eauto.
    + destruct p as [|pre2 child suf2].
      * inversion Hctx; subst; clear Hctx; try discriminate.
      * eapply green_of_red_k_case2_preserves_recursive_wrap_ready_refined_state_regular;
          eauto.
