Lemma green_of_red_k_preserves_recursive_wrap_ready_state_regular_when_case1_wraps :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt (KCons Red (PNode pre i suf) tail) ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_recursive_repair_ready_at k i tail ->
    (forall b c_case1,
      tail = KEnding b ->
      i = Hole ->
      green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
        Some c_case1 ->
      kt4_level_recursive_wrap_ready_state_at k c_case1) ->
    green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpkt Htail Hctx Hcase1 Hred.
  destruct i as [|pre2 child suf2].
  - destruct tail as [b|col p tail2].
    + split.
      * pose proof Hred as Htop.
        apply green_of_red_k_top_green in Htop.
        rewrite Htop. discriminate.
      * eapply Hcase1; eauto.
    + destruct p as [|pre2 child suf2].
      * inversion Hctx.
      * eapply green_of_red_k_case2_preserves_recursive_wrap_ready_state_regular;
          eauto.
  - eapply green_of_red_k_case3_preserves_recursive_wrap_ready_state_regular;
      eauto.
Qed.

Lemma green_of_red_k_preserves_recursive_wrap_ready_state_regular_no_outer_overflow :
