Lemma green_of_red_k_preserves_recursive_wrap_ready_state_regular_when_case1_context_with_output_context_ready :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt (KCons Red (PNode pre i suf) tail) ->
    packet_levels (S k) (PNode pre i suf) ->
    kt4_level_recursive_wrap_ready_state_at
      (S k + packet_depth (PNode pre i suf)) tail ->
    packet_context_recursive_repair_ready_at (S k) i tail ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S (S k)) pre0 ->
      buf_all_at_level (S (S (S k))) b0 ->
      buf_all_at_level (S (S k)) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_at (S k) Hole
        (chain_to_kchain_g c0)) ->
    green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_state_at (S k) c' /\
    green_of_red_k_context_ready_at k Hole c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpkt Htail Hctx Hcase1 Hred.
  destruct (@green_of_red_k_preserves_recursive_wrap_ready_state_regular_when_case1_context
      A (S k) pre i suf tail c'
      Hreg Hpkt Htail Hctx Hcase1 Hred) as [Htop Hstate].
  split; [exact Htop|].
  split; [exact Hstate|].
  eapply green_of_red_k_output_context_ready_from_recursive_context; eauto.
Qed.

Definition recursive_case1_context_ready {A : Type} : Prop :=
  forall k (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
    buf_all_at_level (S k) pre0 ->
    buf_all_at_level (S (S k)) b0 ->
    buf_all_at_level (S k) suf0 ->
    make_small pre0 b0 suf0 = Some c0 ->
    packet_context_recursive_repair_ready_at k Hole
      (chain_to_kchain_g c0).

Definition recursive_case1_chaincons_context_ready {A : Type} : Prop :=
  forall k (pre0 b0 suf0 : Buf5 (E.t A)) (p : Packet A)
         (tail : Chain A),
    buf_all_at_level (S k) pre0 ->
    buf_all_at_level (S (S k)) b0 ->
    buf_all_at_level (S k) suf0 ->
    make_small pre0 b0 suf0 = Some (@ChainCons A p tail) ->
    packet_context_recursive_repair_ready_at k Hole
      (chain_to_kchain_g (@ChainCons A p tail)).

Definition recursive_case1_context_ready_refined {A : Type} : Prop :=
  forall k (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
    buf_all_at_level (S k) pre0 ->
    buf_all_at_level (S (S k)) b0 ->
    buf_all_at_level (S k) suf0 ->
    make_small pre0 b0 suf0 = Some c0 ->
    packet_context_recursive_repair_ready_refined_at k Hole
      (chain_to_kchain_g c0).

Definition recursive_case1_chaincons_context_ready_refined {A : Type}
    : Prop :=
  forall k (pre0 b0 suf0 : Buf5 (E.t A)) (p : Packet A)
         (tail : Chain A),
    buf_all_at_level (S k) pre0 ->
    buf_all_at_level (S (S k)) b0 ->
    buf_all_at_level (S k) suf0 ->
    make_small pre0 b0 suf0 = Some (@ChainCons A p tail) ->
    packet_context_recursive_repair_ready_refined_at k Hole
      (chain_to_kchain_g (@ChainCons A p tail)).

Lemma packet_context_recursive_repair_ready_refined_hole_green_ending_guarded :
  forall A k (pre suf b : Buf5 (E.t A)),
    buf5_is_green_shape pre ->
    buf5_is_green_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    buf_all_at_level (S (S k)) b ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k) pre0 ->
      buf_all_at_level (S (S k)) b0 ->
      buf_all_at_level (S k) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_refined_at k Hole
        (chain_to_kchain_g c0)) ->
    packet_context_recursive_repair_ready_refined_at k Hole
      (KCons Green (PNode pre Hole suf) (KEnding b)).
Proof.
  intros A k pre suf b Hpre_shape Hsuf_shape Hpkt Hb Hcase1.
  inversion Hpkt as [|? ? ? ? Hpre_levels _ Hsuf_levels]; subst.
  eapply pcrrr_hole_kcons.
  - exact Hpre_shape.
  - exact Hsuf_shape.
  - exact Hpkt.
  - apply pcgrr_existing. apply pcgwr_repair.
    apply pcrwr_hole_ending. exact Hb.
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_concat Hsuf_concat.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k outer_pre pre outer_pre' pre'
        Houter_pre Hpre_levels Hpre_shape Hpre_concat)
      as [_ [Hpre'_shape [_ Hpre'_levels]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k suf outer_suf suf' outer_suf'
        Hsuf_levels Houter_suf Hsuf_shape Hsuf_concat)
      as [Hsuf'_shape [_ [Hsuf'_levels _]]].
    eapply pcgrr_repair_refined_non_red_tail.
    + cbn. discriminate.
    + eapply pcrrr_pnode.
      * exact Hpre'_shape.
      * exact Hsuf'_shape.
      * constructor; [exact Hpre'_levels|constructor|exact Hsuf'_levels].
      * apply pcgrr_existing. apply pcgwr_repair.
        apply pcrwr_hole_ending. exact Hb.
      * intros outer_pre2 outer_suf2 outer_pre2' pre2' suf2' outer_suf2'
          c_inner Houter_pre2 Houter_suf2 Hpre_concat2 Hsuf_concat2 Hred.
        unfold green_of_red_k in Hred.
        destruct (make_small pre2' b suf2') as [c0|] eqn:Hmake;
          [|discriminate].
        inversion Hred; subst c_inner; clear Hred.
        eapply Hcase1; [|exact Hb| |exact Hmake].
        -- destruct (@prefix_concat_preserves_outer_green_levels
              A k outer_pre2 pre' outer_pre2' pre2'
              Houter_pre2 Hpre'_levels Hpre'_shape Hpre_concat2)
            as [_ [_ Hpre2'_levels]].
           exact Hpre2'_levels.
        -- destruct (@suffix_concat_preserves_outer_green_levels
              A k suf' outer_suf2 suf2' outer_suf2'
              Hsuf'_levels Houter_suf2 Hsuf'_shape Hsuf_concat2)
            as [Hsuf2'_levels [_ _]].
           exact Hsuf2'_levels.
Qed.

Lemma packet_context_recursive_green_ready_refined_nested_case1_inner_guarded :
  forall A k (pre suf rest : Buf5 (E.t A)),
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    buf_all_at_level (S (S k)) rest ->
    (forall (pre0 b0 suf0 : Buf5 (E.t A)) (c0 : Chain A),
      buf_all_at_level (S k) pre0 ->
      buf_all_at_level (S (S k)) b0 ->
      buf_all_at_level (S k) suf0 ->
      make_small pre0 b0 suf0 = Some c0 ->
      packet_context_recursive_repair_ready_refined_at k Hole
        (chain_to_kchain_g c0)) ->
    packet_context_recursive_green_ready_refined_at k
      (PNode pre Hole suf) (KEnding rest).
Proof.
  intros A k pre suf rest Hpre_shape Hsuf_shape Hpkt Hrest Hcase1.
  inversion Hpkt as [|? ? ? ? Hpre_levels _ Hsuf_levels]; subst.
  eapply pcgrr_repair_refined_non_red_tail.
  - cbn. discriminate.
  - eapply pcrrr_pnode.
    + exact Hpre_shape.
    + exact Hsuf_shape.
    + exact Hpkt.
    + apply pcgrr_existing. apply pcgwr_repair.
      apply pcrwr_hole_ending. exact Hrest.
    + intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred.
      unfold green_of_red_k in Hred.
      destruct (make_small pre' rest suf') as [c0|] eqn:Hmake;
        [|discriminate].
      inversion Hred; subst c_inner; clear Hred.
      eapply Hcase1; [|exact Hrest| |exact Hmake].
      * destruct (@prefix_concat_preserves_outer_green_levels
            A k outer_pre pre outer_pre' pre'
            Houter_pre Hpre_levels Hpre_shape Hpre_concat)
          as [_ [_ Hpre'_levels]].
        exact Hpre'_levels.
      * destruct (@suffix_concat_preserves_outer_green_levels
            A k suf outer_suf suf' outer_suf'
            Hsuf_levels Houter_suf Hsuf_shape Hsuf_concat)
          as [Hsuf'_levels [_ _]].
        exact Hsuf'_levels.
Qed.

Lemma make_small_chaincons_hole_ending_components :
  forall A k (pre0 b0 suf0 pre suf out : Buf5 (E.t A)),
    buf_all_at_level (S k) pre0 ->
    buf_all_at_level (S (S k)) b0 ->
    buf_all_at_level (S k) suf0 ->
    make_small pre0 b0 suf0 =
      Some (@ChainCons A (PNode pre Hole suf) (Ending out)) ->
    buf5_is_green_shape pre /\
    buf5_is_green_shape suf /\
    packet_levels (S k) (PNode pre Hole suf) /\
    buf_all_at_level (S (S k)) out.
Proof.
  intros A k pre0 b0 suf0 pre suf out Hpre Hb Hsuf Hmake.
  unfold make_small in Hmake.
  destruct pre0 as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b0 as [|m1|m1 m2|m1 m2 m3|m1 m2 m3 m4|m1 m2 m3 m4 m5];
    destruct suf0 as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn -[E.pair E.unpair] in Hpre, Hb, Hsuf, Hmake |- *;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : E.unpair A e = _ |- _ => fail
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [OpsKT.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (OpsKT.E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Model.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (Model.E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [buf5_push_naive ?x ?b] |- _ =>
          destruct (buf5_push_naive x b) eqn:?; try discriminate
