    buf5_is_green_shape pre2 /\
    buf5_is_green_shape suf2 /\
    packet_levels (S k) (PNode pre Hole suf) /\
    packet_levels (S (S k)) (PNode pre2 Hole suf2) /\
    buf_all_at_level (S (S (S k))) out.
