        Hpre1 Hb1 Hsuf1 Hmake1). }
  cbn.
  eapply pcrwr_hole_kcons.
  - exact Hpre_shape.
  - exact Hsuf_shape.
  - exact Hparent_pkt.
  - exact Hchild_ctx.
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_concat Hsuf_concat.
    inversion Hparent_pkt as [|? ? ? ? Hpre_levels _ Hsuf_levels]; subst.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k outer_pre pre outer_pre' pre'
