    (forall k (parent_pre parent_suf child_pre : Buf5 (E.t A))
        child child_suf tail,
      @recursive_case1_context_ready A ->
      buf5_is_not_red_shape parent_pre ->
      buf5_is_not_red_shape parent_suf ->
      packet_levels
        (S k) (PNode parent_pre (PNode child_pre child child_suf)
          parent_suf) ->
      packet_context_recursive_green_ready_at
        (S k) (PNode child_pre child child_suf) tail ->
      packet_context_recursive_green_ready_at
        k (PNode parent_pre (PNode child_pre child child_suf)
          parent_suf) tail) ->
    @recursive_case1_chaincons_context_ready A.
Proof.
  unfold recursive_case1_chaincons_context_ready.
  intros A Hcase1 Hpnode k pre0 b0 suf0 p tail Hpre Hb Hsuf Hmake.
  pose proof Hpre as Hpre_orig.
  pose proof Hb as Hb_orig.
  pose proof Hsuf as Hsuf_orig.
  pose proof Hmake as Hmake_orig.
  unfold make_small in Hmake.
  destruct pre0 as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b0 as [|m1|m1 m2|m1 m2 m3|m1 m2 m3 m4|m1 m2 m3 m4 m5];
    destruct suf0 as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn -[E.pair E.unpair] in Hpre, Hb, Hsuf, Hmake |- *;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | H : context [E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : E.unpair A e = _ |- _ => fail
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [OpsKT.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (OpsKT.E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Model.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (Model.E.unpair A e) as [[u0 v0]|] eqn:Hup;
                try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [buf5_push_naive ?x ?b] |- _ =>
          destruct (buf5_push_naive x b) eqn:?; try discriminate
      | H : context [buf5_inject_naive ?b ?x] |- _ =>
          destruct (buf5_inject_naive b x) eqn:?; try discriminate
      | H : context [buf5_pop_naive ?b] |- _ =>
          destruct (buf5_pop_naive b) as [[u v]|] eqn:?; try discriminate
      | H : context [buf5_eject_naive ?b] |- _ =>
          destruct (buf5_eject_naive b) as [[u v]|] eqn:?; try discriminate
      | H : context [pair_each_buf ?b] |- _ =>
          destruct (pair_each_buf b) eqn:?; try discriminate
      end;
    inversion Hmake; subst; clear Hmake;
    try solve [
      eapply recursive_case1_chaincons_hole_ending_context_ready_guarded;
      [exact Hpre_orig|exact Hb_orig|exact Hsuf_orig|exact Hcase1
      |exact Hmake_orig]];
    try solve [
      eapply recursive_case1_chaincons_hole_green_hole_ending_context_ready_from_pnode_strict_child_context_guarded;
      [exact Hpre_orig|exact Hb_orig|exact Hsuf_orig|exact Hcase1
      |exact Hpnode|exact Hmake_orig]];
    try solve [
      eapply recursive_case1_chaincons_nested_hole_ending_context_ready_from_pnode_strict_child_context_guarded;
      [exact Hpre_orig|exact Hb_orig|exact Hsuf_orig|exact Hcase1
      |exact Hpnode|exact Hmake_orig]].
Defined.

Lemma recursive_case1_context_ready_ending_output :
  forall A k (pre0 b0 suf0 out : Buf5 (E.t A)),
    buf_all_at_level (S k) pre0 ->
    buf_all_at_level (S (S k)) b0 ->
    buf_all_at_level (S k) suf0 ->
    make_small pre0 b0 suf0 = Some (Ending out) ->
    packet_context_recursive_repair_ready_at k Hole
      (chain_to_kchain_g (Ending out)).
Proof.
  intros A k pre0 b0 suf0 out Hpre Hb Hsuf Hmake.
  pose proof (@make_small_chain_to_kchain_g_context_ready
      A k pre0 b0 suf0 (Ending out) Hpre Hb Hsuf Hmake) as Hready.
  cbn in Hready |- *.
  constructor. exact Hready.
Qed.

Definition recursive_case1_context_ready_from_chaincons_outputs_guarded {A : Type}
    (Hchaincons : @recursive_case1_chaincons_context_ready A)
    : @recursive_case1_context_ready A :=
  fun k pre0 b0 suf0 c0 Hpre Hb Hsuf Hmake =>
    match c0 as c return
      make_small pre0 b0 suf0 = Some c ->
      packet_context_recursive_repair_ready_at k Hole (chain_to_kchain_g c)
    with
    | Ending out =>
        fun Hmake0 =>
          @recursive_case1_context_ready_ending_output A k pre0 b0 suf0 out
            Hpre Hb Hsuf Hmake0
    | ChainCons p tail =>
        fun Hmake0 =>
          Hchaincons k pre0 b0 suf0 p tail Hpre Hb Hsuf Hmake0
    end Hmake.

Lemma recursive_case1_context_ready_from_chaincons_outputs :
  forall A,
    @recursive_case1_chaincons_context_ready A ->
    @recursive_case1_context_ready A.
Proof.
  intros A Hchaincons.
  exact (recursive_case1_context_ready_from_chaincons_outputs_guarded
    Hchaincons).
Qed.

Theorem recursive_case1_context_ready_iff_chaincons_outputs :
  forall A,
    @recursive_case1_context_ready A <->
    @recursive_case1_chaincons_context_ready A.
Proof.
  intros A. split.
  - unfold recursive_case1_context_ready,
      recursive_case1_chaincons_context_ready.
    intros Hcase1 k pre0 b0 suf0 p tail Hpre Hb Hsuf Hmake.
    exact (Hcase1 k pre0 b0 suf0 (ChainCons p tail)
      Hpre Hb Hsuf Hmake).
  - apply recursive_case1_context_ready_from_chaincons_outputs.
Qed.

Theorem recursive_case1_chaincons_context_ready_gap :
  ~ @recursive_case1_chaincons_context_ready nat.
Proof.
  intros Hcase1.
  unfold recursive_case1_chaincons_context_ready in Hcase1.
  apply packet_context_recursive_repair_ready_hole_green_nested_reachable_ending_boundary_gap.
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  change (packet_context_recursive_repair_ready_at 0 Hole
    (chain_to_kchain_g
      (@ChainCons nat
        (PNode (B2 p p) (PNode (B1 q) Hole (B1 q)) (B2 p p))
        (Ending B0)))).
  exact (Hcase1 0 (B4 p p p p) B0 (B4 p p p p)
    (PNode (B2 p p) (PNode (B1 q) Hole (B1 q)) (B2 p p))
    (Ending B0)
    ltac:(cbn; repeat split; reflexivity)
    ltac:(cbn; exact I)
    ltac:(cbn; repeat split; reflexivity)
    ltac:(cbn; reflexivity)).
Qed.

Lemma green_of_red_k_preserves_recursive_wrap_ready_refined_state_regular_when_case1_context :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt (KCons Red (PNode pre i suf) tail) ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_recursive_wrap_ready_refined_state_at
      (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_recursive_repair_ready_refined_at k i tail ->
    @recursive_case1_context_ready A ->
    green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c' ->
    kchain_top_color c' <> Red /\
    kt4_level_recursive_wrap_ready_refined_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpkt Htail Hctx Hcase1 Hred.
  eapply green_of_red_k_preserves_recursive_wrap_ready_refined_state_regular_when_case1_wraps;
    eauto.
  intros b c_case1 Htail_eq Hi_eq Hred_case1.
  subst tail i.
  assert (Hctx_old :
    packet_context_recursive_repair_ready_at k Hole (KEnding b)).
  { inversion Hctx; subst; clear Hctx; try discriminate.
    exact H. }
  destruct (@green_of_red_k_preserves_recursive_wrap_ready_state_regular_when_case1_context
      A k pre Hole suf (KEnding b) c_case1
      Hreg Hpkt Htail Hctx_old (Hcase1 k) Hred_case1) as [_ Hstate_old].
  eapply kt4_level_recursive_wrap_ready_state_refined_state_at.
  exact Hstate_old.
Qed.

Theorem push_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_repair_regular_when_case1_context :
  forall A (x a b c d : E.t A) i suf tail c',
    E.level A x = 0 ->
    regular_kt (KCons Yellow (PNode (B4 a b c d) i suf) tail) ->
    kt4_public_level_recursive_wrap_ready_refined_state
      (KCons Yellow (PNode (B4 a b c d) i suf) tail) ->
    @recursive_case1_context_ready A ->
    push_kt4 x (KCons Yellow (PNode (B4 a b c d) i suf) tail) =
      PushOk c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A x a b c d i suf tail c' Hx Hreg [_ Hstate] Hcase1 Hpush.
  cbn in Hstate.
  destruct Hstate as [_ [_ [Hpkt [Htail Hctx]]]].
  apply regular_kt_yellow_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  unfold push_kt4 in Hpush; cbn -[green_of_red_k] in Hpush.
  destruct (green_of_red_k
      (KCons Red (PNode (B5 x a b c d) i suf) tail)) as [c''|]
    eqn:Hred; [|discriminate].
  inversion Hpush; subst c''; clear Hpush.
  inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
  cbn in Hpre_levels.
  destruct Hpre_levels as [Ha [Hb [Hc Hd]]].
  assert (Hreg_red :
    regular_kt (KCons Red (PNode (B5 x a b c d) i suf) tail)).
  { constructor; [exact I|exact Htail_top|exact Htail_reg]. }
  assert (Hpkt_red : packet_levels 0 (PNode (B5 x a b c d) i suf)).
  { constructor; cbn; [repeat split; assumption|assumption|assumption]. }
  assert (Htail_red : kt4_level_recursive_wrap_ready_refined_state_at
      (0 + packet_depth (PNode (B5 x a b c d) i suf)) tail).
  { replace (0 + packet_depth (PNode (B5 x a b c d) i suf))
      with (0 + packet_depth (PNode (B4 a b c d) i suf)) by (cbn; lia).
    exact Htail. }
  destruct (@green_of_red_k_preserves_recursive_wrap_ready_refined_state_regular_when_case1_context
      A 0 (B5 x a b c d) i suf tail c'
      Hreg_red Hpkt_red Htail_red Hctx Hcase1 Hred) as [Htop' Hready'].
  split; assumption.
Qed.

Theorem inject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_repair_regular_when_case1_context :
  forall A pre i (a b c d x : E.t A) tail c',
    E.level A x = 0 ->
    regular_kt (KCons Yellow (PNode pre i (B4 a b c d)) tail) ->
    kt4_public_level_recursive_wrap_ready_refined_state
      (KCons Yellow (PNode pre i (B4 a b c d)) tail) ->
