    inject_kt4 (KCons Yellow (PNode pre i (B4 a b c d)) tail) x =
      PushOk c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A pre i a b c d x tail c' Hx Hreg [_ Hstate] Hcase1 Hinject.
  cbn in Hstate.
