      (KCons Yellow (PNode (B1 a) i suf) tail) ->
    @recursive_case1_context_ready A ->
    pop_kt4 (KCons Yellow (PNode (B1 a) i suf) tail) = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A a i suf tail x c' Hreg [_ Hstate] Hcase1 Hpop.
  cbn in Hstate.
  destruct Hstate as [_ [_ [Hpkt [Htail Hctx]]]].
  apply regular_kt_yellow_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  unfold pop_kt4 in Hpop; cbn -[green_of_red_k] in Hpop.
  destruct (green_of_red_k
      (KCons Red (PNode B0 i suf) tail)) as [c''|] eqn:Hred;
    [|discriminate].
  inversion Hpop; subst x c''; clear Hpop.
  inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
  assert (Hreg_red : regular_kt (KCons Red (PNode B0 i suf) tail)).
  { constructor; [exact I|exact Htail_top|exact Htail_reg]. }
  assert (Hpkt_red : packet_levels 0 (PNode B0 i suf)).
  { constructor; cbn; [exact I|assumption|assumption]. }
  assert (Htail_red : kt4_level_recursive_wrap_ready_refined_state_at
      (0 + packet_depth (PNode B0 i suf)) tail).
  { replace (0 + packet_depth (PNode B0 i suf))
      with (0 + packet_depth (PNode (B1 a) i suf)) by (cbn; lia).
    exact Htail. }
  destruct (@green_of_red_k_preserves_recursive_wrap_ready_refined_state_regular_when_case1_context
      A 0 B0 i suf tail c' Hreg_red Hpkt_red Htail_red Hctx Hcase1 Hred)
