Theorem eject_kt4_preserves_public_level_recursive_wrap_ready_refined_state_yellow_repair_regular_when_case1_context :
  forall A pre i (a : E.t A) tail x c',
    regular_kt (KCons Yellow (PNode pre i (B1 a)) tail) ->
    kt4_public_level_recursive_wrap_ready_refined_state
      (KCons Yellow (PNode pre i (B1 a)) tail) ->
    @recursive_case1_context_ready A ->
    eject_kt4 (KCons Yellow (PNode pre i (B1 a)) tail) = PopOk x c' ->
    kt4_public_level_recursive_wrap_ready_refined_state c'.
Proof.
  intros A pre i a tail x c' Hreg [_ Hstate] Hcase1 Heject.
  cbn in Hstate.
  destruct Hstate as [_ [_ [Hpkt [Htail Hctx]]]].
  apply regular_kt_yellow_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  unfold eject_kt4 in Heject; cbn -[green_of_red_k] in Heject.
  destruct (green_of_red_k
      (KCons Red (PNode pre i B0) tail)) as [c''|] eqn:Hred;
    [|discriminate].
  inversion Heject; subst x c''; clear Heject.
  inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
  assert (Hreg_red : regular_kt (KCons Red (PNode pre i B0) tail)).
  { constructor; [exact I|exact Htail_top|exact Htail_reg]. }
  assert (Hpkt_red : packet_levels 0 (PNode pre i B0)).
  { constructor; cbn; [assumption|assumption|exact I]. }
  assert (Htail_red : kt4_level_recursive_wrap_ready_refined_state_at
      (0 + packet_depth (PNode pre i B0)) tail).
  { replace (0 + packet_depth (PNode pre i B0))
      with (0 + packet_depth (PNode pre i (B1 a))) by (cbn; lia).
    exact Htail. }
  destruct (@green_of_red_k_preserves_recursive_wrap_ready_refined_state_regular_when_case1_context
      A 0 pre i B0 tail c' Hreg_red Hpkt_red Htail_red Hctx Hcase1 Hred)
    as [Htop' Hready'].
  split; assumption.
Qed.

Lemma make_small_chain_to_kchain_g_recursive_wrap_ready_state_and_context_when_case1_context :
  forall A k (pre b suf : Buf5 (E.t A)) c,
    buf_all_at_level (S k) pre ->
    buf_all_at_level (S (S k)) b ->
    buf_all_at_level (S k) suf ->
    @recursive_case1_context_ready A ->
    make_small pre b suf = Some c ->
    kt4_level_recursive_wrap_ready_state_at (S k) (chain_to_kchain_g c) /\
    green_of_red_k_context_ready_at k Hole (chain_to_kchain_g c) /\
    packet_context_recursive_repair_ready_at k Hole (chain_to_kchain_g c).
Proof.
  intros A k pre b suf c Hpre Hb Hsuf Hcase1 Hmake.
  assert (Hpkt : packet_levels (S k) (PNode pre Hole suf)).
  { constructor; [exact Hpre|constructor|exact Hsuf]. }
  assert (Htail :
    kt4_level_recursive_wrap_ready_state_at
      (S k + packet_depth (PNode pre Hole suf)) (KEnding b)).
  { cbn. replace (S (k + 1)) with (S (S k)) by lia. exact Hb. }
  assert (Hctx_tail :
    packet_context_recursive_repair_ready_at (S k) Hole (KEnding b)).
  { constructor. exact Hb. }
  assert (Hreg :
    regular_kt (KCons Red (PNode pre Hole suf) (KEnding b))).
  { apply reg_kt_red; [cbn; exact I|cbn; discriminate|constructor]. }
  assert (Hred :
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
      Some (chain_to_kchain_g c)).
  { unfold green_of_red_k. rewrite Hmake. reflexivity. }
  destruct (@green_of_red_k_preserves_recursive_wrap_ready_state_regular_when_case1_context
      A (S k) pre Hole suf (KEnding b) (chain_to_kchain_g c)
      Hreg Hpkt Htail Hctx_tail
      (fun pre0 b0 suf0 c0 Hpre0 Hb0 Hsuf0 Hmake0 =>
         Hcase1 (S k) pre0 b0 suf0 c0 Hpre0 Hb0 Hsuf0 Hmake0)
      Hred) as [_ Hstate].
  repeat split.
  - exact Hstate.
  - exact (@make_small_chain_to_kchain_g_context_ready
      A k pre b suf c Hpre Hb Hsuf Hmake).
  - exact (Hcase1 k pre b suf c Hpre Hb Hsuf Hmake).
Qed.

Definition recursive_green_tail_parent_context_ready {A : Type} : Prop :=
  forall k (i : Packet A) tail c_tail,
    packet_context_recursive_green_ready_at k i tail ->
    green_of_red_k tail = Some c_tail ->
    packet_context_recursive_repair_ready_at k i c_tail.

Definition recursive_green_tail_parent_context_ready_refined {A : Type}
    : Prop :=
  forall k (i : Packet A) tail c_tail,
    packet_context_recursive_green_ready_refined_at k i tail ->
    green_of_red_k tail = Some c_tail ->
    packet_context_recursive_repair_ready_refined_at k i c_tail.

Lemma packet_context_recursive_green_ready_refined_chain_to_kchain_g_repair_ready :
  forall A k (i : Packet A) (c : Chain A),
    packet_context_recursive_green_ready_refined_at
      k i (chain_to_kchain_g c) ->
    packet_context_recursive_repair_ready_refined_at
      k i (chain_to_kchain_g c).
Proof.
  intros A k i c Hctx.
  eapply packet_context_recursive_green_ready_refined_repair_ready_non_red_tail.
  - apply kchain_top_color_chain_to_kchain_g_not_red.
  - exact Hctx.
Qed.

Lemma packet_context_recursive_repair_ready_refined_chain_to_kchain_g_green_ready :
  forall A k (i : Packet A) (c : Chain A),
    packet_context_recursive_repair_ready_refined_at
      k i (chain_to_kchain_g c) ->
    packet_context_recursive_green_ready_refined_at
      k i (chain_to_kchain_g c).
Proof.
  intros A k i c Hctx.
  eapply pcgrr_repair_refined_non_red_tail.
  - apply kchain_top_color_chain_to_kchain_g_not_red.
  - exact Hctx.
Qed.

Definition recursive_green_tail_parent_context_ready_refined_bottom_boundary
    {A : Type} : Prop :=
  forall k (pre suf red_pre red_suf : Buf5 (E.t A)) b c_tail,
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    buf5_is_not_red_or_empty_shape red_pre ->
    buf5_is_not_red_or_empty_shape red_suf ->
    (red_pre = B0 \/ red_suf = B0) ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_levels (S (S k)) (PNode red_pre Hole red_suf) ->
    buf_all_at_level (S (S (S k))) b ->
    green_of_red_k
      (KCons Red (PNode red_pre Hole red_suf) (KEnding b)) =
        Some c_tail ->
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre Hole suf) c_tail.

Definition recursive_green_tail_parent_context_ready_refined_bottom_boundary_components
    {A : Type} : Prop :=
  forall k (pre suf red_pre red_suf : Buf5 (E.t A)) b c_tail,
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
