      packet_context_recursive_repair_ready_refined_at k Hole c_inner.

Lemma packet_context_recursive_green_ready_red_hole_tail_impossible :
  forall A k (i : Packet A) tail,
    packet_context_recursive_green_ready_at k i (KCons Red Hole tail) ->
    False.
Proof.
  intros A k i.
  revert k.
  induction i as [|pre child IHchild suf]; intros k tail Hctx.
  - inversion Hctx; subst; clear Hctx; try discriminate.
    match goal with
    | Hrepair : packet_context_recursive_repair_ready_at _
        Hole (KCons Red Hole _) |- _ =>
        inversion Hrepair; subst; clear Hrepair; discriminate
    end.
  - inversion Hctx; subst; clear Hctx; try discriminate.
    match goal with
    | Hrepair : packet_context_recursive_repair_ready_at _
        (PNode pre child suf) (KCons Red Hole _) |- _ =>
        inversion Hrepair; subst; clear Hrepair; try discriminate
    end.
    match goal with
    | Hchild_ctx : packet_context_recursive_green_ready_at _
        _ (KCons Red Hole _) |- _ =>
        eapply IHchild; exact Hchild_ctx
    end.
Qed.

Definition recursive_repair_tail_parent_context_ready {A : Type} : Prop :=
  forall k (i : Packet A) tail c_tail,
    packet_context_recursive_repair_ready_at k i tail ->
    green_of_red_k tail = Some c_tail ->
    packet_context_recursive_repair_ready_at k i c_tail.

Definition packet_context_recursive_repair_ready_pnode_after_tail_repair_lift
    {A : Type} : Prop :=
  forall k (pre suf : Buf5 (E.t A)) c_tail,
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_context_recursive_repair_ready_at (S k) Hole c_tail ->
    packet_context_recursive_repair_ready_at
      k (PNode pre Hole suf) c_tail.

Definition packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation
    {A : Type} : Prop :=
  forall k (pre suf : Buf5 (E.t A)) c_tail,
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_context_recursive_repair_ready_at (S k) Hole c_tail ->
    forall (outer_pre outer_suf outer_pre' pre_after
        suf_after outer_suf' : Buf5 (E.t A)) c_inner,
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      prefix_concat outer_pre pre = Some (outer_pre', pre_after) ->
      suffix_concat suf outer_suf = Some (suf_after, outer_suf') ->
      green_of_red_k
        (KCons Red (PNode pre_after Hole suf_after) c_tail) =
        Some c_inner ->
      packet_context_recursive_repair_ready_at k Hole c_inner.

Lemma packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_from_post_red_continuation :
  forall A,
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation A ->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift A.
Proof.
  unfold
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation,
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift.
  intros A Hpost k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx.
  eapply pcrwr_pnode.
  - exact Hpre.
  - exact Hsuf.
  - exact Hpkt.
  - apply pcgwr_repair. exact Hctx.
  - intros outer_pre outer_suf outer_pre' pre_after
      suf_after outer_suf' c_inner Houter_pre Houter_suf
      Hpre_concat Hsuf_concat Hred_inner.
    exact (Hpost k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx
      outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
      c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation_from_lift :
  forall A,
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift A ->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation A.
Proof.
  unfold
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift,
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation.
  intros A Hlift k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  specialize (Hlift k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx).
  inversion Hlift as
      [| |? ? ? ? ? _ _ _ _ Hafter];
    subst; clear Hlift; try discriminate.
  exact (Hafter outer_pre outer_suf outer_pre' pre_after
    suf_after outer_suf' c_inner
    Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
Qed.

Theorem packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_iff_post_red_continuation :
  forall A,
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift A <->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation A.
Proof.
  intros A. split.
  - apply packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation_from_lift.
  - apply packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_from_post_red_continuation.
Qed.

Definition packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation
    {A : Type} : Prop :=
  forall k (pre suf : Buf5 (E.t A)) col
         (tail_pre : Buf5 (E.t A)) tail_child tail_suf tail
         outer_pre outer_suf outer_pre' pre_parent
         suf_parent outer_suf'
         case2_pre_out tail_pre' tail_suf' case2_suf_out,
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_context_recursive_repair_ready_at (S k) Hole
      (KCons col (PNode tail_pre tail_child tail_suf) tail) ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre_parent) ->
    suffix_concat suf outer_suf = Some (suf_parent, outer_suf') ->
    green_prefix_concat pre_parent tail_pre =
      Some (case2_pre_out, tail_pre') ->
    green_suffix_concat tail_suf suf_parent =
      Some (tail_suf', case2_suf_out) ->
    forall (future_pre future_suf future_pre' pre_after
        suf_after future_suf' : Buf5 (E.t A)),
      buf_all_at_level k future_pre ->
      buf_all_at_level k future_suf ->
      green_prefix_concat future_pre case2_pre_out =
        Some (future_pre', pre_after) ->
      green_suffix_concat case2_suf_out future_suf =
        Some (suf_after, future_suf') ->
      packet_context_recursive_green_ready_at k
        (PNode pre_after (PNode tail_pre' tail_child tail_suf') suf_after)
        tail.

Definition packet_context_recursive_green_ready_pnode_from_strict_child_context
    {A : Type} : Prop :=
  forall k (pre suf child_pre : Buf5 (E.t A)) child child_suf tail,
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels
      (S k) (PNode pre (PNode child_pre child child_suf) suf) ->
    packet_context_recursive_green_ready_at
      (S k) (PNode child_pre child child_suf) tail ->
    packet_context_recursive_green_ready_at
      k (PNode pre (PNode child_pre child child_suf) suf) tail.

Definition packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output
    {A : Type} : Prop :=
  forall k (pre suf child_pre : Buf5 (E.t A)) child child_suf tail
         outer_pre outer_suf outer_pre' pre_after
         suf_after outer_suf'
         case3_pre_out child_pre_after child_suf_after case3_suf_out,
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels
      (S k) (PNode pre (PNode child_pre child child_suf) suf) ->
    packet_context_recursive_green_ready_at
      (S k) (PNode child_pre child child_suf) tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre_after) ->
    suffix_concat suf outer_suf = Some (suf_after, outer_suf') ->
    prefix_concat pre_after child_pre =
      Some (case3_pre_out, child_pre_after) ->
    suffix_concat child_suf suf_after =
      Some (child_suf_after, case3_suf_out) ->
    packet_context_recursive_repair_ready_at k Hole
      (KCons Green
        (PNode case3_pre_out Hole case3_suf_out)
        (KCons Red
          (PNode child_pre_after child child_suf_after) tail)).

Definition packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_continuation
    {A : Type} : Prop :=
  forall k (pre suf child_pre : Buf5 (E.t A)) child child_suf tail
         outer_pre outer_suf outer_pre' pre_after
         suf_after outer_suf'
         case3_pre_out child_pre_after child_suf_after case3_suf_out,
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels
      (S k) (PNode pre (PNode child_pre child child_suf) suf) ->
    packet_context_recursive_green_ready_at
      (S k) (PNode child_pre child child_suf) tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre_after) ->
    suffix_concat suf outer_suf = Some (suf_after, outer_suf') ->
    prefix_concat pre_after child_pre =
      Some (case3_pre_out, child_pre_after) ->
    suffix_concat child_suf suf_after =
      Some (child_suf_after, case3_suf_out) ->
    forall future_pre future_suf future_pre' pre_out
           suf_out future_suf',
      buf_all_at_level k future_pre ->
      buf_all_at_level k future_suf ->
      green_prefix_concat future_pre case3_pre_out =
        Some (future_pre', pre_out) ->
      green_suffix_concat case3_suf_out future_suf =
        Some (suf_out, future_suf') ->
      packet_context_recursive_green_ready_at k
        (PNode pre_out Hole suf_out)
        (KCons Red
          (PNode child_pre_after child child_suf_after) tail).

Theorem packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_continuation_gap_when_case1_context :
  ~ (@recursive_case1_context_ready nat /\
     @packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_continuation nat).
Proof.
  intros [Hcase1 Hcontinuation].
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  apply packet_context_recursive_green_ready_pnode_red_tail_boundary_gap.
  assert (Hchild_ctx :
    packet_context_recursive_green_ready_at 1
      (PNode (B2 q q) Hole (B1 q)) (KEnding B0)).
  { eapply pcgwr_repair.
    eapply pcrwr_pnode.
    - cbn. exact I.
    - cbn. exact I.
    - constructor.
      + unfold q, p, z. cbn. repeat split; reflexivity.
      + constructor.
      + unfold q, p, z. cbn. reflexivity.
    - eapply pcgwr_repair.
      constructor.
      cbn. exact I.
    - intros outer_pre outer_suf outer_pre' pre_after
        suf_after outer_suf' c_inner
        Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
      destruct (@prefix_concat_preserves_outer_green_levels
          nat 1 outer_pre (B2 q q) outer_pre' pre_after
          Houter_pre
          ltac:(unfold q, p, z; cbn; repeat split; reflexivity)
          ltac:(cbn; exact I)
          Hpre_concat)
        as [_ [_ Hpre_after_level]].
      destruct (@suffix_concat_preserves_outer_green_levels
          nat 1 (B1 q) outer_suf suf_after outer_suf'
          ltac:(unfold q, p, z; cbn; reflexivity)
          Houter_suf
          ltac:(cbn; exact I)
          Hsuf_concat)
        as [Hsuf_after_level _].
      unfold green_of_red_k in Hred_inner.
      destruct (make_small pre_after B0 suf_after) as [c0|] eqn:Hmake;
        [|discriminate].
      inversion Hred_inner; subst c_inner; clear Hred_inner.
      exact (Hcase1 1 pre_after B0 suf_after c0
        Hpre_after_level ltac:(cbn; exact I) Hsuf_after_level Hmake). }
  exact (Hcontinuation
      0 (B1 p) (B1 p) (B2 q q) Hole (B1 q) (KEnding B0)
      B0 B0 (B2 z z) B0 B0 (B2 z z)
      (B2 p p) (B1 q) B0 (B2 p p)
      Hcase1
      ltac:(cbn; exact I)
      ltac:(cbn; exact I)
      ltac:(constructor;
        [unfold p, z; cbn; reflexivity
        |constructor;
          [unfold q, p, z; cbn; repeat split; reflexivity
          |constructor
          |unfold q, p, z; cbn; reflexivity]
        |unfold p, z; cbn; reflexivity])
      Hchild_ctx
      ltac:(cbn; exact I)
      ltac:(cbn; exact I)
      ltac:(unfold p, z; cbn; reflexivity)
      ltac:(unfold p, z; cbn; reflexivity)
      ltac:(unfold q, p, z; cbn; reflexivity)
      ltac:(unfold q, p, z; cbn; reflexivity)
      B0 B0 (B2 z z) (B1 p) (B1 p) (B2 z z)
      ltac:(cbn; exact I)
      ltac:(cbn; exact I)
      ltac:(unfold p, z; cbn; reflexivity)
      ltac:(unfold p, z; cbn; reflexivity)).
Qed.

Theorem packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_gap_when_case1_context :
  ~ (@recursive_case1_context_ready nat /\
     @packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output nat).
Proof.
  intros [Hcase1 Houtput].
  set (z := E.base nat 0).
  set (p := E.pair nat z z eq_refl).
  set (q := E.pair nat p p eq_refl).
  assert (Hchild_ctx :
    packet_context_recursive_green_ready_at 1
      (PNode (B2 q q) Hole (B1 q)) (KEnding B0)).
  { eapply pcgwr_repair.
    eapply pcrwr_pnode.
    - cbn. exact I.
    - cbn. exact I.
    - constructor.
      + unfold q, p, z. cbn. repeat split; reflexivity.
      + constructor.
      + unfold q, p, z. cbn. reflexivity.
    - eapply pcgwr_repair.
      constructor.
      cbn. exact I.
    - intros outer_pre outer_suf outer_pre' pre_after
        suf_after outer_suf' c_inner
        Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
      destruct (@prefix_concat_preserves_outer_green_levels
          nat 1 outer_pre (B2 q q) outer_pre' pre_after
          Houter_pre
          ltac:(unfold q, p, z; cbn; repeat split; reflexivity)
          ltac:(cbn; exact I)
          Hpre_concat)
        as [_ [_ Hpre_after_level]].
      destruct (@suffix_concat_preserves_outer_green_levels
          nat 1 (B1 q) outer_suf suf_after outer_suf'
          ltac:(unfold q, p, z; cbn; reflexivity)
          Houter_suf
          ltac:(cbn; exact I)
          Hsuf_concat)
        as [Hsuf_after_level _].
      unfold green_of_red_k in Hred_inner.
      destruct (make_small pre_after B0 suf_after) as [c0|] eqn:Hmake;
        [|discriminate].
      inversion Hred_inner; subst c_inner; clear Hred_inner.
      exact (Hcase1 1 pre_after B0 suf_after c0
        Hpre_after_level ltac:(cbn; exact I) Hsuf_after_level Hmake). }
  pose proof (Houtput
      0 (B1 p) (B1 p) (B2 q q) Hole (B1 q) (KEnding B0)
      B0 B0 (B2 z z) B0 B0 (B2 z z)
      (B2 p p) (B1 q) B0 (B2 p p)
      Hcase1
      ltac:(cbn; exact I)
      ltac:(cbn; exact I)
      ltac:(constructor;
        [unfold p, z; cbn; reflexivity
        |constructor;
          [unfold q, p, z; cbn; repeat split; reflexivity
          |constructor
          |unfold q, p, z; cbn; reflexivity]
        |unfold p, z; cbn; reflexivity])
      Hchild_ctx
      ltac:(cbn; exact I)
      ltac:(cbn; exact I)
      ltac:(unfold p, z; cbn; reflexivity)
      ltac:(unfold p, z; cbn; reflexivity)
      ltac:(unfold q, p, z; cbn; reflexivity)
      ltac:(unfold q, p, z; cbn; reflexivity)) as Hrepair.
  inversion Hrepair as
      [|? ? ? ? ? ? _ _ _ _ Hafter|]; subst; clear Hrepair.
  apply packet_context_recursive_green_ready_pnode_red_tail_boundary_gap.
  exact (Hafter
      B0 B0 (B2 z z) (B1 p) (B1 p) (B2 z z)
      ltac:(cbn; exact I)
      ltac:(cbn; exact I)
      ltac:(unfold p, z; cbn; reflexivity)
      ltac:(unfold p, z; cbn; reflexivity)).
Qed.

Lemma packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_from_continuation :
  forall A,
    @packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_continuation A ->
    @packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output A.
Proof.
  unfold
    packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_continuation,
    packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output.
  intros A Hcontinuation k pre suf child_pre child child_suf tail
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    case3_pre_out child_pre_after child_suf_after case3_suf_out
    Hcase1 Hpre Hsuf Hpkt Hchild_ctx
    Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase3_pre Hcase3_suf.
  pose proof Hchild_ctx as Hchild_ctx_orig.
  inversion Hpkt as [|? ? ? ? Hpre_level Hchild_pkt_parent Hsuf_level]; subst.
  inversion Hchild_ctx as [? ? ? Hchild_repair|]; subst; clear Hchild_ctx;
    try discriminate.
  inversion Hchild_repair as
      [| |? ? ? ? ? Hchild_pre_shape Hchild_suf_shape Hchild_pkt
           Hgrandchild_ctx Hchild_after];
    subst; clear Hchild_repair; try discriminate.
  inversion Hchild_pkt as [|? ? ? ? Hchild_pre_level Hchild_level Hchild_suf_level];
    subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre_after
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre_after_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf_after outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf_after_level _].
  destruct (@prefix_concat_preserves_outer_green_levels
      A (S k) pre_after child_pre case3_pre_out child_pre_after
      Hpre_after_level Hchild_pre_level Hchild_pre_shape Hcase3_pre)
    as [Hcase3_pre_shape [Hcase3_pre_level Hchild_pre_after_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A (S k) child_suf suf_after child_suf_after case3_suf_out
      Hchild_suf_level Hsuf_after_level Hchild_suf_shape Hcase3_suf)
    as [Hchild_suf_after_level [Hcase3_suf_shape Hcase3_suf_level]].
  assert (Hred_tail_pkt :
    packet_levels (S (S k))
      (PNode child_pre_after child child_suf_after)).
  { constructor; [exact Hchild_pre_after_level|exact Hchild_level|exact Hchild_suf_after_level]. }
  assert (Hred_tail_ctx :
    packet_context_recursive_green_ready_at (S k) Hole
      (KCons Red
        (PNode child_pre_after child child_suf_after) tail)).
  { eapply pcgwr_hole_red_kcons.
    - exact Hred_tail_pkt.
    - exact Hgrandchild_ctx.
    - intros c' Hred.
      exact (Hchild_after pre_after suf_after case3_pre_out
        child_pre_after child_suf_after case3_suf_out c'
        Hpre_after_level Hsuf_after_level Hcase3_pre Hcase3_suf Hred). }
  eapply pcrwr_hole_kcons.
  - exact Hcase3_pre_shape.
  - exact Hcase3_suf_shape.
  - constructor; [exact Hcase3_pre_level|constructor|exact Hcase3_suf_level].
  - exact Hred_tail_ctx.
  - intros future_pre future_suf future_pre' pre_out
      suf_out future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
    exact (Hcontinuation k pre suf child_pre child child_suf tail
      outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
      case3_pre_out child_pre_after child_suf_after case3_suf_out
      Hcase1 Hpre Hsuf Hpkt Hchild_ctx_orig
      Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hcase3_pre Hcase3_suf
      future_pre future_suf future_pre' pre_out suf_out future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat).
Qed.

Lemma packet_context_recursive_green_ready_pnode_from_strict_child_context_from_case3_output :
  forall A,
    @packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output A ->
    @packet_context_recursive_green_ready_pnode_from_strict_child_context A.
Proof.
  unfold
    packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output,
    packet_context_recursive_green_ready_pnode_from_strict_child_context.
  intros A Hcase3_output k pre suf child_pre child child_suf tail
    Hcase1 Hpre Hsuf Hpkt Hchild_ctx.
  eapply pcgwr_repair.
  eapply pcrwr_pnode.
  - exact Hpre.
  - exact Hsuf.
  - exact Hpkt.
  - exact Hchild_ctx.
  - intros outer_pre outer_suf outer_pre' pre_after
      suf_after outer_suf' c_inner
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
    unfold green_of_red_k in Hred_inner.
    destruct (prefix_concat pre_after child_pre)
      as [[case3_pre_out child_pre_after]|] eqn:Hcase3_pre;
      [|discriminate].
    destruct (suffix_concat child_suf suf_after)
      as [[child_suf_after case3_suf_out]|] eqn:Hcase3_suf;
      [|discriminate].
    inversion Hred_inner; subst c_inner; clear Hred_inner.
    exact (Hcase3_output k pre suf child_pre child child_suf tail
      outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
      case3_pre_out child_pre_after child_suf_after case3_suf_out
      Hcase1 Hpre Hsuf Hpkt Hchild_ctx
      Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hcase3_pre Hcase3_suf).
Qed.

Lemma packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_from_pnode_context :
  forall A,
    @packet_context_recursive_green_ready_pnode_from_strict_child_context A ->
    @packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output A.
Proof.
  unfold
    packet_context_recursive_green_ready_pnode_from_strict_child_context,
    packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output.
  intros A Hpnode k pre suf child_pre child child_suf tail
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    case3_pre_out child_pre_after child_suf_after case3_suf_out
    Hcase1 Hpre Hsuf Hpkt Hchild_ctx
    Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase3_pre Hcase3_suf.
  pose proof (Hpnode k pre suf child_pre child child_suf tail
      Hcase1 Hpre Hsuf Hpkt Hchild_ctx) as Hparent_ctx.
  inversion Hparent_ctx as [? ? ? Hrepair|]; subst; clear Hparent_ctx.
  inversion Hrepair as
      [| |? ? ? ? ? _ _ _ _ Hafter]; subst; clear Hrepair;
    try discriminate.
  eapply Hafter.
  - exact Houter_pre.
  - exact Houter_suf.
  - exact Hpre_concat.
  - exact Hsuf_concat.
  - unfold green_of_red_k.
    rewrite Hcase3_pre. rewrite Hcase3_suf. reflexivity.
Qed.

Theorem packet_context_recursive_green_ready_pnode_from_strict_child_context_gap_when_case1_context :
  ~ (@recursive_case1_context_ready nat /\
     @packet_context_recursive_green_ready_pnode_from_strict_child_context nat).
Proof.
  intros [Hcase1 Hpnode].
  apply
    packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_gap_when_case1_context.
  split; [exact Hcase1|].
  eapply packet_context_recursive_green_ready_pnode_from_strict_child_context_case3_output_from_pnode_context.
  exact Hpnode.
Qed.

Lemma packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation_ending :
  forall A k (pre suf b : Buf5 (E.t A)),
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    buf_all_at_level (S (S k)) b ->
    forall (outer_pre outer_suf outer_pre' pre_after
        suf_after outer_suf' : Buf5 (E.t A)) c_inner,
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      prefix_concat outer_pre pre = Some (outer_pre', pre_after) ->
      suffix_concat suf outer_suf = Some (suf_after, outer_suf') ->
      green_of_red_k
        (KCons Red (PNode pre_after Hole suf_after) (KEnding b)) =
        Some c_inner ->
      packet_context_recursive_repair_ready_at k Hole c_inner.
Proof.
  intros A k pre suf b Hcase1 Hpre Hsuf Hpkt Hb
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre_after
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre_after_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf_after outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf_after_level _].
  unfold green_of_red_k in Hred_inner.
  destruct (make_small pre_after b suf_after) as [c0|] eqn:Hmake;
    [|discriminate].
  inversion Hred_inner; subst c_inner; clear Hred_inner.
  exact (Hcase1 k pre_after b suf_after c0
    Hpre_after_level Hb Hsuf_after_level Hmake).
Qed.

Lemma packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation_from_kcons_continuation :
  forall A,
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation A ->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation A.
Proof.
  unfold
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation,
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation.
  intros A Hcontinuation k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx
    outer_pre outer_suf outer_pre' pre_parent suf_parent outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  destruct c_tail as [b|col p tail].
  - inversion Hctx as [k0 b0 Hb| |]; subst; clear Hctx; try discriminate.
    exact
      (@packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation_ending
        A k pre suf b Hcase1 Hpre Hsuf Hpkt Hb
        outer_pre outer_suf outer_pre' pre_parent suf_parent outer_suf'
        c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
  - destruct p as [|tail_pre tail_child tail_suf].
    + inversion Hctx.
    + pose proof Hctx as Hctx_orig.
      inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
      inversion Hctx as
          [|? ? ? ? ? ? Htail_pre_shape Htail_suf_shape Htail_pkt
               Htail_child Htail_after|]; subst; clear Hctx;
        try discriminate.
      destruct (@prefix_concat_preserves_outer_green_levels
          A k outer_pre pre outer_pre' pre_parent
          Houter_pre Hpre_level Hpre Hpre_concat)
        as [_ [_ Hpre_parent_level]].
      destruct (@suffix_concat_preserves_outer_green_levels
          A k suf outer_suf suf_parent outer_suf'
          Hsuf_level Houter_suf Hsuf Hsuf_concat)
        as [Hsuf_parent_level _].
      unfold green_of_red_k in Hred_inner.
      destruct (green_prefix_concat pre_parent tail_pre)
        as [[case2_pre_out tail_pre']|] eqn:Hcase2_pre;
        [|discriminate].
      destruct (green_suffix_concat tail_suf suf_parent)
        as [[tail_suf' case2_suf_out]|] eqn:Hcase2_suf;
        [|discriminate].
      inversion Hred_inner; subst c_inner; clear Hred_inner.
      inversion Htail_pkt as [|? ? ? ? Htail_pre_level
          Htail_child_level Htail_suf_level]; subst.
      destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
          A (S k) pre_parent tail_pre case2_pre_out tail_pre'
          Hpre_parent_level Htail_pre_level Htail_pre_shape Hcase2_pre)
        as [Hcase2_pre_shape [_ [Hcase2_pre_level Htail_pre'_level]]].
      destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
          A (S k) tail_suf suf_parent tail_suf' case2_suf_out
          Htail_suf_level Hsuf_parent_level Htail_suf_shape Hcase2_suf)
        as [_ [Hcase2_suf_shape [Htail_suf'_level Hcase2_suf_level]]].
      eapply pcrwr_hole_kcons.
      * exact Hcase2_pre_shape.
      * exact Hcase2_suf_shape.
      * constructor.
        -- exact Hcase2_pre_level.
        -- constructor; [exact Htail_pre'_level|exact Htail_child_level|exact Htail_suf'_level].
        -- exact Hcase2_suf_level.
      * exact (Htail_after pre_parent suf_parent case2_pre_out
          tail_pre' tail_suf' case2_suf_out
          Hpre_parent_level Hsuf_parent_level Hcase2_pre Hcase2_suf).
      * intros future_pre future_suf future_pre' pre_after
          suf_after future_suf'
          Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
        exact (Hcontinuation k pre suf col tail_pre tail_child tail_suf tail
          outer_pre outer_suf outer_pre' pre_parent suf_parent outer_suf'
          case2_pre_out tail_pre' tail_suf' case2_suf_out
          Hcase1 Hpre Hsuf Hpkt Hctx_orig
          Houter_pre Houter_suf Hpre_concat Hsuf_concat
          Hcase2_pre Hcase2_suf
          future_pre future_suf future_pre' pre_after suf_after future_suf'
          Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat).
Qed.

Lemma packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_from_kcons_continuation :
  forall A,
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation A ->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift A.
Proof.
  intros A Hcontinuation.
  eapply packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_from_post_red_continuation.
  eapply packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation_from_kcons_continuation.
  exact Hcontinuation.
Qed.

Lemma packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation_from_pnode_strict_child_context :
  forall A,
    @packet_context_recursive_green_ready_pnode_from_strict_child_context A ->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation A.
Proof.
  unfold
    packet_context_recursive_green_ready_pnode_from_strict_child_context,
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation.
  intros A Hpnode k pre suf col tail_pre tail_child tail_suf tail
    outer_pre outer_suf outer_pre' pre_parent suf_parent outer_suf'
    case2_pre_out tail_pre' tail_suf' case2_suf_out
    Hcase1 Hpre Hsuf Hpkt Hctx
    Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase2_pre Hcase2_suf
    future_pre future_suf future_pre' pre_after suf_after future_suf'
    Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  inversion Hctx as
      [|? ? ? ? ? ? Htail_pre_shape Htail_suf_shape Htail_pkt
           _Htail_child_ctx Htail_after|];
    subst; clear Hctx; try discriminate.
  inversion Htail_pkt as [|? ? ? ? Htail_pre_level
      Htail_child_level Htail_suf_level]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre_parent
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre_parent_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf_parent outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf_parent_level _].
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A (S k) pre_parent tail_pre case2_pre_out tail_pre'
      Hpre_parent_level Htail_pre_level Htail_pre_shape Hcase2_pre)
    as [Hcase2_pre_shape [_ [Hcase2_pre_level Htail_pre'_level]]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A (S k) tail_suf suf_parent tail_suf' case2_suf_out
      Htail_suf_level Hsuf_parent_level Htail_suf_shape Hcase2_suf)
    as [_ [Hcase2_suf_shape [Htail_suf'_level Hcase2_suf_level]]].
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k future_pre case2_pre_out future_pre' pre_after
      Hfuture_pre Hcase2_pre_level Hcase2_pre_shape Hfuture_pre_concat)
    as [_ [Hpre_after_shape [_ Hpre_after_level]]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k case2_suf_out future_suf suf_after future_suf'
      Hcase2_suf_level Hfuture_suf Hcase2_suf_shape Hfuture_suf_concat)
    as [Hsuf_after_shape [_ [Hsuf_after_level _]]].
  assert (Htail_pkt' :
    packet_levels (S (S k)) (PNode tail_pre' tail_child tail_suf')).
  { constructor; [exact Htail_pre'_level|exact Htail_child_level|exact Htail_suf'_level]. }
  assert (Hparent_pkt :
    packet_levels (S k)
      (PNode pre_after (PNode tail_pre' tail_child tail_suf') suf_after)).
  { constructor; [exact Hpre_after_level|exact Htail_pkt'|exact Hsuf_after_level]. }
  assert (Hchild_ctx :
    packet_context_recursive_green_ready_at (S k)
      (PNode tail_pre' tail_child tail_suf') tail).
  { exact (Htail_after pre_parent suf_parent case2_pre_out
      tail_pre' tail_suf' case2_suf_out
      Hpre_parent_level Hsuf_parent_level Hcase2_pre Hcase2_suf). }
  exact (Hpnode k pre_after suf_after tail_pre' tail_child tail_suf' tail
    Hcase1 Hpre_after_shape Hsuf_after_shape Hparent_pkt Hchild_ctx).
Qed.

Lemma packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_kcons_continuation_from_pnode_strict_child_context_case3_output :
  forall A,
