Lemma packet_context_recursive_green_ready_refined_hole_red_pnode_hole_ending_from_case1_context :
  forall A k (pre suf b : Buf5 (E.t A)),
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
