    buf_all_at_level (S (S k)) b ->
    packet_context_recursive_green_ready_refined_at k Hole
      (KCons Red (PNode pre Hole suf) (KEnding b)).
Proof.
  intros A k pre suf b Hcase1 Hpre Hsuf Hpkt Hb.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  eapply pcgrr_hole_red_kcons_refined.
  - exact Hpkt.
  - apply pcgrr_existing. apply pcgwr_repair. constructor. exact Hb.
  - intros c' Hred.
    unfold green_of_red_k in Hred.
    destruct (make_small pre b suf) as [c0|] eqn:Hmake; [|discriminate].
    inversion Hred; subst c'; clear Hred.
