Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation_from_green_tail_and_post_green_continuation :
  forall A,
    @recursive_green_tail_parent_context_ready A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_post_green_continuation A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation A.
Proof.
  unfold
    recursive_green_tail_parent_context_ready,
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_post_green_continuation,
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation.
  intros A Hgreen_tail Hpost k pre suf child_pre child child_suf
    red_pre red_child red_suf tail Hcase1 Hpre Hsuf Hpkt Hchild_ctx
    c_tail Hred_tail.
  eapply pcrrr_pnode.
  - exact Hpre.
  - exact Hsuf.
  - exact Hpkt.
  - eapply pcgrr_repair_refined_non_red_tail.
    + pose proof Hred_tail as Htop.
      apply green_of_red_k_top_green in Htop.
      rewrite Htop. discriminate.
    + apply pcrrr_existing.
      exact (Hgreen_tail (S k) (PNode child_pre child child_suf)
        (KCons Red (PNode red_pre red_child red_suf) tail)
        c_tail Hchild_ctx Hred_tail).
  - intros outer_pre outer_suf outer_pre' pre_after
      suf_after outer_suf' c_inner Houter_pre Houter_suf
      Hpre_concat Hsuf_concat Hred_inner.
    exact (Hpost k pre suf child_pre child child_suf
      red_pre red_child red_suf tail c_tail
      Hcase1 Hpre Hsuf Hpkt Hchild_ctx Hred_tail
      outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
      c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_post_green_callback_from_child_repair_and_lift :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    forall k (pre suf child_pre : Buf5 (E.t A)) child child_suf
           c_tail,
      @recursive_case1_context_ready A ->
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels
        (S k) (PNode pre (PNode child_pre child child_suf) suf) ->
      packet_context_recursive_repair_ready_at
        (S k) (PNode child_pre child child_suf) c_tail ->
      forall (outer_pre outer_suf outer_pre' pre_after
          suf_after outer_suf' : Buf5 (E.t A)) c_inner,
        buf_all_at_level k outer_pre ->
        buf_all_at_level k outer_suf ->
        prefix_concat outer_pre pre = Some (outer_pre', pre_after) ->
        suffix_concat suf outer_suf = Some (suf_after, outer_suf') ->
        green_of_red_k
          (KCons Red
            (PNode pre_after (PNode child_pre child child_suf) suf_after)
            c_tail) = Some c_inner ->
        packet_context_recursive_repair_ready_refined_at k Hole c_inner.
Proof.
  intros A Hlift k pre suf child_pre child child_suf c_tail
    Hcase1 Hpre Hsuf Hpkt Hchild_repair
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  inversion Hpkt as [|? ? ? ? Hpre_level Hchild_pkt Hsuf_level];
    subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre_after
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre_after_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf_after outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf_after_level _].
  inversion Hchild_repair as
      [| |? ? ? ? ? Hchild_pre_shape Hchild_suf_shape Hchild_pkt'
           Hchild_green Hchild_after];
    subst; clear Hchild_repair; try discriminate.
  inversion Hchild_pkt' as [|? ? ? ? Hchild_pre_level
      Hchild_level Hchild_suf_level]; subst.
  unfold green_of_red_k in Hred_inner.
  destruct (prefix_concat pre_after child_pre)
    as [[case3_pre_out child_pre_after]|] eqn:Hcase3_pre;
    [|discriminate].
  destruct (suffix_concat child_suf suf_after)
    as [[child_suf_after case3_suf_out]|] eqn:Hcase3_suf;
    [|discriminate].
  inversion Hred_inner; subst c_inner; clear Hred_inner.
  destruct (@prefix_concat_preserves_outer_green_levels
      A (S k) pre_after child_pre case3_pre_out child_pre_after
      Hpre_after_level Hchild_pre_level Hchild_pre_shape Hcase3_pre)
    as [Hcase3_pre_shape [Hcase3_pre_level Hchild_pre_after_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A (S k) child_suf suf_after child_suf_after case3_suf_out
      Hchild_suf_level Hsuf_after_level Hchild_suf_shape Hcase3_suf)
    as [Hchild_suf_after_level [Hcase3_suf_shape Hcase3_suf_level]].
  assert (Hchild_after_pkt :
    packet_levels (S (S k))
      (PNode child_pre_after child child_suf_after)).
  { constructor; [exact Hchild_pre_after_level|exact Hchild_level|exact Hchild_suf_after_level]. }
  assert (Hhole_red_ctx :
    packet_context_recursive_green_ready_refined_at (S k) Hole
      (KCons Red (PNode child_pre_after child child_suf_after)
        c_tail)).
  { eapply pcgrr_hole_red_kcons_refined.
    - exact Hchild_after_pkt.
    - apply pcgrr_existing. exact Hchild_green.
    - intros c_child Hred_child.
      apply pcrrr_existing.
      exact (Hchild_after pre_after suf_after case3_pre_out
        child_pre_after child_suf_after case3_suf_out c_child
        Hpre_after_level Hsuf_after_level Hcase3_pre Hcase3_suf
        Hred_child). }
  eapply pcrrr_hole_kcons.
  - exact Hcase3_pre_shape.
  - exact Hcase3_suf_shape.
  - constructor; [exact Hcase3_pre_level|constructor|exact Hcase3_suf_level].
  - exact Hhole_red_ctx.
  - intros future_pre future_suf future_pre' pre_next
      suf_next future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k future_pre case3_pre_out future_pre' pre_next
        Hfuture_pre Hcase3_pre_level Hcase3_pre_shape
        Hfuture_pre_concat)
      as [_ [Hpre_next_shape [_ Hpre_next_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k case3_suf_out future_suf suf_next future_suf'
        Hcase3_suf_level Hfuture_suf Hcase3_suf_shape
        Hfuture_suf_concat)
      as [Hsuf_next_shape [_ [Hsuf_next_level _]]].
    eapply pcgrr_pnode_red_tail_refined.
    + exact Hpre_next_shape.
    + exact Hsuf_next_shape.
    + constructor; [exact Hpre_next_level|constructor|exact Hsuf_next_level].
    + exact Hhole_red_ctx.
    + intros c_child Hred_child.
      eapply Hlift.
      * exact Hcase1.
      * exact Hpre_next_shape.
      * exact Hsuf_next_shape.
      * constructor; [exact Hpre_next_level|constructor|exact Hsuf_next_level].
      * exact (Hchild_after pre_after suf_after case3_pre_out
          child_pre_after child_suf_after case3_suf_out c_child
          Hpre_after_level Hsuf_after_level Hcase3_pre Hcase3_suf
          Hred_child).
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation_from_green_tail_and_lift :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    @recursive_green_tail_parent_context_ready A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation A.
Proof.
  unfold
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation.
  intros A Hlift Hgreen_tail k pre suf child_pre child child_suf
    red_pre red_child red_suf tail Hcase1 Hpre Hsuf Hpkt Hchild_ctx
    c_tail Hred_tail.
  eapply pcrrr_pnode.
  - exact Hpre.
  - exact Hsuf.
  - exact Hpkt.
  - eapply pcgrr_repair_refined_non_red_tail.
    + pose proof Hred_tail as Htop.
      apply green_of_red_k_top_green in Htop.
      rewrite Htop. discriminate.
    + apply pcrrr_existing.
      exact (Hgreen_tail (S k) (PNode child_pre child child_suf)
        (KCons Red (PNode red_pre red_child red_suf) tail)
        c_tail Hchild_ctx Hred_tail).
  - intros outer_pre outer_suf outer_pre' pre_after
      suf_after outer_suf' c_inner Houter_pre Houter_suf
      Hpre_concat Hsuf_concat Hred_inner.
    eapply packet_context_recursive_green_ready_refined_pnode_post_green_callback_from_child_repair_and_lift.
    + exact Hlift.
    + exact Hcase1.
    + exact Hpre.
    + exact Hsuf.
    + exact Hpkt.
    + exact (Hgreen_tail (S k) (PNode child_pre child child_suf)
        (KCons Red (PNode red_pre red_child red_suf) tail)
        c_tail Hchild_ctx Hred_tail).
    + exact Houter_pre.
    + exact Houter_suf.
    + exact Hpre_concat.
    + exact Hsuf_concat.
    + exact Hred_inner.
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_post_green_continuation_from_repair_continuation :
  forall A,
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_post_green_continuation A.
Proof.
  unfold
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_repair_continuation,
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail_post_green_continuation.
  intros A Hcontinuation k pre suf child_pre child child_suf
    red_pre red_child red_suf tail c_tail
    Hcase1 Hpre Hsuf Hpkt Hchild_ctx Hred_tail
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  pose proof (Hcontinuation k pre suf child_pre child child_suf
      red_pre red_child red_suf tail
      Hcase1 Hpre Hsuf Hpkt Hchild_ctx c_tail Hred_tail)
    as Hparent_repair.
  destruct (@packet_context_recursive_repair_ready_refined_pnode_components
      A k pre (PNode child_pre child child_suf) suf c_tail Hparent_repair)
    as [_ [_ [_ [_ Hafter]]]].
  exact (Hafter outer_pre outer_suf outer_pre' pre_after
    suf_after outer_suf' c_inner Houter_pre Houter_suf
    Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_from_repair_continuation :
  forall A,
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_repair_continuation A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail A.
Proof.
  unfold
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_repair_continuation,
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail.
  intros A Hcontinuation k pre suf child_pre child child_suf tail
    Hcase1 Htail_top Hpre Hsuf Hpkt Hchild_ctx.
  eapply pcgrr_repair_refined_non_red_tail.
  - exact Htail_top.
  - eapply pcrrr_pnode.
    + exact Hpre.
    + exact Hsuf.
    + exact Hpkt.
    + apply pcgrr_existing. exact Hchild_ctx.
    + intros outer_pre outer_suf outer_pre' pre_after
        suf_after outer_suf' c_inner
        Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred.
      exact (Hcontinuation k pre suf child_pre child child_suf tail
        Hcase1 Htail_top Hpre Hsuf Hpkt Hchild_ctx
        outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
        c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred).
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_repair_continuation_from_pnode_after_tail_repair_lift :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_repair_continuation A.
Proof.
  unfold
    packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift,
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_repair_continuation.
  intros A Hlift k pre suf child_pre child child_suf tail
    Hcase1 _Htail_top Hpre Hsuf Hpkt Hchild_ctx
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  inversion Hchild_ctx as [? ? ? Hchild_repair|]; subst;
    clear Hchild_ctx; try discriminate.
  inversion Hchild_repair as
      [| |? ? ? ? ? Hchild_pre_shape Hchild_suf_shape Hchild_pkt
           Hgrandchild_ctx Hchild_after];
    subst; clear Hchild_repair; try discriminate.
  inversion Hchild_pkt as [|? ? ? ? Hchild_pre_level Hchild_level
      Hchild_suf_level]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre_after
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre_after_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf_after outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf_after_level _].
  unfold green_of_red_k in Hred.
  destruct (prefix_concat pre_after child_pre)
    as [[case3_pre_out child_pre']|] eqn:Hcase3_pre;
    [|discriminate].
  destruct (suffix_concat child_suf suf_after)
    as [[child_suf' case3_suf_out]|] eqn:Hcase3_suf;
    [|discriminate].
  inversion Hred; subst c_inner; clear Hred.
  destruct (@prefix_concat_preserves_outer_green_levels
      A (S k) pre_after child_pre case3_pre_out child_pre'
      Hpre_after_level Hchild_pre_level Hchild_pre_shape Hcase3_pre)
    as [Hcase3_pre_shape [Hcase3_pre_level Hchild_pre'_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A (S k) child_suf suf_after child_suf' case3_suf_out
      Hchild_suf_level Hsuf_after_level Hchild_suf_shape Hcase3_suf)
    as [Hchild_suf'_level [Hcase3_suf_shape Hcase3_suf_level]].
  assert (Hchild_pkt' :
    packet_levels (S (S k)) (PNode child_pre' child child_suf')).
  { constructor; [exact Hchild_pre'_level|exact Hchild_level|exact Hchild_suf'_level]. }
  assert (Hhole_red_ctx :
    packet_context_recursive_green_ready_refined_at (S k) Hole
      (KCons Red (PNode child_pre' child child_suf') tail)).
  { eapply pcgrr_hole_red_kcons_refined.
    - exact Hchild_pkt'.
    - apply pcgrr_existing. exact Hgrandchild_ctx.
    - intros c_tail Hred_tail.
      apply pcrrr_existing.
      exact (Hchild_after pre_after suf_after case3_pre_out
        child_pre' child_suf' case3_suf_out c_tail
        Hpre_after_level Hsuf_after_level Hcase3_pre Hcase3_suf
        Hred_tail). }
  eapply pcrrr_hole_kcons.
  - exact Hcase3_pre_shape.
  - exact Hcase3_suf_shape.
  - constructor; [exact Hcase3_pre_level|constructor|exact Hcase3_suf_level].
  - exact Hhole_red_ctx.
  - intros future_pre future_suf future_pre' pre_final
      suf_final future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k future_pre case3_pre_out future_pre' pre_final
        Hfuture_pre Hcase3_pre_level Hcase3_pre_shape
        Hfuture_pre_concat)
      as [_ [Hpre_final_shape [_ Hpre_final_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k case3_suf_out future_suf suf_final future_suf'
        Hcase3_suf_level Hfuture_suf Hcase3_suf_shape
        Hfuture_suf_concat)
      as [Hsuf_final_shape [_ [Hsuf_final_level _]]].
    assert (Hparent_pkt :
      packet_levels (S k) (PNode pre_final Hole suf_final)).
    { constructor; [exact Hpre_final_level|constructor|exact Hsuf_final_level]. }
    eapply pcgrr_pnode_red_tail_refined.
    + exact Hpre_final_shape.
    + exact Hsuf_final_shape.
    + exact Hparent_pkt.
    + exact Hhole_red_ctx.
    + intros c_tail Hred_tail.
      eapply Hlift.
      * exact Hcase1.
      * exact Hpre_final_shape.
      * exact Hsuf_final_shape.
      * exact Hparent_pkt.
      * exact (Hchild_after pre_after suf_after case3_pre_out
          child_pre' child_suf' case3_suf_out c_tail
          Hpre_after_level Hsuf_after_level Hcase3_pre Hcase3_suf
          Hred_tail).
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_from_pnode_after_tail_repair_lift :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail A.
Proof.
  intros A Hlift.
  eapply packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_from_repair_continuation.
  eapply packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_repair_continuation_from_pnode_after_tail_repair_lift.
  exact Hlift.
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_from_tail_split :
  forall A,
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_tail A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context A.
Proof.
  unfold
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail,
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_tail,
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context.
  intros A Hnon_red Hred k pre suf child_pre child child_suf tail
    Hcase1 Hpre Hsuf Hpkt Hchild_ctx.
  destruct tail as [b|col red_packet tail'].
  - eapply Hnon_red; eauto. cbn. discriminate.
  - destruct col.
    + eapply Hnon_red; eauto. cbn. discriminate.
    + eapply Hnon_red; eauto. cbn. discriminate.
    + eapply Hred; eauto.
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_from_pnode_after_tail_repair_lift_and_red_tail :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_tail A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context A.
Proof.
  intros A Hlift Hred.
  eapply packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_from_tail_split.
  - eapply packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_non_red_tail_from_pnode_after_tail_repair_lift.
    exact Hlift.
  - exact Hred.
Qed.

Lemma packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_from_pnode_after_tail_repair_lift_and_red_pnode_tail :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_pnode_tail A ->
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context A.
Proof.
  intros A Hlift Hred_pnode.
  eapply packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_from_pnode_after_tail_repair_lift_and_red_tail.
  - exact Hlift.
  - eapply packet_context_recursive_green_ready_refined_pnode_from_strict_child_context_red_tail_from_red_pnode_tail.
    exact Hred_pnode.
Qed.

Definition recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_red_tail_context
    {A : Type} : Prop :=
  forall k (pre suf red_pre red_suf : Buf5 (E.t A)) b
         pre2 child suf2 tail
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         pre_out pre2' suf2' suf_out,
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    buf5_is_not_red_or_empty_shape red_pre ->
    buf5_is_not_red_or_empty_shape red_suf ->
    (red_pre = B0 \/ red_suf = B0) ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_levels (S (S k)) (PNode red_pre Hole red_suf) ->
    buf_all_at_level (S (S (S k))) b ->
    green_of_red_k
      (KCons Red (PNode red_pre Hole red_suf) (KEnding b)) =
        Some (KCons Green (PNode pre2 child suf2) tail) ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    green_prefix_concat pre' pre2 = Some (pre_out, pre2') ->
    green_suffix_concat suf2 suf' = Some (suf2', suf_out) ->
    forall (future_pre future_suf future_pre' pre_next
        suf_next future_suf' : Buf5 (E.t A)),
      buf_all_at_level k future_pre ->
      buf_all_at_level k future_suf ->
      green_prefix_concat future_pre pre_out =
        Some (future_pre', pre_next) ->
      green_suffix_concat suf_out future_suf =
        Some (suf_next, future_suf') ->
      forall (repair_pre repair_suf repair_pre' pre_repair
          suf_repair repair_suf' : Buf5 (E.t A)),
        buf_all_at_level k repair_pre ->
        buf_all_at_level k repair_suf ->
        prefix_concat repair_pre pre_next =
          Some (repair_pre', pre_repair) ->
        suffix_concat suf_next repair_suf =
          Some (suf_repair, repair_suf') ->
        forall case3_pre_out pre2_next suf2_next case3_suf_out,
          prefix_concat pre_repair pre2' =
            Some (case3_pre_out, pre2_next) ->
          suffix_concat suf2' suf_repair =
            Some (suf2_next, case3_suf_out) ->
          packet_context_recursive_green_ready_at (S k) Hole
            (KCons Red (PNode pre2_next child suf2_next) tail).

Definition recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_continuation
    {A : Type} : Prop :=
  forall k (pre suf red_pre red_suf : Buf5 (E.t A)) b
         pre2 child suf2 tail
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         pre_out pre2' suf2' suf_out,
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    buf5_is_not_red_or_empty_shape red_pre ->
    buf5_is_not_red_or_empty_shape red_suf ->
    (red_pre = B0 \/ red_suf = B0) ->
    packet_levels (S k) (PNode pre Hole suf) ->
    packet_levels (S (S k)) (PNode red_pre Hole red_suf) ->
    buf_all_at_level (S (S (S k))) b ->
    green_of_red_k
      (KCons Red (PNode red_pre Hole red_suf) (KEnding b)) =
        Some (KCons Green (PNode pre2 child suf2) tail) ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    green_prefix_concat pre' pre2 = Some (pre_out, pre2') ->
    green_suffix_concat suf2 suf' = Some (suf2', suf_out) ->
    forall (future_pre future_suf future_pre' pre_next
        suf_next future_suf' : Buf5 (E.t A)),
      buf_all_at_level k future_pre ->
      buf_all_at_level k future_suf ->
      green_prefix_concat future_pre pre_out =
        Some (future_pre', pre_next) ->
      green_suffix_concat suf_out future_suf =
        Some (suf_next, future_suf') ->
      forall (repair_pre repair_suf repair_pre' pre_repair
          suf_repair repair_suf' : Buf5 (E.t A)),
        buf_all_at_level k repair_pre ->
        buf_all_at_level k repair_suf ->
        prefix_concat repair_pre pre_next =
          Some (repair_pre', pre_repair) ->
        suffix_concat suf_next repair_suf =
          Some (suf_repair, repair_suf') ->
        forall case3_pre_out pre2_next suf2_next case3_suf_out,
          prefix_concat pre_repair pre2' =
            Some (case3_pre_out, pre2_next) ->
          suffix_concat suf2' suf_repair =
            Some (suf2_next, case3_suf_out) ->
          forall (after_pre after_suf after_pre' pre_after
              suf_after after_suf' : Buf5 (E.t A)),
