              buf_all_at_level k outer_suf2 ->
              prefix_concat outer_pre2 pre_after =
                Some (outer_pre2', pre_after') ->
              suffix_concat suf_after outer_suf2 =
                Some (suf_after', outer_suf2') ->
              forall case2_pre_out pre2_after suf2_after case2_suf_out,
                green_prefix_concat pre_after' pre2_next =
                  Some (case2_pre_out, pre2_after) ->
                green_suffix_concat suf2_next suf_after' =
                  Some (suf2_after, case2_suf_out) ->
                packet_context_recursive_repair_ready_at k Hole
                  (KCons Red (PNode pre_after' Hole suf_after')
                    (KCons Red (PNode pre2_next child suf2_next) tail)).

