Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_red_tail_context_when_case1_context :
  forall A,
    @recursive_case1_context_ready A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_red_tail_context A.
Proof.
  unfold
    recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_red_tail_context.
  intros A Hcase1 k pre suf red_pre red_suf b
    pre2 child suf2 tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    pre_out pre2' suf2' suf_out
    Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred
    Houter_pre Houter_suf Hpre_concat Hsuf_concat Hpre_green Hsuf_green
    future_pre future_suf future_pre' pre_next suf_next future_suf'
    Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat
    repair_pre repair_suf repair_pre' pre_repair suf_repair repair_suf'
    Hrepair_pre Hrepair_suf Hrepair_pre_concat Hrepair_suf_concat
    case3_pre_out pre2_next suf2_next case3_suf_out
    Hcase3_pre Hcase3_suf.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre'
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre'_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf' outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf'_level _].
  unfold green_of_red_k in Hred.
  destruct (make_small red_pre b red_suf) as [c0|] eqn:Hmake;
    [|discriminate].
  destruct c0 as [out|p0 tail0]; cbn in Hred.
  - discriminate.
  - inversion Hred; subst p0 tail; clear Hred.
    inversion Hred_pkt as [|? ? ? ? Hred_pre_level _ Hred_suf_level];
      subst.
    pose proof (Hcase1 (S k) red_pre b red_suf
        (ChainCons (PNode pre2 child suf2) tail0)
        Hred_pre_level Hb Hred_suf_level Hmake) as Hbottom_ctx.
    cbn in Hbottom_ctx.
    inversion Hbottom_ctx as
        [|? ? ? ? ? ? Hpre2_shape Hsuf2_shape Hpkt2 _ Hafter|];
      subst; clear Hbottom_ctx.
    inversion Hpkt2 as [|? ? ? ? Hpre2_level Hchild_level Hsuf2_level];
      subst.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A (S k) pre' pre2 pre_out pre2'
        Hpre'_level Hpre2_level Hpre2_shape Hpre_green)
      as [Hpre_out_shape [_ [Hpre_out_level Hpre2'_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A (S k) suf2 suf' suf2' suf_out
        Hsuf2_level Hsuf'_level Hsuf2_shape Hsuf_green)
      as [_ [Hsuf_out_shape [Hsuf2'_level Hsuf_out_level]]].
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k future_pre pre_out future_pre' pre_next
        Hfuture_pre Hpre_out_level Hpre_out_shape Hfuture_pre_concat)
      as [_ [Hpre_next_shape [_ Hpre_next_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k suf_out future_suf suf_next future_suf'
        Hsuf_out_level Hfuture_suf Hsuf_out_shape Hfuture_suf_concat)
      as [Hsuf_next_shape [_ [Hsuf_next_level _]]].
    destruct (@prefix_concat_preserves_outer_green_levels
        A k repair_pre pre_next repair_pre' pre_repair
        Hrepair_pre Hpre_next_level Hpre_next_shape Hrepair_pre_concat)
      as [_ [_ Hpre_repair_level]].
    destruct (@suffix_concat_preserves_outer_green_levels
        A k suf_next repair_suf suf_repair repair_suf'
        Hsuf_next_level Hrepair_suf Hsuf_next_shape Hrepair_suf_concat)
      as [Hsuf_repair_level _].
    assert (Hinner_green :
      packet_context_recursive_green_ready_at
        (S k) (PNode pre2' child suf2') (chain_to_kchain_g tail0)).
    { exact (Hafter pre' suf' pre_out pre2' suf2' suf_out
        Hpre'_level Hsuf'_level Hpre_green Hsuf_green). }
    inversion Hinner_green as [? ? ? Hinner_repair|]; subst;
      clear Hinner_green.
    inversion Hinner_repair as
        [| |? ? ? ? ? Hpre2'_shape Hsuf2'_shape Hpkt_inner
             Hchild_ctx Hinner_after];
      subst; clear Hinner_repair.
    inversion Hpkt_inner as [|? ? ? ? Hpre2'_level_inner
        Hchild_level_inner Hsuf2'_level_inner]; subst.
    destruct (@prefix_concat_preserves_outer_green_levels
        A (S k) pre_repair pre2' case3_pre_out pre2_next
        Hpre_repair_level Hpre2'_level_inner Hpre2'_shape Hcase3_pre)
      as [_ [_ Hpre2_next_level]].
    destruct (@suffix_concat_preserves_outer_green_levels
        A (S k) suf2' suf_repair suf2_next case3_suf_out
        Hsuf2'_level_inner Hsuf_repair_level Hsuf2'_shape Hcase3_suf)
      as [Hsuf2_next_level _].
    assert (Htail_red_pkt :
      packet_levels (S (S k)) (PNode pre2_next child suf2_next)).
    { constructor; [exact Hpre2_next_level|exact Hchild_level_inner|exact Hsuf2_next_level]. }
    eapply pcgwr_hole_red_kcons.
    + exact Htail_red_pkt.
    + exact Hchild_ctx.
    + intros c' Hred_tail.
      exact (Hinner_after pre_repair suf_repair case3_pre_out
        pre2_next suf2_next case3_suf_out c'
        Hpre_repair_level Hsuf_repair_level Hcase3_pre Hcase3_suf
        Hred_tail).
Qed.

Lemma packet_context_recursive_green_ready_hole_red_tail_repair_ready_from_repair_tail_parent_context_ready :
  forall A k (pre suf : Buf5 (E.t A)) child tail c_tail,
    @recursive_repair_tail_parent_context_ready A ->
    packet_context_recursive_green_ready_at
      k Hole (KCons Red (PNode pre child suf) tail) ->
