Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_ending :
  forall A k (pre suf b : Buf5 (E.t A)),
    @recursive_case1_context_ready A ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels (S k) (PNode pre Hole suf) ->
    buf_all_at_level (S (S k)) b ->
    packet_context_recursive_repair_ready_refined_at
      k (PNode pre Hole suf) (KEnding b).
Proof.
  intros A k pre suf b Hcase1 Hpre Hsuf Hpkt Hb.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  eapply pcrrr_pnode.
  - exact Hpre.
  - exact Hsuf.
  - exact Hpkt.
  - apply pcgrr_existing.
    apply pcgwr_repair.
    constructor. exact Hb.
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
    destruct (@prefix_concat_preserves_outer_green_levels
        A k outer_pre pre outer_pre' pre'
        Houter_pre Hpre_level Hpre Hpre_concat)
      as [_ [_ Hpre'_level]].
    destruct (@suffix_concat_preserves_outer_green_levels
        A k suf outer_suf suf' outer_suf'
        Hsuf_level Houter_suf Hsuf Hsuf_concat)
      as [Hsuf'_level _].
    unfold green_of_red_k in Hred_inner.
    destruct (make_small pre' b suf') as [c0|] eqn:Hmake;
      [|discriminate].
    inversion Hred_inner; subst c_inner; clear Hred_inner.
    apply pcrrr_existing.
    exact (Hcase1 k pre' b suf' c0
      Hpre'_level Hb Hsuf'_level Hmake).
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_post_red_continuation_ending :
  forall A k (pre suf b : Buf5 (E.t A)),
