Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_post_red_continuation_from_pnode_after_tail_repair_lift :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_post_red_continuation A.
Proof.
  unfold
    packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift,
    packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_post_red_continuation.
  intros A Hlift k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx
    outer_pre outer_suf outer_pre' pre_after suf_after outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  specialize (Hlift k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx).
  inversion Hlift as
      [| |? ? ? ? ? Hpre_refined Hsuf_refined Hpkt_refined
           Hchild_refined Hafter_refined];
    subst; clear Hlift.
  - match goal with
    | Hbase : packet_context_recursive_repair_ready_at _
        (PNode _ _ _) _ |- _ =>
        inversion Hbase as
            [| |? ? ? ? ? Hpre_unrefined Hsuf_unrefined Hpkt_unrefined
                 Hchild_unrefined Hafter_unrefined];
        subst; clear Hbase; try discriminate
    end.
    apply pcrrr_existing.
    exact (Hafter_unrefined outer_pre outer_suf outer_pre'
      pre_after suf_after outer_suf' c_inner
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
  - exact (Hafter_refined outer_pre outer_suf outer_pre'
      pre_after suf_after outer_suf' c_inner
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_iff_post_red_continuation :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A <->
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_post_red_continuation A.
Proof.
  intros A. split.
  - apply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_post_red_continuation_from_pnode_after_tail_repair_lift.
  - apply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_from_post_red_continuation.
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_continuation_from_pnode_strict_child_context :
  forall A,
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context A ->
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_continuation A.
Proof.
  unfold
    packet_context_recursive_green_ready_refined_pnode_from_strict_child_context,
    packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_continuation.
  intros A Hpnode k pre suf col tail_pre tail_child tail_suf tail
    outer_pre outer_suf outer_pre' pre_parent suf_parent outer_suf'
    case2_pre_out tail_pre' tail_suf' case2_suf_out
    Hcase1 Hpre Hsuf Hpkt Hctx
    Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase2_pre Hcase2_suf
    future_pre future_suf future_pre' pre_after suf_after future_suf'
    Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  inversion Hctx as
      [|? ? ? ? ? ? Htail_pre_shape Htail_suf_shape Htail_pkt
           _Htail_child_ctx Htail_after|];
    subst; clear Hctx; try discriminate.
  inversion Htail_pkt as [|? ? ? ? Htail_pre_level
      Htail_child_level Htail_suf_level]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre_parent
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre_parent_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf_parent outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf_parent_level _].
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A (S k) pre_parent tail_pre case2_pre_out tail_pre'
      Hpre_parent_level Htail_pre_level Htail_pre_shape Hcase2_pre)
    as [Hcase2_pre_shape [_ [Hcase2_pre_level Htail_pre'_level]]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A (S k) tail_suf suf_parent tail_suf' case2_suf_out
      Htail_suf_level Hsuf_parent_level Htail_suf_shape Hcase2_suf)
    as [_ [Hcase2_suf_shape [Htail_suf'_level Hcase2_suf_level]]].
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k future_pre case2_pre_out future_pre' pre_after
      Hfuture_pre Hcase2_pre_level Hcase2_pre_shape Hfuture_pre_concat)
    as [_ [Hpre_after_shape [_ Hpre_after_level]]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k case2_suf_out future_suf suf_after future_suf'
      Hcase2_suf_level Hfuture_suf Hcase2_suf_shape Hfuture_suf_concat)
    as [Hsuf_after_shape [_ [Hsuf_after_level _]]].
  assert (Htail_pkt' :
    packet_levels (S (S k)) (PNode tail_pre' tail_child tail_suf')).
  { constructor; [exact Htail_pre'_level|exact Htail_child_level|exact Htail_suf'_level]. }
  assert (Hparent_pkt :
    packet_levels (S k)
      (PNode pre_after (PNode tail_pre' tail_child tail_suf') suf_after)).
  { constructor; [exact Hpre_after_level|exact Htail_pkt'|exact Hsuf_after_level]. }
  assert (Hchild_ctx :
    packet_context_recursive_green_ready_at (S k)
      (PNode tail_pre' tail_child tail_suf') tail).
  { exact (Htail_after pre_parent suf_parent case2_pre_out
      tail_pre' tail_suf' case2_suf_out
      Hpre_parent_level Hsuf_parent_level Hcase2_pre Hcase2_suf). }
  exact (Hpnode k pre_after suf_after tail_pre' tail_child tail_suf' tail
    Hcase1 Hpre_after_shape Hsuf_after_shape Hparent_pkt Hchild_ctx).
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_from_continuation :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_continuation A ->
    forall k (pre suf : Buf5 (E.t A)) col
           (tail_pre : Buf5 (E.t A)) tail_child tail_suf tail,
      @recursive_case1_context_ready A ->
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre Hole suf) ->
      packet_context_recursive_repair_ready_at (S k) Hole
        (KCons col (PNode tail_pre tail_child tail_suf) tail) ->
      packet_context_recursive_repair_ready_refined_at
        k (PNode pre Hole suf)
        (KCons col (PNode tail_pre tail_child tail_suf) tail).
Proof.
  unfold
    packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_continuation.
  intros A Hcontinuation k pre suf col tail_pre tail_child tail_suf tail
    _Hcase1 Hpre Hsuf Hpkt Hctx.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  eapply pcrrr_pnode.
  - exact Hpre.
  - exact Hsuf.
  - exact Hpkt.
  - apply pcgrr_existing.
    apply pcgwr_repair.
    exact Hctx.
  - intros outer_pre outer_suf outer_pre' pre_parent suf_parent
      outer_suf' c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hred_inner.
    pose proof Hctx as Hctx_orig.
    inversion Hctx as
        [|? ? ? ? ? ? Htail_pre_shape Htail_suf_shape Htail_pkt
             Htail_child Htail_after|]; subst; clear Hctx.
    destruct (@prefix_concat_preserves_outer_green_levels
        A k outer_pre pre outer_pre' pre_parent
        Houter_pre Hpre_level Hpre Hpre_concat)
      as [_ [_ Hpre_parent_level]].
    destruct (@suffix_concat_preserves_outer_green_levels
        A k suf outer_suf suf_parent outer_suf'
        Hsuf_level Houter_suf Hsuf Hsuf_concat)
      as [Hsuf_parent_level _].
    unfold green_of_red_k in Hred_inner.
    destruct (green_prefix_concat pre_parent tail_pre)
      as [[case2_pre_out tail_pre']|] eqn:Hcase2_pre;
      [|discriminate].
    destruct (green_suffix_concat tail_suf suf_parent)
      as [[tail_suf' case2_suf_out]|] eqn:Hcase2_suf;
      [|discriminate].
    inversion Hred_inner; subst c_inner; clear Hred_inner.
    inversion Htail_pkt as [|? ? ? ? Htail_pre_level
        Htail_child_level Htail_suf_level]; subst.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A (S k) pre_parent tail_pre case2_pre_out tail_pre'
        Hpre_parent_level Htail_pre_level Htail_pre_shape Hcase2_pre)
      as [Hcase2_pre_shape [_ [Hcase2_pre_level Htail_pre'_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A (S k) tail_suf suf_parent tail_suf' case2_suf_out
        Htail_suf_level Hsuf_parent_level Htail_suf_shape Hcase2_suf)
      as [_ [Hcase2_suf_shape [Htail_suf'_level Hcase2_suf_level]]].
    eapply pcrrr_hole_kcons.
    + exact Hcase2_pre_shape.
    + exact Hcase2_suf_shape.
    + constructor.
      * exact Hcase2_pre_level.
      * constructor; [exact Htail_pre'_level|exact Htail_child_level|exact Htail_suf'_level].
      * exact Hcase2_suf_level.
    + apply pcgrr_existing.
      exact (Htail_after pre_parent suf_parent case2_pre_out
        tail_pre' tail_suf' case2_suf_out
        Hpre_parent_level Hsuf_parent_level Hcase2_pre Hcase2_suf).
    + intros future_pre future_suf future_pre' pre_after
        suf_after future_suf'
        Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
      exact (Hcontinuation k pre suf col tail_pre tail_child tail_suf tail
        outer_pre outer_suf outer_pre' pre_parent suf_parent outer_suf'
        case2_pre_out tail_pre' tail_suf' case2_suf_out
        _Hcase1 Hpre Hsuf Hpkt Hctx_orig
        Houter_pre Houter_suf Hpre_concat Hsuf_concat
        Hcase2_pre Hcase2_suf
        future_pre future_suf future_pre' pre_after suf_after future_suf'
        Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat).
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_from_kcons_continuation :
  forall A,
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_continuation A ->
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A.
Proof.
  unfold packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift.
  intros A Hcontinuation k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx.
  destruct c_tail as [b|col p tail].
  - inversion Hctx; subst; clear Hctx; try discriminate.
    eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_ending;
      eauto.
  - destruct p as [|tail_pre tail_child tail_suf].
    + inversion Hctx.
    + eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_from_continuation;
        eauto.
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_from_pnode_strict_child_context :
  forall A,
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context A ->
    forall k (pre suf : Buf5 (E.t A)) col
           (tail_pre : Buf5 (E.t A)) tail_child tail_suf tail,
      @recursive_case1_context_ready A ->
      buf5_is_not_red_shape pre ->
      buf5_is_not_red_shape suf ->
      packet_levels (S k) (PNode pre Hole suf) ->
      packet_context_recursive_repair_ready_at (S k) Hole
        (KCons col (PNode tail_pre tail_child tail_suf) tail) ->
      packet_context_recursive_repair_ready_refined_at
        k (PNode pre Hole suf)
        (KCons col (PNode tail_pre tail_child tail_suf) tail).
Proof.
  intros A Hpnode k pre suf col tail_pre tail_child tail_suf tail
    Hcase1 Hpre Hsuf Hpkt Hctx.
  eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_from_continuation;
    eauto.
  eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_continuation_from_pnode_strict_child_context.
  exact Hpnode.
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_from_pnode_strict_child_context :
  forall A,
    @packet_context_recursive_green_ready_refined_pnode_from_strict_child_context A ->
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A.
Proof.
  unfold packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift.
  intros A Hpnode k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx.
  destruct c_tail as [b|col p tail].
  - inversion Hctx; subst; clear Hctx; try discriminate.
    eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_ending;
      eauto.
  - destruct p as [|tail_pre tail_child tail_suf].
    + inversion Hctx.
    + eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_kcons_from_pnode_strict_child_context;
        eauto.
Qed.

Lemma packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_from_repair_tail_parent_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready A ->
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A.
Proof.
  cofix CIH.
  unfold packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift.
  intros A Hrepair k pre suf c_tail Hcase1 Hpre Hsuf Hpkt Hctx.
  destruct c_tail as [b|col p tail].
  - inversion Hctx; subst; clear Hctx; try discriminate.
    eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_ending;
      eauto.
  - destruct p as [|tail_pre tail_child tail_suf].
    + inversion Hctx.
    + pose proof Hctx as Hctx_orig.
      inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
      inversion Hctx as
          [|? ? ? ? ? ? Htail_pre_shape Htail_suf_shape Htail_pkt
               _Htail_child Htail_after|]; subst; clear Hctx;
        try discriminate.
      eapply pcrrr_pnode.
      * exact Hpre.
      * exact Hsuf.
      * exact Hpkt.
      * apply pcgrr_existing. apply pcgwr_repair. exact Hctx_orig.
      * intros outer_pre outer_suf outer_pre' pre_parent suf_parent
          outer_suf' c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat
          Hred_inner.
        destruct (@prefix_concat_preserves_outer_green_levels
            A k outer_pre pre outer_pre' pre_parent
            Houter_pre Hpre_level Hpre Hpre_concat)
          as [_ [_ Hpre_parent_level]].
        destruct (@suffix_concat_preserves_outer_green_levels
            A k suf outer_suf suf_parent outer_suf'
            Hsuf_level Houter_suf Hsuf Hsuf_concat)
          as [Hsuf_parent_level _].
        unfold green_of_red_k in Hred_inner.
        destruct (green_prefix_concat pre_parent tail_pre)
          as [[case2_pre_out tail_pre']|] eqn:Hcase2_pre;
          [|discriminate].
        destruct (green_suffix_concat tail_suf suf_parent)
          as [[tail_suf' case2_suf_out]|] eqn:Hcase2_suf;
          [|discriminate].
        inversion Hred_inner; subst c_inner; clear Hred_inner.
        inversion Htail_pkt as [|? ? ? ? Htail_pre_level
            Htail_child_level Htail_suf_level]; subst.
        destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
            A (S k) pre_parent tail_pre case2_pre_out tail_pre'
            Hpre_parent_level Htail_pre_level Htail_pre_shape Hcase2_pre)
          as [Hcase2_pre_shape [_ [Hcase2_pre_level Htail_pre'_level]]].
        destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
            A (S k) tail_suf suf_parent tail_suf' case2_suf_out
            Htail_suf_level Hsuf_parent_level Htail_suf_shape Hcase2_suf)
          as [_ [Hcase2_suf_shape [Htail_suf'_level Hcase2_suf_level]]].
        eapply pcrrr_hole_kcons.
        -- exact Hcase2_pre_shape.
        -- exact Hcase2_suf_shape.
        -- constructor.
           ++ exact Hcase2_pre_level.
           ++ constructor; [exact Htail_pre'_level|exact Htail_child_level|exact Htail_suf'_level].
           ++ exact Hcase2_suf_level.
        -- apply pcgrr_existing.
           exact (Htail_after pre_parent suf_parent case2_pre_out
             tail_pre' tail_suf' case2_suf_out
             Hpre_parent_level Hsuf_parent_level Hcase2_pre Hcase2_suf).
        -- intros future_pre future_suf future_pre' pre_after
             suf_after future_suf'
             Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
           destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
               A k future_pre case2_pre_out future_pre' pre_after
               Hfuture_pre Hcase2_pre_level Hcase2_pre_shape Hfuture_pre_concat)
             as [_ [Hpre_after_shape [_ Hpre_after_level]]].
           destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
               A k case2_suf_out future_suf suf_after future_suf'
               Hcase2_suf_level Hfuture_suf Hcase2_suf_shape Hfuture_suf_concat)
             as [Hsuf_after_shape [_ [Hsuf_after_level _]]].
           assert (Htail_pkt' :
             packet_levels (S (S k)) (PNode tail_pre' tail_child tail_suf')).
           { constructor; [exact Htail_pre'_level|exact Htail_child_level|exact Htail_suf'_level]. }
           assert (Hparent_pkt :
             packet_levels (S k)
               (PNode pre_after (PNode tail_pre' tail_child tail_suf') suf_after)).
           { constructor; [exact Hpre_after_level|exact Htail_pkt'|exact Hsuf_after_level]. }
           assert (Hchild_ctx :
             packet_context_recursive_green_ready_at (S k)
               (PNode tail_pre' tail_child tail_suf') tail).
           { exact (Htail_after pre_parent suf_parent case2_pre_out
               tail_pre' tail_suf' case2_suf_out
               Hpre_parent_level Hsuf_parent_level Hcase2_pre Hcase2_suf). }
           destruct (kchain_top_color tail) eqn:Htail_top;
             try
               (eapply pcgrr_repair_refined_non_red_tail;
                [intro Hred_top; rewrite Htail_top in Hred_top; discriminate|];
                eapply pcrrr_pnode;
                [exact Hpre_after_shape
                |exact Hsuf_after_shape
                |exact Hparent_pkt
                |apply pcgrr_existing; exact Hchild_ctx
                |intros outer_pre2 outer_suf2 outer_pre2' pre_after2
                    suf_after2 outer_suf2' c_inner2
                    Houter_pre2 Houter_suf2 Hpre_concat2 Hsuf_concat2
                    Hred_inner2;
                 inversion Hchild_ctx as [? ? ? Hchild_repair|];
                   subst; clear Hchild_ctx; try discriminate;
                 inversion Hchild_repair as
                     [| |? ? ? ? ? Hchild_pre_shape Hchild_suf_shape
                          Hchild_pkt Hgrandchild_ctx Hchild_after];
                   subst; clear Hchild_repair; try discriminate;
                 inversion Hchild_pkt as [|? ? ? ? Hchild_pre_level
                     Hchild_level Hchild_suf_level]; subst;
                 destruct (@prefix_concat_preserves_outer_green_levels
                     A k outer_pre2 pre_after outer_pre2' pre_after2
                     Houter_pre2 Hpre_after_level Hpre_after_shape Hpre_concat2)
                   as [_ [_ Hpre_after2_level]];
                 destruct (@suffix_concat_preserves_outer_green_levels
                     A k suf_after outer_suf2 suf_after2 outer_suf2'
                     Hsuf_after_level Houter_suf2 Hsuf_after_shape Hsuf_concat2)
                   as [Hsuf_after2_level _];
                 unfold green_of_red_k in Hred_inner2;
                 destruct (prefix_concat pre_after2 tail_pre')
                   as [[case3_pre_out child_pre_after]|] eqn:Hcase3_pre;
                   [|discriminate];
                 destruct (suffix_concat tail_suf' suf_after2)
                   as [[child_suf_after case3_suf_out]|] eqn:Hcase3_suf;
                   [|discriminate];
                 inversion Hred_inner2; subst c_inner2; clear Hred_inner2;
                 destruct (@prefix_concat_preserves_outer_green_levels
                     A (S k) pre_after2 tail_pre'
                     case3_pre_out child_pre_after
                     Hpre_after2_level Hchild_pre_level Hchild_pre_shape Hcase3_pre)
                   as [Hcase3_pre_shape [Hcase3_pre_level Hchild_pre_after_level]];
                 destruct (@suffix_concat_preserves_outer_green_levels
                     A (S k) tail_suf' suf_after2
                     child_suf_after case3_suf_out
                     Hchild_suf_level Hsuf_after2_level Hchild_suf_shape Hcase3_suf)
                   as [Hchild_suf_after_level [Hcase3_suf_shape Hcase3_suf_level]];
                 assert (Hchild_after_pkt :
                   packet_levels (S (S k))
                     (PNode child_pre_after tail_child child_suf_after));
                 [constructor; [exact Hchild_pre_after_level|exact Hchild_level|exact Hchild_suf_after_level]|];
                 assert (Hhole_red_ctx :
                   packet_context_recursive_green_ready_refined_at (S k) Hole
                     (KCons Red
                       (PNode child_pre_after tail_child child_suf_after)
                       tail));
                 [eapply pcgrr_hole_red_kcons_refined;
                  [exact Hchild_after_pkt
                  |apply pcgrr_existing; exact Hgrandchild_ctx
                  |intros c_child Hred_child;
                   apply pcrrr_existing;
                   exact (Hchild_after pre_after2 suf_after2
                     case3_pre_out child_pre_after child_suf_after
                     case3_suf_out c_child
                     Hpre_after2_level Hsuf_after2_level
                     Hcase3_pre Hcase3_suf Hred_child)]
                 |];
                 eapply pcrrr_hole_kcons;
                 [exact Hcase3_pre_shape
                 |exact Hcase3_suf_shape
                 |constructor; [exact Hcase3_pre_level|constructor|exact Hcase3_suf_level]
                 |exact Hhole_red_ctx
                 |intros next_pre next_suf next_pre' pre_final
                    suf_final next_suf'
                    Hnext_pre Hnext_suf Hnext_pre_concat Hnext_suf_concat;
                  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
                      A k next_pre case3_pre_out next_pre' pre_final
                      Hnext_pre Hcase3_pre_level Hcase3_pre_shape Hnext_pre_concat)
                    as [_ [Hpre_final_shape [_ Hpre_final_level]]];
                  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
                      A k case3_suf_out next_suf suf_final next_suf'
                      Hcase3_suf_level Hnext_suf Hcase3_suf_shape Hnext_suf_concat)
                    as [Hsuf_final_shape [_ [Hsuf_final_level _]]];
                  assert (Hparent_final_pkt :
                    packet_levels (S k) (PNode pre_final Hole suf_final));
                  [constructor; [exact Hpre_final_level|constructor|exact Hsuf_final_level]|];
                  eapply pcgrr_pnode_red_tail_refined;
                  [exact Hpre_final_shape
                  |exact Hsuf_final_shape
                  |exact Hparent_final_pkt
                  |exact Hhole_red_ctx
                  |intros c_child Hred_child;
                   eapply CIH;
                   [exact Hrepair
                   |exact Hcase1
                   |exact Hpre_final_shape
                   |exact Hsuf_final_shape
                   |exact Hparent_final_pkt
                   |exact (Hchild_after pre_after2 suf_after2
                     case3_pre_out child_pre_after child_suf_after
                     case3_suf_out c_child
                     Hpre_after2_level Hsuf_after2_level
                     Hcase3_pre Hcase3_suf Hred_child)]]]]).
           destruct tail as [tail_b|tail_col tail_packet tail_tail];
             cbn in Htail_top; try discriminate.
           destruct tail_col; cbn in Htail_top; try discriminate.
           destruct tail_packet as [|red_pre red_child red_suf].
           ++ exfalso.
              eapply packet_context_recursive_green_ready_red_hole_tail_impossible.
              exact Hchild_ctx.
           ++ eapply pcgrr_pnode_red_tail_refined.
              ** exact Hpre_after_shape.
              ** exact Hsuf_after_shape.
              ** exact Hparent_pkt.
              ** apply pcgrr_existing. exact Hchild_ctx.
              ** intros red_repaired Hred_tail.
                 assert (Hchild_repair_tail :
                   packet_context_recursive_repair_ready_at (S k)
                     (PNode tail_pre' tail_child tail_suf') red_repaired).
                 { eapply recursive_green_tail_parent_context_ready_from_repair_tail_parent_context_ready;
                     eauto. }
                 eapply pcrrr_pnode.
                 --- exact Hpre_after_shape.
                 --- exact Hsuf_after_shape.
                 --- exact Hparent_pkt.
                 --- eapply pcgrr_repair_refined_non_red_tail.
                     +++ pose proof Hred_tail as Htop_green.
                         apply green_of_red_k_top_green in Htop_green.
                         rewrite Htop_green. discriminate.
                     +++ apply pcrrr_existing. exact Hchild_repair_tail.
                 --- intros outer_pre2 outer_suf2 outer_pre2' pre_after2
                       suf_after2 outer_suf2' c_inner2
                       Houter_pre2 Houter_suf2 Hpre_concat2 Hsuf_concat2
                       Hred_inner2.
                     inversion Hchild_repair_tail as
                         [| |? ? ? ? ? Hchild_pre_shape Hchild_suf_shape
                              Hchild_pkt Hgrandchild_ctx Hchild_after];
                       subst; clear Hchild_repair_tail; try discriminate.
                     inversion Hchild_pkt as [|? ? ? ? Hchild_pre_level
                         Hchild_level Hchild_suf_level]; subst.
                     destruct (@prefix_concat_preserves_outer_green_levels
                         A k outer_pre2 pre_after outer_pre2' pre_after2
                         Houter_pre2 Hpre_after_level Hpre_after_shape Hpre_concat2)
                       as [_ [_ Hpre_after2_level]].
                     destruct (@suffix_concat_preserves_outer_green_levels
                         A k suf_after outer_suf2 suf_after2 outer_suf2'
                         Hsuf_after_level Houter_suf2 Hsuf_after_shape Hsuf_concat2)
                       as [Hsuf_after2_level _].
                     unfold green_of_red_k in Hred_inner2.
                     destruct (prefix_concat pre_after2 tail_pre')
                       as [[case3_pre_out child_pre_after]|] eqn:Hcase3_pre;
                       [|discriminate].
                     destruct (suffix_concat tail_suf' suf_after2)
                       as [[child_suf_after case3_suf_out]|] eqn:Hcase3_suf;
                       [|discriminate].
                     inversion Hred_inner2; subst c_inner2; clear Hred_inner2.
                     destruct (@prefix_concat_preserves_outer_green_levels
                         A (S k) pre_after2 tail_pre'
                         case3_pre_out child_pre_after
                         Hpre_after2_level Hchild_pre_level Hchild_pre_shape Hcase3_pre)
                       as [Hcase3_pre_shape [Hcase3_pre_level Hchild_pre_after_level]].
                     destruct (@suffix_concat_preserves_outer_green_levels
                         A (S k) tail_suf' suf_after2
                         child_suf_after case3_suf_out
                         Hchild_suf_level Hsuf_after2_level Hchild_suf_shape Hcase3_suf)
                       as [Hchild_suf_after_level [Hcase3_suf_shape Hcase3_suf_level]].
                     assert (Hchild_after_pkt :
                       packet_levels (S (S k))
                         (PNode child_pre_after tail_child child_suf_after)).
                     { constructor; [exact Hchild_pre_after_level|exact Hchild_level|exact Hchild_suf_after_level]. }
                     assert (Hhole_red_ctx :
                       packet_context_recursive_green_ready_refined_at (S k) Hole
                         (KCons Red
                           (PNode child_pre_after tail_child child_suf_after)
                           red_repaired)).
                     { eapply pcgrr_hole_red_kcons_refined.
                       - exact Hchild_after_pkt.
                       - apply pcgrr_existing. exact Hgrandchild_ctx.
                       - intros c_child Hred_child.
                         apply pcrrr_existing.
                         exact (Hchild_after pre_after2 suf_after2
                           case3_pre_out child_pre_after child_suf_after
                           case3_suf_out c_child
                           Hpre_after2_level Hsuf_after2_level
                           Hcase3_pre Hcase3_suf Hred_child). }
                     eapply pcrrr_hole_kcons.
                     +++ exact Hcase3_pre_shape.
                     +++ exact Hcase3_suf_shape.
                     +++ constructor; [exact Hcase3_pre_level|constructor|exact Hcase3_suf_level].
                     +++ exact Hhole_red_ctx.
                     +++ intros next_pre next_suf next_pre' pre_final
                           suf_final next_suf'
                           Hnext_pre Hnext_suf Hnext_pre_concat Hnext_suf_concat.
                         destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
                             A k next_pre case3_pre_out next_pre' pre_final
                             Hnext_pre Hcase3_pre_level Hcase3_pre_shape Hnext_pre_concat)
                           as [_ [Hpre_final_shape [_ Hpre_final_level]]].
                         destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
                             A k case3_suf_out next_suf suf_final next_suf'
                             Hcase3_suf_level Hnext_suf Hcase3_suf_shape Hnext_suf_concat)
                           as [Hsuf_final_shape [_ [Hsuf_final_level _]]].
                         assert (Hparent_final_pkt :
                           packet_levels (S k) (PNode pre_final Hole suf_final)).
                         { constructor; [exact Hpre_final_level|constructor|exact Hsuf_final_level]. }
                         eapply pcgrr_pnode_red_tail_refined.
                         *** exact Hpre_final_shape.
                         *** exact Hsuf_final_shape.
                         *** exact Hparent_final_pkt.
                         *** exact Hhole_red_ctx.
                         *** intros c_child Hred_child.
                             eapply CIH.
                             ---- exact Hrepair.
                             ---- exact Hcase1.
                             ---- exact Hpre_final_shape.
                             ---- exact Hsuf_final_shape.
                             ---- exact Hparent_final_pkt.
                             ---- exact (Hchild_after pre_after2 suf_after2
                               case3_pre_out child_pre_after child_suf_after
                               case3_suf_out c_child
                               Hpre_after2_level Hsuf_after2_level
                               Hcase3_pre Hcase3_suf Hred_child).
Qed.

Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_tail_repair_continuation_refined_from_child_context_and_pnode_after_tail_repair_lift :
  forall A,
