    inversion Hpkt_inner as [|? ? ? ? Hpre2'_level_inner
        _ Hsuf2'_level_inner]; subst.
    destruct (@prefix_concat_preserves_outer_green_levels
        A (S k) pre_repair pre2' case3_pre_out pre2_next
