    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k case3_suf_out after_suf suf_after after_suf'
        Hcase3_suf_level Hafter_suf Hcase3_suf_shape Hafter_suf_concat)
      as [Hsuf_after_shape [_ [Hsuf_after_level _]]].
    eapply Hlift.
    + exact Hcase1.
    + exact Hpre_after_shape.
    + exact Hsuf_after_shape.
    + constructor; [exact Hpre_after_level|constructor|exact Hsuf_after_level].
    + exact (Hchild k pre suf red_pre red_suf b pre2 child suf2
        (chain_to_kchain_g tail0)
