    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k after_pre case3_pre_out after_pre' pre_after
        Hafter_pre Hcase3_pre_level Hcase3_pre_shape Hafter_pre_concat)
      as [_ [Hpre_after_shape [_ Hpre_after_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k case3_suf_out after_suf suf_after after_suf'
        Hcase3_suf_level Hafter_suf Hcase3_suf_shape Hafter_suf_concat)
      as [Hsuf_after_shape [_ [Hsuf_after_level _]]].
    destruct (@prefix_concat_preserves_outer_green_levels
        A k outer_pre2 pre_after outer_pre2' pre_after'
        Houter_pre2 Hpre_after_level Hpre_after_shape Hpre_after_concat)
      as [_ [_ Hpre_after'_level]].
    destruct (@suffix_concat_preserves_outer_green_levels
        A k suf_after outer_suf2 suf_after' outer_suf2'
        Hsuf_after_level Houter_suf2 Hsuf_after_shape Hsuf_after_concat)
      as [Hsuf_after'_level _].
    destruct (@green_prefix_concat_success_preserves_green_outer_levels
        A (S k) pre_after' pre2_next case2_pre_out pre2_after
        Hpre_after'_level Hpre2_next_level Hcase2_pre)
      as [Hcase2_pre_shape [Hcase2_pre_level Hpre2_after_level]].
    destruct (@green_suffix_concat_success_preserves_green_outer_levels
        A (S k) suf2_next suf_after' suf2_after case2_suf_out
        Hsuf2_next_level Hsuf_after'_level Hcase2_suf)
      as [Hsuf2_after_level [Hcase2_suf_shape Hcase2_suf_level]].
    unfold green_of_red_k_context_ready_at. cbn.
    repeat split; try assumption.
    constructor; [exact Hcase2_pre_level| |exact Hcase2_suf_level].
    constructor; [exact Hpre2_after_level|exact Hchild_level_inner|exact Hsuf2_after_level].
Qed.

Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_continuation_from_projection_components :
  forall A,
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_components A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_continuation A.
Proof.
  unfold
    recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_components,
    recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_continuation.
  intros A Hcomponents k pre suf red_pre red_suf b
    pre2 child suf2 tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    pre_out pre2' suf2' suf_out
    Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred
    Houter_pre Houter_suf Hpre_concat Hsuf_concat Hpre_green Hsuf_green
    future_pre future_suf future_pre' pre_next suf_next future_suf'
    Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat
    repair_pre repair_suf repair_pre' pre_repair suf_repair repair_suf'
    Hrepair_pre Hrepair_suf Hrepair_pre_concat Hrepair_suf_concat
    case3_pre_out pre2_next suf2_next case3_suf_out
    Hcase3_pre Hcase3_suf
    after_pre after_suf after_pre' pre_after suf_after after_suf'
    Hafter_pre Hafter_suf Hafter_pre_concat Hafter_suf_concat
    outer_pre2 outer_suf2 outer_pre2' pre_after' suf_after' outer_suf2'
    Houter_pre2 Houter_suf2 Hpre_after_concat Hsuf_after_concat
    c_inner Hred_outer.
  unfold green_of_red_k in Hred_outer.
  destruct (green_prefix_concat pre_after' pre2_next)
    as [[case2_pre_out pre2_after]|] eqn:Hcase2_pre;
    [|discriminate].
  destruct (green_suffix_concat suf2_next suf_after')
    as [[suf2_after case2_suf_out]|] eqn:Hcase2_suf;
    [|discriminate].
  inversion Hred_outer; subst c_inner; clear Hred_outer.
  destruct (Hcomponents k pre suf red_pre red_suf b pre2 child suf2 tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      pre_out pre2' suf2' suf_out
      Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hpre_green Hsuf_green
      future_pre future_suf future_pre' pre_next suf_next future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat
      repair_pre repair_suf repair_pre' pre_repair suf_repair repair_suf'
      Hrepair_pre Hrepair_suf Hrepair_pre_concat Hrepair_suf_concat
      case3_pre_out pre2_next suf2_next case3_suf_out
      Hcase3_pre Hcase3_suf
      after_pre after_suf after_pre' pre_after suf_after after_suf'
      Hafter_pre Hafter_suf Hafter_pre_concat Hafter_suf_concat
      outer_pre2 outer_suf2 outer_pre2' pre_after' suf_after' outer_suf2'
      Houter_pre2 Houter_suf2 Hpre_after_concat Hsuf_after_concat
      case2_pre_out pre2_after suf2_after case2_suf_out
      Hcase2_pre Hcase2_suf)
    as [Hready [Hchild Hafter]].
  unfold green_of_red_k_context_ready_at in Hready.
  cbn in Hready.
  destruct Hready as [Hcase2_pre_shape [Hcase2_suf_shape Hpkt_case2]].
  eapply pcrwr_hole_kcons.
  - exact Hcase2_pre_shape.
  - exact Hcase2_suf_shape.
  - exact Hpkt_case2.
  - exact Hchild.
  - exact Hafter.
Qed.

Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_components_from_projection_continuation :
  forall A,
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_continuation A ->
