Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_continuation_from_case1_context_and_projection_continuation :
  forall A,
    @recursive_case1_context_ready A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_continuation A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_continuation A.
Proof.
  unfold
    recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_continuation,
    recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_continuation.
  intros A Hcase1 Hprojection k pre suf red_pre red_suf b
    pre2 child suf2 tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    pre_out pre2' suf2' suf_out
    Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred
    Houter_pre Houter_suf Hpre_concat Hsuf_concat Hpre_green Hsuf_green
    future_pre future_suf future_pre' pre_next suf_next future_suf'
    Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat
    repair_pre repair_suf repair_pre' pre_repair suf_repair repair_suf'
    Hrepair_pre Hrepair_suf Hrepair_pre_concat Hrepair_suf_concat
    case3_pre_out pre2_next suf2_next case3_suf_out
    Hcase3_pre Hcase3_suf
    after_pre after_suf after_pre' pre_after suf_after after_suf'
    Hafter_pre Hafter_suf Hafter_pre_concat Hafter_suf_concat.
  pose proof
    (@recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_red_tail_context_when_case1_context
      A Hcase1
      k pre suf red_pre red_suf b pre2 child suf2 tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      pre_out pre2' suf2' suf_out
      Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hpre_green Hsuf_green
      future_pre future_suf future_pre' pre_next suf_next future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat
      repair_pre repair_suf repair_pre' pre_repair suf_repair repair_suf'
      Hrepair_pre Hrepair_suf Hrepair_pre_concat Hrepair_suf_concat
      case3_pre_out pre2_next suf2_next case3_suf_out
      Hcase3_pre Hcase3_suf) as Htail_red_ctx.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre'
      Houter_pre Hpre_level Hpre Hpre_concat)
    as [_ [_ Hpre'_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf' outer_suf'
      Hsuf_level Houter_suf Hsuf Hsuf_concat)
    as [Hsuf'_level _].
  unfold green_of_red_k in Hred.
  destruct (make_small red_pre b red_suf) as [c0|] eqn:Hmake;
    [|discriminate].
  destruct c0 as [out|p0 tail0]; cbn in Hred.
  - discriminate.
  - inversion Hred; subst p0 tail; clear Hred.
    inversion Hred_pkt as [|? ? ? ? Hred_pre_level _ Hred_suf_level];
      subst.
    pose proof (Hcase1 (S k) red_pre b red_suf
        (ChainCons (PNode pre2 child suf2) tail0)
        Hred_pre_level Hb Hred_suf_level Hmake) as Hbottom_ctx.
    cbn in Hbottom_ctx.
    inversion Hbottom_ctx as
        [|? ? ? ? ? ? Hpre2_shape Hsuf2_shape Hpkt2 _ Hafter|];
      subst; clear Hbottom_ctx.
    inversion Hpkt2 as [|? ? ? ? Hpre2_level Hchild_level Hsuf2_level];
      subst.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A (S k) pre' pre2 pre_out pre2'
