        Hafter_pre Hafter_suf Hafter_pre_concat Hafter_suf_concat
        outer_pre2 outer_suf2 outer_pre2' pre_after'
        suf_after' outer_suf2'
        Houter_pre2 Houter_suf2 Hpre_after_concat Hsuf_after_concat
        c_inner Hred_outer).
Qed.

