      subst; clear Hbottom_ctx.
    inversion Hpkt2 as [|? ? ? ? Hpre2_level Hchild_level Hsuf2_level];
      subst.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A (S k) pre' pre2 pre_out pre2'
        Hpre'_level Hpre2_level Hpre2_shape Hpre_green)
      as [Hpre_out_shape [_ [Hpre_out_level Hpre2'_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A (S k) suf2 suf' suf2' suf_out
        Hsuf2_level Hsuf'_level Hsuf2_shape Hsuf_green)
      as [_ [Hsuf_out_shape [Hsuf2'_level Hsuf_out_level]]].
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k future_pre pre_out future_pre' pre_next
        Hfuture_pre Hpre_out_level Hpre_out_shape Hfuture_pre_concat)
      as [_ [Hpre_next_shape [_ Hpre_next_level]]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k suf_out future_suf suf_next future_suf'
