Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_continuation_from_chaincons :
  forall A,
    @recursive_case1_context_ready A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_continuation A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_continuation A.
Proof.
  unfold recursive_green_tail_parent_context_ready_refined_bottom_boundary_continuation,
         recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_continuation.
  intros A Hcase1 Hchaincons k pre suf red_pre red_suf b c_tail
    Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hinner.
  unfold green_of_red_k in Hred.
  destruct (make_small red_pre b red_suf) as [c0|] eqn:Hmake;
    [|discriminate].
  inversion Hred; subst c_tail; clear Hred.
  destruct c0 as [out|p tail].
  - inversion Hred_pkt as [|? ? ? ? Hred_pre_level _ Hred_suf_level];
      subst.
    pose proof (Hcase1 (S k) red_pre b red_suf (Ending out)
      Hred_pre_level Hb Hred_suf_level Hmake) as Hout_ctx.
    inversion Hout_ctx as [? ? Hout_level| |]; subst; clear Hout_ctx.
    unfold green_of_red_k in Hinner.
    destruct (make_small pre' out suf') as [c1|] eqn:Hmake_inner.
    2:{ cbn in Hinner. rewrite Hmake_inner in Hinner.
        discriminate Hinner. }
    cbn in Hinner. rewrite Hmake_inner in Hinner.
    inversion Hinner; subst c_inner; clear Hinner.
    apply pcrrr_existing.
    eapply Hcase1; [|exact Hout_level| |exact Hmake_inner].
    + inversion Hpkt as [|? ? ? ? Hpre_level _ _]; subst.
      destruct (@prefix_concat_preserves_outer_green_levels
          A k outer_pre pre outer_pre' pre'
          Houter_pre Hpre_level Hpre Hpre_concat)
        as [_ [_ Hpre'_level]].
      exact Hpre'_level.
    + inversion Hpkt as [|? ? ? ? _ _ Hsuf_level]; subst.
      destruct (@suffix_concat_preserves_outer_green_levels
          A k suf outer_suf suf' outer_suf'
          Hsuf_level Houter_suf Hsuf Hsuf_concat)
        as [Hsuf'_level _].
      exact Hsuf'_level.
  - assert (Hred_chaincons :
      green_of_red_k
        (KCons Red (PNode red_pre Hole red_suf) (KEnding b)) =
        Some (KCons Green p (chain_to_kchain_g tail))).
    { unfold green_of_red_k. rewrite Hmake. reflexivity. }
    exact (Hchaincons k pre suf red_pre red_suf b p (chain_to_kchain_g tail)
      Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred_chaincons
      outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hinner).
Qed.

Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_continuation_from_case2_output :
  forall A,
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_continuation A.
