    destruct (green_suffix_concat suf2 suf') as [[suf2' suf_out]|]
      eqn:Hsuf_green; [|discriminate].
    inversion Hinner; subst c_inner; clear Hinner.
    exact (Hcase2 k pre suf red_pre red_suf b pre2 child suf2 tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      pre_out pre2' suf2' suf_out
      Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hpre_green Hsuf_green).
Qed.

Lemma recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_from_case1_context_and_continuation :
