      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold q, p, x; cbn; reflexivity)
      ltac:(unfold q, p, x; cbn; reflexivity)
      B0 B0 (B2 x x) (B1 p) (B1 p) (B2 x x)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      B0 B0 (B2 x x) B0 B0 (B2 x x)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity))
    as [Hpre_repair_green _].
  cbn in Hpre_repair_green.
  exact Hpre_repair_green.
Qed.

Theorem recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_case2_input_context_gap :
  ~ @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_projection_case2_input_context unit.
Proof.
  intros Hinput.
  set (x := E.base unit tt).
  set (p := E.pair unit x x eq_refl).
  set (q := E.pair unit p p eq_refl).
  set (r := E.pair unit q q eq_refl).
  pose proof (Hinput
      0 (B2 p p) (B3 p p p) (B1 q) B0 (B2 r r)
      (B3 q q q) Hole (B2 q q) (KEnding B0)
      (B2 x x) (B4 x x x x)
      (B2 x x) (B2 p p) (B4 p p p p) (B2 x x)
      (B2 p p) (B3 q q q) (B3 q q q) (B2 p p)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(right; reflexivity)
      ltac:(constructor;
        [unfold p, x; cbn; repeat split; try reflexivity
        |constructor
        |unfold p, x; cbn; repeat split; try reflexivity])
      ltac:(constructor;
        [unfold q, p, x; cbn; repeat split; try reflexivity
        |constructor
        |exact I])
      ltac:(unfold r, q, p, x; cbn; repeat split; try reflexivity)
      ltac:(unfold r, q, p, x; cbn; reflexivity)
      ltac:(unfold x; cbn; repeat split; try reflexivity)
      ltac:(unfold x; cbn; repeat split; try reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold q, p, x; cbn; reflexivity)
      ltac:(unfold q, p, x; cbn; reflexivity)
      B0 B0 (B2 x x) (B1 p) (B1 p) (B2 x x)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      B0 B0 (B2 x x) B0 B0 (B2 x x)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      (B2 p p) (B2 q q) (B2 q q) (B2 p p)
      ltac:(unfold q, p, x; cbn; reflexivity)
      ltac:(unfold q, p, x; cbn; reflexivity)
      B0 B0 (B2 x x) (B1 p) (B1 p) (B2 x x)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      B0 B0 (B2 x x) B0 B0 (B2 x x)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(unfold p, x; cbn; reflexivity)
      ltac:(unfold p, x; cbn; reflexivity)
      (B2 p p) (B1 q) (B1 q) (B2 p p)
      ltac:(unfold q, p, x; cbn; reflexivity)
      ltac:(unfold q, p, x; cbn; reflexivity)) as Hctx.
  inversion Hctx; subst; cbn in *; contradiction.
Qed.

Theorem recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_continuation_gap :
  ~ @recursive_green_tail_parent_context_ready_refined_bottom_boundary_chaincons_case2_output_parent_pnode_case3_output_continuation nat.
