      ltac:(exact I)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(right; reflexivity)
      ltac:(constructor;
        [unfold p, z; cbn; reflexivity
        |constructor
        |unfold p, z; cbn; reflexivity])
      ltac:(constructor;
        [unfold q, p, z; cbn; reflexivity
        |constructor
        |exact I])
      ltac:(unfold r, q, p, z; cbn; repeat split; try reflexivity)
      ltac:(unfold r, q, p, z; cbn; reflexivity)
      ltac:(exact I)
      ltac:(exact I)
      ltac:(unfold p, z; cbn; reflexivity)
      ltac:(unfold p, z; cbn; reflexivity)
