Lemma recursive_green_tail_parent_context_ready_refined_from_existing_and_bottom_boundary :
  forall A,
    @recursive_green_tail_parent_context_ready A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary A ->
    @recursive_green_tail_parent_context_ready_refined A.
Proof.
  intros A Hexisting Hbottom k i tail c_tail Hgreen Hred.
  inversion Hgreen; subst.
  - apply pcrrr_existing. eapply Hexisting; eauto.
  - match goal with
    | Htop : kchain_top_color ?tail <> Red,
      Hred_tail : green_of_red_k ?tail = Some ?c_tail |- _ =>
        destruct tail as [b0|col0 p0 tail0]; cbn in Hred_tail;
          [discriminate
          |destruct col0; cbn in Htop, Hred_tail;
             try discriminate; exfalso; apply Htop; reflexivity]
    end.
  - match goal with
    | Hpre : buf5_is_not_red_shape ?pre,
      Hsuf : buf5_is_not_red_shape ?suf,
      Hred_pre : buf5_is_not_red_or_empty_shape ?red_pre,
      Hred_suf : buf5_is_not_red_or_empty_shape ?red_suf,
      Hempty : ?red_pre = B0 \/ ?red_suf = B0,
      Hpkt : packet_levels (S ?k) (PNode ?pre Hole ?suf),
      Hred_pkt : packet_levels (S (S ?k)) (PNode ?red_pre Hole ?red_suf),
      Hb : buf_all_at_level (S (S (S ?k))) ?b
      |- _ =>
        exact (Hbottom k pre suf red_pre red_suf b c_tail
          Hpre Hsuf Hred_pre Hred_suf Hempty Hpkt Hred_pkt Hb Hred)
    end.
  - match goal with
    | Hafter : forall c',
        green_of_red_k (KCons Red (PNode _ _ _) _) = Some c' ->
        packet_context_recursive_repair_ready_refined_at _ _ c'
      |- _ =>
        exact (Hafter c_tail Hred)
    end.
  - match goal with
    | Hafter : forall c',
        green_of_red_k (KCons Red (PNode _ _ _) _) = Some c' ->
        packet_context_recursive_repair_ready_refined_at _ _ c'
      |- _ =>
        exact (Hafter c_tail Hred)
    end.
Qed.

Lemma recursive_green_tail_parent_context_ready_refined_from_existing_and_bottom_boundary_components :
  forall A,
    @recursive_green_tail_parent_context_ready A ->
    @recursive_green_tail_parent_context_ready_refined_bottom_boundary_components A ->
    @recursive_green_tail_parent_context_ready_refined A.
Proof.
