Lemma recursive_repair_tail_parent_context_ready_hole_case1_when_case1_context :
  forall A k (pre suf b : Buf5 (E.t A)) c_tail,
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre Hole suf) (KEnding b)) ->
    @recursive_case1_context_ready A ->
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) =
      Some c_tail ->
    packet_context_recursive_repair_ready_at k Hole c_tail.
Proof.
  intros A k pre suf b c_tail Hctx Hcase1 Hred.
  inversion Hctx as
      [|? ? ? ? ? ? _ _ Hpkt Hchild_ctx _|]; subst; clear Hctx.
  inversion Hpkt as [|? ? ? ? Hpre _ Hsuf]; subst.
  assert (Hb : buf_all_at_level (S (S k)) b).
  { inversion Hchild_ctx; subst.
    inversion H; subst; assumption. }
  unfold green_of_red_k in Hred.
  destruct (make_small pre b suf) as [c0|] eqn:Hmake; [|discriminate].
  inversion Hred; subst c_tail; clear Hred.
  exact (Hcase1 k pre b suf c0 Hpre Hb Hsuf Hmake).
Qed.

Lemma recursive_repair_tail_parent_context_ready_non_red_tail :
  forall A k (i : Packet A) tail c_tail,
    kchain_top_color tail <> Red ->
    packet_context_recursive_repair_ready_at k i tail ->
    green_of_red_k tail = Some c_tail ->
    packet_context_recursive_repair_ready_at k i c_tail.
Proof.
  intros A k i tail c_tail Htop _ Hred.
  destruct tail as [b|col p tail']; cbn in Hred.
  - discriminate.
  - destruct col; cbn in Htop, Hred; try discriminate.
    exfalso. apply Htop. reflexivity.
Qed.

Lemma recursive_repair_tail_parent_context_ready_closed_frontier :
  forall A k (i : Packet A) tail c_tail,
    @recursive_case1_context_ready A ->
    (kchain_top_color tail <> Red \/
      exists (pre suf b : Buf5 (E.t A)),
        i = Hole /\
        tail = KCons Red (PNode pre Hole suf) (KEnding b)) ->
    packet_context_recursive_repair_ready_at k i tail ->
    green_of_red_k tail = Some c_tail ->
    packet_context_recursive_repair_ready_at k i c_tail.
Proof.
  intros A k i tail c_tail Hcase1 Hfrontier Hctx Hred.
  destruct Hfrontier as [Hnon_red|Hcase1_tail].
  - eapply recursive_repair_tail_parent_context_ready_non_red_tail; eauto.
  - destruct Hcase1_tail as [pre [suf [b [Hi Htail]]]].
    subst i tail.
    eapply recursive_repair_tail_parent_context_ready_hole_case1_when_case1_context;
      eauto.
Qed.

Definition recursive_repair_tail_parent_context_ready_red_nonbottom
    {A : Type} : Prop :=
  forall k (i : Packet A) pre child suf tail c_tail,
    (i <> Hole \/ child <> Hole \/ (forall b, tail <> KEnding b)) ->
    packet_context_recursive_repair_ready_at k i
      (KCons Red (PNode pre child suf) tail) ->
    green_of_red_k (KCons Red (PNode pre child suf) tail) = Some c_tail ->
    packet_context_recursive_repair_ready_at k i c_tail.

Definition recursive_repair_tail_parent_context_ready_parent_pnode
    {A : Type} : Prop :=
  forall k (i : Packet A) pre child suf tail c_tail,
    i <> Hole ->
    packet_context_recursive_repair_ready_at k i
      (KCons Red (PNode pre child suf) tail) ->
    green_of_red_k (KCons Red (PNode pre child suf) tail) = Some c_tail ->
    packet_context_recursive_repair_ready_at k i c_tail.

Definition recursive_repair_tail_parent_context_ready_hole
    {A : Type} : Prop :=
  forall k (pre : Buf5 (E.t A)) (child : Packet A)
         (suf : Buf5 (E.t A)) tail c_tail,
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre child suf) tail) ->
    green_of_red_k (KCons Red (PNode pre child suf) tail) = Some c_tail ->
    packet_context_recursive_repair_ready_at k Hole c_tail.

Definition recursive_repair_tail_parent_context_ready_parent_pnode_projection
    {A : Type} : Prop :=
  forall k (pre suf : Buf5 (E.t A)) (inner : Packet A)
         (tail c_tail : KChain A)
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         (c_inner : KChain A),
    packet_context_recursive_repair_ready_at k (PNode pre inner suf) tail ->
    green_of_red_k tail = Some c_tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    green_of_red_k (KCons Red (PNode pre' inner suf') c_tail) =
      Some c_inner ->
    packet_context_recursive_repair_ready_at k Hole c_inner.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_from_projection :
  forall A,
    @recursive_green_tail_parent_context_ready A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode A.
Proof.
  unfold recursive_green_tail_parent_context_ready,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection,
    recursive_repair_tail_parent_context_ready_parent_pnode.
  intros A Hgreen Hprojection k i pre child suf tail c_tail Hi Hctx Hred.
  destruct i as [|ipre iinner isuf]; [exfalso; apply Hi; reflexivity|].
  inversion Hctx as
      [| |? ? ? ? ? Hpre_shape Hsuf_shape Hpkt Hchild_ctx Hctx_after];
    subst.
  eapply pcrwr_pnode.
  - exact Hpre_shape.
  - exact Hsuf_shape.
  - exact Hpkt.
  - eapply pcgwr_repair.
    eapply Hgreen; [exact Hchild_ctx|exact Hred].
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
    exact (Hprojection k ipre isuf iinner
      (KCons Red (PNode pre child suf) tail) c_tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
      Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_from_hole_and_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection,
    recursive_repair_tail_parent_context_ready_parent_pnode.
  intros A Hhole Hprojection k i.
  revert k.
  induction i as [|ipre iinner IHinner isuf];
    intros k pre child suf tail c_tail Hi Hctx Hred.
  - exfalso. apply Hi. reflexivity.
  - pose proof Hctx as Hctx_orig.
    inversion Hctx as
        [| |? ? ? ? ? Hpre_shape Hsuf_shape Hpkt Hchild_ctx _];
      subst.
    eapply pcrwr_pnode.
    + exact Hpre_shape.
    + exact Hsuf_shape.
    + exact Hpkt.
    + destruct iinner as [|child_pre child_inner child_suf].
      * inversion Hchild_ctx as [? ? ? Hchild_repair|? ? ? ? ? _ _ Hafter];
          subst; clear Hchild_ctx.
        -- eapply pcgwr_repair.
           eapply Hhole; eauto.
        -- eapply pcgwr_repair.
           eapply Hafter. exact Hred.
      * inversion Hchild_ctx as [? ? ? Hchild_repair|]; subst;
          clear Hchild_ctx.
        eapply pcgwr_repair.
        eapply IHinner; eauto. discriminate.
    + intros outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
        Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
      exact (Hprojection k ipre isuf iinner
        (KCons Red (PNode pre child suf) tail) c_tail
        outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
        Hctx_orig Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
        Hred_inner).
Qed.

Definition recursive_repair_tail_parent_context_ready_parent_pnode_projection_hole
    {A : Type} : Prop :=
  forall k (pre suf : Buf5 (E.t A))
         (tail c_tail : KChain A)
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         (c_inner : KChain A),
    packet_context_recursive_repair_ready_at k (PNode pre Hole suf) tail ->
    green_of_red_k tail = Some c_tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    green_of_red_k (KCons Red (PNode pre' Hole suf') c_tail) =
      Some c_inner ->
    packet_context_recursive_repair_ready_at k Hole c_inner.

Definition recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested
    {A : Type} : Prop :=
  forall k (pre suf inner_pre : Buf5 (E.t A)) (inner_child : Packet A)
         (inner_suf : Buf5 (E.t A))
         (tail c_tail : KChain A)
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         (c_inner : KChain A),
    packet_context_recursive_repair_ready_at
      k (PNode pre (PNode inner_pre inner_child inner_suf) suf) tail ->
    green_of_red_k tail = Some c_tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    green_of_red_k
      (KCons Red
         (PNode pre' (PNode inner_pre inner_child inner_suf) suf')
         c_tail) = Some c_inner ->
    packet_context_recursive_repair_ready_at k Hole c_inner.

Lemma recursive_green_tail_hole_context_ready_from_repair_tail_hole :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole A ->
    forall k (tail c_tail : KChain A),
      packet_context_recursive_green_ready_at k Hole tail ->
      green_of_red_k tail = Some c_tail ->
      packet_context_recursive_repair_ready_at k Hole c_tail.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole.
  intros A Hhole k tail c_tail Hgreen Hred.
  inversion Hgreen as [? ? ? Hrepair|? ? ? ? ? _ _ Hafter]; subst;
    clear Hgreen.
  - destruct tail as [b|col p tail_rest]; cbn in Hred; try discriminate.
    destruct col; cbn in Hred; try discriminate.
    destruct p as [|pre child suf]; cbn in Hred; try discriminate.
    eapply Hhole; eauto.
  - exact (Hafter c_tail Hred).
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_from_hole_and_nested :
  forall A,
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_hole A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_parent_pnode_projection_hole,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection.
  intros A Hhole_projection Hnested k pre suf inner tail c_tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
    Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  destruct inner as [|inner_pre inner_child inner_suf].
  - exact (Hhole_projection k pre suf tail c_tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
      Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hred_inner).
  - exact (Hnested k pre suf inner_pre inner_child inner_suf tail c_tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
      Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hred_inner).
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_hole_from_repair_tail_hole_and_post_red_continuation :
  forall A,
    @recursive_case1_context_ready A ->
    @recursive_repair_tail_parent_context_ready_hole A ->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_hole A.
Proof.
  unfold
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_hole,
    packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation.
  intros A Hcase1 Hhole Hpost k pre suf tail c_tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
    Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  inversion Hctx as
      [| |? ? ? ? ? Hpre_shape Hsuf_shape Hpkt Hchild_ctx _];
    subst; clear Hctx.
  assert (Hchild_repair :
    packet_context_recursive_repair_ready_at (S k) Hole c_tail).
  { eapply recursive_green_tail_hole_context_ready_from_repair_tail_hole;
      eauto. }
  exact (Hpost k pre suf c_tail Hcase1 Hpre_shape Hsuf_shape Hpkt
    Hchild_repair outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    c_inner Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner).
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_from_repair_tail_hole_post_red_and_nested :
  forall A,
    @recursive_case1_context_ready A ->
    @recursive_repair_tail_parent_context_ready_hole A ->
    @packet_context_recursive_repair_ready_pnode_after_tail_repair_lift_post_red_continuation A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection A.
Proof.
  intros A Hcase1 Hhole Hpost Hnested.
  eapply recursive_repair_tail_parent_context_ready_parent_pnode_projection_from_hole_and_nested.
  - eapply recursive_repair_tail_parent_context_ready_parent_pnode_projection_hole_from_repair_tail_hole_and_post_red_continuation;
      eauto.
  - exact Hnested.
Qed.

Definition recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output
    {A : Type} : Prop :=
  forall k (pre suf inner_pre : Buf5 (E.t A)) (inner_child : Packet A)
         (inner_suf : Buf5 (E.t A)) (tail c_tail : KChain A)
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         case3_pre inner_pre' inner_suf' case3_suf,
    packet_context_recursive_repair_ready_at
      k (PNode pre (PNode inner_pre inner_child inner_suf) suf) tail ->
    green_of_red_k tail = Some c_tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    prefix_concat pre' inner_pre = Some (case3_pre, inner_pre') ->
    suffix_concat inner_suf suf' = Some (inner_suf', case3_suf) ->
    packet_context_recursive_repair_ready_at k Hole
      (KCons Green (PNode case3_pre Hole case3_suf)
         (KCons Red (PNode inner_pre' inner_child inner_suf') c_tail)).

Definition recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output_weak_context
    {A : Type} : Prop :=
  forall k (pre suf inner_pre : Buf5 (E.t A)) (inner_child : Packet A)
         (inner_suf : Buf5 (E.t A)) (tail c_tail : KChain A)
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         case3_pre inner_pre' inner_suf' case3_suf,
    packet_context_recursive_repair_ready_at
      k (PNode pre (PNode inner_pre inner_child inner_suf) suf) tail ->
    green_of_red_k tail = Some c_tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    prefix_concat pre' inner_pre = Some (case3_pre, inner_pre') ->
    suffix_concat inner_suf suf' = Some (inner_suf', case3_suf) ->
    green_of_red_k_context_ready_at k Hole
      (KCons Green (PNode case3_pre Hole case3_suf)
         (KCons Red (PNode inner_pre' inner_child inner_suf') c_tail)).

Definition recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_red_tail_context
    {A : Type} : Prop :=
  forall k (pre suf inner_pre : Buf5 (E.t A)) (inner_child : Packet A)
         (inner_suf : Buf5 (E.t A)) (tail c_tail : KChain A)
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         case3_pre inner_pre' inner_suf' case3_suf,
    packet_context_recursive_repair_ready_at
      k (PNode pre (PNode inner_pre inner_child inner_suf) suf) tail ->
    green_of_red_k tail = Some c_tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    prefix_concat pre' inner_pre = Some (case3_pre, inner_pre') ->
    suffix_concat inner_suf suf' = Some (inner_suf', case3_suf) ->
    packet_context_recursive_green_ready_at (S k) Hole
      (KCons Red (PNode inner_pre' inner_child inner_suf') c_tail).

Definition recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_post_green_continuation
    {A : Type} : Prop :=
  forall k (pre suf inner_pre : Buf5 (E.t A)) (inner_child : Packet A)
         (inner_suf : Buf5 (E.t A)) (tail c_tail : KChain A)
         outer_pre outer_suf outer_pre' pre' suf' outer_suf'
         case3_pre inner_pre' inner_suf' case3_suf,
    packet_context_recursive_repair_ready_at
      k (PNode pre (PNode inner_pre inner_child inner_suf) suf) tail ->
    green_of_red_k tail = Some c_tail ->
    buf_all_at_level k outer_pre ->
    buf_all_at_level k outer_suf ->
    prefix_concat outer_pre pre = Some (outer_pre', pre') ->
    suffix_concat suf outer_suf = Some (suf', outer_suf') ->
    prefix_concat pre' inner_pre = Some (case3_pre, inner_pre') ->
    suffix_concat inner_suf suf' = Some (inner_suf', case3_suf) ->
    forall future_pre future_suf future_pre' pre_out
           suf_out future_suf',
      buf_all_at_level k future_pre ->
      buf_all_at_level k future_suf ->
      green_prefix_concat future_pre case3_pre =
        Some (future_pre', pre_out) ->
      green_suffix_concat case3_suf future_suf =
        Some (suf_out, future_suf') ->
      packet_context_recursive_green_ready_at k
        (PNode pre_out Hole suf_out)
        (KCons Red (PNode inner_pre' inner_child inner_suf') c_tail).

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output_weak_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output_weak_context A.
Proof.
  unfold
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output_weak_context.
  intros A k pre suf inner_pre inner_child inner_suf tail c_tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    case3_pre inner_pre' inner_suf' case3_suf
    Hctx _Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase3_pre Hcase3_suf.
  inversion Hctx as
      [| |? ? ? ? ? Hpre_shape Hsuf_shape Hpkt Hchild_ctx _];
    subst; clear Hctx.
  inversion Hpkt as [|? ? ? ? Hpre_level Hinner_pkt Hsuf_level]; subst.
  inversion Hinner_pkt as [|? ? ? ? Hinner_pre_level _ Hinner_suf_level];
    subst.
  inversion Hchild_ctx as [? ? ? Hchild_repair|]; subst;
    clear Hchild_ctx; try discriminate.
  inversion Hchild_repair as
      [| |? ? ? ? ? Hinner_pre_shape Hinner_suf_shape _ _ _];
    subst; clear Hchild_repair; try discriminate.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre'
      Houter_pre Hpre_level Hpre_shape Hpre_concat)
    as [_ [_ Hpre'_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf' outer_suf'
      Hsuf_level Houter_suf Hsuf_shape Hsuf_concat)
    as [Hsuf'_level _].
  destruct (@prefix_concat_preserves_outer_green_levels
      A (S k) pre' inner_pre case3_pre inner_pre'
      Hpre'_level Hinner_pre_level Hinner_pre_shape Hcase3_pre)
    as [Hcase3_pre_shape [Hcase3_pre_level _]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A (S k) inner_suf suf' inner_suf' case3_suf
      Hinner_suf_level Hsuf'_level Hinner_suf_shape Hcase3_suf)
    as [_ [Hcase3_suf_shape Hcase3_suf_level]].
  unfold green_of_red_k_context_ready_at. cbn.
  repeat split; try assumption.
  constructor; [exact Hcase3_pre_level|constructor|exact Hcase3_suf_level].
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_red_tail_context_from_green_tail :
  forall A,
    @recursive_green_tail_parent_context_ready A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_red_tail_context A.
Proof.
  unfold recursive_green_tail_parent_context_ready,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_red_tail_context.
  intros A Hgreen_tail k pre suf inner_pre inner_child inner_suf tail c_tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    case3_pre inner_pre' inner_suf' case3_suf
    Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase3_pre Hcase3_suf.
  inversion Hctx as
      [| |? ? ? ? ? Hpre_shape Hsuf_shape Hpkt Hchild_ctx _];
    subst; clear Hctx.
  inversion Hpkt as [|? ? ? ? Hpre_level _ Hsuf_level]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A k outer_pre pre outer_pre' pre'
      Houter_pre Hpre_level Hpre_shape Hpre_concat)
    as [_ [_ Hpre'_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A k suf outer_suf suf' outer_suf'
      Hsuf_level Houter_suf Hsuf_shape Hsuf_concat)
    as [Hsuf'_level _].
  pose proof (Hgreen_tail (S k)
      (PNode inner_pre inner_child inner_suf) tail c_tail
      Hchild_ctx Hred) as Hchild_repair.
  inversion Hchild_repair as
      [| |? ? ? ? ? Hinner_pre_shape Hinner_suf_shape Hinner_pkt
           Hgrandchild_ctx Hchild_after];
    subst; clear Hchild_repair; try discriminate.
  inversion Hinner_pkt as
      [|? ? ? ? Hinner_pre_level Hinner_child_level Hinner_suf_level];
    subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A (S k) pre' inner_pre case3_pre inner_pre'
      Hpre'_level Hinner_pre_level Hinner_pre_shape Hcase3_pre)
    as [_ [_ Hinner_pre'_level]].
  destruct (@suffix_concat_preserves_outer_green_levels
      A (S k) inner_suf suf' inner_suf' case3_suf
      Hinner_suf_level Hsuf'_level Hinner_suf_shape Hcase3_suf)
    as [Hinner_suf'_level _].
  eapply pcgwr_hole_red_kcons.
  - constructor; [exact Hinner_pre'_level|exact Hinner_child_level|exact Hinner_suf'_level].
  - exact Hgrandchild_ctx.
  - intros c' Hred_child.
    exact (Hchild_after pre' suf' case3_pre inner_pre' inner_suf'
      case3_suf c' Hpre'_level Hsuf'_level Hcase3_pre Hcase3_suf
      Hred_child).
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output_from_red_tail_and_post_green_continuation :
  forall A,
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_red_tail_context A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_post_green_continuation A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output A.
Proof.
  unfold
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_red_tail_context,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_post_green_continuation,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output.
  intros A Hred_tail Hpost k pre suf inner_pre inner_child inner_suf
    tail c_tail outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    case3_pre inner_pre' inner_suf' case3_suf
    Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase3_pre Hcase3_suf.
  pose proof
    (@recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output_weak_context_ready
      A k pre suf inner_pre inner_child inner_suf tail c_tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      case3_pre inner_pre' inner_suf' case3_suf
      Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hcase3_pre Hcase3_suf) as Hready.
  unfold green_of_red_k_context_ready_at in Hready. cbn in Hready.
  destruct Hready as [Hcase3_pre_shape [Hcase3_suf_shape Hpkt]].
  eapply pcrwr_hole_kcons.
  - exact Hcase3_pre_shape.
  - exact Hcase3_suf_shape.
  - exact Hpkt.
  - exact (Hred_tail k pre suf inner_pre inner_child inner_suf tail c_tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      case3_pre inner_pre' inner_suf' case3_suf
      Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hcase3_pre Hcase3_suf).
  - intros future_pre future_suf future_pre' pre_out suf_out future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
    exact (Hpost k pre suf inner_pre inner_child inner_suf tail c_tail
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      case3_pre inner_pre' inner_suf' case3_suf
      Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
      Hcase3_pre Hcase3_suf
      future_pre future_suf future_pre' pre_out suf_out future_suf'
      Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat).
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_from_output :
  forall A,
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested A.
Proof.
  unfold
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested.
  intros A Houtput k pre suf inner_pre inner_child inner_suf tail c_tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
    Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner.
  unfold green_of_red_k in Hred_inner.
  destruct (prefix_concat pre' inner_pre)
    as [[case3_pre inner_pre_after]|] eqn:Hcase3_pre;
    [|discriminate].
  destruct (suffix_concat inner_suf suf')
    as [[inner_suf_after case3_suf]|] eqn:Hcase3_suf;
    [|discriminate].
  inversion Hred_inner; subst c_inner; clear Hred_inner.
  exact (Houtput k pre suf inner_pre inner_child inner_suf tail c_tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    case3_pre inner_pre_after inner_suf_after case3_suf
    Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase3_pre Hcase3_suf).
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_from_red_tail_and_post_green_continuation :
  forall A,
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_red_tail_context A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_post_green_continuation A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested A.
Proof.
  intros A Hred_tail Hpost.
  eapply recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_from_output.
  eapply recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_output_from_red_tail_and_post_green_continuation;
    eauto.
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_post_green_continuation_from_repair_tail_parent_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready A ->
    @recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_post_green_continuation A.
Proof.
  unfold recursive_repair_tail_parent_context_ready,
    recursive_repair_tail_parent_context_ready_parent_pnode_projection_nested_post_green_continuation.
  intros A Hrepair k pre suf inner_pre inner_child inner_suf tail c_tail
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    case3_pre inner_pre' inner_suf' case3_suf
    Hctx Hred Houter_pre Houter_suf Hpre_concat Hsuf_concat
    Hcase3_pre Hcase3_suf
    future_pre future_suf future_pre' pre_out suf_out future_suf'
    Hfuture_pre Hfuture_suf Hfuture_pre_concat Hfuture_suf_concat.
  pose proof (Hrepair k
      (PNode pre (PNode inner_pre inner_child inner_suf) suf)
      tail c_tail Hctx Hred) as Hctx_repaired.
  inversion Hctx_repaired as
      [| |? ? ? ? ? _ _ _ _ Hafter];
    subst; clear Hctx_repaired; try discriminate.
  assert (Hred_inner :
    green_of_red_k
      (KCons Red
         (PNode pre' (PNode inner_pre inner_child inner_suf) suf')
         c_tail) =
    Some
      (KCons Green (PNode case3_pre Hole case3_suf)
         (KCons Red (PNode inner_pre' inner_child inner_suf') c_tail))).
  { unfold green_of_red_k.
    rewrite Hcase3_pre, Hcase3_suf. reflexivity. }
  pose proof (Hafter outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      (KCons Green (PNode case3_pre Hole case3_suf)
         (KCons Red (PNode inner_pre' inner_child inner_suf') c_tail))
      Houter_pre Houter_suf Hpre_concat Hsuf_concat Hred_inner)
    as Houtput.
  inversion Houtput as
      [|? ? ? ? ? ? _ _ _ _ Houtput_after|];
    subst; clear Houtput; try discriminate.
  exact (Houtput_after future_pre future_suf future_pre' pre_out
    suf_out future_suf' Hfuture_pre Hfuture_suf
    Hfuture_pre_concat Hfuture_suf_concat).
Qed.

Definition recursive_repair_tail_parent_context_ready_hole_case2
    {A : Type} : Prop :=
  forall k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail c_tail : KChain A),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) = Some c_tail ->
    packet_context_recursive_repair_ready_at k Hole c_tail.

Definition recursive_repair_tail_parent_context_ready_hole_case2_output
    {A : Type} : Prop :=
  forall k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    packet_context_recursive_repair_ready_at k Hole
      (KCons Green (PNode pre1' (PNode pre2' child2 suf2') suf1')
         tail).

Definition recursive_repair_tail_parent_context_ready_hole_case2_output_weak_context
    {A : Type} : Prop :=
  forall k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    green_of_red_k_context_ready_at k Hole
      (KCons Green (PNode pre1' (PNode pre2' child2 suf2') suf1')
         tail).

Lemma recursive_repair_tail_parent_context_ready_hole_case2_output_weak_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_output_weak_context A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case2_output_weak_context.
  intros A k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  inversion Hctx as
      [|? ? ? ? ? ? Hpre1_shape Hsuf1_shape Hpkt1 Hchild_ctx _|];
    subst; clear Hctx.
  inversion Hpkt1 as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  assert (Hinner_pkt :
    packet_levels (S (S k)) (PNode pre2 child2 suf2)).
  { inversion Hchild_ctx as [? ? ? Hrepair|? ? ? ? ? Hpkt2 _ _]; subst.
    - inversion Hrepair as [|? ? ? ? ? ? _ _ Hpkt2 _ _|]; subst.
      exact Hpkt2.
    - exact Hpkt2. }
  destruct pre1; cbn in Hpre1_shape, Hpre_concat; try contradiction;
    inversion Hpre_concat; subst; clear Hpre_concat.
  all: destruct suf1; cbn in Hsuf1_shape, Hsuf_concat; try contradiction;
    inversion Hsuf_concat; subst; clear Hsuf_concat.
  all: unfold green_of_red_k_context_ready_at; cbn;
    repeat split; try assumption.
  all: constructor; [assumption|exact Hinner_pkt|assumption].
Qed.

Definition recursive_repair_tail_parent_context_ready_hole_case2_components
    {A : Type} : Prop :=
  forall k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    green_of_red_k_context_ready_at k Hole
      (KCons Green (PNode pre1' (PNode pre2' child2 suf2') suf1')
         tail) /\
    packet_context_recursive_green_ready_at (S k)
      (PNode pre2' child2 suf2') tail /\
    (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        : Buf5 (E.t A)),
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre1' = Some (outer_pre', pre') ->
      green_suffix_concat suf1' outer_suf = Some (suf', outer_suf') ->
      packet_context_recursive_green_ready_at k
        (PNode pre' (PNode pre2' child2 suf2') suf') tail).

Definition recursive_repair_tail_parent_context_ready_hole_case2_inner_ready
    {A : Type} : Prop :=
  forall k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
