      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    packet_context_recursive_green_ready_at (S k)
      (PNode pre2' child2 suf2') tail.

Definition recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail
    {A : Type} : Prop :=
  forall k (pre1 suf1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons Red (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
