      (PNode pre2' child2 suf2') tail.

Definition recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shape_projection
    {A : Type} : Prop :=
  forall k (pre1 suf1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons Red (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    buf5_is_not_red_shape pre2' /\
    buf5_is_not_red_shape suf2' /\
    (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        : Buf5 (E.t A)) c_inner,
      buf_all_at_level (S k) outer_pre ->
      buf_all_at_level (S k) outer_suf ->
      prefix_concat outer_pre pre2' = Some (outer_pre', pre') ->
      suffix_concat suf2' outer_suf = Some (suf', outer_suf') ->
      green_of_red_k (KCons Red (PNode pre' child2 suf') tail) =
        Some c_inner ->
      packet_context_recursive_repair_ready_at (S k) Hole c_inner).

Lemma recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shapes_from_strict_child :
  forall A k (pre1 suf1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons Red (PNode pre2 child2 suf2) tail)) ->
    packet_context_recursive_repair_ready_at (S k)
      (PNode pre2 child2 suf2) tail ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    buf5_is_not_red_shape pre2' /\ buf5_is_not_red_shape suf2'.
Proof.
  intros A k pre1 suf1 pre2 child2 suf2 tail pre1' pre2' suf2' suf1'
    Hctx Hchild_strict Hpre_concat Hsuf_concat.
  inversion Hctx as
      [|? ? ? ? ? ? _ _ Hpkt1 _ _|];
    subst; clear Hctx.
  inversion Hpkt1 as [|? ? ? ? Hpre1_levels _ Hsuf1_levels]; subst.
  inversion Hchild_strict as
      [| |? ? ? ? ? Hpre2_shape Hsuf2_shape Hpkt2 _ _];
    subst; clear Hchild_strict.
  inversion Hpkt2 as [|? ? ? ? Hpre2_levels _ Hsuf2_levels]; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels_from_not_red
      A (S k) pre1 pre2 pre1' pre2'
      Hpre1_levels Hpre2_levels Hpre2_shape Hpre_concat)
    as [_ [Hpre2'_shape _]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels_from_not_red
      A (S k) suf2 suf1 suf2' suf1'
      Hsuf2_levels Hsuf1_levels Hsuf2_shape Hsuf_concat)
    as [Hsuf2'_shape _].
  split; assumption.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_from_second_tail_repair_context :
  forall A k (pre1 suf1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons Red (PNode pre2 child2 suf2) tail)) ->
    packet_context_recursive_repair_ready_at (S k) Hole
      (KCons Red (PNode pre2 child2 suf2) tail) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    packet_context_recursive_green_ready_at (S k)
      (PNode pre2' child2 suf2') tail.
Proof.
  intros A k pre1 suf1 pre2 child2 suf2 tail pre1' pre2' suf2' suf1'
    Hctx Hsecond_tail_repair Hpre_concat Hsuf_concat.
  inversion Hctx as
      [|? ? ? ? ? ? _ _ Hpkt1 _ _|];
    subst; clear Hctx; try discriminate.
  inversion Hpkt1 as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hsecond_tail_repair as
      [|? ? ? ? ? ? _ _ _ _ Hctx_after|];
    subst; clear Hsecond_tail_repair; try discriminate.
  exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1'
    Hpre1 Hsuf1 Hpre_concat Hsuf_concat).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_from_shape_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shape_projection A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail A.
Proof.
  unfold
    recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shape_projection,
    recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail.
  intros A Hshape_projection k pre1 suf1 pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  pose proof Hctx as Hctx_orig.
  inversion Hctx as
      [|? ? ? ? ? ? Hpre1_shape Hsuf1_shape Hpkt1 Hchild_ctx _|];
    subst; clear Hctx.
  inversion Hpkt1 as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hchild_ctx as [? ? ? Hsecond_tail_repair|? ? ? ? ? Hpkt2 Hchild2_ctx _];
    subst; clear Hchild_ctx.
  - eapply recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_from_second_tail_repair_context;
      eauto.
  - destruct (Hshape_projection k pre1 suf1 pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx_orig Hpre_concat Hsuf_concat)
      as [Hpre2'_shape [Hsuf2'_shape Hprojection]].
  destruct pre1; cbn in Hpre1_shape, Hpre_concat; try contradiction;
    inversion Hpre_concat; subst; clear Hpre_concat.
  all: destruct suf1; cbn in Hsuf1_shape, Hsuf_concat; try contradiction;
    inversion Hsuf_concat; subst; clear Hsuf_concat.
  all: eapply pcgwr_repair; eapply pcrwr_pnode.
  all: try exact Hpre2'_shape.
  all: try exact Hsuf2'_shape.
  all: try exact Hpkt2.
  all: try exact Hchild2_ctx.
  all: intros outer_pre outer_suf outer_pre' pre' suf' outer_suf' c_inner
      Houter_pre Houter_suf Hpre_outer Hsuf_outer Hred_inner;
    exact (Hprojection outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      c_inner Houter_pre Houter_suf Hpre_outer Hsuf_outer Hred_inner).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_non_red_tail :
  forall A k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    col <> Red ->
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    packet_context_recursive_green_ready_at (S k)
      (PNode pre2' child2 suf2') tail.
Proof.
  intros A k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hnon_red Hctx Hpre_concat Hsuf_concat.
  inversion Hctx as
      [|? ? ? ? ? ? _ _ Hpkt1 Hchild_ctx _|];
    subst; clear Hctx; try discriminate.
  inversion Hpkt1 as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hchild_ctx as [? ? ? Hrepair|? ? ? ? ? _ _ _];
    subst; clear Hchild_ctx.
  - inversion Hrepair as
        [|? ? ? ? ? ? _ _ _ _ Hctx_after|];
      subst; clear Hrepair; try discriminate.
    exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1'
      Hpre1 Hsuf1 Hpre_concat Hsuf_concat).
  - exfalso. apply Hnon_red. reflexivity.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_from_red_tail :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail,
    recursive_repair_tail_parent_context_ready_hole_case2_inner_ready.
  intros A Hred_tail k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  destruct col.
  - eapply recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_non_red_tail;
      eauto; discriminate.
  - eapply recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_non_red_tail;
      eauto; discriminate.
  - exact (Hred_tail k pre1 suf1 pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat).
Qed.

Definition recursive_repair_tail_parent_context_ready_hole_case2_projection
    {A : Type} : Prop :=
  forall k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        : Buf5 (E.t A)),
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre1' = Some (outer_pre', pre') ->
      green_suffix_concat suf1' outer_suf = Some (suf', outer_suf') ->
      packet_context_recursive_green_ready_at k
        (PNode pre' (PNode pre2' child2 suf2') suf') tail.

Definition recursive_repair_tail_parent_context_ready_hole_case2_projection_continuation
    {A : Type} : Prop :=
  forall k (pre1 suf1 : Buf5 (E.t A)) col
         (pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) ->
    green_prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    green_suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        : Buf5 (E.t A)),
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre1' = Some (outer_pre', pre') ->
      green_suffix_concat suf1' outer_suf = Some (suf', outer_suf') ->
      forall (future_pre future_suf future_pre' pre_out
          suf_out future_suf' : Buf5 (E.t A)) c_inner,
        buf_all_at_level k future_pre ->
        buf_all_at_level k future_suf ->
        prefix_concat future_pre pre' = Some (future_pre', pre_out) ->
        suffix_concat suf' future_suf = Some (suf_out, future_suf') ->
        green_of_red_k
          (KCons Red
             (PNode pre_out (PNode pre2' child2 suf2') suf_out) tail) =
          Some c_inner ->
        packet_context_recursive_repair_ready_at k Hole c_inner.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_projection_from_inner_and_continuation :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_projection_continuation A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_projection A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case2_inner_ready,
    recursive_repair_tail_parent_context_ready_hole_case2_projection_continuation,
    recursive_repair_tail_parent_context_ready_hole_case2_projection.
  intros A Hinner Hcontinuation k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_outer Hsuf_outer.
  pose proof (@recursive_repair_tail_parent_context_ready_hole_case2_output_weak_context_ready
      A k pre1 suf1 col pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat)
    as Hready.
  unfold green_of_red_k_context_ready_at in Hready. cbn in Hready.
  destruct Hready as [Hpre1'_shape [Hsuf1'_shape Hpkt_outer]].
  inversion Hpkt_outer as [|? ? ? ? Hpre1' Hinner_pkt Hsuf1']; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k outer_pre pre1' outer_pre' pre'
      Houter_pre Hpre1' Hpre1'_shape Hpre_outer)
    as [_ [Hpre'_shape [_ Hpre']]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k suf1' outer_suf suf' outer_suf'
      Hsuf1' Houter_suf Hsuf1'_shape Hsuf_outer)
    as [Hsuf'_shape [_ [Hsuf' _]]].
  eapply pcgwr_repair.
  eapply pcrwr_pnode.
  - exact Hpre'_shape.
  - exact Hsuf'_shape.
  - constructor; [exact Hpre'|exact Hinner_pkt|exact Hsuf'].
  - exact (Hinner k pre1 suf1 col pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat).
  - intros future_pre future_suf future_pre' pre_out suf_out future_suf'
      c_inner Hfuture_pre Hfuture_suf Hpre_future Hsuf_future Hred_inner.
    exact (Hcontinuation k pre1 suf1 col pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_outer Hsuf_outer
      future_pre future_suf future_pre' pre_out suf_out future_suf'
      c_inner Hfuture_pre Hfuture_suf Hpre_future Hsuf_future Hred_inner).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_projection_continuation_from_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_projection A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_projection_continuation A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case2_projection,
    recursive_repair_tail_parent_context_ready_hole_case2_projection_continuation.
  intros A Hprojection k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_outer Hsuf_outer
    future_pre future_suf future_pre' pre_out suf_out future_suf'
    c_inner Hfuture_pre Hfuture_suf Hpre_future Hsuf_future Hred_inner.
  pose proof (Hprojection k pre1 suf1 col pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_outer Hsuf_outer) as Hgreen.
  inversion Hgreen; subst; clear Hgreen.
  - inversion H; subst; clear H.
    match goal with
    | Hafter : forall (future_pre0 future_suf0 future_pre0' pre_out0
          suf_out0 future_suf0' : Buf5 (E.t A)) (c_inner0 : KChain A),
        buf_all_at_level k future_pre0 ->
        buf_all_at_level k future_suf0 ->
        prefix_concat future_pre0 pre' = Some (future_pre0', pre_out0) ->
        suffix_concat suf' future_suf0 = Some (suf_out0, future_suf0') ->
        green_of_red_k
          (KCons Red
             (PNode pre_out0 (PNode pre2' child2 suf2') suf_out0) tail) =
          Some c_inner0 ->
        packet_context_recursive_repair_ready_at k Hole c_inner0
      |- _ =>
        exact (Hafter future_pre future_suf future_pre' pre_out
          suf_out future_suf' c_inner Hfuture_pre Hfuture_suf
          Hpre_future Hsuf_future Hred_inner)
    end.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shape_projection_from_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_projection A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shape_projection A.
Proof.
  unfold
    recursive_repair_tail_parent_context_ready_hole_case2_projection,
    recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shape_projection.
  intros A Hprojection k pre1 suf1 pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  pose proof (@recursive_repair_tail_parent_context_ready_hole_case2_output_weak_context_ready
      A k pre1 suf1 Red pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat)
    as Hready.
  unfold green_of_red_k_context_ready_at in Hready.
  cbn in Hready.
  destruct Hready as [Hpre1'_shape [Hsuf1'_shape Hpkt_outer]].
  inversion Hpkt_outer as [|? ? ? ? Hpre1'_levels Hinner_pkt Hsuf1'_levels];
    subst.
  destruct (@green_prefix_concat_total_under_levels A k B0 pre1'
      ltac:(cbn; exact I) Hpre1'_levels Hpre1'_shape)
    as [outer_pre' [pre_after Hpre_outer]].
  destruct (@green_suffix_concat_total_under_levels A k suf1' B0
      Hsuf1'_levels ltac:(cbn; exact I) Hsuf1'_shape)
    as [suf_after [outer_suf' Hsuf_outer]].
  pose proof (Hprojection k pre1 suf1 Red pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
      B0 B0 outer_pre' pre_after suf_after outer_suf'
      ltac:(cbn; exact I) ltac:(cbn; exact I)
      Hpre_outer Hsuf_outer) as Hparent_green.
  inversion Hparent_green as [? ? ? Hparent_repair|]; subst;
    clear Hparent_green; try discriminate.
  inversion Hparent_repair as
      [| |? ? ? ? ? _ _ _ Hchild_green _];
    subst; clear Hparent_repair; try discriminate.
  inversion Hchild_green as [? ? ? Hchild_repair|]; subst;
    clear Hchild_green; try discriminate.
  inversion Hchild_repair as
      [| |? ? ? ? ? Hpre2'_shape Hsuf2'_shape _ _ Hchild_after];
    subst; clear Hchild_repair; try discriminate.
  split; [exact Hpre2'_shape|].
  split; [exact Hsuf2'_shape|].
  intros outer_pre outer_suf outer_pre'' pre' suf' outer_suf'' c_inner
    Houter_pre Houter_suf Hpre_child Hsuf_child Hred_inner.
  exact (Hchild_after outer_pre outer_suf outer_pre'' pre' suf'
    outer_suf'' c_inner Houter_pre Houter_suf Hpre_child Hsuf_child
    Hred_inner).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_components_from_inner_and_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_projection A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_components A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case2_inner_ready,
    recursive_repair_tail_parent_context_ready_hole_case2_projection,
    recursive_repair_tail_parent_context_ready_hole_case2_components.
  intros A Hinner Hprojection k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  split.
  - exact (@recursive_repair_tail_parent_context_ready_hole_case2_output_weak_context_ready
      A k pre1 suf1 col pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat).
  - split.
    + exact (Hinner k pre1 suf1 col pre2 child2 suf2 tail
        pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat).
    + intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        Houter_pre Houter_suf Hpre_outer Hsuf_outer.
      exact (Hprojection k pre1 suf1 col pre2 child2 suf2 tail
        pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
        outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        Houter_pre Houter_suf Hpre_outer Hsuf_outer).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_components_from_inner_and_continuation :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_inner_ready A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_projection_continuation A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_components A.
Proof.
  intros A Hinner Hcontinuation.
  eapply recursive_repair_tail_parent_context_ready_hole_case2_components_from_inner_and_projection.
  - exact Hinner.
  - eapply recursive_repair_tail_parent_context_ready_hole_case2_projection_from_inner_and_continuation;
      eauto.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_output_from_components :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_components A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_output A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case2_components,
    recursive_repair_tail_parent_context_ready_hole_case2_output.
  intros A Hcomponents k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  destruct (Hcomponents k pre1 suf1 col pre2 child2 suf2 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat)
    as [Hready [Hchild_ready Hafter]].
  cbn in Hready.
  destruct Hready as [Hpre1'_shape [Hsuf1'_shape Hpkt]].
  eapply pcrwr_hole_kcons.
  - exact Hpre1'_shape.
  - exact Hsuf1'_shape.
  - exact Hpkt.
  - exact Hchild_ready.
  - exact Hafter.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_output_from_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_projection A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_output A.
Proof.
  intros A Hprojection.
  eapply recursive_repair_tail_parent_context_ready_hole_case2_output_from_components.
  eapply recursive_repair_tail_parent_context_ready_hole_case2_components_from_inner_and_projection.
  - eapply recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_from_red_tail.
    eapply recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_from_shape_projection.
    eapply recursive_repair_tail_parent_context_ready_hole_case2_inner_ready_red_tail_shape_projection_from_projection.
    exact Hprojection.
  - exact Hprojection.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_from_output :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case2_output A ->
    @recursive_repair_tail_parent_context_ready_hole_case2 A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case2_output,
    recursive_repair_tail_parent_context_ready_hole_case2.
  intros A Houtput k pre1 suf1 col pre2 child2 suf2 tail c_tail Hctx Hred.
  unfold green_of_red_k in Hred.
  destruct (green_prefix_concat pre1 pre2) as [[pre1' pre2']|]
    eqn:Hpre_concat; [|discriminate].
  destruct (green_suffix_concat suf2 suf1) as [[suf2' suf1']|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst c_tail; clear Hred.
  eapply Houtput; eauto.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case2_output_from_repair_tail_parent_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_output A.
Proof.
  unfold recursive_repair_tail_parent_context_ready,
    recursive_repair_tail_parent_context_ready_hole_case2_output.
  intros A Hrepair k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  eapply Hrepair.
  - exact Hctx.
  - unfold green_of_red_k.
    rewrite Hpre_concat, Hsuf_concat.
    reflexivity.
Qed.

Definition recursive_repair_tail_parent_context_ready_hole_case3
    {A : Type} : Prop :=
  forall k (pre1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 suf1 : Buf5 (E.t A)) (tail c_tail : KChain A),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail) ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail) =
        Some c_tail ->
    packet_context_recursive_repair_ready_at k Hole c_tail.

Definition recursive_repair_tail_parent_context_ready_hole_case3_output
    {A : Type} : Prop :=
  forall k (pre1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 suf1 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail) ->
    prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    packet_context_recursive_repair_ready_at k Hole
      (KCons Green (PNode pre1' Hole suf1')
