      [|? ? ? ? ? ? _ _ Hpkt1 Hchild_ctx _|]; subst; clear Hctx.
  inversion Hpkt1 as [|? ? ? ? Hpre1 Hinner1 Hsuf1]; subst.
  inversion Hchild_ctx as [? ? ? Hchild_repair|]; subst; clear Hchild_ctx.
  inversion Hchild_repair as
      [| |? ? ? ? ? Hpre2_shape Hsuf2_shape Hpkt2 _ _]; subst.
  inversion Hpkt2 as [|? ? ? ? Hpre2 Hchild2 Hsuf2]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A (S k) pre1 pre2 pre1' pre2'
      Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre1' _]].
