Definition recursive_repair_tail_parent_context_ready_hole_case3_projection_continuation
    {A : Type} : Prop :=
  forall k (pre1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 suf1 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
