        : Buf5 (E.t A)),
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre1' = Some (outer_pre', pre') ->
      green_suffix_concat suf1' outer_suf = Some (suf', outer_suf') ->
      forall (future_pre future_suf future_pre' pre_out
          suf_out future_suf' : Buf5 (E.t A)) c_inner,
        buf_all_at_level k future_pre ->
        buf_all_at_level k future_suf ->
        prefix_concat future_pre pre' = Some (future_pre', pre_out) ->
        suffix_concat suf' future_suf = Some (suf_out, future_suf') ->
        green_of_red_k
          (KCons Red (PNode pre_out Hole suf_out)
             (KCons Red (PNode pre2' child2 suf2') tail)) =
