  destruct (@suffix_concat_preserves_outer_green_levels
      A (S k) suf2 suf1 suf2' suf1'
      Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2' _].
  eapply pcgwr_hole_red_kcons.
  - constructor; [exact Hpre2'|exact Hchild2|exact Hsuf2'].
  - exact Hchild2_ctx.
  - intros c' Hred.
    exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1' c'
      Hpre1 Hsuf1 Hpre_concat Hsuf_concat Hred).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case3_red_tail_refined_context_ready :
  forall A k (pre1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
