Lemma recursive_repair_tail_parent_context_ready_hole_case3_output_refined_from_case1_context_and_pnode_after_tail_repair_lift :
  forall A,
    @recursive_case1_context_ready A ->
    @packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_output_refined A.
Proof.
  unfold recursive_case1_context_ready,
    packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift,
    recursive_repair_tail_parent_context_ready_hole_case3_output_refined.
  intros A Hcase1 Hlift k pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  inversion Hctx as
      [|? ? ? ? ? ? _ _ Hpkt1 Hchild_ctx _|]; subst; clear Hctx.
  inversion Hpkt1 as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hchild_ctx as [? ? ? Hchild_repair|]; subst; clear Hchild_ctx.
  inversion Hchild_repair as
      [| |? ? ? ? ? Hpre2_shape Hsuf2_shape Hpkt2 Hchild2_ctx Hctx_after];
    subst.
  inversion Hpkt2 as [|? ? ? ? Hpre2 Hchild2 Hsuf2]; subst.
  destruct (@prefix_concat_preserves_outer_green_levels
      A (S k) pre1 pre2 pre1' pre2'
      Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre1' Hpre2']].
  destruct (@suffix_concat_preserves_outer_green_levels
      A (S k) suf2 suf1 suf2' suf1'
      Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2' [Hsuf1'_shape Hsuf1']].
  assert (Hred_tail_refined :
    packet_context_recursive_green_ready_refined_at (S k) Hole
      (KCons Red (PNode pre2' child2 suf2') tail)).
  { eapply pcgrr_hole_red_kcons_refined.
    - constructor; [exact Hpre2'|exact Hchild2|exact Hsuf2'].
    - apply pcgrr_existing. exact Hchild2_ctx.
    - intros c_tail Hred_tail.
      apply pcrrr_existing.
      exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1' c_tail
        Hpre1 Hsuf1 Hpre_concat Hsuf_concat Hred_tail). }
  eapply pcrrr_hole_kcons.
  - exact Hpre1'_shape.
  - exact Hsuf1'_shape.
  - constructor; [exact Hpre1'|constructor|exact Hsuf1'].
  - exact Hred_tail_refined.
  - intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_outer Hsuf_outer.
    destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
        A k outer_pre pre1' outer_pre' pre'
        Houter_pre Hpre1' Hpre1'_shape Hpre_outer)
      as [_ [Hpre'_shape [_ Hpre']]].
    destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
        A k suf1' outer_suf suf' outer_suf'
        Hsuf1' Houter_suf Hsuf1'_shape Hsuf_outer)
      as [Hsuf'_shape [_ [Hsuf' _]]].
    assert (Hparent_pkt :
      packet_levels (S k) (PNode pre' Hole suf')).
    { constructor; [exact Hpre'|constructor|exact Hsuf']. }
    eapply pcgrr_pnode_red_tail_refined.
    + exact Hpre'_shape.
    + exact Hsuf'_shape.
    + exact Hparent_pkt.
    + exact Hred_tail_refined.
    + intros c_tail Hred_tail.
      eapply Hlift.
      * exact Hcase1.
      * exact Hpre'_shape.
      * exact Hsuf'_shape.
      * exact Hparent_pkt.
      * exact (Hctx_after pre1 suf1 pre1' pre2' suf2' suf1' c_tail
          Hpre1 Hsuf1 Hpre_concat Hsuf_concat Hred_tail).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case3_output_refined_from_repair_tail_parent_context_ready :
  forall A,
    @recursive_case1_context_ready A ->
    @recursive_repair_tail_parent_context_ready A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_output_refined A.
Proof.
  intros A Hcase1 Hrepair.
  eapply recursive_repair_tail_parent_context_ready_hole_case3_output_refined_from_case1_context_and_pnode_after_tail_repair_lift.
  - exact Hcase1.
  - eapply packet_context_recursive_repair_ready_refined_pnode_after_tail_repair_lift_from_repair_tail_parent_context_ready.
    exact Hrepair.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case3_projection_from_continuation :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case3_projection_continuation A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_projection A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case3_projection_continuation,
    recursive_repair_tail_parent_context_ready_hole_case3_projection.
  intros A Hcontinuation k pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_outer Hsuf_outer.
  pose proof (@recursive_repair_tail_parent_context_ready_hole_case3_output_weak_context_ready
      A k pre1 pre2 child2 suf2 suf1 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat)
    as Hready.
  unfold green_of_red_k_context_ready_at in Hready. cbn in Hready.
  destruct Hready as [Hpre1'_shape [Hsuf1'_shape Hpkt_outer]].
  inversion Hpkt_outer as [|? ? ? ? Hpre1' _ Hsuf1']; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k outer_pre pre1' outer_pre' pre'
      Houter_pre Hpre1' Hpre1'_shape Hpre_outer)
    as [_ [Hpre'_shape [_ Hpre']]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k suf1' outer_suf suf' outer_suf'
      Hsuf1' Houter_suf Hsuf1'_shape Hsuf_outer)
    as [Hsuf'_shape [_ [Hsuf' _]]].
  eapply pcgwr_repair.
  eapply pcrwr_pnode.
  - exact Hpre'_shape.
  - exact Hsuf'_shape.
  - constructor; [exact Hpre'|constructor|exact Hsuf'].
  - exact (@recursive_repair_tail_parent_context_ready_hole_case3_red_tail_context_ready
      A k pre1 pre2 child2 suf2 suf1 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat).
  - intros future_pre future_suf future_pre' pre_out suf_out future_suf'
      c_inner Hfuture_pre Hfuture_suf Hpre_future Hsuf_future Hred_inner.
    exact (Hcontinuation k pre1 pre2 child2 suf2 suf1 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_outer Hsuf_outer
      future_pre future_suf future_pre' pre_out suf_out future_suf'
      c_inner Hfuture_pre Hfuture_suf Hpre_future Hsuf_future Hred_inner).
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case3_projection_continuation_from_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case3_projection A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_projection_continuation A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case3_projection,
    recursive_repair_tail_parent_context_ready_hole_case3_projection_continuation.
  intros A Hprojection k pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_outer Hsuf_outer
    future_pre future_suf future_pre' pre_out suf_out future_suf'
    c_inner Hfuture_pre Hfuture_suf Hpre_future Hsuf_future Hred_inner.
  pose proof (Hprojection k pre1 pre2 child2 suf2 suf1 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
      outer_pre outer_suf outer_pre' pre' suf' outer_suf'
      Houter_pre Houter_suf Hpre_outer Hsuf_outer) as Hgreen.
  inversion Hgreen; subst; clear Hgreen.
  - inversion H; subst; clear H.
    match goal with
    | Hafter : forall (future_pre0 future_suf0 future_pre0' pre_out0
          suf_out0 future_suf0' : Buf5 (E.t A)) (c_inner0 : KChain A),
        buf_all_at_level k future_pre0 ->
        buf_all_at_level k future_suf0 ->
        prefix_concat future_pre0 pre' = Some (future_pre0', pre_out0) ->
        suffix_concat suf' future_suf0 = Some (suf_out0, future_suf0') ->
        green_of_red_k
          (KCons Red (PNode pre_out0 Hole suf_out0)
             (KCons Red (PNode pre2' child2 suf2') tail)) =
          Some c_inner0 ->
        packet_context_recursive_repair_ready_at k Hole c_inner0
      |- _ =>
        exact (Hafter future_pre future_suf future_pre' pre_out
          suf_out future_suf' c_inner Hfuture_pre Hfuture_suf
          Hpre_future Hsuf_future Hred_inner)
    end.
Qed.

Lemma recursive_repair_tail_parent_context_ready_parent_pnode_from_repair_tail_parent_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready A ->
