Lemma recursive_repair_tail_parent_context_ready_hole_case2_projection_from_repair_tail_parent_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready A ->
    @recursive_repair_tail_parent_context_ready_hole_case2_projection A.
Proof.
  unfold recursive_repair_tail_parent_context_ready,
    recursive_repair_tail_parent_context_ready_hole_case2_projection.
  intros A Hrepair k pre1 suf1 col pre2 child2 suf2 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_outer Hsuf_outer.
  pose proof (Hrepair k Hole
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail))
      (KCons Green (PNode pre1' (PNode pre2' child2 suf2') suf1')
         tail)
      Hctx) as Hout.
  assert (Hred :
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child2 suf2) tail)) =
      Some (KCons Green (PNode pre1' (PNode pre2' child2 suf2') suf1')
         tail)).
  { unfold green_of_red_k.
    rewrite Hpre_concat, Hsuf_concat. reflexivity. }
  specialize (Hout Hred).
  inversion Hout; subst; clear Hout.
  match goal with
  | Hafter : forall (outer_pre0 outer_suf0 outer_pre0' pre0 suf0
        outer_suf0' : Buf5 (E.t A)),
      buf_all_at_level k outer_pre0 ->
      buf_all_at_level k outer_suf0 ->
      green_prefix_concat outer_pre0 pre1' = Some (outer_pre0', pre0) ->
      green_suffix_concat suf1' outer_suf0 = Some (suf0, outer_suf0') ->
      packet_context_recursive_green_ready_at k
        (PNode pre0 (PNode pre2' child2 suf2') suf0) tail
    |- _ =>
      exact (Hafter outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        Houter_pre Houter_suf Hpre_outer Hsuf_outer)
  end.
Qed.

Lemma recursive_repair_tail_parent_context_ready_hole_case3_projection_from_repair_tail_parent_context_ready :
  forall A,
    @recursive_repair_tail_parent_context_ready A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_projection A.
Proof.
  unfold recursive_repair_tail_parent_context_ready,
    recursive_repair_tail_parent_context_ready_hole_case3_projection.
  intros A Hrepair k pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_outer Hsuf_outer.
  pose proof (Hrepair k Hole
      (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail)
      (KCons Green (PNode pre1' Hole suf1')
         (KCons Red (PNode pre2' child2 suf2') tail))
      Hctx) as Hout.
  assert (Hred :
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail) =
      Some (KCons Green (PNode pre1' Hole suf1')
         (KCons Red (PNode pre2' child2 suf2') tail))).
  { unfold green_of_red_k.
    rewrite Hpre_concat, Hsuf_concat. reflexivity. }
  specialize (Hout Hred).
  inversion Hout; subst; clear Hout.
  match goal with
  | Hafter : forall (outer_pre0 outer_suf0 outer_pre0' pre0 suf0
        outer_suf0' : Buf5 (E.t A)),
      buf_all_at_level k outer_pre0 ->
