Definition recursive_repair_tail_parent_context_ready_hole_case3_components
    {A : Type} : Prop :=
  forall k (pre1 pre2 : Buf5 (E.t A)) (child2 : Packet A)
         (suf2 suf1 : Buf5 (E.t A)) (tail : KChain A)
         (pre1' pre2' suf2' suf1' : Buf5 (E.t A)),
    packet_context_recursive_repair_ready_at k Hole
      (KCons Red (PNode pre1 (PNode pre2 child2 suf2) suf1) tail) ->
    prefix_concat pre1 pre2 = Some (pre1', pre2') ->
    suffix_concat suf2 suf1 = Some (suf2', suf1') ->
    green_of_red_k_context_ready_at k Hole
      (KCons Green (PNode pre1' Hole suf1')
         (KCons Red (PNode pre2' child2 suf2') tail)) /\
    packet_context_recursive_green_ready_at (S k) Hole
      (KCons Red (PNode pre2' child2 suf2') tail) /\
    (forall (outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        : Buf5 (E.t A)),
      buf_all_at_level k outer_pre ->
      buf_all_at_level k outer_suf ->
      green_prefix_concat outer_pre pre1' = Some (outer_pre', pre') ->
      green_suffix_concat suf1' outer_suf = Some (suf', outer_suf') ->
      packet_context_recursive_green_ready_at k
        (PNode pre' Hole suf')
        (KCons Red (PNode pre2' child2 suf2') tail)).

Lemma recursive_repair_tail_parent_context_ready_hole_case3_components_from_red_tail_and_projection :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case3_red_tail_context A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_projection A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_components A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case3_red_tail_context,
    recursive_repair_tail_parent_context_ready_hole_case3_projection,
    recursive_repair_tail_parent_context_ready_hole_case3_components.
  intros A Hred_tail Hprojection k pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  split.
  - exact (@recursive_repair_tail_parent_context_ready_hole_case3_output_weak_context_ready
      A k pre1 pre2 child2 suf2 suf1 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat).
  - split.
    + exact (Hred_tail k pre1 pre2 child2 suf2 suf1 tail
        pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat).
    + intros outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        Houter_pre Houter_suf Hpre_outer Hsuf_outer.
      exact (Hprojection k pre1 pre2 child2 suf2 suf1 tail
        pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
        outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        Houter_pre Houter_suf Hpre_outer Hsuf_outer).
Qed.

