Lemma recursive_repair_tail_parent_context_ready_hole_case3_output_from_components :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case3_components A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_output A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case3_components,
    recursive_repair_tail_parent_context_ready_hole_case3_output.
  intros A Hcomponents k pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat.
  destruct (Hcomponents k pre1 pre2 child2 suf2 suf1 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat)
    as [Hready [Hchild_ready Hafter]].
  cbn in Hready.
  destruct Hready as [Hpre1'_shape [Hsuf1'_shape Hpkt]].
  eapply pcrwr_hole_kcons.
  - exact Hpre1'_shape.
  - exact Hsuf1'_shape.
  - exact Hpkt.
  - exact Hchild_ready.
  - exact Hafter.
Qed.

