Lemma recursive_repair_tail_parent_context_ready_hole_case3_projection_from_output :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case3_output A ->
    @recursive_repair_tail_parent_context_ready_hole_case3_projection A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case3_output,
    recursive_repair_tail_parent_context_ready_hole_case3_projection.
  intros A Houtput k pre1 pre2 child2 suf2 suf1 tail
    pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat
    outer_pre outer_suf outer_pre' pre' suf' outer_suf'
    Houter_pre Houter_suf Hpre_outer Hsuf_outer.
  pose proof (Houtput k pre1 pre2 child2 suf2 suf1 tail
      pre1' pre2' suf2' suf1' Hctx Hpre_concat Hsuf_concat)
    as Hout.
  inversion Hout; subst; clear Hout; try discriminate.
  match goal with
  | Hafter : forall (outer_pre0 outer_suf0 outer_pre0' pre0 suf0
        outer_suf0' : Buf5 (E.t A)),
      buf_all_at_level k outer_pre0 ->
      buf_all_at_level k outer_suf0 ->
      green_prefix_concat outer_pre0 pre1' = Some (outer_pre0', pre0) ->
      green_suffix_concat suf1' outer_suf0 = Some (suf0, outer_suf0') ->
      packet_context_recursive_green_ready_at k
        (PNode pre0 Hole suf0)
        (KCons Red (PNode pre2' child2 suf2') tail)
    |- _ =>
      exact (Hafter outer_pre outer_suf outer_pre' pre' suf' outer_suf'
        Houter_pre Houter_suf Hpre_outer Hsuf_outer)
  end.
Qed.

