Lemma recursive_repair_tail_parent_context_ready_hole_case3_from_output :
  forall A,
    @recursive_repair_tail_parent_context_ready_hole_case3_output A ->
    @recursive_repair_tail_parent_context_ready_hole_case3 A.
Proof.
  unfold recursive_repair_tail_parent_context_ready_hole_case3_output,
    recursive_repair_tail_parent_context_ready_hole_case3.
  intros A Houtput k pre1 pre2 child2 suf2 suf1 tail c_tail Hctx Hred.
  unfold green_of_red_k in Hred.
  destruct (prefix_concat pre1 pre2) as [[pre1' pre2']|]
    eqn:Hpre_concat; [|discriminate].
  destruct (suffix_concat suf2 suf1) as [[suf2' suf1']|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst c_tail; clear Hred.
  eapply Houtput; eauto.
Qed.

