    recursive_repair_tail_parent_context_ready_red_nonbottom.
  intros A Hpnode Hcase2 Hcase3 k i pre child suf tail c_tail
    Hnonbottom Hctx Hred.
  destruct i as [|ipre ichild isuf].
  - destruct child as [|cpre cchild csuf].
    + destruct tail as [b|col p tail_rest].
      * destruct Hnonbottom as [Hi|[Hchild|Htail]].
        -- exfalso. apply Hi. reflexivity.
        -- exfalso. apply Hchild. reflexivity.
        -- exfalso. apply (Htail b). reflexivity.
      * destruct p as [|pre2 child2 suf2].
        -- cbn in Hred. discriminate.
        -- eapply Hcase2; eauto.
    + eapply Hcase3; eauto.
  - eapply Hpnode; eauto. discriminate.
Qed.

