    @recursive_repair_tail_parent_context_ready A.
Proof.
  unfold recursive_repair_tail_parent_context_ready,
    recursive_repair_tail_parent_context_ready_red_nonbottom.
  intros A Hcase1 Hred_nonbottom k i tail c_tail Hctx Hred.
  pose proof (@green_of_red_k_success_requires_red_top A tail c_tail Hred)
    as Htop.
  destruct tail as [b|col p tail_rest]; cbn in Htop; try discriminate.
  destruct col; cbn in Htop; try discriminate.
  destruct p as [|pre child suf]; cbn in Hred; try discriminate.
  destruct i as [|ipre ichild isuf].
  - destruct child as [|cpre cchild csuf].
    + destruct tail_rest as [b|rest_col rest_p rest_tail].
      * eapply recursive_repair_tail_parent_context_ready_hole_case1_when_case1_context;
          eauto.
      * eapply Hred_nonbottom; eauto.
        right. right. intros b Hending. discriminate.
    + eapply Hred_nonbottom; eauto.
      right. left. discriminate.
  - eapply Hred_nonbottom; eauto.
    left. discriminate.
Qed.

