Lemma green_tail_repair_preserves_recursive_wrap_ready_state_regular_when_case1_contexts :
  forall A k (pre : Buf5 (E.t A)) i suf tail c_tail,
    regular_kt (KCons Green (PNode pre i suf) tail) ->
    kt4_level_recursive_wrap_ready_state_at k
      (KCons Green (PNode pre i suf) tail) ->
    @recursive_case1_context_ready A ->
    green_of_red_k tail = Some c_tail ->
    kt4_level_recursive_wrap_ready_state_at
      (k + packet_depth (PNode pre i suf)) c_tail.
Proof.
  intros A k pre i suf tail c_tail Hreg Hstate Hcase1 Hred.
  cbn in Hstate.
  destruct Hstate as [_ [_ [_ [Htail_state _]]]].
  apply regular_kt_green_inv in Hreg.
  destruct Hreg as [_ Htail_reg].
  destruct tail as [b|tail_col tail_p tail_rest].
  - cbn in Hred. discriminate.
  - destruct tail_col; cbn in Hred; try discriminate.
    destruct tail_p as [|tail_pre tail_i tail_suf];
      cbn in Htail_state, Hred; try contradiction; try discriminate.
    destruct Htail_state as [Htail_pkt [Htail_tail_state Htail_ctx]].
    destruct (@green_of_red_k_preserves_recursive_wrap_ready_state_regular_when_case1_context
        A (k + packet_depth (PNode pre i suf))
        tail_pre tail_i tail_suf tail_rest c_tail
        Htail_reg Htail_pkt Htail_tail_state Htail_ctx
        (fun pre0 b0 suf0 c0 Hpre Hb Hsuf Hmake =>
           Hcase1 (k + packet_depth (PNode pre i suf))
             pre0 b0 suf0 c0 Hpre Hb Hsuf Hmake)
        Hred) as [_ Hready].
    exact Hready.
Qed.

