Theorem push_kt4_preserves_public_level_recursive_wrap_ready_state_yellow_repair_when_repair_wraps :
  forall A (x a b c d : E.t A) i suf tail c',
    E.level A x = 0 ->
    kt4_public_level_recursive_wrap_ready_state
      (KCons Yellow (PNode (B4 a b c d) i suf) tail) ->
    (forall c'',
      green_of_red_k (KCons Red (PNode (B5 x a b c d) i suf) tail) =
        Some c'' ->
      kt4_level_recursive_wrap_ready_state_at 0 c'') ->
    push_kt4 x (KCons Yellow (PNode (B4 a b c d) i suf) tail) =
      PushOk c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A x a b c d i suf tail c' Hx Hstate Hrepair_wrap Hpush.
  unfold push_kt4 in Hpush; cbn -[green_of_red_k] in Hpush.
  destruct (green_of_red_k
      (KCons Red (PNode (B5 x a b c d) i suf) tail)) as [c''|]
    eqn:Hred; [|discriminate].
  inversion Hpush; subst c''; clear Hpush.
  split.
  - pose proof Hred as Htop.
    apply green_of_red_k_top_green in Htop.
    rewrite Htop. discriminate.
  - eapply Hrepair_wrap. reflexivity.
Qed.

