Theorem push_kt4_preserves_public_level_recursive_wrap_ready_state_when_repairs_wrap :
  forall A (x : E.t A) c c',
    E.level A x = 0 ->
    regular_kt c ->
    kt4_public_level_recursive_wrap_ready_state c ->
    (forall pre i suf tail c_tail,
      c = KCons Green (PNode pre i suf) tail ->
      green_of_red_k tail = Some c_tail ->
      kt4_level_recursive_wrap_ready_state_at
        (packet_depth (PNode pre i suf)) c_tail) ->
    (forall pre i suf tail c_tail,
      c = KCons Green (PNode pre i suf) tail ->
      green_of_red_k tail = Some c_tail ->
      packet_context_recursive_repair_ready_at 0 i c_tail) ->
    (forall a b c0 d i suf tail c_repair,
      c = KCons Yellow (PNode (B4 a b c0 d) i suf) tail ->
      green_of_red_k (KCons Red (PNode (B5 x a b c0 d) i suf) tail) =
        Some c_repair ->
      kt4_level_recursive_wrap_ready_state_at 0 c_repair) ->
    push_kt4 x c = PushOk c' ->
    kt4_public_level_recursive_wrap_ready_state c'.
Proof.
  intros A x c c' Hx Hreg Hstate Hgreen_tail_state Hgreen_tail_ctx
    Hyellow_repair_state Hpush.
  destruct c as [b|col p tail].
  - eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_ending;
      eauto.
  - destruct p as [|pre i suf].
    { destruct col; cbn in Hpush; discriminate. }
    cbn in Hstate.
    destruct col.
    + apply regular_kt_green_inv in Hreg.
      destruct Hreg as [_ Htail_reg].
      destruct tail as [tb|tail_col tail_p tail_tail] eqn:Htail_eq.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_green_non_red_tail;
          [exact Hx|exact Hstate|cbn; discriminate|exact Hpush].
      * destruct tail_col.
        -- eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_green_non_red_tail;
             [exact Hx|exact Hstate|cbn; discriminate|exact Hpush].
        -- eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_green_non_red_tail;
             [exact Hx|exact Hstate|cbn; discriminate|exact Hpush].
        -- eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_green_tail_repair_wraps;
             [exact Hx|exact Htail_reg|exact Hstate| | |exact Hpush].
           ++ intros c_tail Hred.
              eapply Hgreen_tail_state; [reflexivity|exact Hred].
           ++ intros c_tail Hred.
              eapply Hgreen_tail_ctx; [reflexivity|exact Hred].
    + destruct pre as [|a|a b0|a b0 c0|a b0 c0 d|a b0 c0 d e];
        cbn in Hpush; try discriminate.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_yellow_no_repair;
          eauto; cbn; exact I.
      * eapply push_kt4_preserves_public_level_recursive_wrap_ready_state_yellow_repair_when_repair_wraps;
          [exact Hx|exact Hstate| |exact Hpush].
        intros c_repair Hred.
        eapply Hyellow_repair_state; [reflexivity|exact Hred].
    + destruct Hstate as [Htop _].
      exfalso. apply Htop. reflexivity.
Qed.

