Lemma yellow_wrap_pr_preserves_wrap_ready_state_wrap_tail :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt tail ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_wrap_ready_state_at (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_wrap_ready_at k i tail ->
    (forall c'',
      green_of_red_k tail = Some c'' ->
      kt4_level_wrap_ready_state_at
        (k + packet_depth (PNode pre i suf)) c'') ->
    yellow_wrap_pr pre i suf tail = PushOk c' ->
    kchain_top_color c' <> Red /\ kt4_level_wrap_ready_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpre Hsuf Hpkt Htail Hwrap
    Htail_after Hyw.
  destruct Hwrap as [Hctx_green Hctx_after].
  unfold yellow_wrap_pr in Hyw.
  destruct tail as [b|col p tail2].
  - inversion Hyw; subst; clear Hyw.
    split; [discriminate|cbn].
    repeat split; try assumption.
    eapply packet_context_green_ready_repair_ready_non_red_tail;
      [cbn; discriminate|exact Hctx_green].
  - destruct col.
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_green_ready_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_green_ready_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + destruct (green_of_red_k (KCons Red p tail2)) as [c''|]
        eqn:Hred; [|discriminate].
      inversion Hyw; subst c'; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      * eapply Htail_after. reflexivity.
      * eapply Hctx_after. reflexivity.
Qed.

Theorem push_kt4_preserves_public_level_wrap_ready_state_green_tail_repair_wraps :
  forall A (x : E.t A) pre i suf tail c',
    E.level A x = 0 ->
    regular_kt tail ->
    kt4_public_level_wrap_ready_state (KCons Green (PNode pre i suf) tail) ->
    (forall c'',
      green_of_red_k tail = Some c'' ->
      kt4_level_wrap_ready_state_at (packet_depth (PNode pre i suf)) c'') ->
    push_kt4 x (KCons Green (PNode pre i suf) tail) = PushOk c' ->
    kt4_public_level_wrap_ready_state c'.
Proof.
  intros A x pre i suf tail c' Hx Hreg [_ Hstate] Htail_after Hpush.
  cbn in Hstate.
  destruct Hstate as [Hpre_shape [Hsuf_shape [Hpkt [Htail [_ Hctx_wrap]]]]].
  unfold push_kt4 in Hpush.
  destruct pre as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hpre_shape, Hpush; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha Hb].
    destruct (@yellow_wrap_pr_preserves_wrap_ready_state_wrap_tail
        A 0 (B3 x a b) i suf tail c' Hreg)
      as [Htop' Hready']; try exact Hpush.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn;
        [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx_wrap.
    + intros c'' Hred. apply Htail_after. exact Hred.
    + split; assumption.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb Hc]].
    destruct (@yellow_wrap_pr_preserves_wrap_ready_state_wrap_tail
        A 0 (B4 x a b c0) i suf tail c' Hreg)
      as [Htop' Hready']; try exact Hpush.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn;
        [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx_wrap.
    + intros c'' Hred. apply Htail_after. exact Hred.
    + split; assumption.
Qed.

