  unfold pop_kt4 in Hpop.
  destruct pre as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hpre_shape, Hpop; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha Hb].
    destruct (yellow_wrap_pr (B1 b) i suf tail) as [|c''] eqn:Hyw;
      [discriminate|].
    inversion Hpop; subst; clear Hpop.
    destruct (@yellow_wrap_pr_preserves_wrap_ready_state_wrap_tail
        A 0 (B1 b) i suf tail c' Hreg)
      as [Htop' Hready']; try exact Hyw.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn; [exact Hb|assumption|assumption].
    + exact Htail.
    + exact Hctx_wrap.
    + intros c'' Hred. apply Htail_after. exact Hred.
    + split; assumption.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hpre_levels. destruct Hpre_levels as [Ha [Hb Hc]].
    destruct (yellow_wrap_pr (B2 b c0) i suf tail) as [|c''] eqn:Hyw;
      [discriminate|].
    inversion Hpop; subst; clear Hpop.
    destruct (@yellow_wrap_pr_preserves_wrap_ready_state_wrap_tail
        A 0 (B2 b c0) i suf tail c' Hreg)
      as [Htop' Hready']; try exact Hyw.
    + cbn. exact I.
    + eapply buf5_green_shape_not_red. exact Hsuf_shape.
    + constructor; cbn; [repeat split; assumption|assumption|assumption].
    + exact Htail.
    + exact Hctx_wrap.
    + intros c'' Hred. apply Htail_after. exact Hred.
    + split; assumption.
Qed.

Theorem eject_kt4_preserves_public_level_wrap_ready_state_green_tail_repair_wraps :
  forall (A : Type) (pre : Buf5 (E.t A)) (i : Packet A)
         (suf : Buf5 (E.t A)) (tail : KChain A) (x : E.t A) c',
    regular_kt tail ->
    kt4_public_level_wrap_ready_state (KCons Green (PNode pre i suf) tail) ->
    (forall c'',
      green_of_red_k tail = Some c'' ->
      kt4_level_wrap_ready_state_at (packet_depth (PNode pre i suf)) c'') ->
    eject_kt4 (KCons Green (PNode pre i suf) tail) = PopOk x c' ->
    kt4_public_level_wrap_ready_state c'.
Proof.
  intros A pre i suf tail x c' Hreg [_ Hstate] Htail_after Heject.
  cbn in Hstate.
  destruct Hstate as [Hpre_shape [Hsuf_shape [Hpkt [Htail [_ Hctx_wrap]]]]].
  unfold eject_kt4 in Heject.
  destruct suf as [|a|a b|a b c0|a b c0 d|a b c0 d e];
    cbn in Hsuf_shape, Heject; try contradiction; try discriminate.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hsuf_levels. destruct Hsuf_levels as [Ha Hb].
    destruct (yellow_wrap_pr pre i (B1 a) tail) as [|c''] eqn:Hyw;
      [discriminate|].
    inversion Heject; subst; clear Heject.
    destruct (@yellow_wrap_pr_preserves_wrap_ready_state_wrap_tail
        A 0 pre i (B1 a) tail c' Hreg)
      as [Htop' Hready']; try exact Hyw.
    + eapply buf5_green_shape_not_red. exact Hpre_shape.
    + cbn. exact I.
    + constructor; cbn; [assumption|assumption|exact Ha].
    + exact Htail.
    + exact Hctx_wrap.
    + intros c'' Hred. apply Htail_after. exact Hred.
    + split; assumption.
  - inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
    cbn in Hsuf_levels. destruct Hsuf_levels as [Ha [Hb Hc]].
    destruct (yellow_wrap_pr pre i (B2 a b) tail) as [|c''] eqn:Hyw;
      [discriminate|].
    inversion Heject; subst; clear Heject.
    destruct (@yellow_wrap_pr_preserves_wrap_ready_state_wrap_tail
        A 0 pre i (B2 a b) tail c' Hreg)
      as [Htop' Hready']; try exact Hyw.
    + eapply buf5_green_shape_not_red. exact Hpre_shape.
    + cbn. exact I.
    + constructor; cbn; [assumption|assumption|repeat split; assumption].
    + exact Htail.
    + exact Hctx_wrap.
    + intros c'' Hred. apply Htail_after. exact Hred.
    + split; assumption.
Qed.

Lemma green_of_red_k_case3_preserves_repair_ready_state :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail c' : KChain A),
    packet_levels k (PNode pre1 (PNode pre2 child suf2) suf1) ->
    kt4_level_repair_ready_state_at
      (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1)) tail ->
    packet_context_repair_ready_at k (PNode pre2 child suf2) tail ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) = Some c' ->
    kchain_top_color c' <> Red /\ kt4_level_repair_ready_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail c' Hpkt Htail Hctx Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 Hinner Hsuf1]; subst.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  inversion Hctx as [| |? ? ? ? ? Hpre2_shape Hsuf2_shape _ Hctx_child];
    subst.
  unfold green_of_red_k in Hred.
  destruct (prefix_concat pre1 pre2) as [[pre1' pre2']|] eqn:Hpre_concat;
    [|discriminate].
  destruct (suffix_concat suf2 suf1) as [[suf2' suf1']|] eqn:Hsuf_concat;
    [|discriminate].
  inversion Hred; subst c'; clear Hred.
  destruct (@prefix_concat_preserves_outer_green_levels A k pre1 pre2
      pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre1' Hpre2']].
  destruct (@suffix_concat_preserves_outer_green_levels A k suf2 suf1
      suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2' [Hsuf1'_shape Hsuf1']].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|constructor|assumption].
  - split.
    + cbn.
      replace (k + 1) with (S k) by lia.
      split; [exact Hinner'|].
      split.
      * replace (S k + S (packet_depth child))
        with (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1))
        by (cbn; lia).
        exact Htail.
      * exact Hctx_child.
    + split.
      * change (exists c'0,
        green_of_red_k (KCons Red (PNode pre2' child suf2') tail) = Some c'0).
        eapply green_of_red_k_total_under_ready_levels; [exact Hinner'|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_repair_ready_context_ready. exact Hctx_child.
      * constructor; assumption.
Qed.

Lemma green_of_red_k_case3_preserves_wrap_ready_state_under_inner_repair_context :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) (tail c' : KChain A),
    packet_levels k (PNode pre1 (PNode pre2 child suf2) suf1) ->
    kt4_level_wrap_ready_state_at
      (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1)) tail ->
    packet_context_repair_ready_at k (PNode pre2 child suf2) tail ->
    (forall pre1' pre2' suf2' suf1' c_inner,
      prefix_concat pre1 pre2 = Some (pre1', pre2') ->
      suffix_concat suf2 suf1 = Some (suf2', suf1') ->
      green_of_red_k (KCons Red (PNode pre2' child suf2') tail) =
        Some c_inner ->
      packet_context_repair_ready_at k Hole c_inner) ->
    green_of_red_k
      (KCons Red (PNode pre1 (PNode pre2 child suf2) suf1) tail) = Some c' ->
    kchain_top_color c' <> Red /\ kt4_level_wrap_ready_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child tail c'
    Hpkt Htail Hctx Hinner_after Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 Hinner Hsuf1]; subst.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  inversion Hctx as [| |? ? ? ? ? Hpre2_shape Hsuf2_shape _ Hctx_child];
    subst.
  unfold green_of_red_k in Hred.
  destruct (prefix_concat pre1 pre2) as [[pre1' pre2']|] eqn:Hpre_concat;
    [|discriminate].
  destruct (suffix_concat suf2 suf1) as [[suf2' suf1']|] eqn:Hsuf_concat;
    [|discriminate].
  inversion Hred; subst c'; clear Hred.
  destruct (@prefix_concat_preserves_outer_green_levels A k pre1 pre2
      pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre1' Hpre2']].
  destruct (@suffix_concat_preserves_outer_green_levels A k suf2 suf1
      suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2' [Hsuf1'_shape Hsuf1']].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|constructor|assumption].
  - split.
    + cbn.
      replace (k + 1) with (S k) by lia.
      split; [exact Hinner'|].
      split.
      * replace (S k + S (packet_depth child))
          with (k + packet_depth (PNode pre1 (PNode pre2 child suf2) suf1))
          by (cbn; lia).
        exact Htail.
      * exact Hctx_child.
    + split.
      * change (exists c'0,
          green_of_red_k (KCons Red (PNode pre2' child suf2') tail) =
            Some c'0).
        eapply green_of_red_k_total_under_ready_levels; [exact Hinner'|].
        eapply green_of_red_k_ready_at_from_context.
        eapply packet_context_repair_ready_context_ready. exact Hctx_child.
      * split.
        -- constructor; assumption.
        -- intros c_inner Hred_inner.
           eapply Hinner_after; eauto.
Qed.

Lemma green_of_red_k_case2_preserves_repair_ready_state_regular :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) col tail c',
    regular_kt
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) ->
    packet_levels k (PNode pre1 Hole suf1) ->
    kt4_level_repair_ready_state_at
      (k + packet_depth (PNode pre1 Hole suf1))
      (KCons col (PNode pre2 child suf2) tail) ->
    packet_context_repair_ready_at k Hole
      (KCons col (PNode pre2 child suf2) tail) ->
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) = Some c' ->
    kchain_top_color c' <> Red /\ kt4_level_repair_ready_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child col tail c'
    Hreg Hpkt Htail_state Hctx Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hctx as [|? ? ? ? ? ? Hpre2_shape Hsuf2_shape Hinner Hctx_child|];
    subst.
  replace (k + packet_depth (PNode pre1 Hole suf1)) with (S k) in Htail_state
    by (cbn; lia).
  unfold green_of_red_k in Hred.
  destruct (green_prefix_concat pre1 pre2) as [[pre1' pre2']|]
    eqn:Hpre_concat; [|discriminate].
  destruct (green_suffix_concat suf2 suf1) as [[suf2' suf1']|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst c'; clear Hred.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k pre1 pre2 pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre2'_shape [Hpre1' Hpre2']]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k suf2 suf1 suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2'_shape [Hsuf1'_shape [Hsuf2' Hsuf1']]].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  apply regular_kt_red_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|exact Hinner'|assumption].
  - split.
    + replace (k + S (S (packet_depth child)))
        with (S (k + S (packet_depth child))) by lia.
      destruct col.
      * cbn in Htail_state.
        destruct Htail_state as [_ [_ [_ [Htail _]]]].
        exact Htail.
      * cbn in Htail_state.
        destruct Htail_state as [_ [_ [_ [Htail _]]]].
        exact Htail.
      * exfalso. apply Htail_top. reflexivity.
    + split.
      * destruct col.
        -- cbn in Htail_state.
           destruct Htail_state as [_ [_ [_ [_ [Hyw _]]]]].
           exact Hyw.
        -- apply regular_kt_yellow_inv in Htail_reg.
           destruct Htail_reg as [_ [Htail_non_red _]].
           destruct tail as [b|tail_col tail_p tail_tail];
             cbn in Htail_non_red |- *; try exact I.
           destruct tail_col; try exact I.
           exfalso. apply Htail_non_red. reflexivity.
        -- exfalso. apply Htail_top. reflexivity.
      * constructor; assumption.
Qed.

Lemma green_of_red_k_case2_preserves_wrap_ready_state_regular :
  forall A k (pre1 suf1 pre2 suf2 : Buf5 (E.t A))
         (child : Packet A) col tail c',
    regular_kt
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) ->
    packet_levels k (PNode pre1 Hole suf1) ->
    kt4_level_wrap_ready_state_at
      (k + packet_depth (PNode pre1 Hole suf1))
      (KCons col (PNode pre2 child suf2) tail) ->
    packet_context_repair_ready_at k Hole
      (KCons col (PNode pre2 child suf2) tail) ->
    green_of_red_k
      (KCons Red (PNode pre1 Hole suf1)
         (KCons col (PNode pre2 child suf2) tail)) = Some c' ->
    kchain_top_color c' <> Red /\ kt4_level_wrap_ready_state_at k c'.
Proof.
  intros A k pre1 suf1 pre2 suf2 child col tail c'
    Hreg Hpkt Htail_state Hctx Hred.
  inversion Hpkt as [|? ? ? ? Hpre1 _ Hsuf1]; subst.
  inversion Hctx as [|? ? ? ? ? ? Hpre2_shape Hsuf2_shape Hinner Hctx_child|];
    subst.
  replace (k + packet_depth (PNode pre1 Hole suf1)) with (S k) in Htail_state
    by (cbn; lia).
  unfold green_of_red_k in Hred.
  destruct (green_prefix_concat pre1 pre2) as [[pre1' pre2']|]
    eqn:Hpre_concat; [|discriminate].
  destruct (green_suffix_concat suf2 suf1) as [[suf2' suf1']|]
    eqn:Hsuf_concat; [|discriminate].
  inversion Hred; subst c'; clear Hred.
  inversion Hinner as [|? ? ? ? Hpre2 Hchild Hsuf2]; subst.
  destruct (@green_prefix_concat_preserves_green_outer_not_red_inner_levels
      A k pre1 pre2 pre1' pre2' Hpre1 Hpre2 Hpre2_shape Hpre_concat)
    as [Hpre1'_shape [Hpre2'_shape [Hpre1' Hpre2']]].
  destruct (@green_suffix_concat_preserves_not_red_inner_green_outer_levels
      A k suf2 suf1 suf2' suf1' Hsuf2 Hsuf1 Hsuf2_shape Hsuf_concat)
    as [Hsuf2'_shape [Hsuf1'_shape [Hsuf2' Hsuf1']]].
  assert (Hinner' : packet_levels (S k) (PNode pre2' child suf2')).
  { constructor; assumption. }
  apply regular_kt_red_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  split; [discriminate|cbn].
  split; [exact Hpre1'_shape|].
  split; [exact Hsuf1'_shape|].
  split.
  - constructor; cbn; [assumption|exact Hinner'|assumption].
  - destruct col.
    + cbn in Htail_state.
      destruct Htail_state as [_ [_ [_ [Htail [Hyw Hctx_wrap_child]]]]].
      destruct Hctx_wrap_child as [_ Hctx_after_child].
      split.
      * replace (k + S (S (packet_depth child)))
          with (S (k + S (packet_depth child))) by lia.
        exact Htail.
      * split.
        -- exact Hyw.
        -- split.
           ++ eapply pcgr_pnode; eauto.
           ++ intros c_after Hafter.
              eapply pcrr_pnode; eauto.
    + cbn in Htail_state.
      destruct Htail_state as [_ [_ [_ [Htail _]]]].
      apply regular_kt_yellow_inv in Htail_reg.
      destruct Htail_reg as [_ [Htail_non_red _]].
      split.
      * replace (k + S (S (packet_depth child)))
          with (S (k + S (packet_depth child))) by lia.
        exact Htail.
      * split.
        -- destruct tail as [b|tail_col tail_p tail_tail];
             cbn in Htail_non_red |- *; try exact I.
           destruct tail_col; try exact I.
           exfalso. apply Htail_non_red. reflexivity.
        -- split.
           ++ eapply pcgr_pnode; eauto.
           ++ intros c_after Hafter.
              destruct tail as [b|tail_col tail_p tail_tail];
                cbn in Hafter; try discriminate.
              destruct tail_col; cbn in Htail_non_red, Hafter;
                try discriminate.
              exfalso. apply Htail_non_red. reflexivity.
    + exfalso. apply Htail_top. reflexivity.
Qed.

Local Ltac kt4_repair_ready_atom :=
  cbn -[E.pair E.unpair] in *;
  repeat match goal with
    | H : _ /\ _ |- _ => destruct H
    end;
  repeat rewrite E.level_pair in *;
  repeat rewrite OpsKT.E.level_pair in *;
  repeat rewrite Model.E.level_pair in *;
  try exact I;
  try assumption;
  try lia;
  match goal with
  | H : E.level ?A ?x = ?m |- E.level ?A ?x = ?n =>
      replace n with m by lia; exact H
  | H : buf_all_at_level ?m ?b |- buf_all_at_level ?n ?b =>
      replace n with m by lia; exact H
  | H : packet_levels ?m ?p |- packet_levels ?n ?p =>
      replace n with m by lia; exact H
  end.

Local Ltac kt4_repair_ready_context :=
  match goal with
  | |- packet_levels _ Hole =>
      constructor
  | |- packet_levels _ (PNode _ _ _) =>
      constructor;
      [kt4_repair_ready_atom
      |kt4_repair_ready_context
      |kt4_repair_ready_atom]
  | |- packet_context_repair_ready_at _ Hole (KEnding _) =>
      constructor; kt4_repair_ready_atom
  | |- packet_context_repair_ready_at _ Hole
          (KCons _ (PNode _ _ _) _) =>
      eapply pcrr_hole_kcons;
      [kt4_repair_ready_atom
      |kt4_repair_ready_atom
      |kt4_repair_ready_context
      |kt4_repair_ready_context]
  | |- packet_context_repair_ready_at _ (PNode _ _ _) _ =>
      eapply pcrr_pnode;
      [kt4_repair_ready_atom
      |kt4_repair_ready_atom
      |kt4_repair_ready_context
      |kt4_repair_ready_context]
  | |- packet_context_green_ready_at _ Hole (KEnding _) =>
      constructor; kt4_repair_ready_atom
  | |- packet_context_green_ready_at _ Hole
          (KCons Green (PNode _ _ _) _) =>
      eapply pcgr_hole_non_red_kcons;
      [discriminate
      |kt4_repair_ready_atom
      |kt4_repair_ready_atom
      |kt4_repair_ready_context
      |kt4_repair_ready_context]
  | |- packet_context_green_ready_at _ Hole
          (KCons Yellow (PNode _ _ _) _) =>
      eapply pcgr_hole_non_red_kcons;
      [discriminate
      |kt4_repair_ready_atom
      |kt4_repair_ready_atom
      |kt4_repair_ready_context
      |kt4_repair_ready_context]
  | |- packet_context_green_ready_at _ Hole
          (KCons Red (PNode _ _ _) _) =>
      eapply pcgr_hole_red_kcons;
      [kt4_repair_ready_context
      |kt4_repair_ready_context]
  | |- packet_context_green_ready_at _ (PNode _ _ _) _ =>
      eapply pcgr_pnode;
      [kt4_repair_ready_atom
      |kt4_repair_ready_atom
      |kt4_repair_ready_context
      |kt4_repair_ready_context]
  end.

Lemma make_small_chain_to_kchain_g_repair_ready_state :
  forall A k (pre b suf : Buf5 (E.t A)) c,
    buf_all_at_level k pre ->
    buf_all_at_level (S k) b ->
    buf_all_at_level k suf ->
    make_small pre b suf = Some c ->
    kt4_level_repair_ready_state_at k (chain_to_kchain_g c).
Proof.
  intros A k pre b suf c Hpre Hb Hsuf Hmake.
  unfold make_small in Hmake.
  destruct pre as [|p1|p1 p2|p1 p2 p3|p1 p2 p3 p4|p1 p2 p3 p4 p5];
    destruct b as [|m1|m1 m2|m1 m2 m3|m1 m2 m3 m4|m1 m2 m3 m4 m5];
    destruct suf as [|s1|s1 s2|s1 s2 s3|s1 s2 s3 s4|s1 s2 s3 s4 s5];
    cbn -[E.pair E.unpair] in Hpre, Hb, Hsuf, Hmake |- *;
    repeat match goal with
      | H : _ /\ _ |- _ => destruct H
      end;
    repeat match goal with
      | H : match E.unpair ?A ?e with Some _ => _ | None => _ end = _ |- _ =>
          let Hup := fresh "Hup" in
          let u0 := fresh "u" in
          let v0 := fresh "v" in
          destruct (E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
          pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
      | H : match OpsKT.E.unpair ?A ?e with Some _ => _ | None => _ end = _ |- _ =>
          let Hup := fresh "Hup" in
          let u0 := fresh "u" in
          let v0 := fresh "v" in
          destruct (OpsKT.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
          pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
      | H : match Model.E.unpair ?A ?e with Some _ => _ | None => _ end = _ |- _ =>
          let Hup := fresh "Hup" in
          let u0 := fresh "u" in
          let v0 := fresh "v" in
          destruct (Model.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
          pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
      | H : context [match E.unpair ?A ?e with Some _ => _ | None => _ end] |- _ =>
          let Hup := fresh "Hup" in
          let u0 := fresh "u" in
          let v0 := fresh "v" in
          destruct (E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
          pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
      | H : context [match OpsKT.E.unpair ?A ?e with Some _ => _ | None => _ end] |- _ =>
          let Hup := fresh "Hup" in
          let u0 := fresh "u" in
          let v0 := fresh "v" in
          destruct (OpsKT.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
          pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
      | H : context [match Model.E.unpair ?A ?e with Some _ => _ | None => _ end] |- _ =>
          let Hup := fresh "Hup" in
          let u0 := fresh "u" in
          let v0 := fresh "v" in
          destruct (Model.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
          pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
      | H : context [E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [OpsKT.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (OpsKT.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Model.E.unpair ?A ?e] |- _ =>
          lazymatch goal with
          | _ : Model.E.unpair A e = _ |- _ => fail
          | _ : OpsKT.E.unpair A e = _ |- _ => fail
          | _ : E.unpair A e = _ |- _ => fail
          | _ =>
              let Hup := fresh "Hup" in
              let u0 := fresh "u" in
              let v0 := fresh "v" in
              destruct (Model.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
              pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
          end
      | H : context [Nat.eq_dec ?x ?y] |- _ =>
          destruct (Nat.eq_dec x y); try discriminate
      | H : context [buf5_push_naive ?x ?b] |- _ =>
          destruct (buf5_push_naive x b) eqn:?; try discriminate
      | H : context [buf5_inject_naive ?b ?x] |- _ =>
          destruct (buf5_inject_naive b x) eqn:?; try discriminate
      | H : context [buf5_pop_naive ?b] |- _ =>
          destruct (buf5_pop_naive b) as [[u v]|] eqn:?; try discriminate
      | H : context [buf5_eject_naive ?b] |- _ =>
          destruct (buf5_eject_naive b) as [[u v]|] eqn:?; try discriminate
      | H : context [pair_each_buf ?b] |- _ =>
          destruct (pair_each_buf b) eqn:?; try discriminate
      end;
    inversion Hmake; subst; clear Hmake;
    cbn -[E.pair E.unpair]; repeat split;
    try solve [kt4_repair_ready_atom];
    try solve [kt4_repair_ready_context].
  all: try match goal with
    | H : context [OpsKT.E.unpair ?A ?e] |- _ =>
        let Hup := fresh "Hup" in
        let u0 := fresh "u" in
        let v0 := fresh "v" in
        destruct (OpsKT.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
        pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
    | H : context [Model.E.unpair ?A ?e] |- _ =>
        let Hup := fresh "Hup" in
        let u0 := fresh "u" in
        let v0 := fresh "v" in
        destruct (Model.E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
        pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
    | H : context [E.unpair ?A ?e] |- _ =>
        let Hup := fresh "Hup" in
        let u0 := fresh "u" in
        let v0 := fresh "v" in
        destruct (E.unpair A e) as [[u0 v0]|] eqn:Hup; try discriminate;
        pose proof (E.unpair_level A e u0 v0 Hup) as [? ?]
    end.
  all: repeat match goal with
      | H : Some _ = Some _ |- _ => inversion H; subst; clear H
      end.
  all: cbn -[E.pair E.unpair]; repeat split.
  all: try solve [kt4_repair_ready_atom].
  all: try solve [kt4_repair_ready_context].
Qed.

Lemma green_of_red_k_case1_preserves_repair_ready_state :
  forall A k (pre suf b : Buf5 (E.t A)) c',
    packet_levels k (PNode pre Hole suf) ->
    kt4_level_repair_ready_state_at
      (k + packet_depth (PNode pre Hole suf)) (KEnding b) ->
    green_of_red_k (KCons Red (PNode pre Hole suf) (KEnding b)) = Some c' ->
    kchain_top_color c' <> Red /\ kt4_level_repair_ready_state_at k c'.
Proof.
  intros A k pre suf b c' Hpkt Hb Hred.
  inversion Hpkt as [|? ? ? ? Hpre _ Hsuf]; subst.
  replace (k + packet_depth (PNode pre Hole suf)) with (S k) in Hb
    by (cbn; lia).
  unfold green_of_red_k in Hred.
  destruct (make_small pre b suf) as [c|] eqn:Hmake; [|discriminate].
  inversion Hred; subst c'; clear Hred.
  split.
  - destruct c; cbn; discriminate.
  - eapply make_small_chain_to_kchain_g_repair_ready_state
      with (pre := pre) (b := b) (suf := suf); eauto.
Qed.

Lemma green_of_red_k_chain_to_kchain_g_none :
  forall A (c : Chain A),
    green_of_red_k (chain_to_kchain_g c) = None.
Proof.
  intros A c.
  destruct c; reflexivity.
Qed.

Lemma kt4_level_repair_ready_chain_to_kchain_g_wrap_ready_state_at :
  forall A k (c : Chain A),
    kt4_level_repair_ready_state_at k (chain_to_kchain_g c) ->
    kt4_level_wrap_ready_state_at k (chain_to_kchain_g c).
Proof.
  intros A k c.
  revert k.
  induction c as [b|p tail IH]; intros k Hready.
  - exact Hready.
  - destruct p as [|pre i suf]; cbn in Hready |- *; try contradiction.
    destruct Hready as [Hpre [Hsuf [Hpkt [Htail [Hyw Hctx]]]]].
    repeat split; try assumption.
    + apply IH. exact Htail.
    + intros c' Hred.
      rewrite green_of_red_k_chain_to_kchain_g_none in Hred.
      discriminate.
Qed.

Lemma make_small_chain_to_kchain_g_wrap_ready_state :
  forall A k (pre b suf : Buf5 (E.t A)) c,
    buf_all_at_level k pre ->
    buf_all_at_level (S k) b ->
    buf_all_at_level k suf ->
    make_small pre b suf = Some c ->
    kt4_level_wrap_ready_state_at k (chain_to_kchain_g c).
Proof.
  intros A k pre b suf c Hpre Hb Hsuf Hmake.
  eapply (@kt4_level_repair_ready_chain_to_kchain_g_wrap_ready_state_at A k c).
  eapply make_small_chain_to_kchain_g_repair_ready_state
      with (pre := pre) (b := b) (suf := suf); eauto.
Qed.

