Lemma green_of_red_k_preserves_repair_ready_state_regular :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt (KCons Red (PNode pre i suf) tail) ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_repair_ready_state_at
      (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_repair_ready_at k i tail ->
    green_of_red_k (KCons Red (PNode pre i suf) tail) = Some c' ->
    kchain_top_color c' <> Red /\ kt4_level_repair_ready_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpkt Htail Hctx Hred.
  destruct i as [|pre2 child suf2].
  - destruct tail as [b|col p tail2].
    + eapply green_of_red_k_case1_preserves_repair_ready_state; eauto.
    + destruct p as [|pre2 child suf2].
      * inversion Hctx.
      * eapply green_of_red_k_case2_preserves_repair_ready_state_regular;
          eauto.
  - eapply green_of_red_k_case3_preserves_repair_ready_state; eauto.
Qed.

Lemma yellow_wrap_pr_preserves_repair_ready_state_wrap_tail :
  forall A k (pre : Buf5 (E.t A)) i suf tail c',
    regular_kt tail ->
    buf5_is_not_red_shape pre ->
    buf5_is_not_red_shape suf ->
    packet_levels k (PNode pre i suf) ->
    kt4_level_repair_ready_state_at (k + packet_depth (PNode pre i suf)) tail ->
    packet_context_wrap_ready_at k i tail ->
    yellow_wrap_pr pre i suf tail = PushOk c' ->
    kchain_top_color c' <> Red /\ kt4_level_repair_ready_state_at k c'.
Proof.
  intros A k pre i suf tail c' Hreg Hpre Hsuf Hpkt Htail Hwrap Hyw.
  destruct Hwrap as [Hctx_green Hctx_after].
  unfold yellow_wrap_pr in Hyw.
  destruct tail as [b|col p tail2].
  - inversion Hyw; subst; clear Hyw.
    split; [discriminate|cbn].
    repeat split; try assumption.
    eapply packet_context_green_ready_repair_ready_non_red_tail;
      [cbn; discriminate|exact Hctx_green].
  - destruct col.
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_green_ready_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + inversion Hyw; subst; clear Hyw.
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply packet_context_green_ready_repair_ready_non_red_tail;
        [cbn; discriminate|exact Hctx_green].
    + destruct (green_of_red_k (KCons Red p tail2)) as [c''|]
        eqn:Hred; [|discriminate].
      inversion Hyw; subst c'; clear Hyw.
      destruct p as [|pre2 i2 suf2]; cbn in Htail; try contradiction.
      destruct Htail as [Hpkt_tail [Htail_tail Hctx_tail]].
      destruct (@green_of_red_k_preserves_repair_ready_state_regular
          A (k + packet_depth (PNode pre i suf)) pre2 i2 suf2 tail2 c''
          Hreg Hpkt_tail Htail_tail Hctx_tail Hred) as [Htop' Hready'].
      split; [discriminate|cbn].
      repeat split; try assumption.
      eapply Hctx_after. reflexivity.
Qed.

Theorem push_kt4_preserves_public_level_repair_ready_state_yellow_repair_regular :
  forall A (x a b c d : E.t A) i suf tail c',
    E.level A x = 0 ->
    regular_kt (KCons Yellow (PNode (B4 a b c d) i suf) tail) ->
    kt4_public_level_repair_ready_state
      (KCons Yellow (PNode (B4 a b c d) i suf) tail) ->
    push_kt4 x (KCons Yellow (PNode (B4 a b c d) i suf) tail) =
      PushOk c' ->
    kt4_public_level_repair_ready_state c'.
Proof.
  intros A x a b c d i suf tail c' Hx Hreg [_ Hstate] Hpush.
  cbn in Hstate.
  destruct Hstate as [_ [Hsuf_shape [Hpkt [Htail Hctx]]]].
  apply regular_kt_yellow_inv in Hreg.
  destruct Hreg as [_ [Htail_top Htail_reg]].
  unfold push_kt4 in Hpush; cbn -[green_of_red_k] in Hpush.
  destruct (green_of_red_k
      (KCons Red (PNode (B5 x a b c d) i suf) tail)) as [c''|]
    eqn:Hred; [|discriminate].
  inversion Hpush; subst c''; clear Hpush.
  inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
  cbn in Hpre_levels.
  destruct Hpre_levels as [Ha [Hb [Hc Hd]]].
  assert (Hreg_red :
    regular_kt (KCons Red (PNode (B5 x a b c d) i suf) tail)).
  { constructor; [exact I|exact Htail_top|exact Htail_reg]. }
  assert (Hpkt_red : packet_levels 0 (PNode (B5 x a b c d) i suf)).
  { constructor; cbn; [repeat split; assumption|assumption|assumption]. }
  assert (Htail_red : kt4_level_repair_ready_state_at
      (0 + packet_depth (PNode (B5 x a b c d) i suf)) tail).
  { replace (0 + packet_depth (PNode (B5 x a b c d) i suf))
      with (0 + packet_depth (PNode (B4 a b c d) i suf)) by (cbn; lia).
    exact Htail. }
  destruct (@green_of_red_k_preserves_repair_ready_state_regular
      A 0 (B5 x a b c d) i suf tail c'
      Hreg_red Hpkt_red Htail_red Hctx Hred) as [Htop' Hready'].
  split; assumption.
Qed.

Theorem inject_kt4_preserves_public_level_repair_ready_state_yellow_repair_regular :
  forall A pre i (a b c d x : E.t A) tail c',
    E.level A x = 0 ->
