      (KCons Red (PNode pre i (B5 a b c d x)) tail)) as [c''|]
    eqn:Hred; [|discriminate].
  inversion Hinject; subst c''; clear Hinject.
  inversion Hpkt as [|? ? ? ? Hpre_levels Hinner Hsuf_levels]; subst.
  cbn in Hsuf_levels.
  destruct Hsuf_levels as [Ha [Hb [Hc Hd]]].
  assert (Hreg_red :
    regular_kt (KCons Red (PNode pre i (B5 a b c d x)) tail)).
  { constructor; [exact I|exact Htail_top|exact Htail_reg]. }
  assert (Hpkt_red : packet_levels 0 (PNode pre i (B5 a b c d x))).
  { constructor; cbn; [assumption|assumption|repeat split; assumption]. }
  assert (Htail_red : kt4_level_wrap_ready_state_at
      (0 + packet_depth (PNode pre i (B5 a b c d x))) tail).
  { replace (0 + packet_depth (PNode pre i (B5 a b c d x)))
      with (0 + packet_depth (PNode pre i (B4 a b c d))) by (cbn; lia).
    exact Htail. }
  assert (Htail_red_repair : kt4_level_repair_ready_state_at
      (0 + packet_depth (PNode pre i (B5 a b c d x))) tail).
  { eapply kt4_level_wrap_ready_state_repair_ready_state_at.
    exact Htail_red. }
  destruct (@green_of_red_k_preserves_repair_ready_state_regular
      A 0 pre i (B5 a b c d x) tail c'
      Hreg_red Hpkt_red Htail_red_repair Hctx Hred) as [Htop' _].
  split; [exact Htop'|].
  eapply Hrepair_wrap. reflexivity.
Qed.

Theorem pop_kt4_preserves_public_level_wrap_ready_state_yellow_repair_regular_when_repair_wraps :
  forall A (a : E.t A) i suf tail x c',
    regular_kt (KCons Yellow (PNode (B1 a) i suf) tail) ->
